globalThis.__BQ = {"cinsiyetKromozomu":{"ilkokul":{"kolay":[{"q":"Bir bebeğin kız mı erkek mi olacağını sağlayan kromozomlara ne ad verilir?","steps":[{"t":"Kromozomları hatırla","a":"Cinsiyet kromozomu","d":"Hücrelerimizde bulunan kromozomların bir kısmı kız mı erkek mi olacağımızı belirler."},{"t":"İsmini söyle","a":"Cinsiyet kromozomları","d":"Bu özel kromozomlara <b>cinsiyet kromozomları</b> denir. Diğerleri vücut özelliklerini taşır."}],"ans":"Cinsiyeti belirleyen kromozomlara cinsiyet kromozomları denir."},{"q":"Annenin çocuğuna verdiği cinsiyet kromozomu hangisidir?","steps":[{"t":"Annenin kromozomlarına bak","a":"İki tane X","d":"Annede iki tane aynı cinsiyet kromozomu vardır, ikisi de X harfiyle gösterilir."},{"t":"Çocuğa hangisini verir?","a":"Her zaman X","d":"Annede sadece X olduğu için çocuğa <b>her zaman X</b> verir."}],"ans":"Anne çocuğuna her zaman X kromozomu verir."},{"q":"Babanın çocuğuna verebileceği cinsiyet kromozomları nelerdir?","steps":[{"t":"Babanın kromozomlarına bak","a":"X ve Y","d":"Babada iki farklı cinsiyet kromozomu vardır: biri X, biri Y."},{"t":"Çocuğa ne verir?","a":"X veya Y","d":"Baba çocuğuna <b>X veya Y</b>'den birini verir. Hangisini verdiği cinsiyeti belirler."}],"ans":"Baba çocuğuna ya X ya da Y kromozomu verir."},{"q":"Bir bebeğin kız olması için babadan hangi kromozomu alması gerekir?","steps":[{"t":"Anneden geleni hatırla","a":"X","d":"Anne her zaman X verir, bu sabittir."},{"t":"Babadan X gelirse","a":"X + X = kız","d":"Baba da X verirse iki X bir araya gelir ve bebek <b>kız</b> olur."}],"ans":"Babadan X kromozomu alan bebek kız olur."},{"q":"Bir bebeğin erkek olması için babadan hangi kromozomu alması gerekir?","steps":[{"t":"Anneden geleni hatırla","a":"X","d":"Anne her zaman X kromozomu verir."},{"t":"Babadan Y gelirse","a":"X + Y = erkek","d":"Baba Y verirse X ile Y bir araya gelir ve bebek <b>erkek</b> olur."}],"ans":"Babadan Y kromozomu alan bebek erkek olur."}],"zor":[{"q":"Cinsiyetin belirlenmesinde babanın daha etkili olduğu söylenir. Bunun nedeni nedir?","steps":[{"t":"Annenin verdiğine bak","a":"Hep X","d":"Anne çocuğa her zaman X verir, yani annenin seçeneği yoktur."},{"t":"Babanın verdiğine bak","a":"X veya Y","d":"Baba ise X ya da Y verebilir. İşte cinsiyeti değiştiren bu seçimdir."}],"ans":"Anne hep X verdiği için cinsiyeti baba belirler; baba X verirse kız, Y verirse erkek olur."},{"q":"Bir ailede üç tane kız çocuk var. Dördüncü bebeğin kız olma ihtimali ile erkek olma ihtimali hakkında ne söylenir?","steps":[{"t":"Her doğum ayrıdır","a":"Önceki etkilemez","d":"Daha önce kaç kız doğduğu yeni bebeği etkilemez. Her doğum yeniden başlar."},{"t":"İhtimali düşün","a":"Yarı yarıya","d":"Baba X de verebilir Y de. Bu yüzden kız ve erkek olma şansı <b>eşittir</b>."}],"ans":"Önceki çocuklar etkilemez; dördüncü bebeğin kız ya da erkek olma ihtimali yarı yarıyadır."},{"q":"Ahmet kız kardeşinin gözlerinin kendisininkine benzediğini görüyor ama o erkek, kardeşi kız. Bu farkı sağlayan kromozomlar hangileridir?","steps":[{"t":"Benzerlik neden var?","a":"Aynı anne-baba","d":"İkisi de aynı anne babadan birçok ortak özellik aldığı için benzerler."},{"t":"Fark neden var?","a":"Cinsiyet kromozomu","d":"Fark, cinsiyet kromozomlarından gelir: Ahmet babadan Y, kardeşi X almıştır."}],"ans":"Benzerlik ortak kromozomlardan, cinsiyet farkı ise babadan gelen X veya Y kromozomundan kaynaklanır."},{"q":"Bir öğrenci 'cinsiyeti anne belirler' diyor. Bu doğru mu, neden?","steps":[{"t":"Annenin rolü","a":"Hep X verir","d":"Anne tek çeşit kromozom (X) verdiği için cinsiyeti değiştiremez."},{"t":"Doğru cevap","a":"Yanlış, baba belirler","d":"Cinsiyeti belirleyen, X veya Y verebilen <b>babadır</b>. Öğrenci yanılıyor."}],"ans":"Yanlış; anne hep X verdiği için cinsiyeti baba belirler."},{"q":"Bir bebeğin hücrelerinde XX kromozomları bulunuyor. Bu bebek hakkında ne söyleyebiliriz?","steps":[{"t":"İki X'i incele","a":"Biri anneden biri babadan","d":"İki X'in biri anneden, diğeri de babadan gelmiştir."},{"t":"Cinsiyeti belirle","a":"Kız","d":"İki X kromozomu taşıyan bir bebek <b>kız</b>dır."}],"ans":"XX kromozomlarına sahip bebek kızdır; X'lerin biri anneden biri babadan gelmiştir."}]},"ortaokul":{"kolay":[{"q":"İnsanda cinsiyeti belirleyen kromozom çifti hangisidir ve dişide nasıl gösterilir?","steps":[{"t":"Cinsiyet kromozomunu bul","a":"23. çift","d":"İnsanda 23 çift kromozomdan son çift cinsiyet kromozomudur."},{"t":"Dişiyi yaz","a":"XX","d":"Dişi bireyin cinsiyet kromozomları <b>XX</b> şeklindedir."}],"ans":"Cinsiyeti 23. kromozom çifti belirler; dişi XX olarak gösterilir."},{"q":"İnsanda erkek bireyin cinsiyet kromozomları nasıl gösterilir?","steps":[{"t":"Erkeği düşün","a":"Bir X bir Y","d":"Erkekte birbirinden farklı iki cinsiyet kromozomu vardır."},{"t":"Yaz","a":"XY","d":"Erkek bireyin cinsiyet kromozomları <b>XY</b> şeklinde yazılır."}],"ans":"Erkek bireyin cinsiyet kromozomları XY'dir."},{"q":"Vücut özelliklerini taşıyan, cinsiyetle ilgili olmayan kromozomlara ne ad verilir?","steps":[{"t":"İki grubu ayır","a":"Otozom ve cinsiyet","d":"Kromozomlar iki gruptur: cinsiyet kromozomları ve diğerleri."},{"t":"Diğerlerini adlandır","a":"Otozom","d":"Cinsiyetle ilgili olmayan vücut kromozomlarına <b>otozom</b> denir."}],"ans":"Cinsiyetle ilgili olmayan kromozomlara otozom denir."},{"q":"İnsan vücut hücresinde kaç çift kromozom bulunur?","steps":[{"t":"Toplam sayıyı hatırla","a":"46 kromozom","d":"İnsan vücut hücresinde toplam 46 kromozom vardır."},{"t":"Çifte çevir","a":"23 çift","d":"Bu kromozomlar ikişerli eşleştiğinde <b>23 çift</b> olur."}],"ans":"İnsan vücut hücresinde 23 çift (46) kromozom bulunur."},{"q":"İnsanda 23 çift kromozomun kaç çifti otozom, kaç çifti cinsiyet kromozomudur?","steps":[{"t":"Cinsiyet çiftini ayır","a":"1 çift","d":"23 çiftin 1 çifti cinsiyet kromozomudur (23. çift)."},{"t":"Otozomu hesapla","a":"22 çift","d":"Geriye kalan <b>22 çift</b> otozomdur."}],"ans":"İnsanda 22 çift otozom, 1 çift cinsiyet kromozomu bulunur."}],"zor":[{"q":"Bir anne ve babadan bir erkek çocuk doğmuştur. Bu çocuğun cinsiyet kromozomlarının hangi ebeveynden geldiğini açıklayınız.","steps":[{"t":"Anneden geleni belirle","a":"X","d":"Anne XX olduğu için çocuğa yalnızca X kromozomu verir."},{"t":"Babadan geleni belirle","a":"Y","d":"Çocuk erkek (XY) olduğuna göre X anneden, <b>Y babadan</b> gelmiştir."}],"ans":"Erkek çocukta X anneden, Y babadan gelir; cinsiyeti belirleyen Y babadan gelmiştir."},{"q":"Anne XX, baba XY ise oluşabilecek çocukların cinsiyetlerini ve oranını çaprazlama ile bulunuz.","steps":[{"t":"Gametleri yaz","a":"Anne: X, X / Baba: X, Y","d":"Anne yalnızca X üretir, baba X ve Y üretir."},{"t":"Çaprazla","a":"XX, XX, XY, XY","d":"Birleşimler XX (kız) ve XY (erkek) olur; ikisi de eşit çıkar."},{"t":"Oranı belirle","a":"%50 - %50","d":"Sonuçta <b>%50 kız, %50 erkek</b> beklenir."}],"ans":"Çocukların yarısı XX (kız), yarısı XY (erkek) olur; oran %50 - %50'dir."},{"q":"Bir öğrenci 'insanda 46 çift kromozom vardır' diyor. Hatasını düzeltiniz.","steps":[{"t":"Doğru bilgiyi hatırla","a":"46 kromozom","d":"İnsan vücut hücresinde toplam kromozom sayısı 46'dır."},{"t":"Çift sayısına çevir","a":"23 çift","d":"46 kromozom ikişerli eşleşince <b>23 çift</b> eder, 46 çift değil."}],"ans":"Yanlış; insanda 46 kromozom yani 23 çift vardır, 46 çift değildir."},{"q":"Cinsiyetin belirlenmesinde dişinin tek çeşit gamet, erkeğin iki çeşit gamet ürettiği söylenir. Bunu açıklayınız.","steps":[{"t":"Dişinin gametleri","a":"Hep X","d":"Dişi XX olduğu için yumurtaların hepsi X taşır, tek çeşittir."},{"t":"Erkeğin gametleri","a":"X ve Y","d":"Erkek XY olduğu için spermlerin yarısı X, yarısı Y taşır; iki çeşittir."}],"ans":"Dişi sadece X taşıyan gamet üretir; erkek hem X hem Y taşıyan iki çeşit gamet üretir, bu yüzden cinsiyeti erkek belirler."},{"q":"Bir insanın yumurta hücresinde 22 otozom ve 1 cinsiyet kromozomu bulunur. Bu cinsiyet kromozomu ne olabilir ve neden?","steps":[{"t":"Yumurtayı kim üretir?","a":"Dişi (XX)","d":"Yumurta dişi tarafından üretilir, dişi ise XX'tir."},{"t":"Hangi kromozomu taşır?","a":"X","d":"Dişide yalnızca X bulunduğu için yumurta her zaman <b>X</b> taşır."}],"ans":"Yumurtadaki cinsiyet kromozomu her zaman X'tir, çünkü onu üreten dişide yalnızca X bulunur."}]},"lise":{"kolay":[{"q":"İnsanda otozom ve gonozom (cinsiyet kromozomu) kavramlarını sayılarıyla birlikte açıklayınız.","steps":[{"t":"Otozomu tanımla","a":"22 çift","d":"Cinsiyetle doğrudan ilgili olmayan, vücut özelliklerini taşıyan kromozomlara otozom denir; insanda 22 çift bulunur."},{"t":"Gonozomu tanımla","a":"1 çift","d":"Cinsiyeti belirleyen kromozomlara gonozom (cinsiyet kromozomu) denir; insanda 1 çift (XX veya XY) bulunur."}],"ans":"İnsanda 22 çift otozom ve 1 çift gonozom (cinsiyet kromozomu) vardır."},{"q":"İnsanda dişi ve erkek bireylerin cinsiyet kromozomu dizilimlerini yazınız.","steps":[{"t":"Dişiyi yaz","a":"XX (homogametik)","d":"Dişi birey iki özdeş X kromozomu taşır, tek tip gamet ürettiği için homogametiktir."},{"t":"Erkeği yaz","a":"XY (heterogametik)","d":"Erkek birey bir X ve bir Y taşır, iki tip gamet ürettiği için heterogametiktir."}],"ans":"İnsanda dişi XX (homogametik), erkek XY (heterogametiktir)."},{"q":"XY tipi cinsiyet belirlenmesinde cinsiyeti hangi ebeveynin belirlediğini gerekçesiyle açıklayınız.","steps":[{"t":"Dişinin gameti","a":"Yalnız X","d":"XX olan dişi yalnızca X taşıyan yumurta üretir, dolayısıyla cinsiyeti değiştiremez."},{"t":"Erkeğin gameti","a":"X veya Y","d":"XY olan erkek X ya da Y taşıyan sperm üretir; döllemede hangisinin geldiği cinsiyeti belirler."}],"ans":"XY sisteminde cinsiyeti, X veya Y taşıyan gamet üreten erkek (heterogametik eşey) belirler."},{"q":"İnsanda zigotun XX ya da XY olmasının döllenme anındaki belirleyicisini açıklayınız.","steps":[{"t":"Yumurtayı sabitle","a":"X","d":"Yumurta her zaman X taşır, bu sabit kalır."},{"t":"Spermi değerlendir","a":"X ⇒ XX, Y ⇒ XY","d":"X taşıyan sperm döllerse zigot XX (dişi), Y taşıyan sperm döllerse XY (erkek) olur."}],"ans":"Zigotun cinsiyetini, yumurtayı dölleyen spermin X mi Y mi taşıdığı belirler."},{"q":"Kuşlarda görülen ZW cinsiyet belirleme sistemini insandaki sistemle karşılaştırınız.","steps":[{"t":"Kuşlarda dişi-erkek","a":"Dişi ZW, erkek ZZ","d":"Kuşlarda erkek ZZ (homogametik), dişi ZW (heterogametiktir)."},{"t":"İnsanla karşılaştır","a":"Ters durum","d":"İnsanda heterogametik eşey erkek (XY) iken kuşlarda heterogametik eşey dişidir (ZW), yani cinsiyeti dişi belirler."}],"ans":"Kuşlarda erkek ZZ, dişi ZW'dir; insanın aksine cinsiyeti heterogametik olan dişi belirler."},{"q":"Homogametik ve heterogametik eşey kavramlarını tanımlayıp insanda hangisinin hangi cinsiyet olduğunu belirtiniz.","steps":[{"t":"Homogametiği tanımla","a":"Tek tip gamet","d":"Aynı tip cinsiyet kromozomu taşıyan gamet üreten eşeydir; insanda dişi (XX)."},{"t":"Heterogametiği tanımla","a":"İki tip gamet","d":"Farklı cinsiyet kromozomu taşıyan iki tip gamet üreten eşeydir; insanda erkek (XY)."}],"ans":"İnsanda dişi homogametik (XX, tek tip gamet), erkek heterogametiktir (XY, iki tip gamet)."},{"q":"İnsan sperm ve yumurta hücrelerinin taşıdığı kromozom sayısını ve cinsiyet kromozomunu açıklayınız.","steps":[{"t":"Sayıyı belirle","a":"23 kromozom","d":"Gametler haploittir; insan gametinde 22 otozom + 1 cinsiyet kromozomu = 23 kromozom vardır."},{"t":"Cinsiyet kromozomunu belirle","a":"Yumurta X, sperm X ya da Y","d":"Yumurta yalnız X taşırken sperm X veya Y taşıyabilir."}],"ans":"İnsan gametinde 23 kromozom vardır; yumurta X, sperm X ya da Y taşır."},{"q":"İnsanda Y kromozomu üzerinde bulunan ve erkeklik gelişimini başlatan bölgenin önemini açıklayınız.","steps":[{"t":"Y'nin işlevi","a":"Erkekliği başlatır","d":"Y kromozomu üzerindeki belirleyici bölge (SRY) testis gelişimini tetikleyerek erkek yönünde gelişimi başlatır."},{"t":"Y yoksa","a":"Dişi gelişim","d":"Y bulunmazsa (XX) bu sinyal oluşmaz ve birey dişi yönünde gelişir."}],"ans":"Y kromozomundaki belirleyici bölge erkek gelişimini başlatır; Y yoksa birey dişi olur."},{"q":"İnsanda cinsiyet oranının yaklaşık %50 dişi - %50 erkek olmasının nedenini açıklayınız.","steps":[{"t":"Sperm oranı","a":"Yarı X, yarı Y","d":"Erkek mayozla X ve Y taşıyan spermleri eşit oranda (yarı yarıya) üretir."},{"t":"Döllenme şansı","a":"Eşit","d":"X ve Y taşıyan spermlerin yumurtayı dölleme şansı yaklaşık eşit olduğundan oran ≈ %50 - %50 çıkar."}],"ans":"Erkek X ve Y spermlerini eşit oranda ürettiği için cinsiyet oranı yaklaşık %50 dişi - %50 erkektir."},{"q":"Bir karyotipte 44 otozom ve XY cinsiyet kromozomu görülüyor. Bu bireyin tür ve cinsiyetini yorumlayınız.","steps":[{"t":"Toplam kromozomu bul","a":"46","d":"44 otozom + 2 cinsiyet kromozomu = 46 kromozom; bu insan sayısıdır."},{"t":"Cinsiyeti belirle","a":"Erkek","d":"Cinsiyet kromozomları XY olduğu için birey erkektir."}],"ans":"44 otozom + XY = 46 kromozomlu insan ve cinsiyeti erkektir."},{"q":"İnsanda cinsiyet kromozomları ile otozomların 'eş (homolog) olma' bakımından farkını açıklayınız.","steps":[{"t":"Otozomları değerlendir","a":"Tam eş","d":"22 çift otozomun her ikisi de aynı gen bölgelerini taşır, tam homologdur."},{"t":"XY çiftini değerlendir","a":"Kısmen eş","d":"X ve Y boy ve gen içeriği bakımından farklıdır, yalnızca küçük bölgelerde eşleşir; XX ise tam eştir."}],"ans":"Otozomlar tam homologdur; cinsiyet kromozomlarından XX tam, XY ise yalnızca kısmen homologdur."},{"q":"İnsanda cinsiyetin döllenme anında kesinleştiğini, sonradan değişmediğini açıklayınız.","steps":[{"t":"Döllenmeyi düşün","a":"Sperm tipi belirler","d":"Cinsiyet, X ya da Y taşıyan spermin yumurtayı döllediği anda kromozomal olarak belirlenir."},{"t":"Sonraki bölünmeler","a":"Aynı kalır","d":"Zigot mitozla bölünürken kromozom takımı kopyalanır, cinsiyet kromozomları değişmeden tüm vücut hücrelerine aktarılır."}],"ans":"Cinsiyet döllenme anında spermin tipiyle belirlenir ve mitozla aktarıldığı için sonradan değişmez."},{"q":"Heterogametik eşeyin cinsiyeti belirlediği ilkesinden yola çıkarak insan ve tavuk için belirleyici eşeyi söyleyiniz.","steps":[{"t":"İnsanı değerlendir","a":"Erkek (XY)","d":"İnsanda heterogametik eşey erkek olduğundan cinsiyeti erkek belirler."},{"t":"Tavuğu değerlendir","a":"Dişi (ZW)","d":"Tavukta heterogametik eşey dişi (ZW) olduğundan cinsiyeti dişi belirler."}],"ans":"Cinsiyeti heterogametik eşey belirler; insanda erkek, tavukta dişi belirleyicidir."},{"q":"İnsanda bir vücut hücresi ile bir gamet hücresinin kromozom sayısını cinsiyet kromozomu açısından karşılaştırınız.","steps":[{"t":"Vücut hücresi","a":"2 cinsiyet kromozomu","d":"Diploit vücut hücresinde 46 kromozom ve 2 cinsiyet kromozomu (XX ya da XY) bulunur."},{"t":"Gamet","a":"1 cinsiyet kromozomu","d":"Haploit gamette 23 kromozom ve yalnızca 1 cinsiyet kromozomu (X ya da Y) bulunur."}],"ans":"Vücut hücresinde 2, gamette 1 cinsiyet kromozomu bulunur (46'ya karşı 23 kromozom)."},{"q":"XX ve XY dizilimlerinden hangisinin tek tip, hangisinin iki tip gamet vereceğini gerekçesiyle açıklayınız.","steps":[{"t":"XX'i incele","a":"Tek tip (X)","d":"İki X özdeş olduğu için mayozda yalnızca X taşıyan gametler oluşur, tek tiptir."},{"t":"XY'yi incele","a":"İki tip (X ve Y)","d":"X ve Y ayrıldığında biri X biri Y taşıyan iki farklı gamet oluşur, iki tiptir."}],"ans":"XX tek tip (X) gamet, XY iki tip (X ve Y) gamet verir."}],"zor":[{"q":"Anne XX, baba XY çaprazlamasında cinsiyet kromozomları açısından oluşabilecek genotipleri ve cinsiyet oranını mayoz-döllenme mantığıyla açıklayınız.","steps":[{"t":"Gametleri belirle","a":"Anne X; baba X, Y","d":"Anne mayozla yalnız X taşıyan yumurta, baba X ve Y taşıyan iki tip sperm üretir."},{"t":"Birleşimleri çıkar","a":"XX ve XY","d":"X-yumurta + X-sperm ⇒ XX; X-yumurta + Y-sperm ⇒ XY birleşimleri oluşur."},{"t":"Oranı hesapla","a":"1 XX : 1 XY","d":"İki birleşim eşit olasılıkta olduğundan beklenen oran %50 dişi - %50 erkektir."}],"ans":"Genotipler XX ve XY; beklenen cinsiyet oranı %50 dişi - %50 erkektir."},{"q":"Bir ailede arka arkaya doğan dört çocuğun da erkek olması olasılığını hesaplayıp yorumlayınız.","steps":[{"t":"Tek doğum olasılığı","a":"1/2","d":"Her doğumda erkek (XY) olma olasılığı 1/2'dir, çünkü baba X ve Y'yi eşit verir."},{"t":"Dört bağımsız doğum","a":"(1/2)⁴ = 1/16","d":"Doğumlar bağımsız olduğundan olasılıklar çarpılır: 1/2 × 1/2 × 1/2 × 1/2 = 1/16."},{"t":"Yorumla","a":"Sonraki yine 1/2","d":"Geçmiş doğumlar yeni doğumu etkilemez; beşinci çocuğun erkek olma olasılığı yine 1/2'dir."}],"ans":"Dört çocuğun da erkek olma olasılığı 1/16'dır; ancak her doğum bağımsız olduğundan sonraki çocuğun cinsiyeti yine 1/2 olasılıkladır."},{"q":"Bir bireyin karyotipinde 22 çift otozom ve tek bir X kromozomu (45, X) görülüyor. Cinsiyet kromozomu sayısı ve olası nedenini açıklayınız.","steps":[{"t":"Kromozom sayısını bul","a":"45","d":"22 çift otozom (44) + 1 cinsiyet kromozomu = 45 kromozom; normal 46'dan bir eksiktir."},{"t":"Nedenini yorumla","a":"Ayrılmama (mayoz hatası)","d":"Mayozda cinsiyet kromozomlarının ayrılmaması sonucu gamet eksik kromozomla oluşmuş ve döllenmede tek X içeren zigot meydana gelmiştir."}],"ans":"Birey 45 kromozomlu olup tek X taşır; bu durum mayozda cinsiyet kromozomlarının ayrılmamasından kaynaklanır."},{"q":"Kuşlarda ZW sistemi için bir tavuk (ZW) × horoz (ZZ) çaprazlaması yapıp yavruların cinsiyet oranını çıkarınız.","steps":[{"t":"Gametleri yaz","a":"Tavuk: Z, W / Horoz: Z","d":"Heterogametik tavuk Z ve W taşıyan iki tip yumurta, homogametik horoz yalnız Z taşıyan sperm üretir."},{"t":"Çaprazla","a":"ZZ ve ZW","d":"Z-yumurta + Z ⇒ ZZ (erkek); W-yumurta + Z ⇒ ZW (dişi)."},{"t":"Oranı belirle","a":"%50 - %50","d":"İki birleşim eşit olduğundan yavruların yarısı erkek (ZZ), yarısı dişidir (ZW)."}],"ans":"Yavruların %50'si ZZ (erkek), %50'si ZW (dişi) olur; cinsiyeti dişi gameti belirler."},{"q":"İnsanda neden Y kromozomunun varlığının dişilik yerine erkekliği belirlediğini, X sayısından bağımsız olarak açıklayınız.","steps":[{"t":"Y'nin rolünü belirle","a":"Erkeklik sinyali","d":"Y kromozomundaki belirleyici bölge erkek gelişimini başlatan baskın bir sinyal taşır."},{"t":"X sayısıyla ilişki","a":"Y varsa erkek","d":"Bir bireyde Y bulunduğu sürece (örneğin XXY) erkek yönünde gelişim olur; Y yoksa (XX, XXX) dişi gelişir."}],"ans":"Erkekliği belirleyen Y kromozomunun varlığıdır; X sayısı ne olursa olsun Y varsa birey erkek yönünde gelişir."},{"q":"Bir kadının yumurtaları ve bir erkeğin spermleri açısından cinsiyet kromozomu çeşitliliğini ve bunun cinsiyet üzerindeki etkisini karşılaştırınız.","steps":[{"t":"Yumurtaları değerlendir","a":"Tümü X","d":"Kadın XX olduğundan tüm yumurtalar X taşır, çeşitlilik yoktur."},{"t":"Spermleri değerlendir","a":"X ya da Y","d":"Erkek XY olduğundan spermlerin yarısı X yarısı Y taşır, iki çeşittir."},{"t":"Etkiyi yorumla","a":"Cinsiyeti sperm belirler","d":"Yumurta sabit olduğundan zigotun cinsiyetini dölleyen spermin türü belirler."}],"ans":"Yumurtalar tek tip (X), spermler iki tiptir (X ve Y); bu nedenle cinsiyeti belirleyen dölleyen spermdir."},{"q":"Mayozda cinsiyet kromozomları normal ayrılırsa bir erkekten oluşan sperm tiplerini ve oranlarını belirtiniz.","steps":[{"t":"Erkeğin kromozomu","a":"XY","d":"Erkek vücut hücresinde bir X ve bir Y bulunur."},{"t":"Mayozdaki ayrılma","a":"X ve Y ayrı gametlere","d":"Mayoz I'de homolog cinsiyet kromozomları ayrılır; X bir gamete, Y diğerine gider."},{"t":"Oranı belirle","a":"%50 X, %50 Y","d":"Sonuçta spermlerin yarısı X, yarısı Y taşır."}],"ans":"Normal ayrılmada erkekten %50 X taşıyan, %50 Y taşıyan iki tip sperm eşit oranda oluşur."},{"q":"İnsanda XX bireyde iki X'in farklı ebeveynlerden gelmesine karşın XY bireyde X ve Y'nin hangi ebeveynden geldiğini açıklayınız.","steps":[{"t":"XX bireyi çöz","a":"Biri anne biri baba","d":"Dişi XX'tir; X'lerden biri anneden (yumurta), diğeri babadan (X taşıyan sperm) gelir."},{"t":"XY bireyi çöz","a":"X anne, Y baba","d":"Erkek XY'dir; X yalnız anneden gelebilir (yumurta X), Y ise yalnız babadan (sperm) gelir."}],"ans":"XX bireyde X'lerin biri anneden biri babadan gelir; XY bireyde X anneden, Y babadan gelir."},{"q":"Bir tür için 'dişi heterogametiktir' bilgisi veriliyor. Bu türün cinsiyet belirleme sistemini ve cinsiyeti belirleyen eşeyi yorumlayınız.","steps":[{"t":"Sistemi tanı","a":"ZW sistemi","d":"Dişinin heterogametik olması ZW tipi cinsiyet belirlemeyi gösterir; dişi ZW, erkek ZZ'dir."},{"t":"Belirleyiciyi bul","a":"Dişi","d":"İki tip gamet (Z ve W) üreten dişi olduğundan yavrunun cinsiyetini dişinin gameti belirler."}],"ans":"Tür ZW sistemine sahiptir (dişi ZW, erkek ZZ) ve cinsiyeti heterogametik olan dişi belirler."},{"q":"İnsanda toplam 46 kromozomun anne ve babadan eşit katkıyla geldiğini, cinsiyet kromozomları örneğiyle açıklayınız.","steps":[{"t":"Toplam katkıyı böl","a":"23 + 23","d":"Diploit zigotta 46 kromozomun 23'ü anneden (yumurta), 23'ü babadan (sperm) gelir."},{"t":"Cinsiyet kromozomuyla göster","a":"1'er adet","d":"Bu 23'erin içinde 1'er cinsiyet kromozomu vardır: anneden hep X, babadan X ya da Y."}],"ans":"46 kromozomun 23'ü anneden 23'ü babadan gelir; cinsiyet kromozomunun biri anneden (X), diğeri babadan (X ya da Y) aktarılır."},{"q":"Bir popülasyonda doğan bebeklerin yaklaşık yarısının kız yarısının erkek olmasını gamet üretimi ve döllenme olasılığı ile açıklayınız.","steps":[{"t":"Gamet oranı","a":"X : Y = 1 : 1","d":"Erkekler mayozla X ve Y taşıyan spermleri yaklaşık eşit oranda üretir."},{"t":"Döllenme olasılığı","a":"Eşit","d":"Sabit X taşıyan yumurtayı X ya da Y spermin dölleme şansı yaklaşık eşittir, böylece XX ve XY zigotları eşit oluşur."},{"t":"Popülasyona yansıt","a":"≈ %50 - %50","d":"Çok sayıda doğumda olasılıklar ortalamaya yaklaştığından oran yaklaşık yarı yarıya gerçekleşir."}],"ans":"Eşit oranda üretilen X ve Y spermlerinin döllenme şansı eşit olduğundan, popülasyonda cinsiyet oranı yaklaşık %50 - %50 olur."},{"q":"Bir karyotipte 47 kromozom ve XXY dizilimi görülüyor. Cinsiyet kromozomu sayısını, olası oluşum nedenini ve beklenen cinsiyet yönünü açıklayınız.","steps":[{"t":"Sayıyı bul","a":"47 (3 cinsiyet kromozomu)","d":"44 otozom + XXY = 47 kromozom; cinsiyet kromozomu sayısı 3'tür."},{"t":"Nedenini yorumla","a":"Ayrılmama","d":"Mayozda cinsiyet kromozomlarının ayrılmaması sonucu bir gamet fazladan cinsiyet kromozomu taşımış ve döllenmede XXY oluşmuştur."},{"t":"Cinsiyet yönü","a":"Erkek","d":"Y bulunduğu için erkeklik sinyali devreye girer ve birey erkek yönünde gelişir."}],"ans":"XXY birey 47 kromozomludur, mayozda ayrılmama sonucu oluşur ve Y bulunduğu için erkek yönünde gelişir."},{"q":"İnsanda cinsiyetin XY sistemiyle, bazı sürüngenlerde ise sıcaklıkla belirlenmesi örneğinden yola çıkarak cinsiyet belirlemenin yalnızca kromozomal olmayabileceğini tartışınız.","steps":[{"t":"İnsanı değerlendir","a":"Kromozomal (XY)","d":"İnsanda cinsiyet, döllenmede gelen X ya da Y kromozomuyla yani kromozomal olarak belirlenir."},{"t":"Sürüngeni değerlendir","a":"Çevresel (sıcaklık)","d":"Bazı sürüngenlerde yumurtanın geliştiği ortam sıcaklığı cinsiyeti belirler; kromozom dizilimi belirleyici değildir."},{"t":"Genel sonucu çıkar","a":"İki tip mekanizma","d":"Cinsiyet kimi canlılarda kromozomal (XY, ZW), kimilerinde çevresel etkenlerle belirlenebilir."}],"ans":"İnsanda cinsiyet kromozomaldır (XY); bazı sürüngenlerde sıcaklıkla belirlenir; bu da cinsiyet belirlemenin her zaman kromozomal olmadığını gösterir."},{"q":"Bir erkeğin X taşıyan sperminin döllemesiyle oluşan kız çocuğun, X kromozomlarının kökenini ve cinsiyetini gerekçesiyle açıklayınız.","steps":[{"t":"Babadan geleni belirle","a":"X","d":"Soruda dölleyen spermin X taşıdığı belirtildiğinden çocuğa babadan X gelmiştir."},{"t":"Anneden geleni belirle","a":"X","d":"Anne XX olduğundan yumurtayla yalnız X gelir."},{"t":"Cinsiyeti çıkar","a":"XX ⇒ kız","d":"İki X bir araya geldiğinden (biri anneden biri babadan) çocuk kız olur."}],"ans":"Çocuk XX'tir, kızdır; X'lerin biri anneden yumurtayla, diğeri babadan X taşıyan spermle gelmiştir."},{"q":"İnsanda 'cinsiyet kromozomları otozomlar gibi her hücrede çift bulunur' ifadesini gamet ve vücut hücresi karşılaştırmasıyla değerlendiriniz.","steps":[{"t":"Vücut hücresinde durum","a":"Doğru","d":"Diploit vücut hücrelerinde otozomlar gibi cinsiyet kromozomları da çift (XX ya da XY) bulunur."},{"t":"Gamette durum","a":"Yanlış","d":"Haploit gametlerde otozomlar tek, cinsiyet kromozomu da tek (X ya da Y) bulunur; çift değildir."},{"t":"Genel değerlendirme","a":"Her hücre için doğru değil","d":"İfade yalnız vücut hücreleri için doğrudur; gametlerde geçerli değildir."}],"ans":"İfade yalnız diploit vücut hücreleri için doğrudur; haploit gametlerde cinsiyet kromozomu tek bulunur, dolayısıyla genelleme yanlıştır."}]}},"cokAlellilik":{"ilkokul":{"kolay":[{"q":"Boyalar arasında kırmızı, mavi ve sarı seçenekleri var. Bir özellik için kaç çeşit seçenek olabilir?","steps":[{"t":"Seçenekleri say","a":"Üç çeşit","d":"Kırmızı, mavi ve sarı diye <b>üç farklı</b> renk seçeneği sayılır."},{"t":"İkiden fazla mı?","a":"Evet, üçten fazla seçenek","d":"İki değil üç seçenek olduğu için bir özelliğin <b>ikiden çok</b> çeşidi olabilir."}],"ans":"Bir özellik için kırmızı, mavi ve sarı gibi ikiden fazla seçenek bulunabilir."},{"q":"Bir dondurmacıda çilekli, çikolatalı ve vanilyalı dondurma var. Tatlar için kaç seçenek vardır?","steps":[{"t":"Tatları say","a":"Üç tat","d":"Çilek, çikolata ve vanilya diye <b>üç ayrı</b> tat seçeneği vardır."},{"t":"Sonuç","a":"Birden çok seçenek","d":"Bir özellik (tat) için birden çok, yani üç seçenek olduğu görülür."}],"ans":"Dondurma tadı için çilek, çikolata ve vanilya olmak üzere üç seçenek vardır."},{"q":"Bir sınıfta öğrencilerin göz rengi kahverengi, mavi ya da yeşil olabiliyor. Göz rengi için kaç çeşit var?","steps":[{"t":"Renkleri say","a":"Üç renk","d":"Kahverengi, mavi ve yeşil diye <b>üç farklı</b> göz rengi sayılır."},{"t":"İkiden fazla mı?","a":"Evet","d":"Göz rengi için iki değil üç seçenek olduğundan ikiden çok çeşit vardır."}],"ans":"Göz rengi için kahverengi, mavi ve yeşil olmak üzere üç çeşit bulunabilir."},{"q":"Bir tişört kırmızı, mavi, sarı veya yeşil olabiliyor. Tişört rengi için ikiden fazla seçenek var mıdır?","steps":[{"t":"Renkleri say","a":"Dört renk","d":"Kırmızı, mavi, sarı ve yeşil diye <b>dört</b> renk seçeneği vardır."},{"t":"İkiden fazla mı?","a":"Evet, dört tane","d":"Seçenek sayısı dört olduğu için ikiden çok seçenek bulunduğu söylenir."}],"ans":"Tişört rengi için dört seçenek olduğundan ikiden fazla seçenek vardır."},{"q":"Bir oyuncak araba kırmızı, yeşil ya da sarı olabiliyor. Senin araban bunların hepsi aynı anda olabilir mi?","steps":[{"t":"Seçenekler","a":"Üç renk","d":"Araba için kırmızı, yeşil ve sarı diye <b>üç seçenek</b> vardır."},{"t":"Bir araba kaç renk?","a":"Tek renk","d":"Bir oyuncak araba aynı anda sadece bir rengi taşır, hepsi birden olamaz."}],"ans":"Üç renk seçeneği olsa da bir araba aynı anda sadece bir rengi taşır."}],"zor":[{"q":"Bir kutuda kırmızı, mavi ve sarı boncuklar var. Sen kutudan sadece 2 boncuk alabiliyorsun. Üç rengin hepsini birden alabilir misin?","steps":[{"t":"Kaç renk var?","a":"Üç renk","d":"Kutuda kırmızı, mavi ve sarı diye <b>üç renk</b> seçeneği bulunur."},{"t":"Kaç tane alıyorsun?","a":"En fazla 2","d":"Sen yalnızca 2 boncuk aldığın için üç rengin <b>hepsi birden</b> elinde olamaz."}],"ans":"Üç renk seçeneği olsa da yalnızca 2 boncuk aldığın için en çok 2 renk alabilirsin."},{"q":"Bir markette çilekli, muzlu ve kayısılı meyve suyu var. Annen sana sadece 2 kutu alıyor. En fazla kaç çeşit tat eve gelir?","steps":[{"t":"Kaç tat var?","a":"Üç tat","d":"Markette çilek, muz ve kayısı diye <b>üç tat</b> seçeneği vardır."},{"t":"Kaç kutu alınıyor?","a":"2 kutu","d":"Sadece 2 kutu alındığı için eve en fazla 2 farklı tat gelebilir."}],"ans":"Üç tat seçeneği olsa da 2 kutu alındığı için eve en fazla 2 çeşit tat gelir."},{"q":"Kalem kutusunda kırmızı, mavi, yeşil ve sarı kalemler var. Sen elinde aynı anda 2 kalem tutabiliyorsun. Dört rengi birden tutabilir misin?","steps":[{"t":"Kaç renk var?","a":"Dört renk","d":"Kutuda kırmızı, mavi, yeşil ve sarı diye <b>dört renk</b> seçeneği vardır."},{"t":"Elinde kaç tane?","a":"En fazla 2","d":"Aynı anda elinde 2 kalem tuttuğun için dört rengin hepsini birden tutamazsın."}],"ans":"Dört renk seçeneği olsa da elinde aynı anda en çok 2 kalem tutabilirsin."},{"q":"Bir tavşan ailesinde kahverengi, gri ve beyaz kürk renkleri görülebiliyor. Bir tavşanın kürkü kaç renk olur?","steps":[{"t":"Kaç seçenek var?","a":"Üç renk","d":"Tavşanlarda kahverengi, gri ve beyaz diye <b>üç kürk rengi</b> seçeneği görülebilir."},{"t":"Bir tavşan?","a":"Tek renk","d":"Seçenekler üç olsa da bir tavşanın kürkü aynı anda tek renktir."}],"ans":"Üç kürk rengi seçeneği olsa da bir tavşanın kürkü tek renk olur."},{"q":"Bir çiçek türünün çiçekleri kırmızı, pembe ya da beyaz açabiliyor. Bahçende 1 tane bu çiçekten varsa kaç renk birden görürsün?","steps":[{"t":"Kaç renk olabilir?","a":"Üç renk","d":"Bu çiçek türü kırmızı, pembe ve beyaz diye <b>üç renkte</b> açabilir."},{"t":"Bir çiçek kaç renk?","a":"Tek renk","d":"Seçenekler üç olsa da senin tek çiçeğin bunlardan yalnızca biriyle açar."}],"ans":"Üç renk seçeneği olsa da tek çiçeğin yalnızca bir renkte açar."}]},"ortaokul":{"kolay":[{"q":"Çok alellilik ne demektir?","steps":[{"t":"Alel sayısı","a":"İkiden fazla alel","d":"Çok alellilikte bir gen için ikiden çok <b>alel</b> (gen çeşidi) bulunur."},{"t":"Sonuç","a":"Birden çok seçenek","d":"Yani bir özelliği belirleyen gen için ikiden fazla farklı seçenek vardır."}],"ans":"Çok alellilik, bir gen için ikiden fazla alel bulunması durumudur."},{"q":"İnsanda kan grubunu belirleyen kaç çeşit alel vardır?","steps":[{"t":"Alelleri say","a":"Üç alel","d":"Kan grubu geninin üç aleli vardır: I<b>A</b>, IB ve i."},{"t":"Sonuç","a":"Üçten fazla seçenek","d":"İki değil üç alel olduğu için kan grubu çok alelliliğe örnektir."}],"ans":"İnsanda kan grubunu belirleyen IA, IB ve i olmak üzere üç çeşit alel vardır."},{"q":"Bir gen için üç alel bulunsa bile bir bireyde en fazla kaç alel olur?","steps":[{"t":"Kromozom sayısı","a":"İki tane","d":"Her genin yeri bir <b>kromozom çiftinde</b> bulunur; biri anneden, biri babadan gelir."},{"t":"Sonuç","a":"En fazla 2 alel","d":"İki kromozom olduğu için bir bireyde bir genin en fazla 2 aleli bulunur."}],"ans":"Bir gen için üç alel olsa da bir bireyde o genin en fazla 2 aleli bulunur."},{"q":"AB0 kan grubu sisteminde IA ve IB alelleri i aleline göre nasıldır?","steps":[{"t":"Baskınlık","a":"IA ve IB baskın","d":"IA ve IB alelleri, i aleline göre <b>baskındır</b> ve fenotipte kendini gösterir."},{"t":"i aleli","a":"Çekinik","d":"i aleli çekiniktir; yalnızca iki tane bir araya gelince (ii) etkisini gösterir."}],"ans":"IA ve IB alelleri i aleline baskındır; i aleli ise çekiniktir."},{"q":"Tavşanlarda kürk renginin birden çok aleli olması neye örnektir?","steps":[{"t":"Alel sayısı","a":"İkiden fazla","d":"Tavşan kürk renginde ikiden çok <b>alel</b> bulunur (yabani, çinçilla, himalaya, albino)."},{"t":"Sonuç","a":"Çok alellilik","d":"Bir gen için ikiden fazla alel olduğundan bu durum çok alelliliğe örnektir."}],"ans":"Tavşan kürk renginde ikiden fazla alel bulunması çok alelliliğe örnektir."}],"zor":[{"q":"Kan grubu geninin IA, IB ve i alelleri varken bir kişi neden bunların yalnızca ikisini taşır?","steps":[{"t":"Alel seçenekleri","a":"Üç alel","d":"Kan grubu geninin <b>üç aleli</b> (IA, IB, i) popülasyonda bulunur."},{"t":"Genin yeri","a":"Kromozom çifti","d":"Bu gen bir kromozom çiftinde yer alır; bir alel anneden, bir alel babadan gelir."},{"t":"Sonuç","a":"En fazla 2","d":"Bir kişide iki kromozom olduğundan üç alelden ancak ikisi bir araya gelir."}],"ans":"Üç alel popülasyonda olsa da gen bir kromozom çiftinde olduğundan bir kişi anneden ve babadan gelen en fazla 2 alel taşır."},{"q":"Genotipi IAi olan bir kişinin kan grubu nedir? Açıklayınız.","steps":[{"t":"Alelleri belirle","a":"IA ve i","d":"Kişide biri IA, biri i olmak üzere iki <b>alel</b> bulunur."},{"t":"Baskınlık","a":"IA baskın","d":"IA aleli i aleline baskın olduğundan fenotipi IA belirler."},{"t":"Sonuç","a":"A grubu","d":"Baskın IA aleli kendini gösterdiği için kişinin kan grubu A olur."}],"ans":"IAi genotipinde IA aleli i'ye baskın olduğundan kişinin kan grubu A'dır."},{"q":"Kan grubu 0 olan bir kişinin genotipi neden ii olmak zorundadır?","steps":[{"t":"0 grubu özelliği","a":"Baskın alel yok","d":"0 grubunda ne IA ne IB aleli bulunur; yalnızca <b>çekinik</b> i aleli vardır."},{"t":"Çekinik kural","a":"İki çekinik gerekli","d":"Çekinik özellik ancak iki çekinik alel bir araya gelince ortaya çıkar."},{"t":"Sonuç","a":"ii","d":"Bu yüzden 0 grubu kişinin genotipi mutlaka ii olur."}],"ans":"0 grubunda baskın alel bulunmadığından genotip yalnızca iki çekinik alelden, yani ii'den oluşur."},{"q":"IA ve IB alelleri bir arada bulunduğunda (IAIB) kan grubu neden AB olur?","steps":[{"t":"Alelleri belirle","a":"IA ve IB","d":"Kişide hem IA hem IB <b>aleli</b> bir aradadır."},{"t":"Eş baskınlık","a":"İkisi de etkili","d":"IA ve IB alelleri eş baskındır; biri diğerini örtmez, ikisi de fenotipte görünür."},{"t":"Sonuç","a":"AB grubu","d":"Her iki alel de etkisini gösterdiği için kan grubu AB olur."}],"ans":"IA ve IB eş baskın olduğundan IAIB genotipinde ikisi birden görünür ve kan grubu AB olur."},{"q":"Kan grubu A olan bir kişinin genotipi neden iki türlü olabilir?","steps":[{"t":"A grubu nasıl oluşur?","a":"IA aleli gerekli","d":"A grubu için en az bir <b>IA aleli</b> bulunmalıdır."},{"t":"İkinci alel","a":"IA veya i","d":"İkinci alel IA olabilir (IAIA) ya da çekinik i olabilir (IAi)."},{"t":"Sonuç","a":"İki genotip","d":"Her iki durumda da IA baskın olduğundan kan grubu A görünür."}],"ans":"A grubu için bir IA aleli yeterli olduğundan ikinci alelin IA ya da i olmasına göre genotip IAIA veya IAi olabilir."}]},"lise":{"kolay":[{"q":"Çok alellilik (multiple alel) kavramı genetikte nasıl tanımlanır?","steps":[{"t":"Tanım","a":"İkiden fazla alel","d":"Çok alellilik, bir genin bir popülasyonda ikiden fazla <b>alel</b> çeşidiyle temsil edilmesidir."},{"t":"Bireydeki durum","a":"En fazla 2 alel","d":"Alel çeşidi çok olsa da diploit bir bireyde bir genin en fazla 2 aleli bulunur."}],"ans":"Çok alellilik, bir genin popülasyonda ikiden fazla alelle temsil edilmesidir; bir bireyde ise en fazla 2 alel bulunur."},{"q":"AB0 kan grubu sisteminde hangi aleller görev alır ve sayıları kaçtır?","steps":[{"t":"Alelleri belirle","a":"IA, IB, i","d":"AB0 sistemini belirleyen genin <b>üç aleli</b> vardır: IA, IB ve i."},{"t":"Çok alellilik mi?","a":"Evet","d":"Üç alel ikiden fazla olduğundan AB0 sistemi çok alelliliğe klasik bir örnektir."}],"ans":"AB0 kan grubu sisteminde IA, IB ve i olmak üzere üç alel görev alır; bu da çok alelliliğe örnektir."},{"q":"AB0 sistemindeki alellerin baskınlık ilişkisi nasıldır?","steps":[{"t":"IA ve IB ilişkisi","a":"Eş baskın","d":"IA ile IB birbirine eş baskındır; bir arada bulunduklarında ikisi de fenotipte görünür."},{"t":"i alelinin durumu","a":"Çekinik","d":"i aleli hem IA'ya hem IB'ye göre <b>çekiniktir</b>, yalnızca ii'de etkisini gösterir."}],"ans":"AB0 sisteminde IA ile IB eş baskın, i aleli ise her ikisine göre çekiniktir."},{"q":"Diploit bir bireyde üç alel bulunan bir gen için neden en fazla 2 alel taşınır?","steps":[{"t":"Genin yeri","a":"Homolog kromozomlar","d":"Bir gen, homolog kromozom çiftinin <b>karşılıklı</b> lokuslarında yer alır."},{"t":"Alel sayısı","a":"İki lokus","d":"Diploit bireyde iki homolog kromozom olduğundan bir gene ait en fazla 2 alel bulunabilir."}],"ans":"Diploit bireyde gen homolog kromozom çiftinin iki lokusunda yer aldığından, alel çeşidi çok olsa da en fazla 2 alel taşınır."},{"q":"AB0 sisteminde A kan grubunu veren genotipler nelerdir?","steps":[{"t":"A grubu için gerekli","a":"IA aleli","d":"A grubu fenotipi için en az bir <b>IA aleli</b> bulunmalıdır."},{"t":"Olası genotipler","a":"IAIA ve IAi","d":"İkinci alel IA olursa IAIA, çekinik i olursa IAi olur; ikisinde de IA baskın olduğundan A görünür."}],"ans":"A kan grubu IAIA (homozigot) veya IAi (heterozigot) genotipleriyle ortaya çıkar."},{"q":"AB0 sisteminde B kan grubunu veren genotipler nelerdir?","steps":[{"t":"B grubu için gerekli","a":"IB aleli","d":"B grubu fenotipi için en az bir <b>IB aleli</b> gereklidir."},{"t":"Olası genotipler","a":"IBIB ve IBi","d":"İkinci alel IB olursa IBIB, çekinik i olursa IBi olur; her ikisinde de B fenotipi görülür."}],"ans":"B kan grubu IBIB (homozigot) veya IBi (heterozigot) genotipleriyle ortaya çıkar."},{"q":"AB kan grubu hangi genotiple oluşur ve bu hangi kalıtım türüne örnektir?","steps":[{"t":"Genotip","a":"IAIB","d":"AB grubu yalnızca hem IA hem IB alelini taşıyan <b>IAIB</b> genotipiyle oluşur."},{"t":"Kalıtım türü","a":"Eş baskınlık","d":"İki alel de fenotipte aynı anda göründüğü için bu durum eş baskınlığa örnektir."}],"ans":"AB kan grubu IAIB genotipiyle oluşur ve eş baskınlığa örnektir."},{"q":"0 kan grubunun genotipi nedir ve neden tek bir genotiple sınırlıdır?","steps":[{"t":"Gerekli alel","a":"Yalnızca i","d":"0 grubunda ne IA ne IB bulunur; sadece çekinik <b>i aleli</b> vardır."},{"t":"Sonuç","a":"ii","d":"Çekinik fenotip ancak iki çekinik alelle ortaya çıktığından genotip tek seçenektir: ii."}],"ans":"0 kan grubunun genotipi yalnızca ii'dir; çünkü baskın alel bulunmaz ve çekinik fenotip iki i aleli gerektirir."},{"q":"Genotip ile fenotip kaç olduğu AB0 sisteminde nasıl karşılaştırılır?","steps":[{"t":"Fenotip sayısı","a":"Dört fenotip","d":"AB0 sisteminde A, B, AB ve 0 olmak üzere <b>dört fenotip</b> görülür."},{"t":"Genotip sayısı","a":"Altı genotip","d":"Üç alelin ikili kombinasyonları altı genotip verir: IAIA, IAi, IBIB, IBi, IAIB, ii."}],"ans":"AB0 sisteminde dört farklı fenotip (A, B, AB, 0) ve altı farklı genotip (IAIA, IAi, IBIB, IBi, IAIB, ii) bulunur."},{"q":"Çok alelli bir gen ile tek genli iki alelli bir gen arasındaki temel fark nedir?","steps":[{"t":"Alel çeşidi","a":"İki vs. ikiden fazla","d":"Tek genli iki alelli sistemde popülasyonda 2 alel, çok alellilikte ikiden çok <b>alel</b> bulunur."},{"t":"Bireydeki ortak nokta","a":"Yine 2 alel","d":"Çeşit sayısı ne olursa olsun, her diploit birey yine yalnızca 2 alel taşır."}],"ans":"Çok alellilikte popülasyonda ikiden fazla alel çeşidi bulunur; ancak her iki sistemde de birey en fazla 2 alel taşır."},{"q":"Tavşanlarda kürk rengini belirleyen alel serisi neye örnektir?","steps":[{"t":"Alel sayısı","a":"Dört alel","d":"Tavşan kürk renginde yabani (C), çinçilla, himalaya ve albino olmak üzere <b>dört alel</b> bulunur."},{"t":"Sonuç","a":"Çok alellilik","d":"Bir gen için ikiden fazla alel olduğundan bu, çok alelliliğin (alel serisinin) güzel bir örneğidir."}],"ans":"Tavşan kürk rengi dört alelli bir gen tarafından belirlenir ve çok alelliliğe (alel serisine) örnektir."},{"q":"Tavşan kürk renginde baskınlık sırası (C > çinçilla > himalaya > albino) ne anlama gelir?","steps":[{"t":"Sıralı baskınlık","a":"Hiyerarşi var","d":"Bu seride her alel, kendinden sonrakilere <b>baskındır</b>; en üstte yabani tip (C) bulunur."},{"t":"Albino aleli","a":"En çekinik","d":"Albino aleli en alttadır; ancak iki albino aleli bir araya gelince beyaz kürk ortaya çıkar."}],"ans":"Baskınlık sırası, her alelin kendinden alttakilere baskın olduğu bir hiyerarşi belirtir; yabani tip en baskın, albino en çekiniktir."},{"q":"Çok alelli bir genin popülasyon düzeyinde fenotip çeşitliliğine etkisi nedir?","steps":[{"t":"Alel çeşidi","a":"Fazla","d":"Bir gende alel çeşidi arttıkça olası ikili <b>kombinasyonlar</b> da artar."},{"t":"Fenotip etkisi","a":"Daha çeşitli","d":"Daha çok genotip oluşacağından popülasyonda gözlenen fenotip çeşitliliği de artar."}],"ans":"Çok alellilik, daha fazla genotip kombinasyonu oluşturarak popülasyondaki fenotip çeşitliliğini artırır."},{"q":"Bir bireyin kan grubu fenotipine bakarak genotipinin her zaman kesin belirlenememesinin nedeni nedir?","steps":[{"t":"A ve B grupları","a":"İki olası genotip","d":"A grubu IAIA ya da IAi, B grubu IBIB ya da IBi olabilir; baskın alel çekiniği <b>maskeler</b>."},{"t":"Kesin olanlar","a":"AB ve 0","d":"Yalnızca AB (IAIB) ve 0 (ii) gruplarında genotip fenotipten kesin belirlenir."}],"ans":"A ve B gruplarında baskın alel çekinik i'yi maskelediğinden genotip kesin bilinemez; yalnızca AB ve 0 gruplarında genotip kesindir."},{"q":"Çok alellilik ile eş baskınlık kavramları arasındaki ilişki AB0 sisteminde nasıl bir araya gelir?","steps":[{"t":"Çok alellilik","a":"Üç alel çeşidi","d":"AB0 sisteminde bir gen için üç <b>alel</b> (IA, IB, i) bulunur; bu çok alelliliktir."},{"t":"Eş baskınlık","a":"IAIB → AB","d":"Bu alellerden IA ve IB bir araya gelince ikisi de fenotipte göründüğünden eş baskınlık ortaya çıkar."},{"t":"İlişki","a":"İki kavram aynı gende","d":"Böylece AB0 sistemi hem çok alelliliğe hem de eş baskınlığa aynı anda örnek oluşturur."}],"ans":"AB0 sistemi üç alelle çok alelliliğe, IA ve IB'nin birlikte görünmesiyle de eş baskınlığa aynı anda örnek olur."}],"zor":[{"q":"Bir gende üç alel bulunmasına rağmen bir bireyde en fazla iki alel taşınmasını, alel çeşidi ve birey ayrımıyla açıklayınız.","steps":[{"t":"Popülasyon düzeyi","a":"Üç alel çeşidi","d":"Çok alellilikte bir gen popülasyonda üç ya da daha çok <b>alel</b> çeşidiyle bulunabilir."},{"t":"Birey düzeyi","a":"İki homolog lokus","d":"Diploit bireyde gen, homolog kromozom çiftinin iki lokusunda yer alır."},{"t":"Sonuç","a":"En fazla 2 alel","d":"Biri anneden biri babadan geldiği için bir birey, çeşit kaç olursa olsun en fazla 2 alel taşır."}],"ans":"Alel çeşitliliği popülasyona aittir; birey gen iki homolog lokusta yer aldığından anneden ve babadan gelen en fazla 2 alel taşır."},{"q":"A grubu (IAi) bir anne ile B grubu (IBi) bir babanın çocuklarında hangi kan grupları görülebilir? Genotipleriyle gösteriniz.","steps":[{"t":"Anne gametleri","a":"IA ve i","d":"IAi anne IA veya i aleli içeren <b>gametler</b> oluşturur."},{"t":"Baba gametleri","a":"IB ve i","d":"IBi baba IB veya i aleli içeren gametler oluşturur."},{"t":"Çaprazlamayı yap","a":"IAIB, IAi, IBi, ii","d":"Gametler birleşince IAIB (AB), IAi (A), IBi (B) ve ii (0) genotipleri eşit olasılıkla oluşur."}],"ans":"Çocuklarda IAIB (AB), IAi (A), IBi (B) ve ii (0) görülebilir; yani dört kan grubunun tümü ortaya çıkabilir."},{"q":"AB grubu bir anne ile 0 grubu bir babanın çocuklarında neden hiçbir zaman AB ya da 0 grubu görülmez? Açıklayınız.","steps":[{"t":"Anne gametleri","a":"IA ve IB","d":"IAIB anne yalnızca IA veya IB aleli taşıyan <b>gametler</b> üretir; i aleli içermez."},{"t":"Baba gametleri","a":"Yalnızca i","d":"ii baba yalnızca i aleli taşıyan gametler üretir."},{"t":"Çaprazlamayı yap","a":"IAi ve IBi","d":"Birleşmeler yalnızca IAi (A) ve IBi (B) verir; IAIB (AB) veya ii (0) oluşamaz."}],"ans":"Anne i, baba ise IA/IB vermediğinden çocuklar yalnızca IAi (A) ya da IBi (B) olur; bu yüzden AB ve 0 grubu görülmez."},{"q":"Bir ailede çocuğun kan grubu 0 ise, anne A baba B grubunda olduğuna göre ebeveynlerin genotipleri ne olmalıdır? Açıklayınız.","steps":[{"t":"Çocuğun genotipi","a":"ii","d":"0 grubu çocuğun genotipi ii'dir; iki i alelinden birini anneden, birini <b>babadan</b> almıştır."},{"t":"Anneden gelen alel","a":"i taşımalı","d":"Anne A grubu olduğundan ve çocuğa i verdiğinden anne genotipi IAi olmalıdır."},{"t":"Babadan gelen alel","a":"i taşımalı","d":"Baba B grubu olduğundan ve çocuğa i verdiğinden baba genotipi IBi olmalıdır."}],"ans":"Çocuk her ebeveynden bir i aleli aldığından anne IAi, baba ise IBi genotipinde olmalıdır."},{"q":"AB0 sisteminin altı genotip ama yalnızca dört fenotip vermesini, baskınlık ilişkileriyle açıklayınız.","steps":[{"t":"Genotipleri sırala","a":"Altı genotip","d":"Olası genotipler IAIA, IAi, IBIB, IBi, IAIB ve ii'dir."},{"t":"A ve B'de maskeleme","a":"Çekinik gizlenir","d":"IAIA ile IAi aynı A fenotipini, IBIB ile IBi aynı B fenotipini verir; çünkü baskın alel çekinik i'yi <b>maskeler</b>."},{"t":"Kalan fenotipler","a":"AB ve 0","d":"IAIB eş baskınlıkla AB, ii ise çekinik fenotiple 0 verir; böylece dört fenotip oluşur."}],"ans":"Baskın aleller çekinik i'yi maskelediğinden iki çift genotip A ve B'de birleşir; IAIB AB, ii 0 verir, böylece altı genotip dört fenotipe iner."},{"q":"Tavşan kürk renginde baskınlık serisi C > c^ch (çinçilla) > c^h (himalaya) > c (albino) olduğuna göre c^ch c^h genotipli tavşanın fenotipini belirleyiniz.","steps":[{"t":"Alelleri belirle","a":"c^ch ve c^h","d":"Tavşanda biri çinçilla (c^ch), biri himalaya (c^h) <b>aleli</b> bulunur."},{"t":"Sıralamaya bak","a":"Çinçilla baskın","d":"Baskınlık serisinde c^ch, c^h aleline göre üst sırada, yani baskındır."},{"t":"Fenotipi bul","a":"Çinçilla","d":"Üstteki alel etkisini gösterdiğinden tavşanın kürk fenotipi çinçilla olur."}],"ans":"Baskınlık serisinde çinçilla (c^ch) himalayaya (c^h) baskın olduğundan c^ch c^h genotipli tavşanın fenotipi çinçilladır."},{"q":"Tavşan kürk renginde albino (beyaz) fenotipinin neden yalnızca cc genotipiyle ortaya çıktığını açıklayınız.","steps":[{"t":"Albino alelinin yeri","a":"Serinin en altı","d":"Albino aleli (c) baskınlık serisinin en altındadır; diğer tüm aleller ona <b>baskındır</b>."},{"t":"Tek alelle ortaya çıkmaz","a":"Maskelenir","d":"Yanında C, c^ch ya da c^h bulunursa albino aleli maskelenir ve beyaz görülmez."},{"t":"Sonuç","a":"cc gerekli","d":"Albino fenotipi ancak iki albino aleli (cc) bir araya gelince ortaya çıkar."}],"ans":"Albino aleli en çekinik olduğundan diğer aleller yanında maskelenir; bu yüzden beyaz kürk yalnızca cc genotipiyle görülür."},{"q":"IAi anne ile IAIB babanın çocuklarında kan gruplarının görülme olasılıklarını hesaplayınız.","steps":[{"t":"Gametleri yaz","a":"Anne IA/i, baba IA/IB","d":"IAi anne IA ve i, IAIB baba ise IA ve IB <b>gametleri</b> oluşturur."},{"t":"Birleşmeleri bul","a":"IAIA, IAIB, IAi, IBi","d":"Dört eşit olasılıklı birleşme: IAIA, IAIB, IAi ve IBi oluşur."},{"t":"Fenotipe çevir","a":"A:2/4, AB:1/4, B:1/4","d":"IAIA ve IAi A grubu (toplam 1/2), IAIB AB grubu (1/4), IBi ise B grubu (1/4) verir."}],"ans":"Çocuklarda 1/2 (%50) A grubu, 1/4 (%25) AB grubu ve 1/4 (%25) B grubu görülür; 0 grubu görülmez."},{"q":"AB0 sisteminde 'i' alelinin hem IA'ya hem IB'ye çekinik, IA ve IB'nin ise birbirine eş baskın olmasını tek bir örnekle açıklayınız.","steps":[{"t":"i'nin çekinikliği","a":"IAi → A, IBi → B","d":"IAi'de A, IBi'de B fenotipi görülür; çünkü i aleli baskın alel yanında <b>maskelenir</b>."},{"t":"IA ve IB birlikte","a":"IAIB → AB","d":"IAIB'de hiçbiri diğerini örtmez; her iki alel de yüzey antijenini üretir ve fenotipte birlikte görünür."},{"t":"Sonuç","a":"İki ilişki bir arada","d":"Böylece aynı gende hem baskın-çekinik (IA/IB ile i) hem eş baskın (IA ile IB) ilişki birlikte bulunur."}],"ans":"IAi A, IBi B verir (i çekinik); IAIB ise AB verir (IA ve IB eş baskın); böylece tek gende baskın-çekinik ve eş baskınlık birlikte görülür."},{"q":"İki ebeveyn de A grubu olduğu hâlde 0 grubu bir çocuk doğabilir mi? Genotiplerle açıklayınız.","steps":[{"t":"A grubu genotipleri","a":"IAIA veya IAi","d":"A grubu ebeveynler IAIA ya da IAi olabilir; 0 çocuk için her ikisinin de <b>i aleli</b> taşıması gerekir."},{"t":"Heterozigot durum","a":"IAi × IAi","d":"Her iki ebeveyn de IAi ise gametlerle IA ve i alelleri çocuğa geçebilir."},{"t":"0 çocuğun oluşumu","a":"ii (1/4)","d":"İki ebeveyn de i aleli verdiğinde çocuk ii (0 grubu) olur; bu 1/4 olasılıkla gerçekleşir."}],"ans":"Her iki ebeveyn de IAi (heterozigot) ise, ikisi de i aleli verdiğinde 1/4 olasılıkla ii genotipli 0 grubu çocuk doğabilir."},{"q":"Çok alelli bir genin iki alelli bir gene göre popülasyonda daha çok genotip ve fenotip oluşturmasını sayısal olarak karşılaştırınız.","steps":[{"t":"İki alelli durum","a":"3 genotip","d":"İki alelli (A, a) gende genotip sayısı 3'tür: AA, Aa, aa."},{"t":"Üç alelli durum","a":"6 genotip","d":"Üç alelli gende genotip sayısı, n alel için n(n+1)/2 ile hesaplanır: 3·4/2 = 6 genotip."},{"t":"Sonuç","a":"Daha çok çeşit","d":"Alel sayısı arttıkça genotip sayısı hızla büyür, bu da olası fenotip çeşidini artırır."}],"ans":"İki alelli gen 3 genotip verirken üç alelli gen n(n+1)/2 = 6 genotip verir; alel çeşidi arttıkça genotip ve fenotip çeşitliliği belirgin biçimde artar."},{"q":"Bir adli olayda çocuğun kan grubu 0, annenin AB grubu olduğu belirleniyor. Bu annenin söz konusu çocuğun biyolojik annesi olamayacağını açıklayınız.","steps":[{"t":"Annenin gametleri","a":"IA veya IB","d":"AB grubu (IAIB) anne yalnızca IA ya da IB aleli taşıyan <b>gametler</b> üretir."},{"t":"0 çocuğun ihtiyacı","a":"İki i aleli","d":"0 grubu çocuk (ii) bir i alelini anneden almak zorundadır."},{"t":"Çelişki","a":"Anne i veremez","d":"AB grubu anne i aleli içeren gamet üretemediğinden çocuğa i veremez; bu bir çelişkidir."}],"ans":"AB grubu anne hiç i aleli taşımadığından 0 grubu (ii) çocuğa gerekli i alelini veremez; bu nedenle bu kadın çocuğun biyolojik annesi olamaz."},{"q":"Tavşan kürk renginde C c (yabani-albino) ile c^h c (himalaya-albino) bireylerinin çaprazlanmasında oluşabilecek fenotipleri belirleyiniz.","steps":[{"t":"Gametleri yaz","a":"C/c ve c^h/c","d":"Bir ebeveyn C ve c, diğeri c^h ve c <b>gametleri</b> oluşturur."},{"t":"Birleşmeleri bul","a":"Cc^h, Cc, c^h c, cc","d":"Dört eşit olasılıklı birleşme: Cc^h, Cc, c^h c ve cc oluşur."},{"t":"Fenotipe çevir","a":"Yabani, yabani, himalaya, albino","d":"C en baskın olduğundan Cc^h ve Cc yabani; c^h c himalaya; cc ise albino fenotipi verir."}],"ans":"Çaprazlamada 1/2 yabani (Cc^h, Cc), 1/4 himalaya (c^h c) ve 1/4 albino (cc) fenotipleri oluşabilir."},{"q":"AB0 kan grubu sisteminin baskınlık hiyerarşisi ile tavşan kürk renginin baskınlık serisini benzerlik ve fark açısından karşılaştırınız.","steps":[{"t":"Ortak nokta","a":"Çok alellilik","d":"Her iki sistemde de bir gen için ikiden fazla <b>alel</b> bulunur, yani çok alellilik görülür."},{"t":"Tavşandaki ilişki","a":"Tam sıralı baskınlık","d":"Tavşanda aleller C > c^ch > c^h > c biçiminde tam bir baskınlık hiyerarşisi gösterir."},{"t":"Kandaki fark","a":"Eş baskınlık var","d":"AB0'da i çekinik olsa da IA ve IB eş baskındır; yani tam sıralı bir hiyerarşi yerine eş baskınlık da bulunur."}],"ans":"Her ikisi de çok alellidir; tavşan kürk renginde tam sıralı baskınlık hiyerarşisi görülürken AB0 sisteminde i çekinik ama IA ile IB eş baskın olduğundan ilişki tam hiyerarşik değildir."},{"q":"AB0 sistemi kullanılarak bir popülasyonda gözlenebilecek tüm genotip-fenotip eşleşmelerini sistematik biçimde gösteriniz.","steps":[{"t":"Alelleri belirle","a":"IA, IB, i","d":"Sistemde üç alel bulunur; bunların ikili <b>kombinasyonları</b> genotipleri verir."},{"t":"Genotipleri eşle","a":"Altı genotip","d":"IAIA ve IAi → A; IBIB ve IBi → B; IAIB → AB; ii → 0 biçiminde eşlenir."},{"t":"Fenotip sayısı","a":"Dört fenotip","d":"Sonuçta A, B, AB ve 0 olmak üzere dört fenotip ortaya çıkar."}],"ans":"Genotip-fenotip eşleşmeleri şöyledir: IAIA ve IAi → A, IBIB ve IBi → B, IAIB → AB, ii → 0; böylece altı genotip dört fenotipe karşılık gelir."}]}},"dihibrit":{"ilkokul":{"kolay":[{"q":"Bir bezelyenin hem sarı tohumu hem de düz yüzeyi var. Bunlar bir bitkide kaç özellik demektir?","steps":[{"t":"Özellikleri say","a":"İki özellik","d":"Burada bir özellik tohum <b>rengi</b> (sarı), bir özellik de tohum <b>yüzeyi</b> (düz) ile ilgilidir."},{"t":"Topla","a":"1 + 1 = 2","d":"Renk ve yüzey iki ayrı özellik olduğu için bezelyede aynı anda iki özelliğe bakılıyor demektir."}],"ans":"Renk ve yüzey iki ayrı özelliktir; yani bu bitkide iki özelliğe birlikte bakılıyor."},{"q":"Anne kedi hem siyah tüylü hem uzun kuyruklu. Yavruya bu iki özellik birden geçebilir mi?","steps":[{"t":"Özellikler nereden gelir?","a":"Anne ve babadan","d":"Yavru, tüy rengini ve kuyruk uzunluğunu <b>anne ve babasından</b> alır."},{"t":"İki özellik birlikte","a":"Geçebilir","d":"Renk ve kuyruk ayrı ayrı geçtiği için yavruya iki özellik birden geçebilir."}],"ans":"Evet; tüy rengi ve kuyruk uzunluğu birlikte yavruya geçebilir."},{"q":"Bir çiçeğin hem rengi hem de kokusu var. Bunlardan kaç tanesi özelliktir?","steps":[{"t":"Renk bir özellik mi?","a":"Evet","d":"Çiçeğin <b>rengi</b> onun bir özelliğidir."},{"t":"Koku da özellik mi?","a":"Evet","d":"Çiçeğin <b>kokusu</b> da ayrı bir özelliktir; ikisi birlikte iki özellik eder."}],"ans":"Renk ve koku iki ayrı özelliktir, yani toplam iki özellik vardır."},{"q":"Bir köpek hem büyük hem de kahverengi. Bu iki özelliği aynı anda söyleyebilir miyiz?","steps":[{"t":"Boy bir özellik","a":"Büyüklük","d":"Köpeğin <b>büyüklüğü</b> bir özelliğidir."},{"t":"Renk de bir özellik","a":"Kahverengi","d":"Köpeğin <b>rengi</b> de ayrı bir özelliktir; ikisini birlikte söyleyebiliriz."}],"ans":"Evet; köpek hem büyük hem kahverengi diyerek iki özelliği birlikte söyleyebiliriz."},{"q":"İki özelliğe (örneğin hem renk hem boy) aynı anda bakmaya günlük dille ne diyebiliriz?","steps":[{"t":"Kaç özellik var?","a":"İki özellik","d":"Burada renk ve boy gibi <b>iki ayrı özelliğe</b> birden bakılıyor."},{"t":"İkisine birden bakmak","a":"İki özelliği birlikte incelemek","d":"Tek özellik yerine iki özelliği aynı anda incelemeye iki özellikli inceleme diyebiliriz."}],"ans":"İki özelliğe (renk ve boy) aynı anda bakmaya iki özelliği birlikte inceleme denir."}],"zor":[{"q":"Bir bitki hem sarı hem düz tohumlu. Başka bir bitki hem yeşil hem buruşuk tohumlu. Toplamda kaç farklı özellik konuşuyoruz?","steps":[{"t":"Hangi özellikler var?","a":"Renk ve yüzey","d":"İki özellik konuşuyoruz: tohum <b>rengi</b> ve tohum <b>yüzeyi</b>."},{"t":"Özellik sayısı","a":"İki özellik","d":"Sarı/yeşil renk özelliği, düz/buruşuk ise yüzey özelliğidir; renk değişse de özellik sayısı yine ikidir."}],"ans":"Renk ve yüzey olmak üzere iki farklı özellik konuşuyoruz."},{"q":"Bir tavşan hem beyaz tüylü hem uzun kulaklı olabiliyorsa, hem kahverengi tüylü hem kısa kulaklı da olabilir mi?","steps":[{"t":"Özellikler ayrı mı?","a":"Evet, ayrı","d":"Tüy <b>rengi</b> ve kulak <b>uzunluğu</b> birbirinden bağımsız iki özelliktir."},{"t":"Karışık olabilir mi?","a":"Olabilir","d":"İki özellik ayrı ayrı geçtiği için renk ve kulak her türlü birleşebilir."}],"ans":"Evet; renk ve kulak ayrı özellikler olduğu için her türlü birlikte görülebilir."},{"q":"Anne çiçek hem kırmızı hem uzun, baba çiçek hem beyaz hem kısa. Yavruda kırmızı renk ile kısa boy birlikte görülebilir mi?","steps":[{"t":"Özellikler nereden gelir?","a":"Anneden ve babadan","d":"Yavru <b>rengi</b> bir ebeveynden, <b>boyu</b> başka ebeveynden alabilir."},{"t":"Karışım mümkün mü?","a":"Mümkün","d":"Renk anneden (kırmızı), boy babadan (kısa) gelirse iki özellik karışık birleşebilir."}],"ans":"Evet; renk anneden, boy babadan gelebileceği için kırmızı ve kısa birlikte görülebilir."},{"q":"İki özellik birlikte düşünülünce kaç farklı görünüş çıkabileceğini örnekle gösterelim: renk (sarı/yeşil) ve yüzey (düz/buruşuk).","steps":[{"t":"Renk seçenekleri","a":"2 tane","d":"Renk için <b>sarı</b> ve <b>yeşil</b> olmak üzere iki seçenek vardır."},{"t":"Eşleştirmeleri yaz","a":"2 × 2 = 4","d":"Her renk her yüzeyle eşleşince sarı-düz, sarı-buruşuk, yeşil-düz, yeşil-buruşuk olmak üzere 4 görünüş çıkar."}],"ans":"İki özellik birleşince sarı-düz, sarı-buruşuk, yeşil-düz, yeşil-buruşuk olmak üzere 4 farklı görünüş olur."},{"q":"Bir bahçede 4 çeşit fasulye var: sarı-düz, sarı-buruşuk, yeşil-düz, yeşil-buruşuk. Bu çeşitler kaç özelliğin karışmasıyla oluşmuş?","steps":[{"t":"Görünüşlere bak","a":"Renk ve yüzey","d":"İsimlerde hem <b>renk</b> (sarı/yeşil) hem <b>yüzey</b> (düz/buruşuk) geçiyor."},{"t":"Özellik sayısı","a":"İki özellik","d":"Dört çeşit, iki özelliğin (renk ve yüzey) farklı şekillerde birleşmesiyle oluşmuştur."}],"ans":"Bu dört çeşit, renk ve yüzey olmak üzere iki özelliğin karışmasıyla oluşmuştur."}]},"ortaokul":{"kolay":[{"q":"Dihibrit çaprazlama ne demektir?","steps":[{"t":"Kaç karaktere bakılır?","a":"İki karakter","d":"Dihibrit çaprazlamada aynı anda <b>iki ayrı karakter</b> (örneğin renk ve yüzey) incelenir."},{"t":"Tanımla","a":"İki karakterli çaprazlama","d":"İki karakter bakımından farklılık gösteren bireylerin çaprazlanmasına dihibrit çaprazlama denir."}],"ans":"Dihibrit çaprazlama, iki karakterin aynı anda incelendiği çaprazlamadır."},{"q":"AaBb genotipli bir bireyde kaç karakter ve her karakterde hangi aleller vardır?","steps":[{"t":"Harfleri ayır","a":"Aa ve Bb","d":"Genotip iki harf çiftinden oluşur: bir karakter için <b>Aa</b>, diğer karakter için <b>Bb</b>."},{"t":"Karakter sayısı","a":"İki karakter","d":"A/a bir karakterin alelleri, B/b ikinci karakterin alelleridir; yani iki karakter vardır."}],"ans":"AaBb bireyde iki karakter vardır; birinde A ve a, diğerinde B ve b alelleri bulunur."},{"q":"AaBb genotipli bir birey kaç çeşit ve hangi gametleri oluşturur?","steps":[{"t":"Her karakterden birer alel","a":"A veya a, B veya b","d":"Her gamet, A/a'dan birini ve B/b'den birini alır."},{"t":"Birleştir","a":"AB, Ab, aB, ab","d":"Bu aleller birleşince AB, Ab, aB, ab olmak üzere <b>4 çeşit</b> gamet oluşur."}],"ans":"AaBb bireyi AB, Ab, aB ve ab olmak üzere 4 çeşit gamet oluşturur."},{"q":"AaBb × AaBb çaprazlamasında oğul döldeki fenotip oranı nedir?","steps":[{"t":"Bilinen oran","a":"9:3:3:1","d":"İki karakter de heterozigot çaprazlandığında klasik <b>9:3:3:1</b> oranı çıkar."},{"t":"Anlamı","a":"Dört fenotip","d":"En çok iki baskın özellikli (9), sonra tek baskınlılar (3 ve 3), en az çift çekinik (1) görülür."}],"ans":"AaBb × AaBb çaprazlamasının fenotip oranı 9:3:3:1'dir."},{"q":"Bağımsız dağılım ilkesi kısaca neyi söyler?","steps":[{"t":"İki karakter","a":"Ayrı ayrı dağılır","d":"Gamet oluşurken bir karakterin alelleri, diğer karakterinkilerden <b>bağımsız</b> dağılır."},{"t":"Sonuç","a":"Karakterler birbirini etkilemez","d":"Bu yüzden A'nın hangi gamete gittiği B'nin gideceği yeri etkilemez; karakterler bağımsız aktarılır."}],"ans":"Bağımsız dağılım, iki karakterin alellerinin gametlere birbirinden bağımsız dağılmasıdır."}],"zor":[{"q":"AaBb × AaBb çaprazlamasında 9:3:3:1 oranındaki sayıların toplamı kaçtır ve bu hangi kareyle ilgilidir?","steps":[{"t":"Sayıları topla","a":"9 + 3 + 3 + 1 = 16","d":"Fenotip oranındaki dört sayıyı toplarsak <b>16</b> elde edilir."},{"t":"Punnett karesi","a":"16'lık kare","d":"Her ebeveyn 4 çeşit gamet verdiğinden Punnett karesi 4 × 4 = 16 kutudan oluşur; toplam da 16'dır."}],"ans":"9 + 3 + 3 + 1 = 16'dır; bu, 4 × 4'lük 16 kutuluk dihibrit Punnett karesiyle ilgilidir."},{"q":"160 bezelye tohumu AaBb × AaBb çaprazlamasından elde edildi. Çift baskın (sarı-düz) fenotipte kaç tohum beklenir?","steps":[{"t":"Oranı yaz","a":"9/16","d":"9:3:3:1 oranında çift baskın fenotip <b>9/16</b> paya sahiptir."},{"t":"Sayıyla çarp","a":"160 × 9/16 = 90","d":"160 tohumu 9/16 ile çarparsak 160 ÷ 16 = 10, 10 × 9 = 90 tohum bulunur."}],"ans":"Çift baskın (sarı-düz) fenotipte yaklaşık 90 tohum beklenir."},{"q":"AaBb × AaBb çaprazlamasında her ebeveynin oluşturduğu gamet çeşitleri çarpılırsa Punnett karesinde kaç kutu olur?","steps":[{"t":"Bir ebeveynin gametleri","a":"4 çeşit","d":"AaBb bireyi AB, Ab, aB, ab olmak üzere <b>4 çeşit</b> gamet oluşturur."},{"t":"Kutuları hesapla","a":"4 × 4 = 16","d":"Bir ebeveynin 4 gameti diğerinin 4 gametiyle eşleşince 4 × 4 = 16 kutu çıkar."}],"ans":"Her ebeveyn 4 gamet verdiği için Punnett karesinde 4 × 4 = 16 kutu olur."},{"q":"AaBb × AaBb çaprazlamasında çift çekinik (yeşil-buruşuk) fenotip oranı nedir ve olasılık çarpımıyla nasıl bulunur?","steps":[{"t":"Her karakter ayrı","a":"aa için 1/4, bb için 1/4","d":"Aa × Aa'dan aa olasılığı 1/4, Bb × Bb'den bb olasılığı da <b>1/4</b>'tür."},{"t":"Olasılıkları çarp","a":"1/4 × 1/4 = 1/16","d":"İki karakter bağımsız olduğundan olasılıklar çarpılır: 1/4 × 1/4 = 1/16."}],"ans":"Çift çekinik fenotip oranı 1/16'dır; 1/4 × 1/4 olasılık çarpımıyla bulunur."},{"q":"AaBb bireyinin oluşturduğu 4 gamet çeşidini, alelleri tek tek eşleştirerek gösteriniz.","steps":[{"t":"A ile B/b","a":"AB ve Ab","d":"A aleli, B veya b ile birleşerek <b>AB</b> ve <b>Ab</b> gametlerini verir."},{"t":"a ile B/b","a":"aB ve ab","d":"a aleli, B veya b ile birleşerek aB ve ab gametlerini verir; toplam 4 çeşit gamet olur."}],"ans":"AaBb bireyi AB, Ab, aB ve ab olmak üzere 4 çeşit gamet oluşturur."}]},"lise":{"kolay":[{"q":"Dihibrit çaprazlama hangi durumu ifade eder?","steps":[{"t":"İncelenen karakter sayısı","a":"İki karakter","d":"Dihibrit çaprazlama, <b>iki ayrı karakter</b> bakımından heterozigot bireylerin çaprazlanmasıdır."},{"t":"Örnek genotip","a":"AaBb × AaBb","d":"Tipik örnek, her iki karakterde de melez olan AaBb × AaBb çaprazlamasıdır."}],"ans":"Dihibrit çaprazlama, iki farklı karakter bakımından heterozigot bireylerin (AaBb × AaBb) çaprazlanmasıdır."},{"q":"AaBb genotipli bir birey kaç çeşit gamet oluşturur ve bunlar nelerdir?","steps":[{"t":"Her karakterden bir alel","a":"A/a ve B/b","d":"Mayozda her gamet A veya a'dan birini, B veya b'den birini alır."},{"t":"Kombinasyonları yaz","a":"AB, Ab, aB, ab","d":"İki karakterin alelleri bağımsız birleşince 2² = 4 çeşit gamet oluşur: <b>AB, Ab, aB, ab</b>."}],"ans":"AaBb bireyi AB, Ab, aB, ab olmak üzere 4 çeşit gamet oluşturur."},{"q":"AaBb × AaBb çaprazlamasının klasik fenotip oranı nedir?","steps":[{"t":"Mendel sonucu","a":"9:3:3:1","d":"İki bağımsız karakter heterozigot çaprazlandığında oğul dölde <b>9:3:3:1</b> fenotip oranı görülür."},{"t":"Oranın anlamı","a":"Dört fenotip sınıfı","d":"9 çift baskın, 3 ve 3 tek baskın, 1 çift çekinik bireyi temsil eder."}],"ans":"AaBb × AaBb çaprazlamasının klasik fenotip oranı 9:3:3:1'dir."},{"q":"Bağımsız dağılım (bağımsız açılım) ilkesi nedir?","steps":[{"t":"Hangi karakterler","a":"Farklı kromozomlardaki genler","d":"İlke, farklı kromozomlarda yer alan genlerin (karakterlerin) gametlere <b>bağımsız</b> dağıldığını söyler."},{"t":"Mayozdaki temeli","a":"Homologların rastgele dizilişi","d":"Mayoz I'de homolog kromozom çiftleri ekvatorda rastgele dizildiğinden bir karakterin aktarımı diğerini etkilemez."}],"ans":"Bağımsız dağılım, farklı kromozomlardaki karakterlerin alellerinin gametlere birbirinden bağımsız olarak dağılmasıdır."},{"q":"Dihibrit Punnett karesinde neden 16 kutu bulunur?","steps":[{"t":"Gamet çeşidi","a":"Her ebeveyn 4 çeşit","d":"AaBb bireyi <b>4 çeşit</b> gamet oluşturur."},{"t":"Kareyi oluştur","a":"4 × 4 = 16","d":"Bir ebeveynin 4 gameti diğerinin 4 gametiyle eşleştiğinden kare 4 × 4 = 16 kutudan oluşur."}],"ans":"Her ebeveyn 4 çeşit gamet oluşturduğundan Punnett karesi 4 × 4 = 16 kutu içerir."},{"q":"AaBb × AaBb çaprazlamasında çift çekinik (aabb) fenotip oranı nedir?","steps":[{"t":"Her karakteri ayır","a":"aa: 1/4, bb: 1/4","d":"Aa × Aa'dan aa olasılığı 1/4, Bb × Bb'den bb olasılığı <b>1/4</b>'tür."},{"t":"Olasılıkları çarp","a":"1/4 × 1/4 = 1/16","d":"Bağımsız olaylar olduğu için olasılıklar çarpılır ve 1/16 bulunur."}],"ans":"Çift çekinik (aabb) fenotip oranı 1/16'dır."},{"q":"Olasılık çarpımı yöntemi dihibrit çaprazlamada neden kullanılır?","steps":[{"t":"Karakterlerin ilişkisi","a":"Bağımsız","d":"İki karakter bağımsız dağıldığından her birinin olasılığı <b>ayrı ayrı</b> hesaplanabilir."},{"t":"Çarpım kuralı","a":"Olasılıkları çarp","d":"Bağımsız olayların birlikte gerçekleşme olasılığı, tek tek olasılıklarının çarpımına eşittir; bu yüzden 16'lık kare çizmeden sonuç bulunur."}],"ans":"İki karakter bağımsız olduğundan olasılık çarpımı yöntemiyle kareyi çizmeden istenen fenotip olasılığı hızlıca hesaplanır."},{"q":"AaBb × AaBb çaprazlamasında bir karakter için baskın fenotip olasılığı nedir?","steps":[{"t":"Aa × Aa sonucu","a":"3 baskın : 1 çekinik","d":"Tek karakterlik Aa × Aa çaprazlamasında <b>3/4</b> baskın, 1/4 çekinik fenotip görülür."},{"t":"Olasılığı yaz","a":"3/4","d":"Dolayısıyla bir karakterde baskın fenotip olasılığı 3/4'tür."}],"ans":"Bir karakter için baskın fenotip olasılığı 3/4'tür."},{"q":"9:3:3:1 oranında '9' hangi fenotip grubunu temsil eder?","steps":[{"t":"En büyük grup","a":"Çift baskın","d":"Oranın <b>9</b> kısmı, her iki karakterde de baskın fenotip gösteren bireyleri temsil eder."},{"t":"Olasılıkla doğrula","a":"3/4 × 3/4 = 9/16","d":"Her karakterde baskın olasılığı 3/4 olduğundan ikisinin çarpımı 9/16 olur; bu da 9'a karşılık gelir."}],"ans":"9:3:3:1 oranındaki '9', her iki karakterde de baskın fenotip gösteren (çift baskın) bireyleri temsil eder."},{"q":"AaBb × AaBb çaprazlamasında her iki karakterde de baskın fenotip olasılığı olasılık çarpımıyla nasıl bulunur?","steps":[{"t":"Tek karakter olasılığı","a":"3/4","d":"Her karakterde baskın fenotip olasılığı Aa × Aa'dan <b>3/4</b>'tür."},{"t":"İkisini çarp","a":"3/4 × 3/4 = 9/16","d":"İki karakter bağımsız olduğundan olasılıklar çarpılır: 3/4 × 3/4 = 9/16."}],"ans":"Her iki karakterde de baskın fenotip olasılığı 3/4 × 3/4 = 9/16'dır."},{"q":"AaBb genotipinin genotip ve fenotip arasındaki ilişkisi nasıldır?","steps":[{"t":"Genotip","a":"AaBb (melez)","d":"AaBb, her iki karakterde de bir baskın bir çekinik alel taşıyan <b>heterozigot</b> genotiptir."},{"t":"Fenotip","a":"Çift baskın görünüm","d":"Baskın aleller etkisini gösterdiğinden birey, her iki karakterde de baskın fenotipi sergiler."}],"ans":"AaBb genotipi her iki karakterde de heterozigottur ve fenotipte her iki karakterin baskın özelliğini gösterir."},{"q":"Dihibrit çaprazlamada gamet çeşidi sayısı nasıl hesaplanır?","steps":[{"t":"Heterozigot karakter sayısı","a":"n = 2","d":"Birey, iki karakter bakımından da heterozigot olduğundan heterozigot gen sayısı <b>2</b>'dir."},{"t":"Formülü uygula","a":"2ⁿ = 2² = 4","d":"Gamet çeşidi 2ⁿ ile bulunur; n = 2 için 2² = 4 çeşit gamet oluşur."}],"ans":"Heterozigot karakter sayısı n ise gamet çeşidi 2ⁿ'dir; AaBb için 2² = 4 çeşit gamet oluşur."},{"q":"AaBb × AaBb çaprazlamasında 9:3:3:1 oranındaki iki '3'lük grup neyi temsil eder?","steps":[{"t":"Birinci 3","a":"A baskın, b çekinik","d":"Bir '3'lük grup, birinci karakterde baskın, ikinci karakterde çekinik fenotip gösteren bireylerdir (A_bb)."},{"t":"İkinci 3","a":"a çekinik, B baskın","d":"Diğer '3'lük grup ise birinci karakterde çekinik, ikincide baskın fenotipli bireylerdir (aaB_)."}],"ans":"İki '3'lük grup, bir karakterde baskın diğerinde çekinik fenotip gösteren iki ayrı birey grubunu (A_bb ve aaB_) temsil eder."},{"q":"AaBb × AaBb çaprazlamasında aabb (çift çekinik) genotipi hangi gametlerin birleşmesiyle oluşur?","steps":[{"t":"Gerekli gametler","a":"ab ve ab","d":"aabb oluşması için her iki ebeveynden de <b>ab</b> gametinin gelmesi gerekir."},{"t":"Olasılığı yaz","a":"1/4 × 1/4 = 1/16","d":"Her ebeveynde ab gameti olasılığı 1/4 olduğundan ikisinin birleşme olasılığı 1/16'dır."}],"ans":"aabb genotipi, her iki ebeveynden gelen ab gametlerinin birleşmesiyle oluşur ve olasılığı 1/16'dır."},{"q":"AaBb × AaBb çaprazlamasında yalnızca bir karakterde baskın fenotip gösteren bireylerin toplam oranı nedir?","steps":[{"t":"İki olası grup","a":"A_bb ve aaB_","d":"Tek karakterde baskın olan bireyler ya birinci karakterde baskın (<b>A_bb</b>) ya da ikinci karakterde baskındır (aaB_)."},{"t":"Her grubun oranı","a":"3/16","d":"A_bb için 3/4 × 1/4 = 3/16, aaB_ için 1/4 × 3/4 = 3/16 olur."},{"t":"Toplamı al","a":"3/16 + 3/16 = 6/16","d":"İki grup toplanınca 6/16 (sadeleşmiş 3/8) bulunur."}],"ans":"Yalnızca bir karakterde baskın fenotip gösteren bireylerin toplam oranı 6/16'dır (3/8)."}],"zor":[{"q":"AaBb × AaBb çaprazlamasında 9:3:3:1 fenotip oranının olasılık çarpımıyla nasıl ortaya çıktığını adım adım gösteriniz.","steps":[{"t":"Tek karakter oranları","a":"3/4 baskın, 1/4 çekinik","d":"Her karakterde Aa × Aa'dan baskın fenotip <b>3/4</b>, çekinik 1/4 çıkar."},{"t":"Dört kombinasyon","a":"Çarpımları al","d":"Baskın-baskın 3/4 × 3/4 = 9/16, baskın-çekinik 3/4 × 1/4 = 3/16, çekinik-baskın 1/4 × 3/4 = 3/16, çekinik-çekinik 1/4 × 1/4 = 1/16."},{"t":"Oranı yaz","a":"9:3:3:1","d":"Paydalar eşit (16) olduğundan paylar 9, 3, 3, 1 olarak yazılır ve klasik 9:3:3:1 oranı elde edilir."}],"ans":"Her karakterde 3/4 ve 1/4 olasılıkları çarpılınca 9/16, 3/16, 3/16 ve 1/16 çıkar; bu da 9:3:3:1 fenotip oranını verir."},{"q":"320 bireylik bir dihibrit (AaBb × AaBb) çaprazlamasında dört fenotip grubundaki birey sayılarını hesaplayınız.","steps":[{"t":"Bir birim payı","a":"320 ÷ 16 = 20","d":"Oran toplamı 16 olduğundan 320 birey 16'ya bölünür: bir birim <b>20</b> bireye karşılık gelir."},{"t":"Grupları çarp","a":"9·20, 3·20, 3·20, 1·20","d":"9 × 20 = 180, 3 × 20 = 60, 3 × 20 = 60, 1 × 20 = 20 birey bulunur."},{"t":"Sonucu yaz","a":"180:60:60:20","d":"Dört fenotip grubu sırasıyla 180, 60, 60 ve 20 bireyden oluşur; toplam yine 320'dir."}],"ans":"Dört fenotip grubu sırasıyla 180, 60, 60 ve 20 bireydir (çift baskın 180, tek baskınlar 60'ar, çift çekinik 20)."},{"q":"AaBb × AaBb çaprazlamasında en az bir karakterde çekinik fenotip gösteren bireylerin oranını hesaplayınız.","steps":[{"t":"Tümleyenle düşün","a":"1 − P(ikisi de baskın)","d":"En az bir çekinik olma olasılığı, hiç çekinik olmama (her ikisi de baskın) olasılığının <b>tümleyenidir</b>."},{"t":"İkisi de baskın","a":"3/4 × 3/4 = 9/16","d":"Her iki karakterde de baskın fenotip olasılığı 9/16'dır."},{"t":"Tümleyeni al","a":"1 − 9/16 = 7/16","d":"En az bir karakterde çekinik gösterme olasılığı 16/16 − 9/16 = 7/16'dır."}],"ans":"En az bir karakterde çekinik fenotip gösteren bireylerin oranı 7/16'dır."},{"q":"AaBb × Aabb çaprazlamasında oğul döldeki fenotip oranını olasılık çarpımıyla bulunuz.","steps":[{"t":"Birinci karakter","a":"Aa × Aa → 3:1","d":"İlk karakterde Aa × Aa olduğundan baskın : çekinik oranı <b>3/4 : 1/4</b>'tür."},{"t":"İkinci karakter","a":"Bb × bb → 1:1","d":"İkinci karakterde Bb × bb olduğundan baskın : çekinik oranı 1/2 : 1/2'dir."},{"t":"Oranları birleştir","a":"(3:1)·(1:1)","d":"İki oran çarpılınca 3·1 : 3·1 : 1·1 : 1·1 = 3:3:1:1 fenotip oranı elde edilir."}],"ans":"AaBb × Aabb çaprazlamasının fenotip oranı 3:3:1:1'dir."},{"q":"AaBb genotipli bir bireyin 4 çeşit gamet oluşturmasını mayozdaki bağımsız dağılımla açıklayınız.","steps":[{"t":"Homologların dizilişi","a":"İki olası dizilim","d":"Mayoz I'de A/a ve B/b'yi taşıyan homolog çiftler ekvatorda <b>iki farklı</b> şekilde dizilebilir."},{"t":"Dizilimlerin gametleri","a":"AB,ab veya Ab,aB","d":"Bir dizilim AB ve ab gametlerini, diğer dizilim Ab ve aB gametlerini verir."},{"t":"Toplam çeşit","a":"4 çeşit","d":"İki dizilim eşit olasılıkla görüldüğünden toplamda AB, Ab, aB, ab olmak üzere 4 çeşit gamet eşit oranda oluşur."}],"ans":"Mayoz I'de homolog çiftlerin iki farklı bağımsız dizilimi, AB, Ab, aB ve ab olmak üzere 4 çeşit gametin eşit oranda oluşmasını sağlar."},{"q":"Bir dihibrit çaprazlamada oğul dölün 3/16'sı yeşil-buruşuk dışında tek çekinikli çıkıyor diye düşünülüyor. AaBb × AaBb için tek karakterde çekinik (A_bb veya aaB_) oranlarını ayrı ayrı bulunuz.","steps":[{"t":"A_bb grubu","a":"3/4 × 1/4","d":"Birinci karakterde baskın (3/4), ikincide çekinik (1/4) olma olasılığı çarpılır: <b>3/16</b>."},{"t":"aaB_ grubu","a":"1/4 × 3/4","d":"Birinci karakterde çekinik (1/4), ikincide baskın (3/4) olma olasılığı çarpılır: 3/16."},{"t":"Karşılaştır","a":"İkisi de 3/16","d":"Her iki tek çekinikli grup da 3/16 oranındadır; toplam tek çekinikli oran 3/16 + 3/16 = 6/16'dır."}],"ans":"A_bb ve aaB_ gruplarının her biri 3/16 oranındadır; tek karakterde çekinik gösteren toplam oran 6/16'dır."},{"q":"AaBb × aabb (kontrol çaprazlaması) yapıldığında oğul döldeki fenotip oranını bulunuz ve neden gamet çeşitlerini doğrudan yansıttığını açıklayınız.","steps":[{"t":"aabb'nin gameti","a":"Tek çeşit: ab","d":"aabb bireyi yalnızca <b>ab</b> gameti verir; bu çekinik gamet baskın aleli maskelemez."},{"t":"AaBb'nin gametleri","a":"AB, Ab, aB, ab","d":"AaBb bireyi 4 çeşit gamet verir; her biri ab ile birleşince doğrudan kendi fenotipini gösterir."},{"t":"Oranı yaz","a":"1:1:1:1","d":"Dört gamet eşit oranda olduğundan oğul dölde dört fenotip 1:1:1:1 oranında çıkar."}],"ans":"AaBb × aabb çaprazlamasının fenotip oranı 1:1:1:1'dir; çekinik birey tek çeşit (ab) gamet verdiğinden oğul döl, AaBb bireyinin gamet çeşitlerini doğrudan yansıtır."},{"q":"Bir dihibrit (AaBb × AaBb) çaprazlamasında 16'lık Punnett karesinde AABB genotipinin neden sadece 1 kutuda çıktığını gösteriniz.","steps":[{"t":"Gerekli gametler","a":"AB ve AB","d":"AABB oluşması için her iki ebeveynden de <b>AB</b> gametinin gelmesi gerekir."},{"t":"Olasılığı hesapla","a":"1/4 × 1/4 = 1/16","d":"Her ebeveynde AB gameti olasılığı 4 gametten biri olduğu için 1/4'tür; ikisi çarpılınca 1/16 olur."},{"t":"Kutu sayısı","a":"1 kutu","d":"16 kutuluk karede 1/16 olasılık, tam olarak 1 kutuya karşılık gelir."}],"ans":"AABB yalnızca AB × AB birleşmesiyle oluşur; olasılığı 1/4 × 1/4 = 1/16 olduğundan 16'lık karede sadece 1 kutuda görülür."},{"q":"AaBb × AaBb çaprazlamasında 9 çift baskın bireyin genotip dağılımını (AABB, AABb, AaBB, AaBb) olasılıklarıyla gösteriniz.","steps":[{"t":"Birinci karakter genotipleri","a":"AA: 1/4, Aa: 2/4","d":"Aa × Aa'dan baskın fenotipliler AA (1/4) ve <b>Aa</b> (2/4) genotiplidir."},{"t":"İkinci karakterle çarp","a":"BB:1/4, Bb:2/4","d":"Aynı şekilde Bb × Bb'den BB (1/4) ve Bb (2/4) çıkar; genotipler çarpılır."},{"t":"Dört genotip","a":"1:2:2:4","d":"AABB = 1/4·1/4 = 1/16, AABb = 1/4·2/4 = 2/16, AaBB = 2/4·1/4 = 2/16, AaBb = 2/4·2/4 = 4/16; toplam 9/16."}],"ans":"9'luk çift baskın grup AABB:AABb:AaBB:AaBb = 1:2:2:4 oranındadır; payları 1/16, 2/16, 2/16 ve 4/16 olup toplamı 9/16'dır."},{"q":"Trihibrit AaBbCc bireyiyle karşılaştırarak, dihibrit AaBb bireyinin gamet çeşidi sayısının 2ⁿ formülüyle nasıl bulunduğunu açıklayınız.","steps":[{"t":"Formülün mantığı","a":"Her heterozigotta 2 seçenek","d":"Heterozigot her karakter gamete 2 farklı alelden birini verebildiğinden çeşit sayısı <b>2ⁿ</b> ile bulunur (n = heterozigot karakter sayısı)."},{"t":"Dihibrit hesabı","a":"2² = 4","d":"AaBb'de n = 2 olduğundan 2² = 4 çeşit gamet (AB, Ab, aB, ab) oluşur."},{"t":"Trihibritle karşılaştır","a":"2³ = 8","d":"AaBbCc'de n = 3 olduğundan 2³ = 8 çeşit gamet oluşur; her ek heterozigot karakter çeşit sayısını ikiye katlar."}],"ans":"Gamet çeşidi 2ⁿ ile bulunur; dihibrit AaBb için 2² = 4, trihibrit AaBbCc için 2³ = 8 çeşit gamet oluşur."},{"q":"AaBb × AaBb çaprazlamasında oğul dölün hem A hem B bakımından homozigot (AABB, AAbb, aaBB, aabb) olma olasılığını toplam olarak bulunuz.","steps":[{"t":"Bir karakterde homozigot","a":"AA veya aa: 1/2","d":"Aa × Aa'da AA (1/4) ve aa (1/4) toplamı homozigot olma olasılığı <b>1/2</b>'dir."},{"t":"İki karakter için","a":"1/2 × 1/2","d":"İki karakter bağımsız olduğundan her ikisinde de homozigot olma olasılığı 1/2 × 1/2 ile bulunur."},{"t":"Sonucu hesapla","a":"1/4","d":"1/2 × 1/2 = 1/4; yani oğul dölün 4'te 1'i her iki karakterde de homozigottur."}],"ans":"Oğul dölün her iki karakterde de homozigot (AABB, AAbb, aaBB veya aabb) olma olasılığı 1/4'tür."},{"q":"İki karakteri bağlı (aynı kromozomda) olan bir bireyin neden 9:3:3:1 oranı vermeyebileceğini bağımsız dağılım ilkesiyle ilişkilendirerek açıklayınız.","steps":[{"t":"9:3:3:1 şartı","a":"Bağımsız dağılım","d":"Klasik 9:3:3:1 oranı, iki karakterin <b>farklı kromozomlarda</b> bulunup bağımsız dağılmasına dayanır."},{"t":"Bağlı genler","a":"Birlikte kalıtım","d":"Genler aynı kromozomdaysa (bağlı), gametlere genellikle birlikte aktarılır ve bağımsız dağılım gerçekleşmez."},{"t":"Sonuç","a":"Oran sapar","d":"Bu yüzden ata genotip kombinasyonları beklenenden fazla, yeni kombinasyonlar (krossing-over ile) az çıkar; fenotip oranı 9:3:3:1'den sapar."}],"ans":"9:3:3:1 oranı bağımsız dağılıma dayanır; karakterler aynı kromozomda bağlıysa birlikte kalıtıldıklarından bağımsız dağılım bozulur ve fenotip oranı 9:3:3:1'den sapar."},{"q":"Bir dihibrit çaprazlamadan elde edilen 800 tohumda çift baskın fenotipli 460 birey sayıldı. Bu sonucun beklenen 9/16 oranına ne kadar uyduğunu hesaplayarak yorumlayınız.","steps":[{"t":"Beklenen sayı","a":"800 × 9/16 = 450","d":"Beklenen çift baskın birey sayısı 800'ün <b>9/16</b>'sıdır: 800 ÷ 16 = 50, 50 × 9 = 450."},{"t":"Gözlemle karşılaştır","a":"460 ≈ 450","d":"Gözlenen 460 birey, beklenen 450'ye çok yakındır; aradaki fark yalnızca 10 bireydir."},{"t":"Yorumla","a":"Orana uyumlu","d":"Küçük sapma rastgele örnekleme dalgalanmasıyla açıklanabilir; sonuç 9/16 beklentisiyle uyumludur."}],"ans":"Beklenen çift baskın sayı 450'dir; gözlenen 460 buna çok yakın olduğundan sonuç, küçük rastgele sapmayla 9/16 oranına uyumludur."},{"q":"AaBb × AaBb çaprazlamasında oğul dölün AaBb genotipli olma olasılığının neden 4/16 (en yüksek tek genotip) olduğunu açıklayınız.","steps":[{"t":"Birinci karakter","a":"Aa olasılığı 2/4","d":"Aa × Aa çaprazlamasında Aa genotipi iki kutuda çıktığından olasılığı <b>2/4</b>'tür."},{"t":"İkinci karakter","a":"Bb olasılığı 2/4","d":"Aynı şekilde Bb × Bb'den Bb genotipi olasılığı da 2/4'tür."},{"t":"İkisini çarp","a":"2/4 × 2/4 = 4/16","d":"İki bağımsız olasılık çarpılınca AaBb olma olasılığı 4/16 olur; her iki karakterde de heterozigotluk en olası durum olduğundan bu tek genotipler içinde en yüksektir."}],"ans":"Her karakterde heterozigot (Aa, Bb) olma olasılığı 2/4 olduğundan AaBb genotipi 2/4 × 2/4 = 4/16 ile tek genotipler arasında en yüksek olasılığa sahiptir."},{"q":"AaBb × AaBb çaprazlamasında bir tohumun sarı (A baskın) VE yüzeyinin çekinik (bb buruşuk) olma olasılığını, ardından kardeşinin de aynı fenotipte olma olasılığını hesaplayınız.","steps":[{"t":"Tek tohumun olasılığı","a":"3/4 × 1/4 = 3/16","d":"Sarı (baskın) olasılığı 3/4, buruşuk (çekinik) olasılığı 1/4'tür; bağımsız olduklarından çarpılır: <b>3/16</b>."},{"t":"İki bağımsız tohum","a":"Olasılıkları çarp","d":"İki ayrı tohumun fenotipi birbirinden bağımsız olduğundan, ikisinin de sarı-buruşuk olma olasılığı tek tek olasılıkların çarpımıdır."},{"t":"Sonucu hesapla","a":"3/16 × 3/16 = 9/256","d":"3/16 × 3/16 = 9/256; yani her iki tohumun da sarı-buruşuk olma olasılığı 9/256'dır."}],"ans":"Bir tohumun sarı-buruşuk olma olasılığı 3/16'dır; iki bağımsız tohumun ikisinin de bu fenotipte olma olasılığı 3/16 × 3/16 = 9/256'dır."}]}},"eksikBaskinlik":{"ilkokul":{"kolay":[{"q":"Kırmızı çiçekli bir bitki ile beyaz çiçekli bir bitki birleşince yavru pembe oluyor. Bu nasıl olur?","steps":[{"t":"İki rengi düşün","a":"kırmızı + beyaz","d":"Anne bitki kırmızı, baba bitki beyaz çiçek rengi taşır."},{"t":"Renkler karışır","a":"pembe","d":"İki renk birbirine karışınca arada bir renk olan pembe ortaya çıkar."}],"ans":"Kırmızı ile beyaz renk karışınca yavru bitki, ikisinin arasındaki renk olan <b>pembe</b> olur."},{"q":"Pembe çiçek, anne ve babasından hangi renkleri almıştır?","steps":[{"t":"Anneye bak","a":"bir renk","d":"Anne bitki örneğin kırmızı çiçek rengini verir."},{"t":"Babaya bak","a":"öbür renk","d":"Baba bitki beyaz çiçek rengini verir."}],"ans":"Pembe çiçek, anne ve babasından gelen <b>kırmızı ile beyaz</b> renklerin karışmasıyla oluşmuştur."},{"q":"İki çiçek karışınca neden bazen tam ortada bir renk çıkar?","steps":[{"t":"Renkler eşit güçte","a":"hiçbiri kazanmaz","d":"Bazı bitkilerde iki renk de aynı güçtedir, biri öbürünü yenemez."},{"t":"Sonuç","a":"ara renk","d":"İkisi yarı yarıya karışınca arada yeni bir renk görünür."}],"ans":"İki renk de aynı güçte olduğu için biri öbürünü yenemez ve <b>tam ortada</b> yeni bir renk oluşur."},{"q":"Akşamsefası çiçeğinde kırmızı ile beyaz birleşince hangi renk olur?","steps":[{"t":"Anne-baba rengi","a":"kırmızı, beyaz","d":"Bir çiçek kırmızı, öbürü beyazdır."},{"t":"Yavrunun rengi","a":"pembe","d":"Akşamsefasında bu iki renk karışınca yavru pembe açar."}],"ans":"Akşamsefasında kırmızı ile beyaz çiçek birleşince yavru <b>pembe</b> renkte olur."},{"q":"Pembe çiçekli bir bitki anne-babasının hangisine benzer?","steps":[{"t":"Anne-babaya bak","a":"biri kırmızı biri beyaz","d":"Anne kırmızı, baba beyazdır; renkleri farklıdır."},{"t":"Yavruya bak","a":"ikisine de tam benzemez","d":"Pembe çiçek ne tam kırmızı ne tam beyazdır, ikisinin arasındadır."}],"ans":"Pembe çiçek anne ya da babanın birine tam benzemez; <b>ikisinin arasındaki</b> yeni bir renktedir."}],"zor":[{"q":"Kırmızı ve beyaz çiçek karışınca pembe oluyorsa, renklerin gücü hakkında ne söyleyebiliriz?","steps":[{"t":"Renkleri karşılaştır","a":"kırmızı ve beyaz eşit","d":"Renklerden biri diğerini örtmüyor, ikisi de etkisini gösteriyor."},{"t":"Sonucu yorumla","a":"ikisi de görünüyor","d":"İkisi de eşit güçte olduğu için karışım rengi pembe çıkıyor."}],"ans":"Renkler eşit güçte olduğu için biri öbürünü örtemez; bu yüzden karışım rengi olan <b>pembe</b> ortaya çıkar."},{"q":"İki pembe çiçek birleşse yavrularında hangi renkler görülebilir?","steps":[{"t":"Pembelerin içini düşün","a":"hem kırmızı hem beyaz","d":"Her pembe çiçek içinde hem kırmızı hem beyaz rengi taşır."},{"t":"Yavruları düşün","a":"kırmızı, pembe, beyaz","d":"Bu renkler farklı karışınca kırmızı, pembe ve beyaz yavrular olabilir."}],"ans":"İki pembe çiçekten <b>kırmızı, pembe ve beyaz</b> renkte yavrular oluşabilir."},{"q":"Bir bahçede sadece pembe çiçek isteyen biri hangi iki rengi birleştirmelidir?","steps":[{"t":"Hangi renkler gerekli","a":"kırmızı + beyaz","d":"Pembe için bir kırmızı bir de beyaz çiçek gerekir."},{"t":"Neden","a":"karışım pembe verir","d":"Bu iki renk birleşince yavruların hepsi pembe olur."}],"ans":"Hep pembe çiçek için saf <b>kırmızı</b> ile saf <b>beyaz</b> çiçekler birleştirilmelidir."},{"q":"Pembe çiçek neden 'karışım renk' olarak adlandırılabilir?","steps":[{"t":"İçindeki renkler","a":"kırmızı ve beyaz","d":"Pembe, içinde hem kırmızı hem beyaz taşır."},{"t":"Görünüşü","a":"ortada bir renk","d":"İki renk eşit etki gösterince arada pembe görünür."}],"ans":"Pembe, kırmızı ile beyazın eşit karışmasıyla oluştuğu için bir <b>karışım renk</b>tir."},{"q":"Bir çiçek bahçesinde kırmızı, beyaz ve pembe çiçekler var. Pembelerin nasıl oluştuğunu açıkla.","steps":[{"t":"Saf renkler","a":"kırmızı, beyaz","d":"Saf kırmızı ve saf beyaz çiçekler ayrı ayrı bulunur."},{"t":"Karışım","a":"pembe","d":"Kırmızı ile beyazın birleşmesinden ara renk olan pembe oluşur."}],"ans":"Pembe çiçekler, bahçedeki <b>kırmızı ile beyaz</b> çiçeklerin birleşmesinden oluşan ara renktir."}]},"ortaokul":{"kolay":[{"q":"Eksik baskınlık (yarı baskınlık) nedir? Kısaca açıklayınız.","steps":[{"t":"Genleri düşün","a":"ikisi de etkili","d":"İki farklı alel bir arada bulunduğunda biri diğerini tam örtemez."},{"t":"Sonucu düşün","a":"ara özellik","d":"İkisinin etkisi karışır ve arada yeni bir özellik ortaya çıkar."}],"ans":"Eksik baskınlık, iki alelden hiçbirinin diğerine tam baskın olamadığı, melez bireyde <b>ara özellik</b> görüldüğü durumdur."},{"q":"Kırmızı (KK) ve beyaz (BB) çiçekli akşamsefaları çaprazlanırsa melez (KB) bireyin rengi ne olur?","steps":[{"t":"Aleller birleşir","a":"K ve B birlikte","d":"Melez birey hem kırmızı hem beyaz aleli taşır."},{"t":"Etki ara olur","a":"pembe","d":"Hiçbir alel diğerini örtmediği için renk ortada, yani pembe olur."}],"ans":"Melez birey (KB) ne kırmızı ne beyaz olur; ara renk olan <b>pembe</b> çiçek açar."},{"q":"Eksik baskınlıkta melez bireyin görünüşü neden ata bireylerden farklıdır?","steps":[{"t":"Aleller eşit","a":"tam baskınlık yok","d":"İki alel de etkisini gösterir, biri diğerini bastıramaz."},{"t":"Ortaya çıkan özellik","a":"ara fenotip","d":"İki etkinin karışımı, atalardan farklı yeni bir görünüş verir."}],"ans":"Hiçbir alel diğerine baskın olamadığı için melez birey, ata bireylerden farklı bir <b>ara görünüşe</b> sahiptir."},{"q":"Tam baskınlık ile eksik baskınlık arasındaki temel fark nedir?","steps":[{"t":"Tam baskınlık","a":"biri örter","d":"Tam baskınlıkta baskın alel çekinik aleli tamamen örter."},{"t":"Eksik baskınlık","a":"ara özellik","d":"Eksik baskınlıkta hiçbir alel örtmez, melezde ara özellik çıkar."}],"ans":"Tam baskınlıkta baskın alel diğerini örter; eksik baskınlıkta ise melezde <b>ara özellik</b> görülür."},{"q":"Pembe çiçekli bir akşamsefasının genotipinde hangi aleller bulunur?","steps":[{"t":"Renkleri eşle","a":"kırmızı ve beyaz","d":"Pembe renk, kırmızı ve beyaz alellerin birlikte bulunmasından gelir."},{"t":"Genotipi yaz","a":"melez (KB)","d":"Bu nedenle pembe birey iki farklı alel taşıyan melezdir."}],"ans":"Pembe çiçek <b>melez</b> bir bireydir; genotipinde bir kırmızı (K) ve bir beyaz (B) alel bulunur."}],"zor":[{"q":"Pembe (KB) × pembe (KB) çaprazlamasında oğul bireylerin fenotip oranı ne olur?","steps":[{"t":"Çaprazlamayı kur","a":"KB × KB","d":"Her iki ebeveyn de bir kırmızı bir beyaz alel taşır."},{"t":"Genotipleri çıkar","a":"KK, KB, KB, BB","d":"Karenin sonuçları 1 KK, 2 KB ve 1 BB olur."},{"t":"Fenotipe çevir","a":"1 kırmızı, 2 pembe, 1 beyaz","d":"Ara fenotip nedeniyle her genotip ayrı renk verir."}],"ans":"Pembe × pembe çaprazında oğul döl fenotip oranı <b>1 kırmızı : 2 pembe : 1 beyaz</b> olur."},{"q":"Eksik baskınlıkta neden fenotip oranı ile genotip oranı birbirine eşittir?","steps":[{"t":"Genotipleri yaz","a":"1 KK : 2 KB : 1 BB","d":"Melez çaprazında üç farklı genotip 1:2:1 oranında oluşur."},{"t":"Fenotipe bak","a":"her genotip ayrı görünüm","d":"Her genotip kendine özgü bir renk (kırmızı, pembe, beyaz) verir."},{"t":"Karşılaştır","a":"oranlar aynı","d":"Genotip ile fenotip birebir karşılık geldiği için oranlar eşittir."}],"ans":"Her genotipin ayrı bir fenotipi olduğu için genotip oranı (1:2:1) ile fenotip oranı (1:2:1) <b>birbirine eşittir</b>."},{"q":"Aslanağzı bitkisinde kırmızı ve beyaz çiçekler çaprazlanınca F1 hepsi pembe oluyor. Bu hangi kalıtım türüdür ve neden?","steps":[{"t":"F1'i incele","a":"hepsi pembe","d":"Melez bireyler ne kırmızı ne beyaz, ara renkte çıkıyor."},{"t":"Nedenini bul","a":"alel örtemiyor","d":"Hiçbir alel diğerini örtmediği için ara fenotip oluşuyor."}],"ans":"Bu <b>eksik baskınlık</b>tır; çünkü hiçbir alel diğerine baskın olamayıp melezde ara renk (pembe) ortaya çıkar."},{"q":"Tam baskınlıkta melez çaprazı 3:1 fenotip verirken, eksik baskınlıkta neden 1:2:1 verir?","steps":[{"t":"Tam baskınlık","a":"melez = baskın görünür","d":"KK ve Kk aynı görünür, bu yüzden 3 baskın : 1 çekinik olur."},{"t":"Eksik baskınlık","a":"melez ayrı görünür","d":"KB ara fenotip verdiği için ayrı sayılır, genotiple aynı orana düşer."}],"ans":"Tam baskınlıkta melez baskınla aynı göründüğü için 3:1; eksik baskınlıkta melez ayrı (ara) göründüğü için <b>1:2:1</b> fenotip oranı oluşur."},{"q":"Bir bahçede pembe akşamsefaları kendi aralarında üretilirse, oğul döllerin hepsi neden pembe olmaz?","steps":[{"t":"Pembelerin genotipi","a":"melez (KB)","d":"Her pembe birey bir kırmızı bir beyaz alel taşır."},{"t":"Çaprazı düşün","a":"KB × KB","d":"Melez × melez çaprazında aleller farklı şekillerde eşleşebilir."},{"t":"Sonucu çıkar","a":"kırmızı, pembe, beyaz","d":"KK ve BB birleşimleri saf renkleri yeniden ortaya çıkarır."}],"ans":"Pembeler melez (KB) olduğu için döllerinde KK ve BB de oluşabilir; bu yüzden <b>kırmızı ve beyaz</b> bireyler de ortaya çıkar, hepsi pembe olmaz."}]},"lise":{"kolay":[{"q":"Eksik baskınlık kavramını moleküler/fenotipik düzeyde tanımlayınız.","steps":[{"t":"Alel ilişkisi","a":"baskınlık yok","d":"Bir alel diğerini fenotipte tam olarak maskeleyemez."},{"t":"Heterozigot görünüm","a":"ara fenotip","d":"Heterozigot birey, iki homozigot atanın arasında bir özellik gösterir."}],"ans":"Eksik baskınlık, alellerden hiçbirinin diğerine tam baskın olamadığı ve heterozigotta <b>ara fenotip</b> oluşan kalıtım biçimidir."},{"q":"Eksik baskınlıkta heterozigotta ara fenotip oluşmasının biyokimyasal nedeni nedir?","steps":[{"t":"Gen ürünü","a":"enzim/pigment miktarı","d":"Baskın alel belirli miktarda pigment ya da enzim üretir."},{"t":"Tek alel etkisi","a":"yetersiz ürün","d":"Heterozigotta tek işlevsel alel olduğu için ürün miktarı yarıya iner."}],"ans":"Heterozigotta tek işlevsel alel bulunduğundan gen ürünü (örneğin pigment) yarı düzeyde kalır ve bu nedenle <b>ara fenotip</b> oluşur."},{"q":"Aslanağzında kırmızı (R₁R₁) × beyaz (R₂R₂) çaprazında F1 fenotipi ne olur?","steps":[{"t":"F1 genotipi","a":"R₁R₂","d":"Tüm F1 bireyleri bir kırmızı bir beyaz alel taşır."},{"t":"Fenotip","a":"pembe","d":"Hiçbir alel baskın olmadığı için F1 ara renk olan pembe açar."}],"ans":"F1 bireylerinin tümü heterozigot (R₁R₂) ve fenotipçe <b>pembe</b> olur."},{"q":"Eksik baskınlıkta F2 dölünde beklenen fenotip oranını yazınız.","steps":[{"t":"F1 çaprazı","a":"R₁R₂ × R₁R₂","d":"Pembe melezler kendi aralarında çaprazlanır."},{"t":"Oran","a":"1:2:1","d":"Üç genotipin her biri farklı fenotip verdiği için oran 1:2:1 olur."}],"ans":"F2'de beklenen fenotip oranı <b>1 kırmızı : 2 pembe : 1 beyaz</b> şeklindedir."},{"q":"Eksik baskınlıkta neden fenotip oranı ve genotip oranı aynıdır?","steps":[{"t":"Genotip oranı","a":"1:2:1","d":"Heterozigot çaprazda genotipler 1 homozigot : 2 heterozigot : 1 homozigot oluşur."},{"t":"Fenotip karşılığı","a":"her genotip ayrı","d":"Her genotip ayrı bir görünüm verdiği için fenotip de 1:2:1 olur."}],"ans":"Her genotip ayrı bir fenotipe karşılık geldiğinden, hem genotip hem fenotip oranı <b>1:2:1</b> olur."},{"q":"Eksik baskınlık ile tam baskınlığın F2 fenotip oranlarını karşılaştırınız.","steps":[{"t":"Tam baskınlık","a":"3:1","d":"Heterozigot baskınla aynı göründüğü için baskın:çekinik 3:1 olur."},{"t":"Eksik baskınlık","a":"1:2:1","d":"Heterozigot ara fenotip verdiği için ayrı sayılır."}],"ans":"Tam baskınlıkta F2 oranı 3:1 iken eksik baskınlıkta heterozigot ayrı göründüğü için <b>1:2:1</b>'dir."},{"q":"Bir bireyin pembe çiçekli (heterozigot) olduğunu fenotipinden anlayabilir miyiz? Açıklayınız.","steps":[{"t":"Fenotip-genotip ilişkisi","a":"birebir","d":"Eksik baskınlıkta her fenotip tek bir genotipe karşılık gelir."},{"t":"Pembe → heterozigot","a":"R₁R₂","d":"Pembe rengi yalnızca heterozigot genotip verir."}],"ans":"Evet; eksik baskınlıkta fenotip genotipi birebir yansıttığı için pembe birey kesinlikle <b>heterozigottur</b>."},{"q":"Eksik baskınlıkta saf döl (homozigot) bireylerin fenotipi nasıldır?","steps":[{"t":"Homozigot tipler","a":"R₁R₁ ve R₂R₂","d":"İki saf döl genotipi bulunur."},{"t":"Fenotipleri","a":"kırmızı ve beyaz","d":"R₁R₁ kırmızı, R₂R₂ beyaz açar; ara renk vermez."}],"ans":"Homozigot bireyler ara renk değil, saf ana renkleri (<b>kırmızı veya beyaz</b>) gösterir."},{"q":"Eksik baskınlıkta alelleri büyük/küçük harf yerine R₁, R₂ gibi yazmanın nedeni nedir?","steps":[{"t":"Baskınlık durumu","a":"baskınlık yok","d":"Hiçbir alel baskın olmadığı için büyük/küçük harf ayrımı anlamsız olur."},{"t":"Gösterim","a":"eşit statü","d":"Aynı harfin alt indisli (R₁, R₂) yazımı alellerin eşit etkisini vurgular."}],"ans":"Aleller eşit etkili olduğundan baskınlık belirten büyük/küçük harf yerine eşit statüyü gösteren <b>R₁, R₂</b> yazımı kullanılır."},{"q":"Pembe × beyaz çaprazından elde edilen döllerin fenotip oranı ne olur?","steps":[{"t":"Çaprazı kur","a":"R₁R₂ × R₂R₂","d":"Pembe melez, beyaz saf dölle çaprazlanır."},{"t":"Sonucu çıkar","a":"R₁R₂ ve R₂R₂","d":"Döllerin yarısı heterozigot, yarısı homozigot beyaz olur."}],"ans":"Pembe × beyaz çaprazında döller <b>1 pembe : 1 beyaz</b> oranında oluşur."},{"q":"Eksik baskınlıkta heterozigotun fenotipi neden iki atanın tam ortasında olur?","steps":[{"t":"Pigment miktarı","a":"yarı doz","d":"Heterozigotta tek kırmızı alel bulunduğu için pigment yarı düzeydedir."},{"t":"Görünüme etkisi","a":"orta yoğunluk","d":"Yarı pigment, kırmızı ile beyaz arasında pembe tonunu verir."}],"ans":"Tek işlevsel alel yarı doz pigment ürettiği için heterozigot, iki atanın <b>tam ortasında</b> bir fenotip (pembe) gösterir."},{"q":"Bir bitkide F1'in tümü ata bireylerden farklı ara fenotip gösteriyorsa hangi kalıtım türü akla gelir?","steps":[{"t":"F1 gözlemi","a":"ara fenotip","d":"Melez bireyler iki atadan da farklı, ortada bir özellik gösterir."},{"t":"Sonuç","a":"eksik baskınlık","d":"Bu durum baskınlığın olmadığını, eksik baskınlığı işaret eder."}],"ans":"F1'in tümü ata bireylerden farklı ara fenotip gösteriyorsa bu <b>eksik baskınlık</b>tır."},{"q":"Eksik baskınlıkta Mendel'in ayrılma ilkesi geçerli midir? Açıklayınız.","steps":[{"t":"Alellerin ayrılması","a":"hâlâ geçerli","d":"Gametlere alellerin ayrı ayrı geçmesi kuralı değişmez."},{"t":"Farklılık","a":"fenotipik ifade","d":"Yalnızca alellerin fenotipe yansıma biçimi (ara fenotip) farklıdır."}],"ans":"Evet, ayrılma ilkesi geçerlidir; sadece alellerin <b>fenotipe yansıma biçimi</b> (ara fenotip) tam baskınlıktan farklıdır."},{"q":"İnsanda orak hücreli aneminin taşıyıcılığı eksik baskınlığa örnek olarak nasıl açıklanır?","steps":[{"t":"Genotipler","a":"sağlam, taşıyıcı, hasta","d":"Üç farklı genotip; sağlıklı, taşıyıcı ve hastalıklı bireyler vardır."},{"t":"Taşıyıcının durumu","a":"ara özellik","d":"Taşıyıcıda hem normal hem orak hücreler bulunur, ara bir durumdur."}],"ans":"Taşıyıcı bireyde hem normal hem orak hücreler bulunması, sağlıklı ile hasta arasında <b>ara fenotip</b> oluşturduğu için eksik baskınlık örneğidir."},{"q":"Eksik baskınlıkta bir popülasyonda fenotip çeşitliliği tam baskınlığa göre neden daha fazladır?","steps":[{"t":"Tam baskınlık","a":"2 fenotip","d":"Tam baskınlıkta yalnızca baskın ve çekinik iki fenotip görülür."},{"t":"Eksik baskınlık","a":"3 fenotip","d":"Eksik baskınlıkta homozigotlar ve heterozigot ayrı, üç fenotip oluşur."}],"ans":"Heterozigot ayrı bir ara fenotip oluşturduğundan, eksik baskınlıkta iki yerine <b>üç farklı fenotip</b> görülür ve çeşitlilik artar."}],"zor":[{"q":"Kırmızı (R₁R₁) × beyaz (R₂R₂) aslanağzı çaprazında F1 ve F2'nin genotip ve fenotip oranlarını adım adım çıkarınız.","steps":[{"t":"F1 oluşumu","a":"tümü R₁R₂ pembe","d":"Saf ataların çaprazından tüm F1 heterozigot ve pembedir."},{"t":"F2 genotipleri","a":"1 R₁R₁ : 2 R₁R₂ : 1 R₂R₂","d":"Pembe × pembe çaprazında genotipler 1:2:1 oranında dağılır."},{"t":"F2 fenotipleri","a":"1 kırmızı : 2 pembe : 1 beyaz","d":"Her genotip ayrı renk verdiği için fenotip oranı da 1:2:1 olur."}],"ans":"F1 tümü pembe (R₁R₂); F2'de hem genotip hem fenotip oranı <b>1 kırmızı : 2 pembe : 1 beyaz</b> olur."},{"q":"Eksik baskınlıkta F2'de pembe çiçek oranı neden 1/2 iken tam baskınlıkta baskın fenotip 3/4'tür? Açıklayınız.","steps":[{"t":"Heterozigot oranı","a":"2/4 = 1/2","d":"Melez çaprazında heterozigot oranı her zaman 1/2'dir."},{"t":"Eksik baskınlık","a":"pembe = heterozigot","d":"Pembe yalnızca heterozigotlar olduğu için oranı 1/2'dir."},{"t":"Tam baskınlık","a":"baskın = KK + Kk","d":"Tam baskınlıkta hem homozigot hem heterozigot baskın görünür, 3/4 olur."}],"ans":"Pembe yalnızca heterozigotları (1/2) kapsarken, tam baskınlıkta baskın fenotip homozigot ve heterozigotu birlikte (3/4) içerir; bu yüzden oranlar farklıdır."},{"q":"512 adet F2 aslanağzı bireyinde kaç adet pembe, kaç adet kırmızı çiçek beklenir?","steps":[{"t":"Oranı belirle","a":"1:2:1","d":"F2 fenotip oranı 1 kırmızı : 2 pembe : 1 beyazdır, toplam 4 pay."},{"t":"Bir payı hesapla","a":"512 ÷ 4 = 128","d":"Toplam 512 birey 4 paya bölündüğünde her pay 128 olur."},{"t":"Renkleri bul","a":"pembe 256, kırmızı 128","d":"Pembe 2 pay (256), kırmızı 1 pay (128) bireye karşılık gelir."}],"ans":"512 bireyde yaklaşık <b>256 pembe</b> ve <b>128 kırmızı</b> çiçek beklenir (beyaz da 128'dir)."},{"q":"Eksik baskınlıkta heterozigotun ara fenotip göstermesini gen-doz (dozaj) etkisiyle açıklayınız.","steps":[{"t":"Homozigot baskın","a":"çift doz pigment","d":"R₁R₁ bireyde iki işlevsel alel tam miktarda pigment üretir."},{"t":"Heterozigot","a":"tek doz pigment","d":"R₁R₂ bireyde tek işlevsel alel yarı miktarda pigment yapar."},{"t":"Sonuç","a":"ara yoğunluk","d":"Yarı pigment, kırmızı ile beyaz arasında pembe tonunu doğurur."}],"ans":"Pigment miktarı alel sayısıyla orantılı olduğundan, tek işlevsel alel taşıyan heterozigot yarı doz pigmentle <b>ara fenotip</b> (pembe) gösterir; bu gen-doz etkisidir."},{"q":"Bir çaprazlamada döller 1 kırmızı : 2 pembe : 1 beyaz çıktıysa ana-baba genotipleri ne olmalıdır?","steps":[{"t":"Oranı yorumla","a":"melez × melez","d":"1:2:1 oranı yalnızca iki heterozigotun çaprazında oluşur."},{"t":"Genotipleri yaz","a":"R₁R₂ × R₁R₂","d":"Her iki ebeveyn de bir kırmızı bir beyaz alel taşımalıdır."}],"ans":"1:2:1 oranını veren çaprazlamada her iki ebeveyn de pembe heterozigot, yani <b>R₁R₂ × R₁R₂</b> olmalıdır."},{"q":"Eksik baskınlık ile eş baskınlığın (kodominantlık) heterozigot fenotip açısından farkını açıklayınız.","steps":[{"t":"Eksik baskınlık","a":"karışım/ara","d":"İki alelin etkisi karışır, ortada tek yeni fenotip (pembe) çıkar."},{"t":"Eş baskınlık","a":"ikisi de ayrı görünür","d":"Eş baskınlıkta her iki alel de aynı anda ayrı ayrı belirir (örn. AB kan grubu)."},{"t":"Karşılaştırma","a":"karışım vs birlikte","d":"Eksikte özellikler harmanlanır, eş baskınlıkta yan yana ikisi de görülür."}],"ans":"Eksik baskınlıkta iki etki karışıp tek bir ara fenotip oluşur; eş baskınlıkta ise her iki alel <b>ayrı ayrı ve birlikte</b> görünür (karışmaz)."},{"q":"Pembe çiçekli bir bitkiyi geri çaprazlarla saf kırmızı elde etmek isteyen ıslahçı hangi yolu izlemelidir?","steps":[{"t":"Pembenin genotipi","a":"R₁R₂","d":"Pembe birey bir kırmızı bir beyaz alel taşır."},{"t":"Kırmızıyla çaprazla","a":"R₁R₂ × R₁R₁","d":"Pembeyi saf kırmızıyla çaprazlarsa döllerde kırmızı oranı artar."},{"t":"Seçilim yap","a":"kırmızıları ayır","d":"Oluşan kırmızı (R₁R₁) bireyler seçilip üretilir."}],"ans":"Pembeyi saf kırmızı (R₁R₁) ile çaprazlayıp döllerden kırmızı bireyleri seçmeli; bu kırmızılar saf <b>R₁R₁</b> olduğundan amaç gerçekleşir."},{"q":"Eksik baskınlıkta test çaprazı (kontrol çaprazı) yapmaya neden gerek kalmaz?","steps":[{"t":"Test çaprazının amacı","a":"genotip belirleme","d":"Tam baskınlıkta baskın bireyin homozigot mu heterozigot mu olduğu testle bulunur."},{"t":"Eksik baskınlıkta durum","a":"fenotip = genotip","d":"Her genotip ayrı fenotip verdiği için genotip doğrudan görünür."}],"ans":"Eksik baskınlıkta fenotip genotipi birebir yansıttığından genotip doğrudan anlaşılır; bu nedenle <b>test çaprazına gerek kalmaz</b>."},{"q":"İki gen birlikte eksik baskınlık gösterseydi (örneğin renk ve boy), F2 fenotip çeşitliliği nasıl değişirdi?","steps":[{"t":"Tek gen","a":"3 fenotip","d":"Bir genin eksik baskınlığında 3 fenotip (kırmızı, pembe, beyaz) çıkar."},{"t":"İki gen birlikte","a":"3 × 3","d":"İkinci gen de 3 fenotip verirse olasılıklar çarpılır."},{"t":"Sonuç","a":"9 fenotip","d":"3 × 3 = 9 farklı fenotip kombinasyonu oluşur."}],"ans":"Her gen 3 fenotip verdiğinden iki genin bağımsız eksik baskınlığında F2'de 3 × 3 = <b>9 farklı fenotip</b> oluşurdu."},{"q":"Bir popülasyonda 1 kırmızı : 2 pembe : 1 beyaz oranı görülüyorsa, bu popülasyonda kırmızı alel frekansı hakkında ne söylenebilir?","steps":[{"t":"Genotip oranı","a":"1:2:1","d":"Bu oran R₁ ve R₂ alellerinin eşit sıklıkta olduğunu gösterir."},{"t":"Alel sayımı","a":"R₁ = R₂","d":"Her genotipteki alelleri sayınca kırmızı ve beyaz alel sayısı eşit çıkar."},{"t":"Frekans","a":"0,5 ve 0,5","d":"Buna göre kırmızı alel frekansı 0,5'tir."}],"ans":"1:2:1 dağılımı R₁ ve R₂ alellerinin eşit sıklıkta olduğunu gösterir; kırmızı alel frekansı yaklaşık <b>0,5</b>'tir."},{"q":"Eksik baskınlık gösteren bir özellikte heterozigot oranı F1'de 1 iken F2'de 1/2'ye düşer; bunun nedenini açıklayınız.","steps":[{"t":"F1 oluşumu","a":"saf × saf","d":"İki saf döl çaprazlandığında tüm döller zorunlu olarak heterozigottur."},{"t":"F2 oluşumu","a":"melez × melez","d":"Heterozigotlar çaprazlanınca aleller yeniden homozigot da eşleşebilir."},{"t":"Sonuç","a":"heterozigot 2/4","d":"F2'de heterozigot oranı 2/4, yani 1/2'ye iner."}],"ans":"F1 saf atalardan oluştuğu için tümü heterozigottur; F2'de melezler çaprazlanınca homozigotlar da oluştuğundan heterozigot oranı <b>1/2</b>'ye düşer."},{"q":"Eksik baskınlıkta heterozigot fenotip çoğu zaman ataların aritmetik ortası gibi görünür; bunun ölçülebilir bir özellikte (örneğin boy) nasıl gözlendiğini açıklayınız.","steps":[{"t":"Atalar","a":"uzun ve kısa","d":"Bir ata uzun (örn. 60 cm), diğeri kısa (örn. 20 cm) olsun."},{"t":"Heterozigot","a":"ara değer","d":"Eksik baskınlıkta melez yaklaşık 40 cm, yani ortalama boyda olur."},{"t":"Yorum","a":"nicel ara fenotip","d":"Ölçülebilir özelliklerde ara fenotip sayısal ortalamaya yakın çıkar."}],"ans":"Ölçülebilir bir özellikte heterozigot, atalarının yaklaşık <b>aritmetik ortalaması</b> kadar bir değer gösterir (örneğin 60 ve 20 cm'lik atalardan ~40 cm)."},{"q":"Eksik baskınlıkta bir melez bireyin kendileşmesi (self) ile saf dölle çaprazının döl oranları nasıl farklılaşır?","steps":[{"t":"Kendileşme","a":"R₁R₂ × R₁R₂","d":"Melezin kendileşmesi 1 kırmızı : 2 pembe : 1 beyaz verir."},{"t":"Saf kırmızıyla çapraz","a":"R₁R₂ × R₁R₁","d":"Bu çaprazda döller 1 kırmızı : 1 pembe olur."},{"t":"Karşılaştır","a":"farklı oranlar","d":"Kendileşmede 3 fenotip, saf dölle çaprazda 2 fenotip görülür."}],"ans":"Melezin kendileşmesi <b>1:2:1</b> (3 fenotip) verirken, saf kırmızıyla çaprazı <b>1 kırmızı : 1 pembe</b> (2 fenotip) verir."},{"q":"Eksik baskınlık neden Mendel'in 'karışım kalıtımı'na (blending) benzese de aslında ondan farklıdır?","steps":[{"t":"Karışım kalıtımı iddiası","a":"özellikler kalıcı karışır","d":"Eski görüşe göre ata özellikleri harmanlanır ve bir daha ayrılmaz."},{"t":"Eksik baskınlık gerçeği","a":"aleller ayrı kalır","d":"Pembe melezden yeniden saf kırmızı ve beyaz çıkabilir."},{"t":"Sonuç","a":"parçacık kalıtımı","d":"Aleller bütünlüğünü koruduğu için ata fenotipler tekrar ortaya çıkar."}],"ans":"Fenotip karışmış görünse de aleller bütünlüğünü koruyup döllerde ayrışabildiğinden (saf kırmızı/beyaz yeniden çıkar), eksik baskınlık karışım kalıtımı değil <b>parçacık (Mendel) kalıtımı</b>dır."},{"q":"F2'de 1 kırmızı : 2 pembe : 1 beyaz dağılımında, rastgele seçilen bir pembe bireyin kendileştiğinde kırmızı döl verme olasılığı nedir?","steps":[{"t":"Pembenin genotipi","a":"R₁R₂","d":"Pembe birey kesinlikle heterozigottur."},{"t":"Kendileşme","a":"R₁R₂ × R₁R₂","d":"Heterozigotun kendileşmesi 1 R₁R₁ : 2 R₁R₂ : 1 R₂R₂ verir."},{"t":"Kırmızı olasılığı","a":"1/4","d":"R₁R₁ (kırmızı) genotipi döllerin 1/4'ünü oluşturur."}],"ans":"Pembe birey heterozigot olduğundan kendileşmesinde kırmızı (R₁R₁) döl verme olasılığı <b>1/4</b>'tür."}]}},"esBaskinlikKan":{"ilkokul":{"kolay":[{"q":"İnsanlarda kaç çeşit kan grubu vardır? Adlarını söyle.","steps":[{"t":"Grupları say","a":"dört çeşit","d":"İnsanların kanı dört ana gruba ayrılır."},{"t":"Adlarını yaz","a":"A, B, AB, 0","d":"Bu gruplar A grubu, B grubu, AB grubu ve 0 (sıfır) grubudur."}],"ans":"İnsanlarda A, B, AB ve 0 olmak üzere dört çeşit kan grubu vardır."},{"q":"Senin kan grubunu kim söyleyebilir?","steps":[{"t":"Nereden öğrenilir","a":"kan testi","d":"Kan grubu, doktorun yaptığı küçük bir kan testiyle öğrenilir."},{"t":"Kim yapar","a":"doktor veya hemşire","d":"Hastanede doktor ya da hemşire kanına bakarak grubunu söyler."}],"ans":"Kan grubunu, hastanede yapılan basit bir kan testiyle doktor ya da hemşire söyleyebilir."},{"q":"AB kan grubu adında neden hem A hem B harfi vardır?","steps":[{"t":"İki özellik birlikte","a":"A ve B birlikte","d":"AB grubunda hem A grubunun hem de B grubunun özelliği bir arada bulunur."},{"t":"İsmi nasıl olur","a":"AB","d":"İki özellik birlikte olduğu için bu gruba kısaca AB denir."}],"ans":"AB kan grubunda hem A hem de B özelliği birlikte bulunduğu için adında iki harf vardır."},{"q":"Hangi kan grubu hiç A ve B özelliği taşımaz?","steps":[{"t":"Boş grubu düşün","a":"0 grubu","d":"0 (sıfır) grubunda ne A ne de B özelliği vardır."},{"t":"Adı niye sıfır","a":"hiçbiri yok","d":"İçinde A ya da B bulunmadığı için bu gruba sıfır denir."}],"ans":"0 (sıfır) kan grubu ne A ne de B özelliği taşır."},{"q":"Kan vermek (kan bağışı) ne işe yarar?","steps":[{"t":"Kim ihtiyaç duyar","a":"hasta insanlar","d":"Kaza geçiren veya ameliyat olan kişilerin kana ihtiyacı olur."},{"t":"Kan vermek","a":"hayat kurtarır","d":"Sağlıklı insanlar kan vererek hastaların iyileşmesine yardım eder."}],"ans":"Kan bağışı, kana ihtiyacı olan hastalara yardım ederek hayat kurtarır."}],"zor":[{"q":"Annesi A grubu, babası B grubu olan bir çocuk AB grubu olabilir mi?","steps":[{"t":"Anne ve babadan gelen","a":"A ve B birlikte","d":"Çocuk annesinden A, babasından B özelliğini alabilir."},{"t":"İkisi birleşince","a":"AB grubu","d":"A ile B bir arada olunca çocuk AB grubu olur."}],"ans":"Evet, çocuk anneden A, babadan B özelliği alırsa AB kan grubu olabilir."},{"q":"AB grubu kişide A ve B özelliği nasıl birlikte görünür?","steps":[{"t":"İki özellik var","a":"A ve B","d":"AB grubunda hem A hem B özelliği aynı anda bulunur."},{"t":"Biri diğerini gizlemez","a":"ikisi de görünür","d":"Bu grupta A, B'yi ya da B, A'yı gizlemez; ikisi birden ortaya çıkar."}],"ans":"AB grubunda A ve B özellikleri birbirini gizlemez, ikisi birlikte görünür."},{"q":"Bir sınıfta en çok hangi kan grupları görülür diye nasıl öğrenebiliriz?","steps":[{"t":"Bilgi topla","a":"herkesin grubu","d":"Önce sınıftaki herkesin kan grubunu bir listeye yazarız."},{"t":"Say ve karşılaştır","a":"en çok olan","d":"A, B, AB ve 0 gruplarının kaç kişide olduğunu sayar, en çok olanı buluruz."}],"ans":"Sınıftaki herkesin kan grubunu yazıp sayarak en çok hangi grubun olduğunu öğrenebiliriz."},{"q":"Kardeşlerin kan grupları neden farklı olabilir?","steps":[{"t":"Anne babadan gelir","a":"karışık özellikler","d":"Her çocuk, anne ve babadan farklı özellikler alabilir."},{"t":"Farklı karışım","a":"farklı grup","d":"Bir kardeş A, diğeri B özelliğini öne çıkaran karışımı alabilir."}],"ans":"Kardeşler anne ve babadan farklı özellik karışımları aldığı için kan grupları farklı olabilir."},{"q":"0 grubu bir kişi neden 'her özelliği eksik' gibi düşünülür?","steps":[{"t":"A ve B yok","a":"ikisi de yok","d":"0 grubunda ne A ne de B özelliği bulunur."},{"t":"Bu yüzden sıfır","a":"boş grup","d":"İçinde A ya da B olmadığı için sıfır (0) adını alır."}],"ans":"0 grubunda A ve B özelliklerinin hiçbiri olmadığı için bu gruba sıfır denir."}]},"ortaokul":{"kolay":[{"q":"Eş baskınlık ne demektir? Kısaca açıklayınız.","steps":[{"t":"İki alel birlikte","a":"ikisi de etkili","d":"Eş baskınlıkta iki farklı alel birbirini bastırmaz, ikisi birlikte etki eder."},{"t":"Sonuç görünüm","a":"her ikisi de görünür","d":"Bu durumda her iki alelin özelliği aynı anda ortaya çıkar."}],"ans":"Eş baskınlık, iki alelin birbirini bastırmadan ikisinin özelliğini birlikte gösterdiği durumdur."},{"q":"AB0 kan grubu sisteminde kaç farklı alel rol oynar?","steps":[{"t":"Alelleri say","a":"üç alel","d":"Bu sistemde A, B ve 0 olmak üzere üç farklı alel vardır."},{"t":"Bir kişide kaç tane","a":"iki tane","d":"Her kişi bu üç alelden yalnızca ikisini taşır."}],"ans":"AB0 sisteminde A, B ve 0 olmak üzere üç alel vardır; her kişi bunlardan ikisini taşır."},{"q":"AB kan grubu eş baskınlığa nasıl bir örnektir?","steps":[{"t":"İki alel bir arada","a":"A ve B aleli","d":"AB grubunda hem A alelinin hem B alelinin özelliği bulunur."},{"t":"İkisi de görünür","a":"eş baskın","d":"İkisi de etki ettiği için bu, eş baskınlığa güzel bir örnektir."}],"ans":"AB grubunda A ve B alellerinin ikisi birlikte etki eder; bu yüzden eş baskınlığa örnektir."},{"q":"0 kan grubunu oluşturan alel hangi alellere göre çekiniktir?","steps":[{"t":"0 aleli","a":"çekinik","d":"0 alelini gösteren özellik, A ve B'nin yanında baskılanır."},{"t":"Ne zaman görünür","a":"iki 0 bir arada","d":"0 grubu ancak iki 0 aleli bir araya gelince ortaya çıkar."}],"ans":"0 aleli hem A hem B alelinin yanında çekiniktir; 0 grubu ancak iki 0 aleli birlikteyken görülür."},{"q":"Rh faktörü kan grubuna ne ekler?","steps":[{"t":"Ek bir özellik","a":"Rh varlığı","d":"Rh faktörü, kanda bulunup bulunmamasıyla ek bir özellik katar."},{"t":"İki durum","a":"Rh⁺ veya Rh⁻","d":"Rh varsa kan Rh⁺, yoksa Rh⁻ olarak adlandırılır."}],"ans":"Rh faktörü kana ek bir özellik katar; varsa kan Rh⁺, yoksa Rh⁻ olur."}],"zor":[{"q":"Bir kişinin kan grubu A ise olası genotipleri nelerdir?","steps":[{"t":"A için seçenekler","a":"AA veya A0","d":"A grubu, ya iki A aleliyle (AA) ya da bir A ve bir 0 aleliyle (A0) oluşur."},{"t":"Neden ikisi de A","a":"0 çekinik","d":"0 aleli çekinik olduğu için A0'da yalnızca A özelliği görünür."}],"ans":"A grubu bir kişinin genotipi AA ya da A0 olabilir; 0 çekinik olduğu için ikisi de A grubu görünür."},{"q":"AB grubu bir kişinin genotipi neden tek türlüdür?","steps":[{"t":"AB için tek seçenek","a":"AB aleli","d":"AB grubu yalnızca bir A ve bir B aleli bir araya gelince oluşur."},{"t":"İkisi de baskın","a":"eş baskın","d":"A ve B eş baskın olduğu için ikisi de görünür ve genotip tektir."}],"ans":"AB grubu yalnızca A ve B alelinin birlikte bulunmasıyla oluştuğu için genotip tek türlüdür."},{"q":"0 grubu bir kişinin genotipi neden tek türlü olabilir?","steps":[{"t":"0 için tek seçenek","a":"00","d":"0 grubu yalnızca iki çekinik 0 aleli bir araya gelince oluşur."},{"t":"Tek olası dizilim","a":"00 genotipi","d":"Başka alel olsa A ya da B görünürdü, bu yüzden tek olasılık 00'dır."}],"ans":"0 grubu yalnızca iki çekinik 0 alelinden oluştuğu için genotipi sadece 00 olabilir."},{"q":"Eş baskınlık ile çekinik-baskın ilişkisi arasındaki fark nedir?","steps":[{"t":"Baskın-çekinik","a":"biri gizlenir","d":"Normalde baskın alel, çekinik alelin özelliğini gizler."},{"t":"Eş baskınlık","a":"ikisi de görünür","d":"Eş baskınlıkta ise hiçbir alel diğerini gizlemez, ikisi birlikte görünür."}],"ans":"Baskın-çekinikte bir alel diğerini gizlerken, eş baskınlıkta iki alel birbirini gizlemeden ikisi birlikte görünür."},{"q":"Anne A0, baba B0 genotipliyse çocuk 0 grubu olabilir mi?","steps":[{"t":"Anneden gelen","a":"0 olabilir","d":"Anne A0 olduğu için çocuğa 0 alelini verebilir."},{"t":"Babadan gelen","a":"0 olabilir","d":"Baba B0 olduğu için çocuğa 0 alelini verebilir."},{"t":"İkisi birleşince","a":"00","d":"İki 0 aleli birleşirse çocuk 00, yani 0 grubu olur."}],"ans":"Evet, çocuk anneden ve babadan birer 0 aleli alırsa 00 genotipiyle 0 grubu olabilir."}]},"lise":{"kolay":[{"q":"AB0 kan grubu sistemi neden çok alellilik (multiple allel) örneğidir?","steps":[{"t":"Alel sayısı","a":"üç alel","d":"Bir gen için ikiden fazla, yani I^A, I^B ve i olmak üzere üç alel bulunur."},{"t":"Bireydeki sayı","a":"yine ikisi","d":"Çok alel olsa da her birey bu üç alelden yalnızca ikisini taşır."}],"ans":"AB0 sisteminde bir gene ait üç alel (I^A, I^B, i) bulunduğu için bu, çok alellilik örneğidir."},{"q":"AB0 sisteminde alellerin baskınlık ilişkisini yazınız.","steps":[{"t":"I^A ve I^B","a":"birbirine eş baskın","d":"I^A ile I^B birbirine göre eş baskındır, ikisi birlikte ifade edilir."},{"t":"i aleli","a":"ikisine de çekinik","d":"i aleli hem I^A hem I^B alelinin yanında çekiniktir."}],"ans":"I^A ile I^B eş baskındır; i aleli ise hem I^A hem I^B alelinin yanında çekiniktir."},{"q":"AB grubunun genotipi neden eş baskınlığı açıkça gösterir?","steps":[{"t":"Genotip","a":"I^A I^B","d":"AB grubunun genotipi I^A I^B'dir, iki farklı baskın alel bir aradadır."},{"t":"Fenotipe yansıma","a":"her iki antijen","d":"Eritrosit yüzeyinde hem A hem B antijeni birlikte üretilir."}],"ans":"AB grubu I^A I^B genotipiyle hem A hem B antijenini birlikte ürettiği için eş baskınlığı açıkça gösterir."},{"q":"A grubu bir bireyin olası genotiplerini yazınız.","steps":[{"t":"Olasılıklar","a":"I^A I^A veya I^A i","d":"A fenotipi homozigot I^A I^A ya da heterozigot I^A i ile oluşabilir."},{"t":"Neden ikisi de A","a":"i çekinik","d":"i aleli çekinik olduğundan I^A i'de yalnızca A antijeni görünür."}],"ans":"A grubu bireyin genotipi I^A I^A ya da I^A i olabilir; i çekinik olduğu için ikisi de A fenotipi verir."},{"q":"0 grubu bireyin genotipi neden tek türlüdür?","steps":[{"t":"Genotip","a":"ii","d":"0 grubu yalnızca iki çekinik i alelinin bir araya gelmesiyle oluşur."},{"t":"Antijen durumu","a":"A ve B yok","d":"ii genotipinde ne A ne de B antijeni üretilir."}],"ans":"0 grubu yalnızca ii genotipiyle oluşur; bu nedenle genotipi tek türlüdür ve hiçbir antijen taşımaz."},{"q":"Eritrosit yüzeyindeki antijen ile plazmadaki antikor arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Antijen","a":"yüzeyde A/B","d":"Eritrosit zarında bulunan A ya da B antijenleri kan grubunu belirler."},{"t":"Antikor","a":"plazmada zıt olan","d":"Plazmada, kişinin taşımadığı antijene karşı antikor bulunur."}],"ans":"Kişinin eritrositi hangi antijeni taşıyorsa, plazmasında taşımadığı antijene karşı antikor bulunur; örneğin A grubunda anti-B vardır."},{"q":"Rh faktörünün baskınlık durumu nedir ve genotiplerle nasıl gösterilir?","steps":[{"t":"Rh aleli","a":"R baskın, r çekinik","d":"Rh⁺ özelliği veren alel (R) baskındır, Rh⁻ veren alel (r) çekiniktir."},{"t":"Genotipler","a":"RR, Rr, rr","d":"RR ve Rr Rh⁺ fenotipi, rr ise Rh⁻ fenotipi verir."}],"ans":"Rh⁺ aleli baskındır; RR ve Rr genotipleri Rh⁺, rr genotipi ise Rh⁻ fenotip verir."},{"q":"MN kan grubu sistemi eş baskınlığa nasıl bir örnektir?","steps":[{"t":"İki alel","a":"M ve N","d":"MN sisteminde M ve N alelleri birbirine eş baskındır."},{"t":"MN fenotipi","a":"ikisi de görünür","d":"MN genotipinde hem M hem N antijeni eritsosit yüzeyinde üretilir."}],"ans":"MN sisteminde M ve N alelleri eş baskındır; MN bireyde her iki antijen birlikte görüldüğü için eş baskınlık örneğidir."},{"q":"B grubu bir bireyin olası genotipleri nelerdir?","steps":[{"t":"Olasılıklar","a":"I^B I^B veya I^B i","d":"B fenotipi homozigot I^B I^B ya da heterozigot I^B i ile oluşur."},{"t":"Neden ikisi de B","a":"i çekinik","d":"i aleli çekinik olduğu için I^B i'de yalnızca B antijeni görünür."}],"ans":"B grubu bireyin genotipi I^B I^B ya da I^B i olabilir; i çekinik olduğundan ikisi de B fenotipi verir."},{"q":"AB0 sisteminde toplam kaç farklı genotip ve kaç farklı fenotip görülür?","steps":[{"t":"Genotipleri yaz","a":"altı genotip","d":"I^A I^A, I^A i, I^B I^B, I^B i, I^A I^B ve ii olmak üzere altı genotip vardır."},{"t":"Fenotipe indir","a":"dört fenotip","d":"Bu genotipler A, B, AB ve 0 olmak üzere dört fenotip oluşturur."}],"ans":"AB0 sisteminde altı farklı genotip (I^A I^A, I^A i, I^B I^B, I^B i, I^A I^B, ii) ve dört farklı fenotip (A, B, AB, 0) görülür."},{"q":"Genel verici ve genel alıcı kan grupları hangileridir, neden?","steps":[{"t":"Genel verici","a":"0 grubu","d":"0 grubunda A ve B antijeni olmadığı için kanı herkese verilebilir."},{"t":"Genel alıcı","a":"AB grubu","d":"AB grubunda anti-A ve anti-B antikoru olmadığı için her kanı alabilir."}],"ans":"Antijen taşımadığı için 0 grubu genel verici; antikor taşımadığı için AB grubu genel alıcı kabul edilir."},{"q":"Bir bireyin tam kan grubu (örneğin A Rh⁺) kaç ayrı genden gelen bilgiyi içerir?","steps":[{"t":"AB0 geni","a":"A/B/0 bilgisi","d":"İlk gen, A antijenini belirleyen AB0 sistemine ait genotipi taşır."},{"t":"Rh geni","a":"Rh⁺/Rh⁻ bilgisi","d":"İkinci gen, Rh faktörünün varlığını belirleyen genotipi taşır."}],"ans":"Tam kan grubu, biri AB0 sistemine biri Rh faktörüne ait olmak üzere iki ayrı genden gelen bilgiyi içerir."},{"q":"İnsan kan gruplarında hem eş baskınlık hem çok alellilik bir arada nasıl görülür?","steps":[{"t":"Çok alellilik","a":"üç alel","d":"AB0 geninde I^A, I^B ve i olmak üzere üç alel bulunması çok alellilik örneğidir."},{"t":"Eş baskınlık","a":"I^A ile I^B","d":"Bu alellerden I^A ile I^B'nin birlikte ifade edilmesi eş baskınlıktır."}],"ans":"AB0 geninde üç alel bulunması çok alelliliği, I^A ile I^B'nin birlikte ifade edilmesi ise eş baskınlığı gösterir; ikisi aynı sistemde bir aradadır."},{"q":"Eş baskınlık ile eksik baskınlık arasındaki temel fark nedir?","steps":[{"t":"Eş baskınlık","a":"ikisi de tam görünür","d":"Eş baskınlıkta iki alelin özelliği ayrı ayrı ve tam olarak ortaya çıkar."},{"t":"Eksik baskınlık","a":"ara fenotip","d":"Eksik baskınlıkta ise iki alel karışır ve ikisinin ortasında bir fenotip oluşur."}],"ans":"Eş baskınlıkta iki özellik ayrı ve tam görünürken, eksik baskınlıkta özellikler karışıp ara bir fenotip oluşturur."},{"q":"Kan grubu çaprazlamasında neden 'fenotip' yerine 'genotip' üzerinden çalışmak gerekir?","steps":[{"t":"Fenotip yetersiz","a":"gizli alel","d":"A grubu görünen biri I^A I^A da I^A i de olabilir; fenotip gizli i alelini saklar."},{"t":"Genotip gerekli","a":"alel takibi","d":"Çaprazlamada hangi alelin geçeceğini bilmek için genotipi kullanmak gerekir."}],"ans":"Aynı fenotip farklı genotiplerden gelebildiği için, çaprazlamada hangi alelin aktarılacağını belirlemek üzere genotip üzerinden çalışmak gerekir."}],"zor":[{"q":"Anne I^A i, baba I^B i genotipli ise çocukların olası kan gruplarını ve oranlarını bulunuz.","steps":[{"t":"Alelleri belirle","a":"I^A, i ve I^B, i","d":"Anne I^A ve i; baba I^B ve i alellerini verebilir."},{"t":"Çaprazla","a":"I^A I^B, I^A i, I^B i, ii","d":"Dört kombinasyon ortaya çıkar: I^A I^B, I^A i, I^B i ve ii."},{"t":"Fenotipe çevir","a":"AB, A, B, 0","d":"Bu genotipler sırasıyla AB, A, B ve 0 fenotiplerini verir."}],"ans":"Çocuklar 1/4 AB, 1/4 A, 1/4 B ve 1/4 0 olabilir; yani dört farklı kan grubu da eşit olasılıkla görülebilir."},{"q":"İki AB grubu (I^A I^B) bireyin çocuklarında 0 grubu neden hiç görülmez?","steps":[{"t":"Aktarılabilen aleller","a":"yalnızca I^A veya I^B","d":"AB bireyler çocuğa ancak I^A ya da I^B aleli verebilir; i aleli taşımaz."},{"t":"Olası genotipler","a":"I^A I^A, I^A I^B, I^B I^B","d":"Çaprazlamada I^A I^A (A), I^A I^B (AB) ve I^B I^B (B) çıkar."},{"t":"0 olasılığı","a":"sıfır","d":"0 grubu için iki i aleli gerekir, ama hiçbir ebeveyn i taşımaz."}],"ans":"İki AB birey i aleli taşımadığı için çocuklara i geçemez; bu yüzden ii (0 grubu) çocuk hiç oluşmaz, çocuklar A, AB ya da B olur."},{"q":"0 grubu bir anne ile AB grubu bir babanın çocukları neden hiçbir zaman 0 ya da AB olmaz?","steps":[{"t":"Anneden gelen","a":"yalnızca i","d":"Anne ii olduğu için çocuğa daima i aleli verir."},{"t":"Babadan gelen","a":"I^A veya I^B","d":"Baba I^A I^B olduğu için çocuğa ya I^A ya da I^B verir."},{"t":"Sonuç genotipler","a":"I^A i ve I^B i","d":"Birleşince çocuk I^A i (A) ya da I^B i (B) olur."}],"ans":"Anneden hep i, babadan I^A ya da I^B geldiği için çocuklar yalnızca A (I^A i) ya da B (I^B i) olur; 0 ve AB asla görülmez."},{"q":"Bir çocuğun kan grubu 0 ise ebeveynlerinin genotipleri hakkında ne söylenebilir?","steps":[{"t":"Çocuğun genotipi","a":"ii","d":"0 grubu çocuk yalnızca ii genotipinde olabilir."},{"t":"Aleller nereden","a":"her ebeveynden bir i","d":"Bir i aleli anneden, bir i aleli babadan gelmek zorundadır."},{"t":"Ebeveyn şartı","a":"ikisi de i taşır","d":"O hâlde her iki ebeveyn de en az bir i aleli taşımalıdır."}],"ans":"0 grubu çocuğun her iki ebeveyni de en az bir i aleli taşımalıdır; yani ebeveynler I^A i, I^B i ya da ii genotipli olabilir, ama ikisi de mutlaka bir i bulundurur."},{"q":"Anne A grubu (I^A i), baba B grubu (I^B i) iken doğan çocuk 0 grubu çıkmıştır; bu nasıl mümkün olur?","steps":[{"t":"Anneden gelen","a":"i olabilir","d":"Anne I^A i olduğu için çocuğa i alelini verebilir."},{"t":"Babadan gelen","a":"i olabilir","d":"Baba I^B i olduğu için çocuğa i alelini verebilir."},{"t":"Birleşim","a":"ii","d":"İki çekinik i aleli birleşince çocuk ii, yani 0 grubu olur."}],"ans":"Anne ve babanın taşıdığı çekinik i alellerinin çocukta birleşmesiyle ii genotipi oluşur; bu nedenle A ve B grubu ebeveynlerden 0 grubu çocuk doğabilir."},{"q":"Rh⁻ bir anne ile Rh⁺ bir babanın çocuğunda eritroblastozis fötalis riskini genotip üzerinden açıklayınız.","steps":[{"t":"Ebeveyn genotipleri","a":"anne rr, baba RR/Rr","d":"Anne Rh⁻ olduğu için rr; baba Rh⁺ olduğu için RR ya da Rr'dir."},{"t":"Çocuğun durumu","a":"Rr olabilir","d":"Baba R aleli verirse çocuk Rr, yani Rh⁺ olur."},{"t":"Bağışıklık tepkisi","a":"anne antikoru","d":"Rh⁻ anne, Rh⁺ bebeğin kanına karşı antikor üretip sonraki gebelikte saldırabilir."}],"ans":"rr anne ile Rh⁺ baba çocuğa R verirse bebek Rh⁺ (Rr) olur; annenin ürettiği anti-Rh antikorları özellikle sonraki Rh⁺ gebelikte bebeğin eritrositlerine saldırarak eritroblastozis fötalise yol açabilir."},{"q":"Hem AB0 hem Rh dikkate alındığında I^A i Rr birey, ii rr birey ile çaprazlanırsa çocuk fenotiplerini bulunuz.","steps":[{"t":"AB0 ayağı","a":"A veya 0","d":"I^A i × ii çaprazında çocuk I^A i (A) ya da ii (0) olur; 1/2 A, 1/2 0."},{"t":"Rh ayağı","a":"Rh⁺ veya Rh⁻","d":"Rr × rr çaprazında çocuk Rr (Rh⁺) ya da rr (Rh⁻) olur; 1/2 Rh⁺, 1/2 Rh⁻."},{"t":"Birleştir","a":"dört fenotip","d":"İki bağımsız geni çarparak A Rh⁺, A Rh⁻, 0 Rh⁺, 0 Rh⁻ elde edilir."}],"ans":"Çocuklar 1/4 A Rh⁺, 1/4 A Rh⁻, 1/4 0 Rh⁺ ve 1/4 0 Rh⁻ olabilir; AB0 ve Rh genleri bağımsız aktarıldığı için olasılıklar çarpılır."},{"q":"Bir adli olayda çocuk 0 grubu, anne AB grubudur; bu kişi gerçekten annesi olabilir mi?","steps":[{"t":"Çocuğun genotipi","a":"ii","d":"0 grubu çocuğun genotipi mutlaka ii'dir, anneden bir i alması gerekir."},{"t":"Annenin alelleri","a":"yalnızca I^A veya I^B","d":"AB grubu anne I^A I^B'dir ve çocuğa yalnızca I^A ya da I^B verebilir, i veremez."},{"t":"Sonuç","a":"olamaz","d":"Anne i aleli taşımadığından çocuğa gerekli i alelini sağlayamaz."}],"ans":"AB grubu anne i aleli taşımadığı için 0 grubu (ii) bir çocuğa gerekli i alelini veremez; dolayısıyla bu kadın çocuğun biyolojik annesi olamaz."},{"q":"MN kan grubunda anne MN, baba MN ise çocukların fenotip oranlarını bulunuz.","steps":[{"t":"Aletleri belirle","a":"M ve N","d":"MN bireyler çocuğa ya M ya N aleli verebilir."},{"t":"Çaprazla","a":"MM, MN, NM, NN","d":"Çaprazlamada MM, iki MN ve NN genotipleri oluşur."},{"t":"Fenotip oranı","a":"1 M : 2 MN : 1 N","d":"M ve N eş baskın olduğu için her genotip kendi fenotipini verir."}],"ans":"MN × MN çaprazında çocuklar 1/4 M, 2/4 MN ve 1/4 N grubu olur; eş baskınlık nedeniyle genotip oranı doğrudan fenotip oranına yansır (1:2:1)."},{"q":"A grubu bir anne ile A grubu bir babanın 0 grubu çocuğu olabilir mi? Genotiple açıklayınız.","steps":[{"t":"A grubunun seçenekleri","a":"I^A I^A veya I^A i","d":"Her iki ebeveyn de A grubu olduğundan I^A i (heterozigot) olabilir."},{"t":"i aktarımı","a":"ikisi de i verebilir","d":"İki ebeveyn de I^A i ise çocuğa i alelini geçirebilir."},{"t":"Birleşim","a":"ii","d":"İki i bir araya gelirse çocuk ii, yani 0 grubu olur."}],"ans":"Evet; her iki A grubu ebeveyn de I^A i heterozigot ise çocuğa birer i aleli geçirebilir, böylece ii genotipiyle 0 grubu çocuk doğabilir."},{"q":"Eş baskınlık (AB grubu) ile eksik baskınlığı (örneğin pembe çiçek) genotip-fenotip ilişkisi açısından karşılaştırınız.","steps":[{"t":"Eş baskınlık","a":"iki ürün birlikte","d":"AB grubunda I^A ve I^B alelleri ayrı ayrı A ve B antijenini birlikte üretir."},{"t":"Eksik baskınlık","a":"karışık ara fenotip","d":"Eksik baskınlıkta kırmızı ve beyaz alel karışıp pembe gibi ara bir fenotip oluşturur."},{"t":"Temel fark","a":"birlikte vs karışım","d":"Eş baskınlıkta ürünler birlikte görünür, eksik baskınlıkta tek bir ara ürün oluşur."}],"ans":"Eş baskınlıkta (AB grubu) iki alelin ürünü ayrı ayrı birlikte görünürken, eksik baskınlıkta (pembe çiçek) aleller karışıp ikisinin ortasında tek bir ara fenotip oluşturur."},{"q":"Bir kişi I^A I^B genotipliyse plazmasında hangi antikorlar bulunur ve neden?","steps":[{"t":"Taşınan antijenler","a":"A ve B","d":"I^A I^B genotipinde eritrosit yüzeyinde hem A hem B antijeni bulunur."},{"t":"Antikor kuralı","a":"kendine karşı yok","d":"Vücut kendi taşıdığı antijene karşı antikor üretmez."},{"t":"Sonuç","a":"antikor yok","d":"A ve B antijenleri kendine ait olduğundan plazmada anti-A ve anti-B bulunmaz."}],"ans":"AB grubu (I^A I^B) bireyin plazmasında ne anti-A ne de anti-B bulunur; çünkü vücut kendi taşıdığı A ve B antijenlerine karşı antikor üretmez."},{"q":"Çocukları arasında A, B, AB ve 0 gruplarının dördü de görülen bir ailede ebeveyn genotipleri ne olmalıdır?","steps":[{"t":"AB için şart","a":"biri I^A biri I^B","d":"AB çocuk için bir ebeveynden I^A, diğerinden I^B gelmelidir."},{"t":"0 için şart","a":"ikisi de i taşır","d":"0 çocuk için her iki ebeveyn de i aleli taşımalıdır."},{"t":"Tek olası kombinasyon","a":"I^A i × I^B i","d":"Bu iki şartı birlikte sağlayan tek genotip çifti I^A i ve I^B i'dir."}],"ans":"Dört grubun da görülmesi için ebeveynler I^A i ve I^B i genotipinde olmalıdır; böylece çocuklar I^A I^B (AB), I^A i (A), I^B i (B) ve ii (0) olabilir."},{"q":"Aynı gende üç alel bulunmasına rağmen bir popülasyonda neden yalnızca dört kan grubu fenotipi görülür?","steps":[{"t":"Genotip sayısı","a":"altı genotip","d":"Üç alelin ikili kombinasyonlarından altı farklı genotip oluşur."},{"t":"Baskınlık ilişkisi","a":"eş baskın + çekinik","d":"I^A ile I^B eş baskın, i ise ikisine de çekiniktir."},{"t":"Fenotipe indirgenme","a":"dört fenotip","d":"I^A I^A ve I^A i → A; I^B I^B ve I^B i → B'ye indiğinden altı genotip dört fenotip verir."}],"ans":"Üç alel altı genotip oluştursa da, i'nin çekinikliği ve I^A-I^B eş baskınlığı nedeniyle genotipler A, B, AB ve 0 olmak üzere yalnızca dört fenotipte toplanır."},{"q":"Heterozigot A grubu (I^A i) ile heterozigot B grubu (I^B i) çaprazında 'her doğan çocuk farklı grupta olur' demek doğru mudur?","steps":[{"t":"Olası gruplar","a":"AB, A, B, 0","d":"Çaprazlama dört farklı fenotibi (AB, A, B, 0) mümkün kılar."},{"t":"Olasılık vs kesinlik","a":"şans, garanti değil","d":"Her grup 1/4 olasılıkla görülür; ama bu olasılıktır, kesinlik değildir."},{"t":"Gerçek sonuç","a":"tekrarlayabilir","d":"İki çocuk tesadüfen aynı grupta da doğabilir, çünkü her döllenme bağımsızdır."}],"ans":"Hayır; dört grup da 1/4 olasılıkla mümkündür, ancak her döllenme bağımsız olduğundan çocukların aynı grupta doğması da olasıdır, her birinin farklı olması garanti değildir."}]}},"genelBakis":{"ilkokul":{"kolay":[{"q":"Kalıtım ne demektir? Kısaca açıkla.","steps":[{"t":"Anne babadan geçen","a":"özellikler aktarılır","d":"Anne ve babanın bazı özellikleri yavrularına geçer."},{"t":"Buna verilen ad","a":"kalıtım","d":"Özelliklerin anne babadan çocuğa geçmesine kalıtım denir."}],"ans":"Kalıtım, anne ve babanın özelliklerinin çocuklarına geçmesidir."},{"q":"Bir çocuğun göz rengi neden anne veya babasına benzer?","steps":[{"t":"Özellik kaynağı","a":"anne ve baba","d":"Çocuk, göz rengini anne ve babasından alır."},{"t":"Aktarım","a":"kalıtımla geçer","d":"Bu özellik kalıtım yoluyla çocuğa geçtiği için onlara benzer."}],"ans":"Çocuğun göz rengi anne babasından kalıtımla geçtiği için onlara benzer."},{"q":"Yavru bir kedi neden anne kedisine benzer?","steps":[{"t":"Benzerliğin nedeni","a":"anneden gelen özellikler","d":"Yavru kedi, tüy rengi gibi özellikleri annesinden alır."},{"t":"Aktarım yolu","a":"kalıtım","d":"Bu özellikler kalıtımla geçtiği için yavru annesine benzer."}],"ans":"Yavru kedi, özelliklerini annesinden kalıtımla aldığı için ona benzer."},{"q":"Saç rengi gibi özellikler insana nereden gelir?","steps":[{"t":"Özelliğin kaynağı","a":"ailesinden","d":"İnsanın saç rengi gibi özellikleri ailesinden gelir."},{"t":"Geçiş yolu","a":"doğuştan","d":"Bu özellikler doğmadan önce anne babadan alınır."}],"ans":"Saç rengi gibi özellikler insana doğuştan ailesinden (anne babadan) gelir."},{"q":"Bir tohumdan dikilen elma ağacı neden elma verir, armut değil?","steps":[{"t":"Tohumun kaynağı","a":"elma ağacı","d":"Tohum bir elma ağacından alınmıştır."},{"t":"Özelliğin geçişi","a":"aynı meyve","d":"Ağaç, elma verme özelliğini kendi tohumuna aktarır."}],"ans":"Tohum elma ağacından geldiği için, elma verme özelliği aktarılır ve ağaç elma verir."}],"zor":[{"q":"Kalıtsal bir özellik ile sonradan kazanılan bir özelliği ayır: göz rengi, yüzme bilmek.","steps":[{"t":"Kalıtsalı bul","a":"göz rengi","d":"Göz rengi anne babadan doğuştan gelen kalıtsal bir özelliktir."},{"t":"Sonradan kazanılanı bul","a":"yüzme bilmek","d":"Yüzme, sonradan öğrenilir; doğuştan gelmez."}],"ans":"Göz rengi kalıtsaldır (doğuştan gelir); yüzme bilmek sonradan öğrenilen bir özelliktir."},{"q":"İkiz kardeşler neden birbirine çok benzer?","steps":[{"t":"Ortak köken","a":"aynı anne baba","d":"İkizler aynı anne ve babadan gelen özellikleri taşır."},{"t":"Benzerliğin nedeni","a":"benzer kalıtım","d":"Aynı özellikleri aldıkları için görünüşleri birbirine çok benzer."}],"ans":"İkizler anne babadan benzer özellikleri aldığı için birbirlerine çok benzer."},{"q":"Bir ailede herkesin saçı kıvırcıkken çocuğun saçı da kıvırcık olur mu? Neden?","steps":[{"t":"Ailedeki özellik","a":"kıvırcık saç","d":"Annede ve babada kıvırcık saç özelliği bulunur."},{"t":"Çocuğa geçiş","a":"kalıtım olasılığı","d":"Bu özellik kalıtımla çocuğa geçebilir, bu yüzden çocuğun saçı da kıvırcık olabilir."}],"ans":"Anne babada kıvırcık saç özelliği olduğu için bu özellik kalıtımla çocuğa geçebilir ve çocuğun saçı da kıvırcık olabilir."},{"q":"Köpek yavruları neden farklı renklerde olabilir?","steps":[{"t":"Anne baba özelliği","a":"farklı renkler","d":"Anne ve baba köpek farklı tüy renkleri taşıyabilir."},{"t":"Karışım","a":"farklı yavrular","d":"Yavrular bu özellikleri farklı şekilde aldığından renkleri farklı olabilir."}],"ans":"Yavrular tüy rengini anne babadan farklı şekillerde aldığı için farklı renklerde olabilir."},{"q":"Bir kişi doğduktan sonra geçirdiği kaza izi çocuğuna geçer mi? Neden?","steps":[{"t":"İzin kaynağı","a":"sonradan oluştu","d":"Kaza izi doğuştan değil, yaşam içinde sonradan oluşmuştur."},{"t":"Geçiş durumu","a":"geçmez","d":"Sonradan kazanılan bu tür özellikler kalıtımla çocuğa geçmez."}],"ans":"Kaza izi sonradan oluştuğu için kalıtsal değildir ve çocuğa geçmez."}]},"ortaokul":{"kolay":[{"q":"Kalıtım biliminin (genetik) inceleme konusu nedir?","steps":[{"t":"İnceleme alanı","a":"özelliklerin aktarımı","d":"Genetik, canlı özelliklerinin nesilden nesile nasıl aktarıldığını inceler."},{"t":"Amaç","a":"benzerlik ve farklılık","d":"Canlılar arasındaki benzerlik ve farklılıkların nedenini araştırır."}],"ans":"Kalıtım bilimi (genetik), canlı özelliklerinin kuşaktan kuşağa nasıl aktarıldığını inceleyen bilim dalıdır."},{"q":"Gen nedir ve nerede bulunur?","steps":[{"t":"Tanımı","a":"kalıtım birimi","d":"Gen, bir özelliği belirleyen en küçük kalıtım birimidir."},{"t":"Yeri","a":"DNA üzerinde","d":"Genler, hücre çekirdeğindeki DNA üzerinde yer alır."}],"ans":"Gen, bir özelliği belirleyen kalıtım birimidir ve DNA üzerinde bulunur."},{"q":"Gen, DNA ve kromozom arasındaki büyüklük ilişkisi nasıldır?","steps":[{"t":"En küçükten","a":"gen","d":"Gen, DNA üzerinde belirli bir bölgedir; en küçük birimdir."},{"t":"Daha büyük yapı","a":"DNA → kromozom","d":"Genleri taşıyan DNA, paketlenerek kromozomu oluşturur."}],"ans":"Gen DNA üzerinde bir parçadır; DNA paketlenerek kromozomu oluşturur, yani kromozom > DNA > gen şeklindedir."},{"q":"Modern genetiğin kurucusu sayılan bilim insanı kimdir?","steps":[{"t":"Bilim insanı","a":"Gregor Mendel","d":"Bezelyelerle yaptığı deneylerle kalıtım kurallarını bulan kişidir."},{"t":"Önemi","a":"genetiğin babası","d":"Çalışmaları nedeniyle modern genetiğin kurucusu kabul edilir."}],"ans":"Modern genetiğin kurucusu, bezelye deneyleriyle kalıtım kurallarını bulan Gregor Mendel'dir."},{"q":"Karakter ve özellik kavramları arasındaki fark nedir?","steps":[{"t":"Karakter","a":"genel nitelik","d":"Karakter, kalıtılan genel bir niteliktir; örneğin göz rengi."},{"t":"Özellik","a":"o niteliğin hali","d":"Özellik, o karakterin aldığı belirli durumdur; örneğin mavi göz."}],"ans":"Karakter kalıtılan genel niteliktir (göz rengi); özellik ise o karakterin belirli bir halidir (mavi göz)."}],"zor":[{"q":"Mendel deneylerinde neden bezelye bitkisini seçmiştir?","steps":[{"t":"Üreme kolaylığı","a":"hızlı ve çok döl","d":"Bezelye hızlı ürer ve kısa sürede çok sayıda yavru verir."},{"t":"Belirgin özellikler","a":"net farklar","d":"Bezelyenin tohum rengi gibi açıkça ayırt edilebilen özellikleri vardır."}],"ans":"Mendel bezelyeyi; hızlı üremesi, çok döl vermesi ve belirgin ayırt edilebilir özellikleri olması nedeniyle seçmiştir."},{"q":"Kalıtsal bilgi bir hücreden yeni hücreye nasıl aktarılır?","steps":[{"t":"Bilginin yeri","a":"DNA","d":"Kalıtsal bilgi DNA molekülünde şifreli olarak saklanır."},{"t":"Aktarım","a":"DNA kopyalanır","d":"Hücre bölünmeden önce DNA'sını eşler ve kopyayı yeni hücreye verir."}],"ans":"Kalıtsal bilgi DNA'da saklanır; hücre bölünürken DNA kopyalanarak yeni hücreye aktarılır."},{"q":"Genler ile kromozom sayısı arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Genin yeri","a":"kromozom üzerinde","d":"Çok sayıda gen, kromozomlar üzerinde sıralı şekilde dizilir."},{"t":"Tür ve sayı","a":"sabit kromozom sayısı","d":"Her canlı türünün belirli ve sabit bir kromozom sayısı vardır."}],"ans":"Genler kromozomlar üzerinde dizilidir ve her türün belirli, sabit bir kromozom sayısı bulunur."},{"q":"Tek yumurta ikizleri aynı geni taşır; o halde küçük farklar neden olabilir?","steps":[{"t":"Aynı kalıtım","a":"aynı genler","d":"Tek yumurta ikizleri başlangıçta birbirinin aynı genleri taşır."},{"t":"Çevre etkisi","a":"farklı yaşam","d":"Farklı beslenme ve alışkanlıklar gibi çevresel etkenler ufak farklar yaratır."}],"ans":"Tek yumurta ikizleri aynı genleri taşısa da farklı çevre koşulları (beslenme, alışkanlık) küçük farklara yol açar."},{"q":"Kalıtsal özellikler ile çevresel özellikleri örneklerle ayırt ediniz.","steps":[{"t":"Kalıtsal özellik","a":"kan grubu, göz rengi","d":"Doğuştan genlerle gelen kan grubu ve göz rengi gibi özelliklerdir."},{"t":"Çevresel özellik","a":"yabancı dil, kas","d":"Sonradan kazanılan dil bilme veya spor yaparak gelişen kaslardır."}],"ans":"Kalıtsal özellikler genlerle doğuştan gelir (kan grubu, göz rengi); çevresel özellikler sonradan kazanılır (yabancı dil, kas gelişimi)."}]},"lise":{"kolay":[{"q":"Kalıtım (genetik) biliminin temel inceleme alanını bilimsel olarak tanımlayınız.","steps":[{"t":"İnceleme konusu","a":"kalıtsal aktarım","d":"Genetik, kalıtsal özelliklerin nesilden nesile aktarım mekanizmasını inceler."},{"t":"Kapsam","a":"gen yapısı ve işlevi","d":"Genlerin yapısını, işlevini ve varyasyonun kaynağını araştırır."}],"ans":"Genetik, kalıtsal özelliklerin kuşaktan kuşağa aktarımını, genlerin yapı ve işlevini inceleyen bilim dalıdır."},{"q":"Gen kavramını moleküler düzeyde tanımlayınız.","steps":[{"t":"Yapı","a":"DNA bölgesi","d":"Gen, DNA molekülü üzerinde belirli bir nükleotit dizisidir."},{"t":"İşlev","a":"protein şifresi","d":"Bu dizi, belirli bir protein ya da işlevsel ürünün bilgisini taşır."}],"ans":"Gen, DNA üzerinde belirli bir protein ya da işlevsel ürünün bilgisini taşıyan nükleotit dizisidir."},{"q":"Gen, DNA ve kromozom arasındaki yapısal ilişkiyi açıklayınız.","steps":[{"t":"DNA ve gen","a":"gen = DNA parçası","d":"Gen, uzun DNA molekülünün belirli bir bölgesidir."},{"t":"Paketlenme","a":"DNA → kromozom","d":"DNA, histon proteinleriyle sarılıp katlanarak kromozomu oluşturur."}],"ans":"Gen DNA'nın bir bölgesidir; DNA histon proteinleriyle paketlenerek kromozomu oluşturur, dolayısıyla kromozom > DNA > gen düzeyindedir."},{"q":"Genotip ve fenotip kavramlarını ayırt ediniz.","steps":[{"t":"Genotip","a":"gen yapısı","d":"Genotip, bireyin taşıdığı genlerin tümünü ifade eder."},{"t":"Fenotip","a":"dış görünüş","d":"Fenotip, genotip ve çevrenin etkisiyle ortaya çıkan görünür özelliklerdir."}],"ans":"Genotip bireyin sahip olduğu genlerin yapısı, fenotip ise bu genlerin ve çevrenin etkisiyle oluşan gözlenebilir özelliklerdir."},{"q":"Karakter, özellik ve alel kavramlarını ilişkilendiriniz.","steps":[{"t":"Karakter ve özellik","a":"nitelik / hali","d":"Karakter kalıtılan niteliktir (boy), özellik onun bir halidir (uzun boy)."},{"t":"Alel","a":"gen çeşidi","d":"Alel, aynı karakteri belirleyen bir genin farklı versiyonudur."}],"ans":"Karakter kalıtılan niteliktir, özellik onun belirli halidir; alel ise o karakteri belirleyen genin farklı versiyonudur."},{"q":"Mendel'in modern genetiğin kurucusu sayılmasının nedeni nedir?","steps":[{"t":"Yöntemi","a":"sayısal deney","d":"Bezelyelerle yaptığı çaprazlamaları sayarak istatistiksel olarak inceledi."},{"t":"Bulgusu","a":"kalıtım kuralları","d":"Özelliklerin belirli oranlarla aktarıldığı kalıtım ilkelerini ortaya koydu."}],"ans":"Mendel, bezelye çaprazlamalarını sayısal-istatistiksel inceleyerek kalıtım kurallarını ilk kez ortaya koyduğu için modern genetiğin kurucusu sayılır."},{"q":"Homozigot ve heterozigot kavramlarını tanımlayınız.","steps":[{"t":"Homozigot","a":"aynı aleller","d":"Bir karakter için iki aynı aleli taşıyan bireydir (AA veya aa)."},{"t":"Heterozigot","a":"farklı aleller","d":"Bir karakter için iki farklı aleli taşıyan bireydir (Aa)."}],"ans":"Homozigot birey bir karakter için aynı alelleri (AA, aa), heterozigot birey ise farklı alelleri (Aa) taşır."},{"q":"Dominant (baskın) ve resesif (çekinik) alel kavramlarını ayırt ediniz.","steps":[{"t":"Dominant alel","a":"etkisini gösterir","d":"Heterozigot durumda bile fenotipte kendini gösteren aleldir."},{"t":"Resesif alel","a":"saklanabilir","d":"Etkisini ancak iki kopya bir arada (homozigot) olduğunda gösterir."}],"ans":"Dominant alel heterozigot durumda bile fenotipte görünür; resesif alel ise yalnızca homozigot durumda etkisini gösterir."},{"q":"Kalıtsal bilginin nesilden nesile aktarımını sağlayan hücre türü nedir?","steps":[{"t":"Aktarım aracı","a":"üreme hücreleri","d":"Kalıtsal bilgi yumurta ve sperm gibi üreme (eşey) hücreleriyle taşınır."},{"t":"İşlevi","a":"genleri birleştirir","d":"Döllenmede anne ve babanın genleri yeni bireyde birleşir."}],"ans":"Kalıtsal bilgi, yumurta ve sperm gibi üreme (eşey) hücreleriyle aktarılır; döllenmede ebeveyn genleri yeni bireyde birleşir."},{"q":"Diploit ve haploit kromozom sayısı kavramlarını açıklayınız.","steps":[{"t":"Diploit (2n)","a":"çift takım","d":"Vücut hücrelerinde kromozomlar biri anneden biri babadan çift takım hâldedir."},{"t":"Haploit (n)","a":"tek takım","d":"Üreme hücrelerinde kromozom sayısı yarıya iner, tek takım olur."}],"ans":"Diploit (2n) hücreler çift takım kromozom taşır (vücut hücreleri); haploit (n) hücreler tek takım taşır (üreme hücreleri)."},{"q":"İnsanda vücut hücrelerinin kromozom sayısı ve dağılımı nasıldır?","steps":[{"t":"Toplam sayı","a":"46 kromozom","d":"İnsan vücut hücresinde 46 (23 çift) kromozom bulunur."},{"t":"Dağılımı","a":"44 + 2","d":"Bunların 44'ü vücut (otozom), 2'si eşey (cinsiyet) kromozomudur."}],"ans":"İnsan vücut hücresinde 46 kromozom vardır; 44'ü otozom (vücut), 2'si eşey (cinsiyet) kromozomudur."},{"q":"Kalıtsal ve çevresel (modifikasyon) özellikleri ayırt eden temel ölçüt nedir?","steps":[{"t":"Kalıtsal özellik","a":"gen kökenli","d":"Genlerle belirlenir ve döllere aktarılabilir; örneğin kan grubu."},{"t":"Çevresel özellik","a":"aktarılamaz","d":"Çevre etkisiyle oluşur, genotipi değiştirmez ve döllere geçmez."}],"ans":"Temel ölçüt döllere aktarılabilirliktir: kalıtsal özellikler genlerle belirlenip aktarılır, çevresel özellikler aktarılamaz."},{"q":"Genom kavramı neyi ifade eder?","steps":[{"t":"Tanımı","a":"tüm genetik bilgi","d":"Genom, bir canlının sahip olduğu kalıtsal bilginin tümüdür."},{"t":"Kapsamı","a":"tüm DNA dizisi","d":"O türe ait bütün genleri ve DNA dizilerini içine alır."}],"ans":"Genom, bir canlının taşıdığı tüm kalıtsal bilgiyi, yani bütün DNA dizisini ifade eder."},{"q":"Mutasyon ve modifikasyon arasındaki temel farkı belirtiniz.","steps":[{"t":"Mutasyon","a":"DNA değişimi","d":"Genotipte (DNA'da) meydana gelen kalıcı ve aktarılabilir değişimdir."},{"t":"Modifikasyon","a":"çevresel değişim","d":"Yalnızca fenotipi etkileyen, döllere geçmeyen çevresel değişimdir."}],"ans":"Mutasyon DNA'da oluşan kalıtsal değişimken, modifikasyon yalnızca fenotipi etkileyen ve döllere geçmeyen çevresel değişimdir."},{"q":"Saf döl (arı döl) kavramı neyi ifade eder?","steps":[{"t":"Tanımı","a":"homozigot birey","d":"Saf döl, belirli karakter için aynı alelleri taşıyan homozigot bireydir."},{"t":"Sonucu","a":"değişmez döl","d":"Kendi içinde üretildiğinde hep aynı özelliği veren döller verir."}],"ans":"Saf döl, bir karakter için homozigot olan ve kendileştiğinde hep aynı özelliği veren bireydir."}],"zor":[{"q":"Bir genin alelleri farklı olduğu hâlde fenotipin neden tek bir alel tarafından belirlenebildiğini açıklayınız.","steps":[{"t":"Heterozigot durum","a":"iki farklı alel","d":"Birey bir karakter için biri dominant biri resesif iki alel taşıyabilir."},{"t":"Baskınlık ilişkisi","a":"dominant maskeler","d":"Dominant alel, resesif alelin etkisini fenotipte örter (maskeler)."},{"t":"Sonuç","a":"tek alel görünür","d":"Bu yüzden heterozigotta yalnızca dominant alelin etkisi gözlenir."}],"ans":"Heterozigot bireyde dominant alel, resesif alelin etkisini maskelediği için fenotip yalnızca dominant alel tarafından belirlenir."},{"q":"Üreme hücrelerinin kromozom sayısının vücut hücrelerinin yarısı olmasının kalıtsal önemini açıklayınız.","steps":[{"t":"İndirgenme","a":"n kromozom","d":"Üreme hücreleri mayoz ile haploit (n) hâle gelir, kromozom sayısı yarılanır."},{"t":"Döllenme","a":"2n geri gelir","d":"Yumurta ve sperm birleşince kromozom sayısı tekrar diploite (2n) çıkar."},{"t":"Sonuç","a":"sabit kalır","d":"Böylece türün kromozom sayısı nesiller boyunca değişmeden korunur."}],"ans":"Üreme hücreleri haploit (n) olduğundan döllenmede tekrar 2n oluşur; böylece türün kromozom sayısı nesiller boyunca sabit kalır."},{"q":"Genotipi aynı olan iki bireyin fenotipinin farklı olabilmesini açıklayınız.","steps":[{"t":"Aynı genotip","a":"aynı aleller","d":"İki birey belirli karakter için tamamen aynı alelleri taşıyabilir."},{"t":"Çevre etkisi","a":"modifikasyon","d":"Sıcaklık, ışık ve beslenme gibi çevresel faktörler gen ifadesini değiştirir."},{"t":"Sonuç","a":"farklı fenotip","d":"Bu yüzden genotip aynı olsa da gözlenen fenotip farklılaşabilir."}],"ans":"Fenotip, genotip ile çevrenin ortak ürünüdür; aynı genotipli bireyler farklı çevre koşullarında farklı fenotipler (modifikasyon) gösterebilir."},{"q":"Mendel döneminde DNA bilinmediği hâlde kalıtım kurallarını nasıl bulabildiğini değerlendiriniz.","steps":[{"t":"Gözlem yöntemi","a":"fenotip sayımı","d":"Mendel, döllerin fenotiplerini titizlikle sayarak verileri kaydetti."},{"t":"İstatistik","a":"oranlar","d":"3:1 gibi tutarlı oranlar fark ederek matematiksel kurallar çıkardı."},{"t":"Çıkarım","a":"soyut faktör","d":"Görmediği hâlde özellikleri taşıyan 'faktörler' (genler) olduğunu öne sürdü."}],"ans":"Mendel, DNA'yı bilmeden döl fenotiplerini sayıp tutarlı oranlar bularak kalıtımın soyut 'faktörlerle' (genlerle) yürüdüğünü istatistiksel olarak çıkarmıştır."},{"q":"Bir karakter için saf döl iki bireyin çaprazlanmasında F₁ dölünün tamamı neden tek tip görünür?","steps":[{"t":"Ebeveyn yapısı","a":"AA × aa","d":"Saf döl ebeveynler homozigot dominant (AA) ve homozigot resesiftir (aa)."},{"t":"F₁ genotipi","a":"hepsi Aa","d":"Tüm yavrular birer alel alarak heterozigot (Aa) olur."},{"t":"Fenotip","a":"dominant görünür","d":"Heterozigotta dominant alel etkisini gösterdiği için hepsi aynı görünür."}],"ans":"AA × aa çaprazında F₁ dölünün tamamı Aa (heterozigot) olur; dominant alel etkisini gösterdiği için hepsi tek tip (dominant) fenotipte görünür."},{"q":"Otozomal ve eşey kromozomları kalıtım açısından karşılaştırınız.","steps":[{"t":"Otozomlar","a":"vücut karakterleri","d":"44 otozom, cinsiyetten bağımsız vücut özelliklerinin genlerini taşır."},{"t":"Eşey kromozomları","a":"cinsiyet + bağlı","d":"X ve Y kromozomları cinsiyeti ve eşeye bağlı karakterleri belirler."},{"t":"Kalıtım farkı","a":"eşey farkı","d":"Eşeye bağlı genler cinsiyete göre farklı oranlarda kalıtılır."}],"ans":"Otozomlar (44) cinsiyetten bağımsız karakterleri taşır; eşey kromozomları (XY) cinsiyeti belirler ve eşeye bağlı genleri cinsiyete göre farklı kalıtır."},{"q":"Kalıtsal bilginin DNA dizisinde 'şifreli' olarak saklanmasının ne anlama geldiğini açıklayınız.","steps":[{"t":"Dizilim","a":"baz sırası","d":"Bilgi, A, T, G, C bazlarının DNA üzerindeki sıralanışında saklanır."},{"t":"Kod","a":"üçlü baz","d":"Üçer baz bir aminoasidi kodlar, böylece protein bilgisi yazılır."},{"t":"Sonuç","a":"protein → özellik","d":"Bu şifre proteinleri belirler, proteinler de canlının özelliklerini oluşturur."}],"ans":"Kalıtsal bilgi, DNA'daki bazların (A, T, G, C) sırasında şifrelidir; üçlü baz dizileri proteinleri kodlar, proteinler de canlının özelliklerini belirler."},{"q":"Aynı türün bireyleri arasındaki kalıtsal çeşitliliğin (varyasyonun) kaynaklarını açıklayınız.","steps":[{"t":"Mayozda karışım","a":"gen ayrılması","d":"Mayozda kromozomların bağımsız dağılımı yeni gen kombinasyonları yaratır."},{"t":"Krossing over","a":"parça değişimi","d":"Homolog kromozomlar arasında parça değişimi alel kombinasyonunu artırır."},{"t":"Döllenme ve mutasyon","a":"yeni birleşim","d":"Rastgele döllenme ve mutasyonlar ek çeşitlilik sağlar."}],"ans":"Kalıtsal çeşitlilik; mayozdaki bağımsız dağılım, krossing-over, rastgele döllenme ve mutasyonların birlikte oluşturduğu yeni gen kombinasyonlarından kaynaklanır."},{"q":"Bir özelliğin kalıtsal mı yoksa çevresel mi olduğunu tek yumurta ikizleri ile nasıl araştırabiliriz?","steps":[{"t":"Aynı genotip","a":"ikizler","d":"Tek yumurta ikizleri tamamen aynı genotipi taşır."},{"t":"Farklı çevre","a":"ayrı ortam","d":"İkizler farklı çevrelerde yetiştirilirse genotip sabit, çevre değişken olur."},{"t":"Karşılaştırma","a":"fark = çevre","d":"Aralarındaki farklar çevreden, benzerlikler genden kaynaklanır."}],"ans":"Aynı genotipli tek yumurta ikizleri farklı çevrelerde incelendiğinde; benzerlikler kalıtsal, farklılıklar çevresel etkiyi gösterir."},{"q":"Kromozom sayısının türe özgü ve sabit olmasının kalıtsal önemini değerlendiriniz.","steps":[{"t":"Türe özgülük","a":"sabit sayı","d":"Her türün kendine has, belirli bir kromozom sayısı vardır."},{"t":"Korunma","a":"mayoz + döllenme","d":"Mayozla yarılanıp döllenmeyle birleşerek sayı nesiller boyu korunur."},{"t":"Önem","a":"tür kimliği","d":"Sabit kromozom sayısı, türün kalıtsal kimliğinin ve sürekliliğinin temelidir."}],"ans":"Kromozom sayısı türe özgü ve sabittir; mayoz ile döllenmenin dengesi bu sayıyı koruyarak türün kalıtsal sürekliliğini ve kimliğini sağlar."},{"q":"Gen, alel ve lokus kavramlarını birbiriyle ilişkilendirerek açıklayınız.","steps":[{"t":"Lokus","a":"genin adresi","d":"Lokus, bir genin kromozom üzerinde bulunduğu sabit konumdur."},{"t":"Gen ve alel","a":"konum / versiyon","d":"O konumdaki gen, farklı versiyonlar (aleller) hâlinde bulunabilir."},{"t":"İlişki","a":"aynı lokus","d":"Homolog kromozomların aynı lokusunda farklı aleller karşılıklı yer alır."}],"ans":"Lokus genin kromozomdaki sabit konumudur; o konumdaki gen farklı versiyonlara (alellere) sahiptir ve homolog kromozomların aynı lokusunda karşılıklı aleller bulunur."},{"q":"Klasik (Mendel) genetik ile moleküler genetiğin kalıtıma bakış açısı arasındaki temel farkı açıklayınız.","steps":[{"t":"Klasik genetik","a":"soyut faktör","d":"Mendel genetiği özellikleri görünmeyen 'faktörler' ve oranlarla açıklar."},{"t":"Moleküler genetik","a":"DNA düzeyi","d":"Moleküler genetik kalıtımı DNA, gen ifadesi ve protein düzeyinde inceler."},{"t":"İlişki","a":"tamamlayıcı","d":"Moleküler genetik, klasik genetiğin soyut faktörlerinin maddesel temelini açıklar."}],"ans":"Klasik genetik kalıtımı soyut faktörler ve oranlarla açıklarken, moleküler genetik aynı olayları DNA ve protein düzeyinde inceler; ikisi birbirini tamamlar."},{"q":"Bir bireyin fenotipinde gözlenmeyen bir özelliğin döllerinde ortaya çıkabilmesini açıklayınız.","steps":[{"t":"Taşıyıcılık","a":"gizli resesif","d":"Birey, fenotipinde görünmeyen bir resesif aleli heterozigot olarak taşıyabilir."},{"t":"İki taşıyıcı","a":"Aa × Aa","d":"İki taşıyıcı ebeveynden her ikisi de resesif aleli aktarabilir."},{"t":"Sonuç","a":"aa dölü","d":"Resesif alelleri bir araya gelen döl (aa) özelliği fenotipte gösterir."}],"ans":"Ebeveynler resesif aleli heterozigot (taşıyıcı) olarak taşıdığında fenotiplerinde görünmez; iki taşıyıcının dölünde aleller birleşip homozigot (aa) olunca özellik ortaya çıkar."},{"q":"Kalıtsal bilginin korunması ile çeşitliliğin sağlanması arasındaki dengenin canlılar için önemini değerlendiriniz.","steps":[{"t":"Korunma","a":"DNA eşlenmesi","d":"DNA'nın doğru kopyalanması türün temel bilgisini değişmeden aktarır."},{"t":"Çeşitlilik","a":"mayoz + mutasyon","d":"Mayoz ve mutasyonlar yeni kombinasyonlarla varyasyon yaratır."},{"t":"Denge","a":"uyum + süreklilik","d":"Korunma türün sürekliliğini, çeşitlilik ise değişen çevreye uyumu sağlar."}],"ans":"Kalıtsal bilginin korunması türün sürekliliğini, çeşitlilik ise değişen koşullara uyum ve evrimi sağlar; bu denge canlıların hem kararlı hem uyum yeteneğine sahip olmasının temelidir."},{"q":"İnsanlarda boy uzunluğu gibi bir özelliğin hem kalıtsal hem çevresel etkenlerle belirlenmesini açıklayınız.","steps":[{"t":"Kalıtsal temel","a":"çok genli","d":"Boy, birçok genin birlikte etki ettiği poligenik bir karakterdir."},{"t":"Çevresel etki","a":"beslenme, sağlık","d":"Beslenme, hastalık ve yaşam koşulları boy gelişimini etkiler."},{"t":"Sonuç","a":"ortak belirleme","d":"Genler potansiyel sınırı çizer, çevre bu sınır içinde sonucu belirler."}],"ans":"Boy poligenik kalıtsal bir özelliktir; genler potansiyel aralığı belirlerken beslenme ve sağlık gibi çevresel etkenler bu aralık içinde gerçek boyu belirler."}]}},"genotipFenotip":{"ilkokul":{"kolay":[{"q":"Bir canlının dışarıdan gördüğümüz özelliklerine ne ad verilir?","steps":[{"t":"Dışarıdan bak","a":"görünen özellik","d":"Saç rengi, göz rengi, boy gibi gözle görebildiğimiz özelliklerdir."},{"t":"Adını söyle","a":"fenotip","d":"Bir canlının dıştan görünen bu özelliklerinin tümüne fenotip denir."}],"ans":"Bir canlının dışarıdan görünen özelliklerine fenotip denir."},{"q":"Kahverengi gözlü bir çocuğun göz rengi fenotip midir genotip midir?","steps":[{"t":"Gözle görüyor muyuz?","a":"evet, görüyoruz","d":"Göz rengini bakınca herkes görebilir, yani dıştan bellidir."},{"t":"Karar ver","a":"fenotip","d":"Dıştan görünen özellik olduğu için bu bir fenotiptir."}],"ans":"Göz rengini gözle görebildiğimiz için bu özellik fenotiptir."},{"q":"Canlının içinde sakladığı, hangi özelliğe sahip olacağını belirleyen 'gizli talimata' ne denir?","steps":[{"t":"İçeride saklı","a":"görünmeyen yapı","d":"Bu talimat hücrenin içinde saklıdır, dıştan göremeyiz."},{"t":"Adını söyle","a":"genotip","d":"Canlının içinde sakladığı bu gizli kalıtsal yapıya genotip denir."}],"ans":"Canlının içinde sakladığı, özelliklerini belirleyen gizli yapıya genotip denir."},{"q":"İki kardeşin saç rengi neden farklı olabilir?","steps":[{"t":"Farklı talimat","a":"farklı genotip","d":"Her kardeş anne ve babadan farklı kalıtsal talimatlar alabilir."},{"t":"Sonuç","a":"farklı görünüş","d":"Farklı talimat aldıkları için saç renkleri (fenotip) farklı olur."}],"ans":"Kardeşler farklı kalıtsal talimat (genotip) aldıkları için saç renkleri farklı olabilir."},{"q":"Bir bitkinin uzun boylu görünmesi onun hangi özelliğidir?","steps":[{"t":"Görebiliyor muyuz?","a":"evet","d":"Bitkinin boyu dışarıdan bakınca kolayca görülebilir."},{"t":"Karar ver","a":"fenotip","d":"Dıştan görünen bir özellik olduğu için boy bir fenotiptir."}],"ans":"Bitkinin uzun boylu görünmesi onun fenotipidir, çünkü dıştan görülür."}],"zor":[{"q":"Bir çiçeğin kırmızı renkli açması fenotip, içindeki renk talimatı ise nedir?","steps":[{"t":"Görünen renk","a":"fenotip","d":"Kırmızı renk dışarıdan görüldüğü için fenotiptir."},{"t":"İçteki talimat","a":"genotip","d":"Çiçeğe 'kırmızı ol' diyen içteki gizli talimat ise genotiptir."}],"ans":"Kırmızı renk fenotip, çiçeğe rengi söyleyen içteki gizli talimat ise genotiptir."},{"q":"Aynı tür iki köpekten biri çok iyi besleniyor, diğeri az besleniyor. Boyları neden farklı olabilir?","steps":[{"t":"Talimat aynı olabilir","a":"genotip benzer","d":"İki köpek de iri olma talimatı taşıyor olabilir."},{"t":"Çevre etkisi","a":"beslenme farkı","d":"İyi beslenen köpek daha iyi büyür, az beslenen küçük kalabilir."}],"ans":"Genotipleri benzer olsa bile beslenme gibi çevre etkisiyle boyları (fenotip) farklı olabilir."},{"q":"Bir tohumdaki gizli talimat 'sarı çiçek' diyorsa, açacak çiçeğin rengi ne olur?","steps":[{"t":"Talimatı oku","a":"sarı talimat","d":"Tohumun içindeki genotip çiçeğe 'sarı ol' diyor."},{"t":"Sonuca bak","a":"sarı çiçek","d":"Talimat sarı olduğu için açan çiçek sarı görünür."}],"ans":"İçteki talimat sarı çiçek dediği için açan çiçeğin fenotipi de sarı olur."},{"q":"İkiz iki kedinin aynı talimatı (genotip) taşıması, görünüşlerinin tamamen aynı olmasını garanti eder mi?","steps":[{"t":"Talimat aynı","a":"aynı genotip","d":"İkizler içte aynı kalıtsal talimatı taşıyabilir."},{"t":"Çevre devrede","a":"farklı yaşam","d":"Biri farklı beslenir veya yaralanırsa görünüşü biraz değişebilir."}],"ans":"Hayır; talimat aynı olsa bile çevre etkisiyle görünüşleri (fenotip) biraz farklı olabilir."},{"q":"Anne ve babası kıvırcık saçlı bir çocuğun düz saçlı olması neyi gösterir?","steps":[{"t":"Talimat çeşitli","a":"gizli talimatlar","d":"Anne ve baba kıvırcık görünse de içlerinde düz saç talimatı saklı olabilir."},{"t":"Çocuğa geçen","a":"düz talimat","d":"Çocuk bu gizli talimatları alırsa saçı düz görünür."}],"ans":"Ebeveynlerin içinde saklı kalan talimatların çocuğa geçmesiyle çocuk farklı (düz saçlı) görünebilir."}]},"ortaokul":{"kolay":[{"q":"Genotip ve fenotip kavramlarını kısaca tanımlayınız.","steps":[{"t":"Genotip","a":"kalıtsal yapı","d":"Genotip, bir canlının taşıdığı genlerin (kalıtsal bilginin) tümüdür."},{"t":"Fenotip","a":"görünen özellik","d":"Fenotip, bu genlerin dışa yansıyan gözlenebilir özellikleridir."}],"ans":"Genotip canlının kalıtsal yapısı (genleri), fenotip ise bu yapının dışa yansıyan görünen özellikleridir."},{"q":"Alel nedir? Kısaca açıklayınız.","steps":[{"t":"Genin çeşidi","a":"bir genin farklı hali","d":"Bir özelliği belirleyen genin farklı biçimlerine alel denir."},{"t":"Örnek","a":"uzun/kısa alel","d":"Boy geninin 'uzun' ve 'kısa' biçimleri birer aleldir."}],"ans":"Alel, bir geni oluşturan ve aynı özelliğin farklı biçimlerini belirleyen gen çeşididir."},{"q":"Baskın alel ile çekinik alel arasındaki temel fark nedir?","steps":[{"t":"Baskın alel","a":"etkisini gösterir","d":"Tek başına bile fenotipte kendini gösteren aleldir, büyük harfle yazılır."},{"t":"Çekinik alel","a":"baskılanır","d":"Yanında baskın alel varsa etkisini gösteremez, küçük harfle yazılır."}],"ans":"Baskın alel tek başına bile fenotipte görülürken, çekinik alel ancak yanında baskın alel yoksa görülür."},{"q":"Fenotipi belirleyen iki temel etken nedir?","steps":[{"t":"İçten gelen","a":"genotip","d":"Canlının taşıdığı genler fenotipin temelini belirler."},{"t":"Dıştan gelen","a":"çevre","d":"Beslenme, ışık, sıcaklık gibi çevre koşulları da fenotipi etkiler."}],"ans":"Fenotip, hem canlının genotipi hem de yaşadığı çevre koşulları tarafından belirlenir."},{"q":"AA ve Aa genotipli iki birey neden aynı fenotipe sahip olabilir?","steps":[{"t":"Baskın alel var","a":"her ikisinde A","d":"İki bireyde de baskın olan A aleli bulunur."},{"t":"Baskın etkiyi gösterir","a":"aynı görünüş","d":"Baskın alel etkisini gösterdiği için ikisi de aynı fenotipte olur."}],"ans":"Hem AA hem Aa baskın A aleli taşıdığı için baskın özelliği gösterir; bu yüzden fenotipleri aynı olur."}],"zor":[{"q":"Bir özellik için saf döl (AA) ile melez (Aa) birey aynı görünüyorsa, genotiplerini ayırt etmek için ne yapılabilir?","steps":[{"t":"Sorun","a":"fenotip aynı","d":"AA ve Aa baskın alel taşıdığı için dıştan aynı görünür."},{"t":"Yöntem","a":"çekinikle çaprazla","d":"Bireyi çekinik (aa) bir bireyle çaprazlarız (kontrol çaprazlaması)."},{"t":"Yorum","a":"yavrulara bak","d":"Yavrularda çekinik özellik çıkarsa birey melez (Aa), çıkmazsa saftır (AA)."}],"ans":"Birey çekinik (aa) bireyle çaprazlanır; yavrularda çekinik özellik görülürse genotip Aa, görülmezse AA'dır."},{"q":"Aynı genotipe sahip iki bitkiden biri güneşte iri, diğeri gölgede cılız büyümüştür. Bu durumu açıklayınız.","steps":[{"t":"Genotip aynı","a":"kalıtsal yapı eşit","d":"İki bitki de aynı büyüme potansiyelini taşıyan genleri içerir."},{"t":"Çevre farklı","a":"ışık miktarı","d":"Biri bol ışık alırken diğeri gölgede az ışık almıştır."},{"t":"Sonuç","a":"fenotip değişir","d":"Genotip aynı olsa da çevre farkı fenotipi (boy/iri) değiştirir."}],"ans":"Genotipleri aynı olsa da farklı çevre (ışık) koşulları nedeniyle fenotipleri (iri/cılız) farklı olmuştur."},{"q":"Aa genotipli bir bireyde çekinik alel neden fenotipte görünmez?","steps":[{"t":"İki alel var","a":"A ve a","d":"Birey biri baskın (A), biri çekinik (a) iki alel taşır."},{"t":"Baskınlık ilkesi","a":"A baskılar","d":"Baskın A aleli, çekinik a alelinin etkisini örter."},{"t":"Sonuç","a":"baskın fenotip","d":"Bu yüzden bireyde yalnızca baskın özellik gözlenir."}],"ans":"Aa bireyde baskın A aleli çekinik a alelinin etkisini örttüğü için fenotipte yalnızca baskın özellik görünür, çekinik alel gizli kalır."},{"q":"Tavşanların kürk rengini hem genotip hem sıcaklık etkiliyorsa, soğuk uçların koyu olması neyi gösterir?","steps":[{"t":"Genotip rol","a":"renk potansiyeli","d":"Tavşanın geni koyu renk üretebilme yeteneği verir."},{"t":"Sıcaklık etkisi","a":"soğukta aktif","d":"Renk üreten enzim yalnızca soğuk bölgelerde (kulak, ayak) çalışır."},{"t":"Sonuç","a":"genotip + çevre","d":"Bu yüzden uçlar koyu, sıcak gövde açık renk olur."}],"ans":"Bu durum fenotipin sadece genotiple değil, sıcaklık gibi çevre faktörüyle birlikte belirlendiğini gösterir."},{"q":"İki farklı genotip (AA ve Aa) nasıl olur da aynı fenotipi, iki aynı genotip (aa ve aa) ise farklı fenotipi verebilir?","steps":[{"t":"Aynı fenotip","a":"baskınlık","d":"AA ve Aa baskın alel taşıdığından ikisi de baskın fenotibi gösterir."},{"t":"Farklı fenotip","a":"çevre etkisi","d":"İki aa birey aynı genotipte olsa da farklı çevrede farklı görünebilir."},{"t":"Sonuç","a":"ilişki tek yönlü değil","d":"Genotip-fenotip ilişkisi hem baskınlık hem çevreyle şekillenir."}],"ans":"Baskınlık nedeniyle farklı genotipler (AA, Aa) aynı fenotibi verebilir; çevre etkisiyle de aynı genotipler (aa, aa) farklı fenotip gösterebilir."}]},"lise":{"kolay":[{"q":"Genotip kavramını akademik olarak tanımlayınız.","steps":[{"t":"Kalıtsal içerik","a":"alel takımı","d":"Genotip, bir bireyin bir özellik ya da tüm özellikler için taşıdığı alellerin toplamıdır."},{"t":"Kalıtsal temel","a":"DNA'da kodlu","d":"Bu bilgi DNA üzerindeki genlerde kodlanmış olarak bulunur."}],"ans":"Genotip, bir bireyin DNA'sında kodlanmış ve özelliklerini belirleyen alellerin (kalıtsal yapının) tümüdür."},{"q":"Fenotip kavramını ve onu belirleyen etkenleri açıklayınız.","steps":[{"t":"Tanım","a":"gözlenen özellik","d":"Fenotip, bir bireyin morfolojik, fizyolojik ve davranışsal gözlenebilir özellikleridir."},{"t":"Belirleyiciler","a":"genotip + çevre","d":"Fenotip, genotip ile çevre koşullarının ortak etkisiyle ortaya çıkar."}],"ans":"Fenotip, bireyin gözlenebilen özelliklerinin tümüdür ve genotip ile çevrenin etkileşimi sonucu oluşur."},{"q":"'Fenotip = genotip + çevre' ifadesinin anlamını açıklayınız.","steps":[{"t":"Genotip katkısı","a":"potansiyel","d":"Genotip, özelliğin sınırlarını ve potansiyelini belirler."},{"t":"Çevre katkısı","a":"ifade düzeyi","d":"Çevre, bu potansiyelin ne ölçüde ifade edileceğini belirler."}],"ans":"Bu ifade, gözlenen özelliğin (fenotip) hem kalıtsal yapı (genotip) hem de çevre koşullarının birlikte etkisiyle oluştuğunu anlatır."},{"q":"Homozigot ve heterozigot genotipleri tanımlayınız.","steps":[{"t":"Homozigot","a":"aynı aleller","d":"Bir özellik için iki aynı aleli taşıyan bireydir (AA veya aa)."},{"t":"Heterozigot","a":"farklı aleller","d":"Bir özellik için biri baskın biri çekinik farklı alel taşıyan bireydir (Aa)."}],"ans":"Homozigot birey aynı alelleri (AA/aa), heterozigot birey ise farklı alelleri (Aa) taşır."},{"q":"Baskın bir alel fenotipe nasıl yansır?","steps":[{"t":"Baskın etki","a":"tek doz yeter","d":"Baskın alel, ister homozigot ister heterozigot olsun etkisini gösterir."},{"t":"Fenotip sonucu","a":"baskın özellik","d":"Bu nedenle AA ve Aa bireyler aynı baskın fenotipi sergiler."}],"ans":"Baskın alel tek bir kopya halinde bile (Aa) fenotipte etkisini gösterir; bu yüzden hem AA hem Aa baskın özelliği yansıtır."},{"q":"Çekinik bir alel fenotipte hangi koşulda görünür?","steps":[{"t":"Baskı koşulu","a":"baskın yokken","d":"Çekinik alel ancak yanında baskın alel bulunmadığında ifade edilir."},{"t":"Genotip şartı","a":"homozigot resesif","d":"Bu da yalnızca aa (homozigot çekinik) genotipinde gerçekleşir."}],"ans":"Çekinik alel yalnızca homozigot çekinik (aa) genotipte, yani yanında baskın alel yokken fenotipe yansır."},{"q":"Aynı fenotip neden farklı genotiplerden kaynaklanabilir? Bir örnek veriniz.","steps":[{"t":"Baskınlık nedeni","a":"baskın örter","d":"Baskın alel çekinik alelin etkisini örttüğü için fark gizlenir."},{"t":"Örnek","a":"AA ve Aa","d":"Mor çiçek fenotipi hem AA hem Aa genotipinden çıkabilir."}],"ans":"Baskın alel çekinik alelin etkisini örttüğü için AA ve Aa gibi farklı genotipler aynı baskın fenotibi verebilir."},{"q":"Genotip ve fenotip ilişkisinde 'bire bir karşılık yoktur' ifadesi neyi anlatır?","steps":[{"t":"Tek genotip-çok fenotip","a":"çevre etkisi","d":"Aynı genotip farklı çevrelerde farklı fenotip verebilir."},{"t":"Çok genotip-tek fenotip","a":"baskınlık","d":"Farklı genotipler baskınlık nedeniyle aynı fenotibi gösterebilir."}],"ans":"Genotip ile fenotip arasında birebir karşılık yoktur; çünkü çevre ve baskınlık nedeniyle aynı genotip farklı, farklı genotipler aynı fenotibi verebilir."},{"q":"Saf döl (arı döl) terimi genotip açısından ne ifade eder?","steps":[{"t":"Genotip durumu","a":"homozigot","d":"Saf döl, ilgili özellik için aynı alelleri taşıyan homozigot bireydir."},{"t":"Döl özelliği","a":"sabit fenotip","d":"Kendi içinde döllendiğinde hep aynı fenotipte yavru verir."}],"ans":"Saf döl, bir özellik bakımından homozigot (AA veya aa) olan ve kendi içinde hep aynı fenotipte döl veren bireydir."},{"q":"Genotipi yazarken baskın ve çekinik aleller nasıl gösterilir?","steps":[{"t":"Baskın gösterim","a":"büyük harf","d":"Baskın alel büyük harfle gösterilir, örneğin A."},{"t":"Çekinik gösterim","a":"küçük harf","d":"Çekinik alel aynı harfin küçüğüyle gösterilir, örneğin a."}],"ans":"Baskın alel büyük harfle (A), çekinik alel aynı harfin küçüğüyle (a) gösterilir; genotip bu iki alelin birleşimiyle yazılır."},{"q":"Çevrenin fenotipe etkisine bir örnek veriniz.","steps":[{"t":"Genotip sabit","a":"aynı kalıtsal yapı","d":"Örneğin ortanca bitkisinin genotipi belirli renk potansiyeli taşır."},{"t":"Çevre etkisi","a":"toprak pH'si","d":"Asidik toprakta çiçek mavi, bazik toprakta pembe açar."}],"ans":"Ortanca bitkisi aynı genotipte olsa da toprak pH'sine göre çiçeğini mavi ya da pembe açar; bu çevrenin fenotipe etkisidir."},{"q":"Genotip neden 'fenotipin potansiyel sınırını' belirler?","steps":[{"t":"Üst sınır","a":"genetik tavan","d":"Genotip, bir özelliğin ulaşabileceği en yüksek değeri belirler."},{"t":"Çevre rolü","a":"sınır içinde","d":"Çevre, fenotipi bu sınırlar içinde aşağı veya yukarı kaydırır."}],"ans":"Genotip özelliğin ulaşabileceği potansiyel aralığı (sınırı) belirler; çevre ise fenotipi bu sınırların içinde şekillendirir."},{"q":"Bir bireyin fenotipinden genotipi her zaman kesin olarak anlaşılabilir mi?","steps":[{"t":"Baskın fenotip","a":"belirsiz","d":"Baskın fenotipli bir birey AA veya Aa olabilir, ayırt edilemez."},{"t":"Çekinik fenotip","a":"kesin","d":"Çekinik fenotipli birey ise kesinlikle aa genotipindedir."}],"ans":"Hayır; çekinik fenotipten genotip (aa) kesin anlaşılırken, baskın fenotipli birey AA mı Aa mı olduğu doğrudan anlaşılamaz."},{"q":"Eş baskınlık (kodominantlık) genotip-fenotip ilişkisini nasıl değiştirir?","steps":[{"t":"Klasik baskınlık","a":"biri örter","d":"Klasik durumda baskın alel çekiniği tamamen örter."},{"t":"Eş baskınlık","a":"ikisi de görünür","d":"Eş baskın alellerin her ikisi de fenotipte ayrı ayrı görülür."}],"ans":"Eş baskınlıkta heterozigot bireyde her iki alel de fenotipe ayrı ayrı yansır; örneğin AB kan grubunda hem A hem B antijeni görülür."},{"q":"Bir özelliğin gen tarafından mı yoksa yalnızca çevre tarafından mı belirlendiği nasıl anlaşılır?","steps":[{"t":"Kalıtsallık testi","a":"yavruya geçer mi","d":"Özellik döllere aktarılıyorsa kalıtsal (genotip kaynaklı) demektir."},{"t":"Çevre testi","a":"koşul değişince","d":"Yalnızca çevreyle ortaya çıkıyor ve aktarılmıyorsa modifikasyondur."}],"ans":"Özellik döllere aktarılıyorsa genotip kaynaklıdır; yalnızca çevre koşullarıyla ortaya çıkıp sonraki döle geçmiyorsa yalnızca çevre etkisindedir (modifikasyon)."}],"zor":[{"q":"Norm of reaction (tepki normu) kavramını genotip-fenotip ilişkisi açısından açıklayınız.","steps":[{"t":"Tanım","a":"genotipin tepki yelpazesi","d":"Bir genotipin farklı çevrelerde verdiği tüm fenotiplerin aralığıdır."},{"t":"Çevre değişimi","a":"fenotip değişir","d":"Aynı genotip farklı çevre koşullarında farklı fenotipler üretir."},{"t":"Sonuç","a":"sabit değil","d":"Bu yüzden bir genotip tek bir fenotipe değil, bir fenotip aralığına karşılık gelir."}],"ans":"Tepki normu, belirli bir genotipin farklı çevre koşullarında ortaya koyduğu fenotip aralığıdır; bu, genotipin tek değil bir yelpaze fenotip ürettiğini gösterir."},{"q":"Aynı genotipli iki bireyin tepki normu farklı çevrelerde nasıl farklı fenotipler verir? Bir grafik mantığıyla açıklayınız.","steps":[{"t":"Eksenler","a":"çevre-fenotip","d":"Yatay eksen çevre koşulu, dikey eksen ölçülen fenotip değeridir."},{"t":"Eğri okuma","a":"her noktaya fenotip","d":"Genotipin eğrisi, her çevre değerine karşılık gelen fenotibi gösterir."},{"t":"Yorum","a":"eğri düz değilse plastik","d":"Eğri dik değişiyorsa genotip çevreye duyarlı (plastik) demektir."}],"ans":"Tepki normu grafiğinde her çevre değerine bir fenotip karşılık gelir; eğri dik değişiyorsa o genotip çevreye duyarlıdır ve farklı çevrelerde belirgin farklı fenotipler verir."},{"q":"Fenotipik plastisite nedir ve neden bazı genotipler diğerlerinden daha plastiktir?","steps":[{"t":"Tanım","a":"çevreye fenotip uyumu","d":"Fenotipik plastisite, bir genotipin çevreye göre fenotibini değiştirebilme yeteneğidir."},{"t":"Farklılık nedeni","a":"genetik düzenleme","d":"Gen ifadesinin çevreye duyarlı düzenlenmesi plastisiteyi belirler."},{"t":"Sonuç","a":"esnek vs sabit","d":"Bazı genotiplerin tepki normu diktir (plastik), bazılarınınki düzdür (kararlı)."}],"ans":"Fenotipik plastisite, bir genotipin çevreye göre farklı fenotipler üretebilme yeteneğidir; gen ifadesinin çevreye duyarlılığı farklı olduğu için bazı genotipler daha plastiktir."},{"q":"Çoklu alelli bir özellikte (örneğin ABO kan grubu) genotip-fenotip ilişkisini açıklayınız.","steps":[{"t":"Alel havuzu","a":"üç alel","d":"Popülasyonda A, B (eş baskın) ve O (çekinik) olmak üzere üç alel vardır."},{"t":"Birey iki alel taşır","a":"genotip çiftleri","d":"Bir birey bu alellerden ikisini taşır: örneğin AB, AO, BB, OO."},{"t":"Fenotip eşlemesi","a":"baskınlık+eş baskınlık","d":"AO ve AA → A grubu; AB → AB grubu; OO → O grubu fenotibini verir."}],"ans":"ABO sisteminde üç alel (A, B eş baskın; O çekinik) bulunur; birey iki alel taşır ve baskınlık ile eş baskınlık kurallarına göre AO/AA→A, AB→AB, OO→O fenotipi ortaya çıkar."},{"q":"Eksik baskınlık durumunda heterozigot genotipin fenotibi neden ara bir değerdir?","steps":[{"t":"Alel etkisi","a":"hiçbiri tam baskın değil","d":"Eksik baskınlıkta hiçbir alel diğerini tam olarak örtemez."},{"t":"Ürün miktarı","a":"yarı doz pigment","d":"Heterozigot birey baskın alel ürününün yarısını üretir."},{"t":"Sonuç","a":"ara fenotip","d":"Bu nedenle kırmızı × beyaz çiçekten pembe gibi ara fenotip çıkar."}],"ans":"Eksik baskınlıkta alellerden hiçbiri diğerini tam örtemez; heterozigot birey ürünün yarısını oluşturduğu için fenotip iki saf döl arasında ara bir değer (örneğin pembe) olur."},{"q":"Pleiotropi (çok etkili gen) genotip-fenotip ilişkisini nasıl karmaşıklaştırır?","steps":[{"t":"Tanım","a":"tek gen çok etki","d":"Pleiotropide tek bir gen birden çok farklı fenotipik özelliği etkiler."},{"t":"Mekanizma","a":"ortak ürün","d":"Genin kodladığı protein birçok dokuda ve süreçte rol alır."},{"t":"Sonuç","a":"çoklu fenotip","d":"Bu nedenle tek genotip değişimi birden fazla özellikte değişiklik yapar."}],"ans":"Pleiotropide tek bir gen birden çok özelliği etkilediği için tek bir genotipik değişiklik birçok fenotipik özellikte değişime yol açar; bu da genotip-fenotip ilişkisini doğrusal olmaktan çıkarır."},{"q":"Poligenik kalıtımda fenotipin sürekli (kesintisiz) dağılım göstermesinin nedeni nedir?","steps":[{"t":"Çok gen katkısı","a":"birikimli etki","d":"Boy, deri rengi gibi özellikleri birçok gen birlikte belirler."},{"t":"Alel toplamı","a":"derecelenme","d":"Etkili alellerin sayısı arttıkça fenotip değeri kademeli artar."},{"t":"Çevre eklenir","a":"süreklilik","d":"Çevre etkisi de eklenince ara değerler dolar ve dağılım sürekli olur."}],"ans":"Poligenik özelliklerde birçok genin birikimli etkisi ve çevrenin katkısı, fenotibin kesintisiz (boy gibi sürekli) bir dağılım göstermesine yol açar."},{"q":"Bir genotipin penetransı (yansıma oranı) ve ekspresivitesi fenotibi nasıl etkiler?","steps":[{"t":"Penetrans","a":"yansıma oranı","d":"Belirli genotipi taşıyanlardan kaçında özelliğin görüldüğüdür."},{"t":"Ekspresivite","a":"yansıma şiddeti","d":"Özelliğin görülen bireylerde ne kadar şiddetli ifade edildiğidir."},{"t":"Sonuç","a":"değişken fenotip","d":"Aynı genotip kimi bireyde hiç, kiminde hafif, kiminde güçlü görülebilir."}],"ans":"Penetrans bir genotipi taşıyanlardan kaçında özelliğin göründüğünü, ekspresivite ise göründüğünde ne kadar şiddetli olduğunu belirler; bu yüzden aynı genotip farklı bireylerde farklı fenotipler verebilir."},{"q":"Tek yumurta ikizlerinin (aynı genotip) zamanla farklı fenotipler geliştirmesi neyi kanıtlar?","steps":[{"t":"Başlangıç","a":"özdeş genotip","d":"Tek yumurta ikizleri başlangıçta aynı kalıtsal yapıyı taşır."},{"t":"Yaşam farkı","a":"çevre + epigenetik","d":"Farklı beslenme, alışkanlık ve epigenetik değişimler birikir."},{"t":"Sonuç","a":"fenotip ayrışır","d":"Zamanla kilo, hastalık riski gibi fenotiplerde farklar oluşur."}],"ans":"Aynı genotipe rağmen ikizlerin farklı fenotipler geliştirmesi, fenotibin yalnızca genotiple değil çevre ve epigenetik etkilerle de belirlendiğini kanıtlar."},{"q":"Sıcaklığa duyarlı enzim (örneğin Himalaya tavşanı/Siyam kedisi) örneğinde genotip-çevre etkileşimini açıklayınız.","steps":[{"t":"Genotip","a":"pigment geni var","d":"Hayvan koyu pigment üreten enzimin genini taşır."},{"t":"Çevre koşulu","a":"sıcaklığa bağlı enzim","d":"Bu enzim yalnızca düşük sıcaklıkta aktif, yüksek sıcaklıkta inaktiftir."},{"t":"Sonuç","a":"bölgesel renk","d":"Soğuk uçlar (kulak, ayak, burun) koyu, sıcak gövde açık renk olur."}],"ans":"Hayvan koyu pigment genini taşısa da enzim yalnızca soğukta aktif olduğundan vücudun soğuk uç bölgeleri koyu, sıcak bölgeleri açık renk olur; bu, fenotibin genotip ile sıcaklık etkileşimiyle belirlendiğini gösterir."},{"q":"Çevresel etkiyle oluşan modifikasyonlar neden sonraki döllere aktarılmaz?","steps":[{"t":"Etkilenen yapı","a":"sadece fenotip","d":"Modifikasyon yalnızca bireyin görünümünü (fenotip) değiştirir."},{"t":"DNA durumu","a":"genotip değişmez","d":"Üreme hücrelerindeki DNA dizisi (genotip) değişmemiştir."},{"t":"Sonuç","a":"aktarılmaz","d":"Kalıtsal bilgi değişmediğinden modifikasyon yavrulara geçmez."}],"ans":"Modifikasyonlar yalnızca fenotibi etkiler, üreme hücrelerindeki DNA (genotip) değişmediği için sonraki döllere aktarılmaz."},{"q":"Aynı genotipin iki farklı çevrede en yüksek ve en düşük fenotip verdiği duruma 'optimum çevre' kavramıyla yaklaşınız.","steps":[{"t":"Tepki normu","a":"çevreye bağlı eğri","d":"Genotipin fenotibi çevre koşuluna göre bir eğri çizer."},{"t":"Optimum nokta","a":"en yüksek fenotip","d":"Eğrinin tepe yaptığı çevre, o genotip için optimum koşuldur."},{"t":"Uç koşullar","a":"fenotip düşer","d":"Optimumdan uzaklaşan çevrede (çok sıcak/soğuk) fenotip değeri azalır."}],"ans":"Bir genotipin tepki normunda fenotibin en yüksek olduğu çevre 'optimum çevre'dir; bu noktadan uzaklaştıkça aynı genotip daha düşük fenotip verir, yani fenotip çevreyle değişen bir tepkidir."},{"q":"İki bireyin fenotipleri aynı olduğu halde çaprazlama sonuçları farklı çıkıyorsa bunun genotipik açıklaması nedir?","steps":[{"t":"Aynı fenotip","a":"baskın özellik","d":"İki birey de aynı baskın fenotibi gösteriyor olabilir."},{"t":"Gizli fark","a":"AA vs Aa","d":"Biri homozigot (AA), diğeri heterozigot (Aa) olabilir."},{"t":"Çapraz sonucu","a":"çekinik döl","d":"Heterozigot birey çaprazda çekinik fenotipli yavru verebilir, diğeri vermez."}],"ans":"Aynı baskın fenotipli iki bireyden biri AA, diğeri Aa olabilir; gizli çekinik aleli taşıyan heterozigot birey çaprazlamada çekinik fenotipli döl verdiği için sonuçlar farklı çıkar."},{"q":"Genotip-fenotip ilişkisinde gen-çevre etkileşimi (G×E) ile gen-çevre kovaryansı arasındaki farkı açıklayınız.","steps":[{"t":"G×E etkileşimi","a":"çevreye farklı tepki","d":"Farklı genotipler aynı çevre değişimine farklı fenotip tepkisi verir."},{"t":"G-E kovaryansı","a":"genotip-çevre eşleşmesi","d":"Belirli genotiplerin belirli çevrelerle birlikte bulunma eğilimidir."},{"t":"Ayrım","a":"tepki vs dağılım","d":"Biri tepkinin biçimini, diğeri genotip ile çevrenin birlikte dağılımını anlatır."}],"ans":"G×E etkileşimi farklı genotiplerin aynı çevre değişimine farklı fenotipik tepki vermesidir; gen-çevre kovaryansı ise belirli genotiplerin belirli çevrelerle birlikte bulunma eğilimidir; biri tepki biçimini, diğeri birlikte dağılımı ifade eder."},{"q":"'Kalıtsallık (heritabilite) yüksekse fenotip çevreden bağımsızdır' yargısı neden yanlıştır?","steps":[{"t":"Kalıtsallık tanımı","a":"varyansın oranı","d":"Heritabilite, bir popülasyondaki fenotip varyansının genetik kaynaklı oranıdır."},{"t":"Popülasyona özgü","a":"mutlak değil","d":"Bu oran belirli popülasyon ve çevre için geçerlidir, evrensel değildir."},{"t":"Çevre hâlâ etkili","a":"birey düzeyi","d":"Yüksek heritabilite bile bireyin fenotibinin çevreden etkilenmediğini göstermez."}],"ans":"Heritabilite bir popülasyondaki fenotip farklılığının genetik oranını verir; belirli koşullara özgüdür ve bireyin fenotibinin çevreden etkilenmediği anlamına gelmez, bu yüzden yargı yanlıştır."}]}},"homozigotHeterozigot":{"ilkokul":{"kolay":[{"q":"Bir çiçeğin iki kalıtım harfi de aynı (AA) ise buna ne denir? Sade anlat.","steps":[{"t":"Harflere bak","a":"ikisi de aynı","d":"AA yazılışında her iki harf de büyük A, yani birbirinin aynısıdır."},{"t":"Adını söyle","a":"saf (arı döl)","d":"İki harfi aynı olan canlıya saf yani <b>arı döl</b> denir."}],"ans":"İki kalıtım harfi de aynı olan (AA) canlıya saf, yani arı döl denir."},{"q":"Bir bezelyenin harfleri farklı (Aa) ise buna ne denir? Kısaca açıkla.","steps":[{"t":"Harflere bak","a":"biri büyük biri küçük","d":"Aa yazılışında bir harf büyük A, diğeri küçük a, yani farklıdır."},{"t":"Adını söyle","a":"melez","d":"İki harfi farklı olan canlıya <b>melez</b> denir."}],"ans":"İki kalıtım harfi farklı olan (Aa) canlıya melez denir."},{"q":"AA ve aa harfleri için 'aynı mı farklı mı' diye söyle.","steps":[{"t":"AA'ya bak","a":"aynı","d":"AA'da iki harf de A olduğu için harfler aynıdır."},{"t":"aa'ya bak","a":"aynı","d":"aa'da iki harf de küçük a olduğu için harfler yine aynıdır."}],"ans":"Hem AA hem aa harfleri kendi içinde aynıdır; ikisi de saf (arı döl) sayılır."},{"q":"Aşağıdakilerden hangisi melezdir: AA, Aa, aa? Seç ve söyle.","steps":[{"t":"Aynıları ele","a":"AA ve aa","d":"AA ve aa harfleri kendi içinde aynı olduğu için saftır, melez değildir."},{"t":"Farklıyı bul","a":"Aa","d":"Sadece Aa'da harfler farklı olduğu için melez odur."}],"ans":"Bunlardan sadece Aa melezdir; AA ile aa ise saftır."},{"q":"Saf bir bitki kendi gibi başka saf bir bitkiyle eşleşirse yavruları nasıl olur? Sade düşün.","steps":[{"t":"Anne baba aynı","a":"ikisi de AA","d":"İki ebeveyn de saf ve aynı (AA) ise hepsinin harfi A'dır."},{"t":"Yavruyu düşün","a":"yine AA","d":"Yavru anneden A, babadan A alır, yani yine AA olur."}],"ans":"İki saf bitki (AA × AA) eşleşince yavrular da anne baba gibi saf (AA) olur."}],"zor":[{"q":"AA, Aa, aa için her birinin 'saf mı melez mi' olduğunu ayır.","steps":[{"t":"Saf olanları seç","a":"AA ve aa","d":"AA ve aa'da iki harf aynı olduğu için bunlar saftır (arı döl)."},{"t":"Melezi seç","a":"Aa","d":"Aa'da harfler farklı olduğu için bu melezdir."}],"ans":"AA ve aa saftır; Aa ise melezdir."},{"q":"Saf siyah (BB) ve melez siyah (Bb) bir tavşanın harfleri neden farklıdır?","steps":[{"t":"BB'ye bak","a":"iki harf aynı","d":"Saf tavşanda iki harf de büyük B'dir, yani aynıdır."},{"t":"Bb'ye bak","a":"iki harf farklı","d":"Melez tavşanda bir harf büyük B, diğeri küçük b'dir, yani farklıdır."}],"ans":"Saf tavşanın (BB) harfleri aynı, melez tavşanın (Bb) harfleri farklı olduğu için yapıları farklıdır."},{"q":"Bir bitki melez (Aa) ise hangi harfleri yavrularına verebilir? Düşünerek söyle.","steps":[{"t":"Harfleri ayır","a":"A ve a","d":"Melez bitkinin bir harfi A, diğeri a'dır."},{"t":"Verebileceğini bul","a":"ya A ya a","d":"Bitki yavrusuna bu harflerden ya A'yı ya da a'yı verebilir."}],"ans":"Melez bir bitki (Aa) yavrusuna iki farklı harf verebilir: ya A ya da a."},{"q":"Saf bir bitki (AA) yavrularına hangi harfi verir? Melezden farkı nedir?","steps":[{"t":"Saf bitkiyi düşün","a":"sadece A","d":"AA bitkisinin iki harfi de A olduğu için sadece A verebilir."},{"t":"Melezle karşılaştır","a":"melez iki harf verir","d":"Melez (Aa) ise hem A hem a verebilirken saf tek çeşit harf verir."}],"ans":"Saf bitki (AA) sadece tek çeşit harf (A) verirken, melez (Aa) iki farklı harf (A ya da a) verebilir."},{"q":"İki melez siyah tavşan (Bb × Bb) eşleşirse beyaz (bb) yavru çıkabilir mi? Neden?","steps":[{"t":"Harfleri yaz","a":"ikisi de Bb","d":"Her iki tavşan da bir B ve bir b harfi taşır."},{"t":"Yavruyu düşün","a":"bb mümkün","d":"Bir yavru anneden b, babadan b alırsa harfleri bb olur ve beyaz görünür."}],"ans":"Evet çıkabilir; iki melez (Bb) tavşandan birer b harfi gelirse yavru bb (beyaz) olabilir."}]},"ortaokul":{"kolay":[{"q":"Homozigot ve heterozigot kavramlarını kısaca tanımlayınız.","steps":[{"t":"Homozigot","a":"aynı genler","d":"Bir özellik için iki geni de aynı olan canlıya homozigot (saf, arı döl) denir."},{"t":"Heterozigot","a":"farklı genler","d":"İki geni farklı olan canlıya heterozigot (melez) denir."}],"ans":"Homozigot, bir özellik için iki geni aynı (AA veya aa) olan; heterozigot ise iki geni farklı (Aa) olan canlıdır."},{"q":"AA, Aa ve aa genotiplerini homozigot ve heterozigot olarak sınıflandırınız.","steps":[{"t":"Homozigotları seç","a":"AA ve aa","d":"AA ve aa'da iki gen de aynı olduğu için bunlar homozigottur."},{"t":"Heterozigotu seç","a":"Aa","d":"Aa'da genler farklı olduğu için bu heterozigottur."}],"ans":"AA ve aa homozigot (saf), Aa ise heterozigottur (melez)."},{"q":"Baskın homozigot ile çekinik homozigot arasındaki fark nedir?","steps":[{"t":"Baskın homozigot","a":"AA","d":"İki geni de baskın olan (AA) bireydir, baskın özelliği gösterir."},{"t":"Çekinik homozigot","a":"aa","d":"İki geni de çekinik olan (aa) bireydir, çekinik özelliği gösterir."}],"ans":"Baskın homozigot AA olup baskın özelliği, çekinik homozigot aa olup çekinik özelliği gösterir."},{"q":"Heterozigot (Aa) bir bireyde hangi özellik görülür, neden?","steps":[{"t":"Genleri belirle","a":"A baskın, a çekinik","d":"Heterozigotta bir baskın (A) bir çekinik (a) gen bulunur."},{"t":"Hangisi görünür","a":"baskın olan","d":"Baskın gen, çekinik genin etkisini örttüğü için onun özelliği görülür."}],"ans":"Heterozigotta (Aa) baskın gen çekiniği örttüğü için baskın özellik görülür."},{"q":"Bir canlının saf döl (arı döl) olması ne anlama gelir?","steps":[{"t":"Gen yapısı","a":"iki gen aynı","d":"Saf döl bireyin bir özellik için iki geni de aynıdır (AA veya aa)."},{"t":"Döllerine etkisi","a":"hep aynı gen","d":"Bu yüzden yavrularına her zaman aynı çeşit geni aktarır."}],"ans":"Saf döl (arı döl) olmak, bireyin o özellik için homozigot olması ve döllerine hep aynı geni vermesi demektir."}],"zor":[{"q":"Heterozigot bir birey kaç çeşit gamet (üreme hücresi) oluşturur? Örnekle açıklayınız.","steps":[{"t":"Genleri ayır","a":"A ve a","d":"Heterozigot (Aa) bireyin bir geni A, diğeri a'dır."},{"t":"Gametleri bul","a":"A ve a olmak üzere 2 çeşit","d":"Üreme sırasında genler ayrılır; yarısı A, yarısı a taşıyan gamet oluşur."}],"ans":"Heterozigot birey (Aa) iki çeşit gamet oluşturur: bir kısmı A, bir kısmı a taşır."},{"q":"Homozigot bir birey kaç çeşit gamet oluşturur, bunun nedeni nedir?","steps":[{"t":"Genleri belirle","a":"ikisi aynı","d":"Homozigot bireyin (AA ya da aa) iki geni de aynıdır."},{"t":"Gameti düşün","a":"tek çeşit","d":"Genler aynı olduğu için ayrıldığında hep aynı çeşit gamet oluşur."}],"ans":"Homozigot birey tek çeşit gamet oluşturur; çünkü iki geni de aynı olduğundan ayrıldığında hepsi aynı geni taşır."},{"q":"Bir bahçıvan elindeki mor çiçekli bitkinin saf mı melez mi olduğunu nasıl anlayabilir?","steps":[{"t":"Sorun","a":"görünüş aynı","d":"Saf baskın (PP) ile melez (Pp) bitkinin dış görünüşü aynı (mor) olabilir."},{"t":"Çözüm","a":"çekinikle çaprazla","d":"Bitkiyi beyaz (pp) bitkiyle çaprazlar; deneme çaprazlaması yapar."},{"t":"Sonucu yorumla","a":"beyaz çıkarsa melez","d":"Beyaz yavru çıkarsa bitki melez (Pp), hepsi mor çıkarsa saftır (PP)."}],"ans":"Bahçıvan bitkiyi çekinik (beyaz, pp) bitkiyle çaprazlar; beyaz yavru çıkarsa bitki melez, tüm yavrular mor çıkarsa saftır."},{"q":"İki heterozigot bireyin (Aa × Aa) çaprazında neden çekinik özellik tekrar ortaya çıkabilir?","steps":[{"t":"Gametleri yaz","a":"her ikisi A ve a","d":"Her iki ebeveyn de hem A hem a taşıyan gamet üretir."},{"t":"Birleşimi bul","a":"aa mümkün","d":"Bir gametteki a ile diğerindeki a birleşirse aa genotipi oluşur."},{"t":"Sonucu yorumla","a":"çekinik görünür","d":"aa bireyinde baskın gen olmadığı için çekinik özellik görünür."}],"ans":"İki heterozigot bireyden gelen çekinik gametler (a + a) birleşip aa oluşturabildiği için, ebeveynlerde gizli kalan çekinik özellik yavruda ortaya çıkar."},{"q":"Saf döl elde etmek isteyen bir çiftçi melez bireyleri neden saf bireylerle değil, kendi aralarında çaprazlar?","steps":[{"t":"Amaç","a":"homozigot birey","d":"Çiftçi iki geni de aynı olan saf (homozigot) bireyler elde etmek ister."},{"t":"Yöntem","a":"melezleri çaprazla","d":"Melezleri (Aa × Aa) kendi aralarında çaprazlayınca AA ve aa bireyler ayrışır."},{"t":"Seçim yap","a":"saf olanı seç","d":"Çıkan AA veya aa bireyleri seçerek üretimi sürdürür."}],"ans":"Melezleri kendi aralarında çaprazlayınca AA ve aa gibi homozigot bireyler ayrıştığı için, çiftçi bu saf bireyleri seçerek saf döl elde edebilir."}]},"lise":{"kolay":[{"q":"Homozigot terimini genotip düzeyinde tanımlayınız.","steps":[{"t":"Alel kavramı","a":"bir genin çeşidi","d":"Aleller, bir genin farklı biçimleridir (örneğin A ve a)."},{"t":"Homozigotluk","a":"iki alel aynı","d":"Bir lokustaki iki alelin aynı olması durumudur (AA veya aa)."}],"ans":"Homozigot, bir gen için taşınan iki alelin birbirinin aynı olduğu (AA ya da aa) genotip durumudur."},{"q":"Heterozigot terimini genotip düzeyinde tanımlayınız.","steps":[{"t":"İki alele bak","a":"farklı aleller","d":"Heterozigotta bir lokustaki iki alel birbirinden farklıdır."},{"t":"Gösterim","a":"Aa","d":"Bu durum biri baskın biri çekinik (Aa) şeklinde gösterilir."}],"ans":"Heterozigot, bir gen için taşınan iki alelin birbirinden farklı olduğu (Aa) genotip durumudur."},{"q":"Homozigot dominant, homozigot resesif ve heterozigot genotipleri yazıp adlandırınız.","steps":[{"t":"Homozigotlar","a":"AA ve aa","d":"AA homozigot baskın (dominant), aa homozigot çekinik (resesif) genotiptir."},{"t":"Heterozigot","a":"Aa","d":"Aa ise iki aleli farklı olan heterozigot genotiptir."}],"ans":"AA homozigot dominant, aa homozigot resesif, Aa ise heterozigot genotiptir."},{"q":"Heterozigot bir bireyin fenotipini belirleyen kural nedir?","steps":[{"t":"Alelleri belirle","a":"A baskın, a çekinik","d":"Heterozigotta bir baskın bir çekinik alel bulunur."},{"t":"Tam dominantlık","a":"baskın örter","d":"Tam baskınlıkta baskın alel çekiniğin etkisini tamamen örter."}],"ans":"Tam baskınlıkta heterozigot bireyin (Aa) fenotipi, baskın alel çekiniği örttüğü için baskın fenotiptir."},{"q":"Homozigot bir bireyin oluşturduğu gamet çeşidini ve oranını belirtiniz.","steps":[{"t":"Alelleri ayır","a":"ikisi aynı","d":"Homozigot bireyin (AA) iki aleli de aynıdır."},{"t":"Mayoz sonucu","a":"tek çeşit gamet","d":"Mayozda aleller ayrılınca tüm gametler aynı aleli taşır."}],"ans":"Homozigot birey tek çeşit gamet oluşturur; örneğin AA bireyin tüm gametleri A taşır (%100)."},{"q":"Heterozigot bir bireyin oluşturduğu gamet çeşidini ve oranını belirtiniz.","steps":[{"t":"Alelleri ayır","a":"A ve a","d":"Heterozigot bireyin (Aa) bir aleli A, diğeri a'dır."},{"t":"Mayoz sonucu","a":"iki çeşit, eşit oran","d":"Mayozda aleller ayrılınca yarısı A, yarısı a taşıyan gamet oluşur."}],"ans":"Heterozigot birey iki çeşit gamet oluşturur: %50 A, %50 a taşıyan gametler."},{"q":"'Arı döl' ve 'melez' terimleri hangi genotiplere karşılık gelir?","steps":[{"t":"Arı döl","a":"homozigot","d":"Arı döl, iki aleli aynı olan homozigot bireydir (AA veya aa)."},{"t":"Melez","a":"heterozigot","d":"Melez, iki aleli farklı olan heterozigot bireydir (Aa)."}],"ans":"Arı döl homozigot (AA/aa) bireye, melez ise heterozigot (Aa) bireye karşılık gelir."},{"q":"Genotip ile fenotip arasındaki ilişkiyi homozigot resesif birey üzerinden açıklayınız.","steps":[{"t":"Genotip","a":"aa","d":"Homozigot resesif bireyin genotipi aa'dır, baskın alel taşımaz."},{"t":"Fenotip","a":"çekinik özellik","d":"Baskın alel olmadığı için çekinik özellik dışarıdan gözlenir."}],"ans":"Homozigot resesif bireyin genotipi aa'dır; baskın alel bulunmadığından çekinik fenotip ortaya çıkar."},{"q":"İki homozigot baskın bireyin (AA × AA) çaprazında döllerin genotipi ne olur?","steps":[{"t":"Gametleri yaz","a":"ikisi de A","d":"Her iki ebeveyn de yalnızca A taşıyan gamet oluşturur."},{"t":"Birleşimi bul","a":"AA","d":"A + A birleşiminden tüm döller AA genotipinde olur."}],"ans":"AA × AA çaprazında tüm döller homozigot baskın (AA) genotipinde olur."},{"q":"Saf baskın (AA) ile saf çekinik (aa) bireyin çaprazında döl genotipi ne olur?","steps":[{"t":"Gametleri yaz","a":"A ve a","d":"Bir ebeveyn yalnız A, diğeri yalnız a taşıyan gamet verir."},{"t":"Birleşimi bul","a":"Aa","d":"A + a birleşiminden tüm döller Aa olur."}],"ans":"AA × aa çaprazında tüm döller heterozigot (Aa, melez) genotipinde olur."},{"q":"Bir bireyin homozigot olup olmadığı yalnızca fenotipe bakılarak her zaman anlaşılabilir mi?","steps":[{"t":"Baskın fenotip","a":"belirsiz","d":"Baskın fenotipli birey AA veya Aa olabilir; ikisi de aynı görünür."},{"t":"Çekinik fenotip","a":"kesin homozigot","d":"Çekinik fenotipli birey kesinlikle aa, yani homozigot resesiftir."}],"ans":"Hayır; baskın fenotipli birey AA da Aa da olabilir, ancak çekinik fenotipli birey kesinlikle homozigot resesiftir (aa)."},{"q":"Tek melez (monohibrit) bir bireyin genotip ve fenotip ifadesi neden farklıdır?","steps":[{"t":"Genotip","a":"Aa","d":"Genotip, bireyin taşıdığı alellerin tümünü (Aa) belirtir."},{"t":"Fenotip","a":"baskın görünüm","d":"Fenotip ise dışarıdan görünen özelliktir; Aa'da baskın özellik görünür."}],"ans":"Monohibrit (Aa) bireyin genotipi alel yapısını (Aa), fenotipi ise dışarıdan görünen baskın özelliği belirttiği için farklıdır."},{"q":"Homozigotluk ve heterozigotluk kavramları neden bir özellik (lokus) için tanımlanır?","steps":[{"t":"Lokus kavramı","a":"genin yeri","d":"Her özelliğin geni kromozom üzerinde belirli bir lokusta bulunur."},{"t":"Karşılaştırma","a":"aynı lokus alelleri","d":"Homozigot/heterozigotluk, aynı lokustaki iki alelin aynı ya da farklı olmasına bakar."}],"ans":"Bu kavramlar, aynı lokustaki iki alelin aynı (homozigot) ya da farklı (heterozigot) olmasını anlattığı için tek bir özellik bazında tanımlanır."},{"q":"Bir bireyin 'AaBB' genotipinde hangi gen homozigot, hangisi heterozigottur?","steps":[{"t":"A genine bak","a":"Aa, heterozigot","d":"A geni için aleller farklı (A ve a) olduğundan bu lokus heterozigottur."},{"t":"B genine bak","a":"BB, homozigot","d":"B geni için aleller aynı (B ve B) olduğundan bu lokus homozigottur."}],"ans":"AaBB genotipinde A geni heterozigot (Aa), B geni ise homozigot baskındır (BB)."},{"q":"Çekinik bir kalıtsal hastalığı taşıyan ama hasta olmayan bireyin genotipi nasıl olmalıdır?","steps":[{"t":"Hasta olmama","a":"baskın alel var","d":"Birey hasta değilse en az bir baskın (sağlam) alel taşımalıdır."},{"t":"Taşıyıcılık","a":"bir çekinik alel","d":"Hastalığı aktarabilmesi için bir de çekinik alel taşır."}],"ans":"Hasta olmayıp çekinik hastalığı taşıyan birey heterozigottur (Aa); bir baskın sağlam, bir çekinik hastalık aleli taşır."}],"zor":[{"q":"Heterozigot bir bireyin (Aa) iki, homozigotun ise tek çeşit gamet oluşturmasının nedenini mayoz açısından açıklayınız.","steps":[{"t":"Homolog ayrılması","a":"aleller ayrılır","d":"Mayoz I'de homolog kromozomlar ayrılırken her alel ayrı gamete gider."},{"t":"Heterozigot","a":"A ve a ayrılır","d":"Aa bireyde A ve a farklı gametlere gittiği için iki çeşit gamet oluşur."},{"t":"Homozigot","a":"aynı alel ayrılır","d":"AA bireyde her iki gamet de A taşır, çünkü iki alel aynıdır."}],"ans":"Mayozda homolog kromozomlar ayrılırken aleller farklı gametlere dağılır; heterozigotta A ve a ayrı düştüğü için iki çeşit, homozigotta iki alel aynı olduğu için tek çeşit gamet oluşur."},{"q":"İki gen bakımından heterozigot bir birey (AaBb) kaç çeşit gamet oluşturur? Hesaplayınız.","steps":[{"t":"Her gen için çeşit","a":"2 ve 2","d":"Aa geni 2 çeşit (A, a), Bb geni 2 çeşit (B, b) gamet verir."},{"t":"Bağımsız dağılım","a":"çarp","d":"Genler farklı kromozomlardaysa çeşitler çarpılır: 2 × 2."},{"t":"Sonucu yaz","a":"4 çeşit","d":"Oluşan gametler: AB, Ab, aB, ab olmak üzere 4 çeşittir."}],"ans":"AaBb birey, bağımsız dağılımla 2 × 2 = 4 çeşit gamet oluşturur: AB, Ab, aB, ab."},{"q":"n tane gen bakımından heterozigot bir bireyin oluşturabileceği gamet çeşidi sayısı nasıl bulunur?","steps":[{"t":"Tek gen","a":"2 çeşit","d":"Heterozigot tek gen 2 çeşit gamet verir."},{"t":"Genelleme","a":"2 üzeri n","d":"Bağımsız her heterozigot gen çeşidi 2 ile çarpıldığından sonuç 2ⁿ olur."},{"t":"Örnek","a":"3 gen → 8","d":"3 gen heterozigot ise 2³ = 8 çeşit gamet oluşur."}],"ans":"n gen bakımından heterozigot bireyin gamet çeşidi 2ⁿ formülüyle bulunur; örneğin 3 gen için 2³ = 8 çeşit gamettir."},{"q":"Aynı fenotipe sahip iki bireyden farklı çaprazlama sonuçları alınmasının nedeni genotip farkı olabilir mi? Açıklayınız.","steps":[{"t":"Aynı fenotip","a":"AA veya Aa","d":"Baskın fenotipli iki birey AA ya da Aa genotipinde olabilir."},{"t":"Gamet farkı","a":"tek vs iki çeşit","d":"AA tek çeşit (A), Aa iki çeşit (A, a) gamet üretir."},{"t":"Çaprazlama etkisi","a":"farklı döl oranı","d":"Bu yüzden aynı eşle çaprazda farklı genotip ve fenotip oranları çıkar."}],"ans":"Evet; aynı baskın fenotip AA veya Aa olabilir, AA tek çeşit Aa iki çeşit gamet ürettiğinden aynı eşle çaprazda farklı döl oranları elde edilir."},{"q":"Bir deneme çaprazlamasında (test cross) baskın fenotipli birey çekinikle çaprazlanır; sonuçlar bireyin homozigot mu heterozigot mu olduğunu nasıl gösterir?","steps":[{"t":"Test eşi","a":"aa","d":"Birey homozigot resesif (aa) bireyle çaprazlanır."},{"t":"Birey AA ise","a":"hepsi baskın","d":"AA × aa çaprazında tüm döller Aa olur ve baskın fenotip gösterir."},{"t":"Birey Aa ise","a":"1:1 ayrışır","d":"Aa × aa çaprazında döllerin yarısı Aa (baskın), yarısı aa (çekinik) olur."}],"ans":"Test çaprazında tüm döller baskın fenotip gösterirse birey homozigottur (AA); döller yaklaşık 1:1 baskın-çekinik ayrışırsa birey heterozigottur (Aa)."},{"q":"İki heterozigot bireyin (Aa × Aa) çaprazında ortaya çıkan genotip ve fenotip oranlarını adım adım bulunuz.","steps":[{"t":"Gametleri yaz","a":"A, a / A, a","d":"Her iki ebeveyn %50 A, %50 a taşıyan gamet üretir."},{"t":"Genotip oranı","a":"1 AA : 2 Aa : 1 aa","d":"Punnett karesinde birleşimler 1 AA, 2 Aa, 1 aa oranında çıkar."},{"t":"Fenotip oranı","a":"3 baskın : 1 çekinik","d":"AA ve Aa baskın görünür, aa çekinik görünür; oran 3:1 olur."}],"ans":"Aa × Aa çaprazında genotip oranı 1 AA : 2 Aa : 1 aa, fenotip oranı ise 3 baskın : 1 çekinik şeklindedir."},{"q":"Homozigot resesif bir bireyin neden 'genotipi fenotipinden kesin okunabilen' tek genotip olduğunu açıklayınız.","steps":[{"t":"Çekinik fenotip","a":"baskın alel yok","d":"Çekinik özelliğin görünmesi için baskın alel hiç bulunmamalıdır."},{"t":"Tek olasılık","a":"aa","d":"Bu yüzden çekinik fenotipli birey yalnızca aa olabilir, başka seçenek yoktur."},{"t":"Karşıtlık","a":"baskın belirsiz","d":"Baskın fenotip ise AA veya Aa olabildiği için belirsizdir."}],"ans":"Çekinik fenotip yalnızca baskın alelin hiç bulunmadığı aa genotipinde görülebildiği için, homozigot resesif birey genotipi fenotipinden kesin okunabilen tek durumdur."},{"q":"Bir çiftçi yıllarca verim veren saf (homozigot) hat elde etmek için melez bitkilerden nasıl yararlanır?","steps":[{"t":"Başlangıç","a":"melezleri çaprazla","d":"Melez (Aa) bitkiler kendi aralarında veya kendileştirme ile çaprazlanır."},{"t":"Ayrışma","a":"AA, Aa, aa","d":"Döllerde 1 AA : 2 Aa : 1 aa oranında genotipler ayrışır."},{"t":"Seçilim","a":"homozigotları seç","d":"İstenen özelliğe sahip homozigot (AA veya aa) bireyler seçilip üretilir."}],"ans":"Çiftçi melezleri kendileştirip döllerde AA, Aa, aa ayrışmasını sağlar; istenen özellikteki homozigot bireyleri seçerek nesiller boyu saf hat elde eder."},{"q":"Kendileştirme (self-pollination) bir popülasyonda heterozigotluğu neden azaltır? Nesil bazında açıklayınız.","steps":[{"t":"Heterozigotun dölü","a":"Aa → 1:2:1","d":"Her kendileşen Aa bireyden 1 AA : 2 Aa : 1 aa oranında döl çıkar."},{"t":"Heterozigot payı","a":"her nesil yarıya iner","d":"Her nesilde heterozigot oranı bir önceki neslin yarısına düşer."},{"t":"Uzun vade","a":"homozigotlaşma","d":"Nesiller ilerledikçe popülasyon giderek AA ve aa homozigotlara ayrışır."}],"ans":"Kendileştirmede her Aa bireyin döllerinde heterozigot oranı yarıya indiğinden, nesiller ilerledikçe popülasyon giderek homozigotlaşır ve heterozigotluk azalır."},{"q":"Eksik baskınlıkta (örneğin kırmızı KK × beyaz kk → pembe Kk) heterozigotun fenotipi neden ara özellik gösterir?","steps":[{"t":"Tam baskınlıkla fark","a":"alel örtmüyor","d":"Eksik baskınlıkta baskın alel çekiniği tam örtemez."},{"t":"Etki birleşir","a":"ara fenotip","d":"İki alelin etkisi karışınca heterozigotta ara bir fenotip (pembe) oluşur."},{"t":"Genotip-fenotip","a":"birebir okunur","d":"Her genotip farklı fenotip verdiği için Kk birey doğrudan ayırt edilir."}],"ans":"Eksik baskınlıkta baskın alel çekiniği tam örtemediği için iki alelin etkisi karışır ve heterozigot (Kk) kırmızı ile beyaz arası pembe gibi ara bir fenotip gösterir."},{"q":"Eş baskınlık (AB kan grubu gibi) durumunda heterozigot bireyde her iki alel de nasıl ifade edilir?","steps":[{"t":"Eş baskın aleller","a":"ikisi de etkili","d":"Eş baskınlıkta iki alel de birbirini örtmez, ikisi de tam ifade edilir."},{"t":"Heterozigot fenotip","a":"iki özellik birlikte","d":"Örneğin Iᴬ Iᴮ bireyde hem A hem B antijeni birlikte üretilir."},{"t":"Sonuç","a":"AB kan grubu","d":"Bu yüzden birey ara değil, iki özelliği aynı anda taşıyan AB grubunda olur."}],"ans":"Eş baskınlıkta heterozigot bireyde iki alel de tam ifade edilir; örneğin Iᴬ Iᴮ genotipli kişide hem A hem B antijeni birlikte üretilerek AB kan grubu oluşur."},{"q":"Bir AaBbCc bireyin yalnızca 'abc' gameti oluşturma olasılığı nedir? Adım adım hesaplayınız.","steps":[{"t":"Her gen için olasılık","a":"1/2","d":"Her heterozigot genden çekinik aleli taşıyan gamet olasılığı 1/2'dir."},{"t":"Bağımsız çarpım","a":"1/2 · 1/2 · 1/2","d":"Genler bağımsızsa olasılıklar çarpılır."},{"t":"Sonuç","a":"1/8","d":"1/2 × 1/2 × 1/2 = 1/8 sonucu bulunur."}],"ans":"AaBbCc bireyin 'abc' gameti oluşturma olasılığı 1/2 × 1/2 × 1/2 = 1/8'dir."},{"q":"Heterozigot bir bireyin gamet çeşitliliği, çaprazlama sonucundaki döl çeşitliliğini nasıl artırır?","steps":[{"t":"Gamet çeşidi","a":"birden fazla","d":"Heterozigot birey farklı alel kombinasyonlu çok çeşit gamet üretir."},{"t":"Birleşim sayısı","a":"artan kombinasyon","d":"Eşle birleşmede gamet çeşidi arttıkça olası döl genotipleri de artar."},{"t":"Sonuç","a":"çeşitlilik","d":"Bu nedenle heterozigot ebeveynler genetik bakımdan daha çeşitli döl verir."}],"ans":"Heterozigot birey birçok çeşit gamet ürettiği için bunların eş gametleriyle birleşimi daha çok döl genotipi oluşturur; böylece çaprazlama sonucundaki genetik çeşitlilik artar."},{"q":"Bir popülasyonda tüm bireyler homozigot (saf hat) olsaydı, evrim ve uyum açısından ne gibi bir dezavantaj doğardı?","steps":[{"t":"Homozigotluk","a":"tek alel havuzu","d":"Tüm bireyler aynı alelleri taşıdığından alel çeşitliliği çok düşük olur."},{"t":"Gamet ve döl","a":"benzer döller","d":"Gametler tek çeşit olduğundan döller de birbirine benzer, varyasyon azalır."},{"t":"Çevresel baskı","a":"uyum sağlayamama","d":"Çevre değişince seçilime uğrayacak farklı bireyler bulunmaz."}],"ans":"Tümüyle homozigot bir popülasyonda alel çeşitliliği ve varyasyon çok düşük olacağından, çevre değiştiğinde uyum sağlayabilecek farklı bireyler bulunmaz ve popülasyon yok olma riski taşır."},{"q":"Akrabalı yetiştirmenin (inbreeding) çekinik kalıtsal hastalıkların görülme sıklığını artırmasını homozigotluk üzerinden açıklayınız.","steps":[{"t":"Ortak aleller","a":"benzer genler","d":"Akrabalar aynı atadan geldiği için aynı çekinik alelleri taşıma olasılığı yüksektir."},{"t":"Homozigotlaşma","a":"aa artar","d":"İki taşıyıcı akraba çiftleşirse çekinik aleller homozigot (aa) bir araya gelebilir."},{"t":"Sonuç","a":"hastalık ortaya çıkar","d":"Çekinik alel homozigot hale gelince gizli hastalık fenotip olarak görünür."}],"ans":"Akrabalar aynı çekinik alelleri taşıdığından, çiftleşmelerinde bu aleller homozigot (aa) hale gelme olasılığı artar; böylece normalde gizli kalan çekinik kalıtsal hastalıklar daha sık ortaya çıkar."}]}},"mendelYasalari":{"ilkokul":{"kolay":[{"q":"Mendel adlı bilim insanı deneylerini hangi bitkiyle yapmıştır?","steps":[{"t":"Bitkiyi düşün","a":"bezelye","d":"Mendel bahçesinde yetiştirdiği bezelye bitkileriyle çalışmıştır."},{"t":"Ne incelemiş","a":"özellik geçişi","d":"Bezelyelerin renk ve şekil gibi özelliklerinin yavrulara nasıl geçtiğine bakmıştır."}],"ans":"Mendel deneylerini <b>bezelye</b> bitkisiyle yapmış ve özelliklerin yavrulara geçişini incelemiştir."},{"q":"Mendel bezelyelerde neyi merak edip araştırmıştır?","steps":[{"t":"Soruyu düşün","a":"özellikler nasıl geçer","d":"Anne ve baba bitkinin özelliklerinin yavruya nasıl geçtiğini merak etmiştir."},{"t":"Ne bulmuş","a":"kurallı geçiş","d":"Özelliklerin belli bir kurala göre yavrulara geçtiğini bulmuştur."}],"ans":"Mendel, bitki özelliklerinin yavrulara <b>belli bir kurala göre</b> geçtiğini araştırmıştır."},{"q":"Uzun bir bezelye ile kısa bir bezelye çaprazlanırsa Mendel ne gözlemlemiştir?","steps":[{"t":"İlk yavruları düşün","a":"hepsi uzun","d":"İlk doğan bezelye yavrularının hepsi uzun boylu olmuştur."},{"t":"Neden","a":"uzunluk baskın","d":"Uzun boy özelliği kısa boya göre daha güçlü (baskın) çıkmıştır."}],"ans":"Uzun ve kısa bezelye çaprazlanınca ilk yavruların hepsi <b>uzun</b> olmuş; uzunluk daha güçlü (baskın) özelliktir."},{"q":"Bezelyelerin hangi özellikleri farklı renklerde olabilir? Bir örnek ver.","steps":[{"t":"Bir özellik seç","a":"çiçek rengi","d":"Bezelyenin çiçekleri mor ya da beyaz renkte olabilir."},{"t":"Başka örnek","a":"tohum rengi","d":"Bezelye tohumları da sarı ya da yeşil olabilir."}],"ans":"Bezelyelerin çiçek rengi (mor/beyaz) ve tohum rengi (sarı/yeşil) gibi özellikleri farklı olabilir."},{"q":"Mendel'in bulduğu en önemli şey nedir?","steps":[{"t":"Ne keşfetmiş","a":"özellikler geçer","d":"Anne babanın özelliklerinin yavrulara geçtiğini keşfetmiştir."},{"t":"Nasıl geçer","a":"kurallı biçimde","d":"Bu geçişin rastgele değil, belirli kurallarla olduğunu göstermiştir."}],"ans":"Mendel, canlıların özelliklerinin yavrulara <b>kurallı bir biçimde</b> geçtiğini bulmuştur."}],"zor":[{"q":"Mendel neden deneyleri için bezelyeyi seçmiştir? Bir neden söyle.","steps":[{"t":"Bezelyenin iyi yanı","a":"hızlı yetişir","d":"Bezelye kolay ve çabuk yetiştiği için kısa sürede çok yavru elde edilir."},{"t":"İncelemesi kolay","a":"belirgin özellikler","d":"Uzun-kısa, sarı-yeşil gibi farkları gözle kolayca görülür."}],"ans":"Mendel bezelyeyi <b>hızlı yetişip belirgin özelliklere sahip</b> olduğu için seçmiştir."},{"q":"İki sarı tohumlu bezelyenin yavrularından bazıları yeşil çıkabilir mi? Neden?","steps":[{"t":"Gizli özellik","a":"saklı kalmış","d":"Anne babada yeşil özelliği gizli (saklı) olarak bulunabilir."},{"t":"Yavruda ortaya çıkma","a":"yeşil görünür","d":"Bu gizli özellik bazı yavrularda yeşil renk olarak ortaya çıkabilir."}],"ans":"Evet çıkabilir; çünkü anne babada <b>gizli kalmış yeşil özelliği</b> bazı yavrularda ortaya çıkabilir."},{"q":"Mendel deneylerinde neden çok sayıda bezelye kullanmıştır?","steps":[{"t":"Az sayı yeterli mi","a":"hayır","d":"Birkaç bitkiye bakarak doğru bir sonuca varmak zordur."},{"t":"Çok sayının yararı","a":"doğru sonuç","d":"Çok sayıda bezelye sayıldığında sonuçlar daha güvenilir olur."}],"ans":"Mendel, sonuçların <b>doğru ve güvenilir</b> olması için çok sayıda bezelye kullanmıştır."},{"q":"Baskın ve çekinik özellik ne demektir? Bezelye örneğiyle açıkla.","steps":[{"t":"Baskın özellik","a":"öne çıkan","d":"Uzun boy gibi yavruda hemen görünen güçlü özelliğe baskın denir."},{"t":"Çekinik özellik","a":"saklanan","d":"Kısa boy gibi gizli kalıp her zaman görünmeyen özelliğe çekinik denir."}],"ans":"<b>Baskın</b> özellik (uzun boy) öne çıkıp görünür; <b>çekinik</b> özellik (kısa boy) gizli kalabilir."},{"q":"Mor çiçekli ve beyaz çiçekli bezelyeler çaprazlanınca ilk yavrular neden hep mor olur?","steps":[{"t":"Hangi renk güçlü","a":"mor baskın","d":"Mor renk, beyaz renge göre daha güçlü (baskın) bir özelliktir."},{"t":"Beyazın durumu","a":"gizli kalır","d":"Beyaz renk bu yavrularda gizli kalır ve görünmez."}],"ans":"İlk yavrular hep mor olur; çünkü <b>mor renk baskındır</b> ve beyaz renk gizli kalır."}]},"ortaokul":{"kolay":[{"q":"Gregor Mendel kimdir ve kalıtım için neden önemlidir?","steps":[{"t":"Kim olduğu","a":"rahip-bilim insanı","d":"Mendel, bezelyelerle deney yapan bir rahip ve bilim insanıdır."},{"t":"Önemi","a":"kalıtımın kuralları","d":"Özelliklerin kuşaklar arası geçiş kurallarını ilk kez bilimsel olarak ortaya koymuştur."}],"ans":"Mendel, bezelye deneyleriyle kalıtımın temel kurallarını bulan ve <b>genetiğin kurucusu</b> sayılan bilim insanıdır."},{"q":"Çaprazlama deneylerinde P, F1 ve F2 kuşakları neyi ifade eder?","steps":[{"t":"P kuşağı","a":"ana-baba (ata)","d":"P kuşağı, çaprazlamaya başlanan saf ana-baba bitkilerdir."},{"t":"F1 ve F2","a":"birinci ve ikinci döl","d":"P'den oluşan ilk yavrular F1, F1'in kendi aralarından oluşan döl ise F2'dir."}],"ans":"P kuşağı ana-baba bitkileri, F1 onların ilk yavrularını, F2 ise F1'den oluşan ikinci döl kuşağını ifade eder."},{"q":"Mendel'in deneylerinde 'saf döl' ne demektir?","steps":[{"t":"Saf döl tanımı","a":"hep aynı özellik","d":"Saf döl, kendileştiğinde her zaman aynı özellikteki yavruyu veren bitkidir."},{"t":"Örnek","a":"hep uzun veren","d":"Saf uzun bezelye, döllendiğinde sadece uzun yavrular verir."}],"ans":"Saf döl, kendi aralarında üretildiğinde <b>her zaman aynı özelliği</b> veren bitkidir; örneğin hep uzun veren bezelye."},{"q":"Baskın ve çekinik gen kavramları arasındaki fark nedir?","steps":[{"t":"Baskın gen","a":"etkisini gösterir","d":"Baskın gen, varlığında özelliğini her zaman dışarıya yansıtır."},{"t":"Çekinik gen","a":"saklanabilir","d":"Çekinik gen, yalnızca baskın geni karşısında bulamazsa etkisini gösterir."}],"ans":"Baskın gen etkisini her zaman gösterir; çekinik gen ise yalnızca baskın eşi yokken kendini gösterir."},{"q":"Mendel neden deneylerinde bezelye bitkisini tercih etmiştir? İki neden söyleyiniz.","steps":[{"t":"Üreme özelliği","a":"hızlı ve bol döl","d":"Bezelye kısa sürede çok sayıda yavru verir, kontrollü döllenebilir."},{"t":"Özellikleri","a":"belirgin/zıt","d":"Sarı-yeşil, uzun-kısa gibi açıkça ayırt edilebilen zıt özellikleri vardır."}],"ans":"Mendel bezelyeyi <b>hızlı ürediği, çok döl verdiği ve belirgin zıt özellikler taşıdığı</b> için seçmiştir."}],"zor":[{"q":"Mendel'in birinci yasası (ayrılma yasası) neyi ifade eder?","steps":[{"t":"Genlerin durumu","a":"çiftler hâlinde","d":"Bir özelliği belirleyen genler bireyde çiftler hâlinde bulunur."},{"t":"Üreme hücresine geçiş","a":"ayrılırlar","d":"Üreme hücreleri oluşurken bu gen çifti birbirinden ayrılır, her hücreye biri gider."}],"ans":"Ayrılma yasasına göre, bir özelliği belirleyen gen çifti üreme hücreleri oluşurken <b>birbirinden ayrılır</b>."},{"q":"Saf uzun (UU) ile saf kısa (uu) bezelye çaprazlanırsa F1 dölü nasıl olur?","steps":[{"t":"Genlerin birleşmesi","a":"Uu","d":"Anneden U, babadan u geni gelir; tüm F1 bireyleri Uu olur."},{"t":"Görünüş","a":"hepsi uzun","d":"U geni baskın olduğu için Uu bireyler uzun görünür."}],"ans":"F1 dölünün tamamı <b>Uu</b> yapısında olur ve baskın gen nedeniyle hepsi uzun boylu görünür."},{"q":"F1 dölündeki Uu bezelyeler kendi aralarında çaprazlanırsa F2'de hangi oran beklenir?","steps":[{"t":"Olası birleşmeler","a":"UU, Uu, Uu, uu","d":"Uu × Uu çaprazında dört olası genotip oluşur."},{"t":"Görünüş oranı","a":"3 uzun : 1 kısa","d":"Üç birey uzun (UU, Uu, Uu), bir birey kısa (uu) görünür."}],"ans":"F2 dölünde görünüş bakımından yaklaşık <b>3 uzun : 1 kısa</b> oranı beklenir."},{"q":"Genotip ve fenotip kavramları arasındaki fark nedir?","steps":[{"t":"Genotip","a":"gen yapısı","d":"Genotip, bireyin taşıdığı genlerin yapısıdır (örneğin Uu)."},{"t":"Fenotip","a":"dış görünüş","d":"Fenotip, bu genlerin dışarıya yansıyan görünür özelliğidir (örneğin uzun boy)."}],"ans":"Genotip bireyin <b>gen yapısı</b> (Uu), fenotip ise bu genlerin oluşturduğu <b>dış görünüştür</b> (uzun)."},{"q":"Çekinik bir özellik (örneğin beyaz çiçek) yalnızca hangi genotipte ortaya çıkar?","steps":[{"t":"Çekinik gen koşulu","a":"baskın olmamalı","d":"Çekinik özellik, yanında baskın gen bulunmadığında ortaya çıkar."},{"t":"Gerekli genotip","a":"iki çekinik gen","d":"Birey çekinik özelliği göstermesi için iki çekinik geni (aa) taşımalıdır."}],"ans":"Çekinik özellik yalnızca birey <b>iki çekinik geni (aa)</b> birlikte taşıdığında ortaya çıkar."}]},"lise":{"kolay":[{"q":"Mendel'in deneylerinde başarılı olmasının temel nedenlerini açıklayınız.","steps":[{"t":"Doğru model organizma","a":"bezelye","d":"Hızlı üreyen, kontrollü döllenebilen ve belirgin zıt karakterli bezelyeyi seçti."},{"t":"Bilimsel yöntem","a":"sayım + istatistik","d":"Çok sayıda bireyi takip edip sonuçları matematiksel oranlarla değerlendirdi."}],"ans":"Mendel'in başarısı; <b>uygun model organizma (bezelye) seçmesi</b>, tek karakteri izlemesi ve sonuçları <b>çok sayıda bireyle istatistiksel</b> olarak değerlendirmesinden kaynaklanır."},{"q":"Mendel'in 'kalıtım faktörü' dediği yapı bugün hangi terimle karşılanır?","steps":[{"t":"Mendel'in adlandırması","a":"faktör","d":"Mendel, özellikleri belirleyen birimlere 'faktör' demiştir."},{"t":"Günümüz terimi","a":"gen","d":"Bu faktörler bugün DNA üzerindeki gen olarak adlandırılır."}],"ans":"Mendel'in 'faktör' dediği kalıtım birimi, günümüzde <b>gen</b> olarak adlandırılır."},{"q":"Homozigot ve heterozigot birey kavramlarını ayırt ediniz.","steps":[{"t":"Homozigot","a":"aynı iki alel","d":"Bir karakter için iki özdeş alel taşır (AA veya aa), yani saftır."},{"t":"Heterozigot","a":"farklı iki alel","d":"Bir karakter için biri baskın biri çekinik iki farklı alel taşır (Aa)."}],"ans":"Homozigot birey aynı iki aleli (AA/aa) taşıyıp saftır; heterozigot birey ise farklı iki aleli (Aa) taşır."},{"q":"Mendel'in çalıştığı bezelyenin yapısı kontrollü çaprazlamaya neden uygundur?","steps":[{"t":"Çiçek yapısı","a":"kapalı çiçek","d":"Bezelye çiçeği kapalı olduğundan doğal hâlde kendine tozlaşır."},{"t":"Denetim olanağı","a":"yapay tozlaşma","d":"Araştırmacı çiçeği açıp istediği iki bitkiyi çaprazlayabilir."}],"ans":"Bezelye doğal hâlde kendine tozlaştığından saf döl tutar; çiçeği açılarak <b>istenen iki bitki kontrollü çaprazlanabilir</b>."},{"q":"Monohibrit çaprazlama nedir?","steps":[{"t":"Tanımı","a":"tek karakter","d":"Tek bir karakter (örneğin tohum rengi) bakımından yapılan çaprazlamadır."},{"t":"Amacı","a":"kalıtım takibi","d":"O karakterin kuşaklar boyunca nasıl aktarıldığını izlemek için yapılır."}],"ans":"Monohibrit çaprazlama, <b>tek bir karakter</b> bakımından farklı bireylerin çaprazlanarak o karakterin kalıtımının izlenmesidir."},{"q":"Alel kavramını tanımlayınız ve bir örnek veriniz.","steps":[{"t":"Tanımı","a":"genin farklı biçimi","d":"Alel, bir genin aynı özelliği belirleyen farklı versiyonudur."},{"t":"Örnek","a":"sarı/yeşil aleli","d":"Tohum rengi geninin sarı (S) ve yeşil (s) alelleri vardır."}],"ans":"Alel, bir genin aynı karakteri belirleyen farklı biçimidir; örneğin tohum rengi geninin sarı (S) ve yeşil (s) alelleri."},{"q":"Baskınlık ilkesi (Mendel'in birinci gözlemi) neyi açıklar?","steps":[{"t":"Heterozigot durum","a":"Aa","d":"Birey biri baskın biri çekinik iki farklı alel taşıdığında (Aa)."},{"t":"Görünen özellik","a":"baskın olan","d":"Fenotipte yalnızca baskın alelin belirlediği özellik gözlenir."}],"ans":"Baskınlık ilkesine göre, heterozigot bireyde (Aa) yalnızca <b>baskın alelin özelliği</b> fenotipte görünür."},{"q":"Saf sarı tohumlu (SS) ile saf yeşil tohumlu (ss) bezelye çaprazlanırsa F1 fenotipi ne olur?","steps":[{"t":"Genotip","a":"hepsi Ss","d":"Tüm F1 bireyleri bir S ve bir s aleli alır, genotipleri Ss olur."},{"t":"Fenotip","a":"sarı","d":"S aleli baskın olduğu için tüm F1 tohumları sarı görünür."}],"ans":"F1 dölünün tamamı <b>Ss</b> genotipinde ve baskınlık nedeniyle fenotipte <b>sarı tohumlu</b> olur."},{"q":"Test çaprazlaması (kontrol çaprazlaması) ne amaçla yapılır?","steps":[{"t":"Sorun","a":"genotip bilinmiyor","d":"Baskın fenotipli bir bireyin homozigot mu heterozigot mu olduğu görünüşten anlaşılmaz."},{"t":"Yöntem","a":"çekinikle çaprazla","d":"Birey saf çekinik (aa) bireyle çaprazlanır, döllerin fenotipine bakılır."}],"ans":"Test çaprazlaması, baskın fenotipli bir bireyin <b>genotipini belirlemek</b> için onu saf çekinik (aa) bireyle çaprazlamaktır."},{"q":"Mendel'in bezelyede incelediği karakterlerden üçünü söyleyiniz.","steps":[{"t":"Tohum karakterleri","a":"renk ve şekil","d":"Tohum rengi (sarı/yeşil) ve tohum şekli (düz/buruşuk) incelenmiştir."},{"t":"Bitki karakterleri","a":"boy","d":"Gövde boyu (uzun/kısa) da incelenen karakterlerdendir."}],"ans":"Mendel; tohum rengi (sarı/yeşil), tohum şekli (düz/buruşuk) ve gövde boyu (uzun/kısa) gibi karakterleri incelemiştir."},{"q":"Dihibrit çaprazlama monohibrit çaprazlamadan nasıl ayrılır?","steps":[{"t":"Monohibrit","a":"tek karakter","d":"Monohibrit çaprazlamada yalnızca bir karakter izlenir."},{"t":"Dihibrit","a":"iki karakter","d":"Dihibrit çaprazlamada iki karakter aynı anda izlenir (örneğin renk ve şekil)."}],"ans":"Monohibrit çaprazlama tek karakteri izlerken, dihibrit çaprazlama <b>iki karakteri aynı anda</b> izler."},{"q":"F1 dölündeki heterozigot bireyler kendileştiğinde F2'de çekinik özellik neden yeniden ortaya çıkar?","steps":[{"t":"F1 genotipi","a":"Aa","d":"F1 bireyleri çekinik aleli (a) gizli olarak taşır."},{"t":"F2'de birleşme","a":"aa oluşabilir","d":"İki F1 çaprazlandığında çekinik aleller bir araya gelip aa bireyi verebilir."}],"ans":"F1'de gizli kalan çekinik alel, F2'de iki kez bir araya gelerek (aa) <b>çekinik özelliği yeniden ortaya çıkarır</b>."},{"q":"Mendel sonuçlarını değerlendirirken hangi yaklaşımı kullanmıştır?","steps":[{"t":"Verinin toplanması","a":"birey sayımı","d":"Her döldeki bireyleri tek tek sayarak veri topladı."},{"t":"Değerlendirme","a":"oran/istatistik","d":"Bu sayıları oranlara dökerek matematiksel düzenlilik aradı."}],"ans":"Mendel, çok sayıda bireyi sayıp sonuçları <b>oranlara ve istatistiğe</b> dökerek değerlendiren bir yaklaşım kullanmıştır."},{"q":"Bir Aa × Aa çaprazında genotip oranı ne olur?","steps":[{"t":"Olası genotipler","a":"AA, Aa, Aa, aa","d":"İki heterozigot çaprazından dört eşit olasılıkla genotip oluşur."},{"t":"Oran","a":"1 : 2 : 1","d":"Bunlar 1 AA, 2 Aa, 1 aa olacak şekilde dağılır."}],"ans":"Aa × Aa çaprazında genotip oranı <b>1 AA : 2 Aa : 1 aa</b> şeklindedir."},{"q":"Mendel'in çalışmaları neden uzun süre fark edilmemiştir?","steps":[{"t":"Yayın dönemi","a":"1866 az bilinen dergi","d":"Mendel sonuçlarını dönemin az okunan bir yerel dergide yayımladı."},{"t":"Bilim camiası","a":"matematiği anlaşılmadı","d":"İstatistiksel yaklaşımı dönemin biyologlarınca yeterince anlaşılamadı."}],"ans":"Mendel'in çalışmaları, az bilinen bir dergide yayımlanması ve <b>matematiksel yaklaşımının dönemce anlaşılamaması</b> nedeniyle yıllarca fark edilmemiştir."}],"zor":[{"q":"Mendel'in ayrılma yasasını (birinci yasa) mayoz bölünme ile ilişkilendirerek açıklayınız.","steps":[{"t":"Alel çiftleri","a":"homolog kromozomlarda","d":"Bir karakterin iki aleli, homolog kromozom çiftinin karşılıklı yerlerinde bulunur."},{"t":"Mayozda ayrılma","a":"homologlar ayrılır","d":"Mayoz-I'de homolog kromozomlar zıt kutuplara çekildiğinden aleller de ayrılır."},{"t":"Sonuç","a":"gamette tek alel","d":"Her gamet, bir karaktere ait yalnızca bir alel taşır."}],"ans":"Ayrılma yasası, mayoz-I'de homolog kromozomların ayrılmasının fiziksel karşılığıdır; bu nedenle her gamet o karaktere ait <b>tek bir alel</b> taşır."},{"q":"Mendel'in bağımsız dağılım yasasını (ikinci yasa) açıklayıp hangi koşulda geçerli olduğunu belirtiniz.","steps":[{"t":"Yasanın ifadesi","a":"aleller bağımsız dağılır","d":"Farklı karakterlere ait alel çiftleri gametlere birbirinden bağımsız dağılır."},{"t":"Mayozdaki temel","a":"bağımsız ayrılma","d":"Mayoz-I'de homolog çiftlerin metafaz plağındaki rastgele dizilişine dayanır."},{"t":"Koşul","a":"farklı kromozomlarda","d":"Yalnızca genler farklı (bağımsız) kromozomlarda yer alıyorsa geçerlidir."}],"ans":"Bağımsız dağılım yasası, farklı karakterlerin alellerinin gametlere bağımsız dağıldığını söyler; bu yalnızca ilgili genler <b>farklı kromozomlarda</b> olduğunda geçerlidir."},{"q":"SsYy genotipli bir bezelye kaç farklı gamet oluşturur ve bunlar nasıl belirlenir?","steps":[{"t":"Heterozigot gen sayısı","a":"2 (Ss, Yy)","d":"Birey iki karakter bakımından heterozigottur."},{"t":"Gamet sayısı","a":"2² = 4","d":"n heterozigot gen için 2ⁿ gamet oluşur; burada 2² = 4'tür."},{"t":"Gamet tipleri","a":"SY, Sy, sY, sy","d":"Bağımsız dağılımla aleller her olası kombinasyonda eşleşir."}],"ans":"SsYy bireyi <b>2² = 4</b> farklı gamet oluşturur: <b>SY, Sy, sY ve sy</b>."},{"q":"SsYy × SsYy dihibrit çaprazında F2 fenotip oranı nedir ve nasıl elde edilir?","steps":[{"t":"Her karakter ayrı","a":"3:1 ve 3:1","d":"Bağımsızlık nedeniyle her karakter ayrı ayrı 3 baskın : 1 çekinik verir."},{"t":"Olasılıkların çarpımı","a":"(3:1)×(3:1)","d":"İki karakterin olasılıkları çarpılarak birleşik oran bulunur."},{"t":"Sonuç","a":"9:3:3:1","d":"Dört fenotip sınıfı 9:3:3:1 oranında oluşur."}],"ans":"Dihibrit çaprazda F2 fenotip oranı <b>9:3:3:1</b>'dir; bu, her karakterin 3:1 oranının bağımsız olarak çarpılmasından elde edilir."},{"q":"Mendel'in 'faktör' kavramı ile mayoz/kromozom teorisi arasındaki bağ tarihsel olarak nasıl kurulmuştur?","steps":[{"t":"Mendel'in çıkarımı","a":"ayrılan faktörler","d":"Mendel, gözlemlerden özelliklerin gametlerde ayrılan birimlerce taşındığını çıkardı."},{"t":"Kromozom davranışı","a":"mayozda ayrılma","d":"Sonradan kromozomların mayozda tıpkı faktörler gibi ayrıldığı görüldü."},{"t":"Kromozom teorisi","a":"genler kromozomda","d":"Sutton ve Boveri, Mendel faktörlerinin kromozomlarda taşındığını ortaya koydu."}],"ans":"Mendel'in soyut 'faktör'lerinin davranışı, kromozomların mayozdaki ayrılmasıyla birebir örtüştüğünden; kalıtım birimlerinin (genlerin) <b>kromozomlarda taşındığı</b> kromozom teorisiyle açıklanmıştır."},{"q":"Eksik baskınlık, Mendel'in baskınlık ilkesinden nasıl bir sapma gösterir? Örnekle açıklayınız.","steps":[{"t":"Klasik baskınlık","a":"biri tam baskın","d":"Mendel örneklerinde heterozigotta yalnızca baskın alel görünür."},{"t":"Eksik baskınlık","a":"ara fenotip","d":"Bazı karakterlerde heterozigot, iki alelin karışımı bir ara fenotip gösterir."},{"t":"Örnek","a":"pembe çiçek","d":"Kırmızı (RR) × beyaz (rr) aslanağzında F1 (Rr) pembe çiçekli olur."}],"ans":"Eksik baskınlıkta heterozigot birey iki alelin karışımı bir <b>ara fenotip</b> (örneğin pembe) gösterir; bu, Mendel'in tam baskınlık ilkesinden bir sapmadır."},{"q":"Bağlı genler (linkage), Mendel'in bağımsız dağılım yasasını neden ihlal eder?","steps":[{"t":"Yasanın koşulu","a":"farklı kromozomlar","d":"Bağımsız dağılım, genlerin ayrı kromozomlarda olmasını gerektirir."},{"t":"Bağlı genler","a":"aynı kromozomda","d":"Aynı kromozomda yakın duran genler birlikte aktarılma eğilimindedir."},{"t":"Sonuç","a":"beklenen oran bozulur","d":"Birlikte taşındıkları için 9:3:3:1 oranı görülmez."}],"ans":"Aynı kromozomda yer alan bağlı genler birlikte aktarıldığından gametlere bağımsız dağılamaz; bu nedenle beklenen <b>9:3:3:1 oranı bozulur</b> ve bağımsız dağılım yasası ihlal edilir."},{"q":"Bir test çaprazlamasında baskın fenotipli birey saf çekinikle çaprazlanıyor; döllerin yarısı baskın yarısı çekinik fenotipte. Bireyin genotipi nedir, açıklayınız.","steps":[{"t":"Olasılıklar","a":"AA veya Aa","d":"Baskın fenotipli birey ya AA ya da Aa genotipinde olabilir."},{"t":"AA olsaydı","a":"hepsi baskın","d":"AA × aa çaprazında tüm döller Aa olur ve hepsi baskın görünürdü."},{"t":"Gözleme uygunluk","a":"1:1 → Aa","d":"Yarı baskın yarı çekinik (1:1) sonucu yalnızca Aa × aa verir."}],"ans":"Döllerin <b>1:1</b> baskın:çekinik dağılması yalnızca <b>Aa</b> × aa çaprazıyla açıklanır; dolayısıyla birey <b>heterozigot (Aa)</b>'dir."},{"q":"Mendel saf döller elde etmek için neden önce bitkileri birkaç kuşak kendileştirmiştir?","steps":[{"t":"Amaç","a":"homozigotluk","d":"Deneyin güvenilir olması için ata bitkilerin saf (homozigot) olması gerekir."},{"t":"Kendileşme etkisi","a":"heterozigotluk azalır","d":"Her kendileşmede heterozigot oranı yarıya iner, homozigotlar artar."},{"t":"Sonuç","a":"saf hat","d":"Birkaç kuşak sonra tek tip döl veren saf hatlar elde edilir."}],"ans":"Mendel, çaprazlamaya <b>saf (homozigot) ata bitkilerle</b> başlamak için bitkileri birkaç kuşak kendileştirmiş; böylece her kuşakta heterozigotluk azalıp saf hatlar elde edilmiştir."},{"q":"İki karakter için heterozigot bir bireyin (AaBb) gametlerinde olası 4 kombinasyonu mayozdaki metafaz dizilişiyle ilişkilendiriniz.","steps":[{"t":"Metafaz-I dizilişi","a":"rastgele yönelim","d":"Homolog çiftler metafaz plağında iki farklı şekilde dizilebilir."},{"t":"Olası dizilişler","a":"2 farklı düzen","d":"Bir dizilişte AB/ab, diğerinde Ab/aB kutuplara gider."},{"t":"Gamet tipleri","a":"AB, ab, Ab, aB","d":"İki diziliş birlikte dört farklı gamet kombinasyonu doğurur."}],"ans":"Metafaz-I'de homolog çiftlerin rastgele iki farklı dizilişi, AaBb bireyinde <b>AB, ab, Ab, aB</b> olmak üzere dört eşit olasılıklı gameti oluşturur."},{"q":"Bir bezelye popülasyonunda sarı (S baskın) tohum F2'de 6022, yeşil (çekinik) tohum 2001 sayılmış. Bu sonuç hangi yasayı destekler? Açıklayınız.","steps":[{"t":"Oranı hesapla","a":"≈ 3 : 1","d":"6022 ÷ 2001 ≈ 3 olduğundan oran yaklaşık 3 sarı : 1 yeşildir."},{"t":"Beklenen oran","a":"monohibrit 3:1","d":"Tek karakterli (monohibrit) çaprazda beklenen F2 oranı 3:1'dir."},{"t":"Sonuç","a":"ayrılma yasası","d":"Çekinik özelliğin 1/4 oranında yeniden çıkması alellerin ayrıldığını gösterir."}],"ans":"6022:2001 ≈ <b>3:1</b> oranı, monohibrit çaprazın beklenen sonucudur ve alellerin gametlere ayrılmasını öngören <b>ayrılma yasasını</b> destekler."},{"q":"Mendel'in çalışmalarında 'olasılık ilkeleri'nin (çarpım ve toplama kuralı) rolünü açıklayınız.","steps":[{"t":"Çarpım kuralı","a":"birlikte olma","d":"Bağımsız iki olayın birlikte gerçekleşme olasılığı, olasılıklarının çarpımıdır."},{"t":"Toplama kuralı","a":"ya biri ya öteki","d":"Birbirini dışlayan olaylardan herhangi birinin olasılığı, olasılıkların toplamıdır."},{"t":"Uygulama","a":"genotip tahmini","d":"Bu kurallarla dihibrit çaprazda her genotip/fenotipin oranı hesaplanır."}],"ans":"Mendel'in oranları, çarpım kuralı (bağımsız olayların birlikte olasılığı) ve toplama kuralı (alternatif olayların olasılığı) ile açıklanır; bu sayede karmaşık çaprazların döl oranları <b>matematiksel olarak öngörülebilir</b>."},{"q":"Mendel yasaları DNA ve gen kavramı bilinmeden ortaya konabilmiştir; bu durum bilimsel yöntem açısından ne anlatır?","steps":[{"t":"Veriye dayalı çıkarım","a":"gözlem + model","d":"Mendel, moleküler yapıyı bilmeden gözlemlerinden tutarlı bir model kurdu."},{"t":"Tahmin gücü","a":"sınanabilir öngörü","d":"Modeli, yapılmamış çaprazların sonuçlarını doğru öngörebiliyordu."},{"t":"Sonradan doğrulama","a":"mekanizmayla örtüşme","d":"Yıllar sonra keşfedilen kromozom ve gen, modeli birebir doğruladı."}],"ans":"Mendel'in başarısı, mekanizma bilinmeden de <b>gözleme dayalı, sınanabilir ve öngörü gücü olan bir model</b> kurulabileceğini gösterir; model, sonradan keşfedilen moleküler temelle (kromozom/gen) doğrulanmıştır."},{"q":"AaBb × AaBb dihibrit çaprazında yalnızca her iki karakter bakımından çekinik (aabb) bireyin oranını hesaplayıp açıklayınız.","steps":[{"t":"Birinci karakter","a":"aa = 1/4","d":"Aa × Aa çaprazında çekinik aa olma olasılığı 1/4'tür."},{"t":"İkinci karakter","a":"bb = 1/4","d":"Bb × Bb çaprazında çekinik bb olma olasılığı da 1/4'tür."},{"t":"Çarpım kuralı","a":"1/4 × 1/4","d":"Bağımsız olduklarından olasılıklar çarpılır."}],"ans":"İki karakter bağımsız olduğundan aabb bireyin oranı 1/4 × 1/4 = <b>1/16</b>'dır; bu da 9:3:3:1 oranındaki son sınıfa karşılık gelir."},{"q":"Mendel sonuçlarını yorumlarken yalnızca tek bir karakteri izleyip diğerlerini sabit tutmasının yöntemsel önemi nedir?","steps":[{"t":"Değişken denetimi","a":"tek değişken","d":"Aynı anda tek karakteri izleyerek diğer karakterlerin etkisini dışladı."},{"t":"Karışıklığın önlenmesi","a":"net oran","d":"Böylece elde edilen oranlar başka karakterlerce bulanıklaştırılmadı."},{"t":"Genelleme","a":"yasa çıkarımı","d":"Net ve tekrarlanabilir oranlar, genel yasaların çıkarılmasını sağladı."}],"ans":"Tek karakteri izleyip diğerlerini sabit tutmak, bir <b>değişken denetimi</b> uygulamasıdır; bu sayede oranlar bulanıklaşmadan net ölçüldü ve genellenebilir yasalar çıkarılabildi."}]}},"monohibrit":{"ilkokul":{"kolay":[{"q":"Anne kedi ve baba kedinin ikisi de kara renkli. Yavru kedi büyük olasılıkla hangi renkte olur?","steps":[{"t":"Anne ve babaya bak","a":"İkisi de kara","d":"Yavrular özelliklerini anne ve babadan alır. İkisi de kara renkliyse renk kara taraftan gelir."},{"t":"Yavruyu tahmin et","a":"Kara renkli","d":"Anne baba kara olunca yavru da çoğunlukla kara renkli olur."}],"ans":"Yavru kedi büyük olasılıkla kara renkli olur."},{"q":"Uzun boylu bir bezelye bitkisi ile yine uzun boylu bir bezelye bitkisinin tohumundan çıkan yeni bitki çoğunlukla nasıl olur?","steps":[{"t":"Ana bitkilere bak","a":"İkisi de uzun","d":"Yeni bitki özelliklerini iki ana bitkiden alır. İkisi de uzunsa uzunluk özelliği geçer."},{"t":"Yeni bitkiyi tahmin et","a":"Uzun boylu","d":"Uzun ile uzunun tohumundan çoğunlukla uzun bitki çıkar."}],"ans":"Yeni bitki çoğunlukla uzun boylu olur."},{"q":"Bir çiçeğin kırmızı renk özelliği anneden mi babadan mı yoksa ikisinden de mi gelebilir?","steps":[{"t":"Özellik nereden gelir?","a":"Anne ve babadan","d":"Canlılar özelliklerini hem anneden hem babadan alır. Renk de böyle bir özelliktir."},{"t":"Cevabı söyle","a":"İkisinden de","d":"Kırmızı renk özelliği hem anneden hem babadan gelebilir."}],"ans":"Renk özelliği hem anneden hem babadan gelebilir."},{"q":"Sarı tüylü anne tavşan ile sarı tüylü baba tavşanın yavruları en çok hangi renkte olur?","steps":[{"t":"Anne babanın rengi","a":"İkisi de sarı","d":"Yavru tüy rengini anne ve babadan alır. İkisi de sarıysa sarı renk yavruya geçer."},{"t":"Yavruyu tahmin et","a":"Sarı tüylü","d":"Sarı ile sarıdan çoğunlukla sarı tüylü yavru olur."}],"ans":"Yavrular en çok sarı tüylü olur."},{"q":"Bir bitkinin tohumundan çıkan yeni bitkiler neden ana bitkiye benzer?","steps":[{"t":"Benzerlik nereden?","a":"Ana bitkiden","d":"Yeni bitki özelliklerini tohumu veren ana bitkiden alır."},{"t":"Sonucu söyle","a":"Özellik aktarılır","d":"Renk, boy gibi özellikler ana bitkiden yeni bitkiye geçtiği için birbirlerine benzerler."}],"ans":"Çünkü özellikler ana bitkiden yeni bitkiye aktarılır."}],"zor":[{"q":"Anne tavşan beyaz, baba tavşan da beyaz. Ama büyük annenin kara olduğu biliniyor. Yavrularda kara renk ortaya çıkabilir mi?","steps":[{"t":"Gizli özellik","a":"Karadan gelen iz","d":"Beyaz tavşanlarda büyük anneden gelen kara renk özelliği gizli kalmış olabilir."},{"t":"Yavruyu düşün","a":"Bazen kara çıkar","d":"Anne ve babada gizli duran kara özellik birleşirse bazı yavrularda kara renk görülebilir."}],"ans":"Evet, gizli kalan kara özellik birleşirse bazı yavrular kara olabilir."},{"q":"Uzun anne ile kısa baba bitkinin tohumundan çıkan bitkiler hep uzun oluyor. Hangi özellik daha güçlü görünmüştür?","steps":[{"t":"Hangi özellik göründü?","a":"Uzunluk","d":"Yavruların hepsi uzun çıktıysa uzunluk özelliği kısalığı bastırıp görünür olmuştur."},{"t":"Sonucu söyle","a":"Uzun daha güçlü","d":"Burada uzunluk özelliği kısalıktan daha baskın (güçlü) görünmüştür."}],"ans":"Uzunluk özelliği daha güçlü (baskın) görünmüştür."},{"q":"İki kahverengi gözlü anne baba, mavi gözlü bir bebeğe sahip oldu. Bu nasıl olabilir?","steps":[{"t":"Gizli özellik var mı?","a":"Mavi göz gizli","d":"Anne ve babanın gözü kahverengi olsa da içlerinde gizli mavi göz özelliği taşıyor olabilir."},{"t":"Bebeği açıkla","a":"Gizliler birleşti","d":"İki gizli mavi özellik bebekte bir araya gelirse bebek mavi gözlü olabilir."}],"ans":"Anne babada gizli duran mavi göz özelliği bebekte birleştiği için bebek mavi gözlü olmuştur."},{"q":"Bir çiftçi en uzun bitkilerden tohum alıp ekiyor ve her yıl bitkileri daha çok uzun çıkıyor. Çiftçi neyi kullanmıştır?","steps":[{"t":"Ne yaptı?","a":"Uzunları seçti","d":"Çiftçi sadece uzun bitkilerin tohumunu ekerek uzunluk özelliğini yeni bitkilere aktarmıştır."},{"t":"Sonucu söyle","a":"Özellik aktarımı","d":"Özelliklerin ana bitkiden yeni bitkiye geçmesini kullanarak uzun bitkiler elde etmiştir."}],"ans":"Özelliklerin yavruya aktarılmasını kullanarak uzun bitkileri seçmiştir."},{"q":"Bir hayvan türünde siyah tüy beyaz tüyü bastırıyor. İki siyah hayvanın yavrularından bazıları beyaz çıktı. Anne baba nasıl olmalı?","steps":[{"t":"Beyaz nasıl çıktı?","a":"Gizli beyaz","d":"Siyah beyazı bastırdığı için anne baba siyah görünür ama içlerinde gizli beyaz özellik taşıyor olabilir."},{"t":"Sonucu söyle","a":"İkisi de gizli taşıyor","d":"Hem anne hem baba gizli beyaz özellik taşıdığı için bazı yavrular beyaz olmuştur."}],"ans":"Anne ve babanın ikisi de gizli beyaz özellik taşımaktadır."}]},"ortaokul":{"kolay":[{"q":"Bir özelliği belirleyen ve anne babadan yavruya geçen yapı birimine ne denir?","steps":[{"t":"Özelliği ne taşır?","a":"Gen","d":"Boy, renk gibi özellikleri belirleyen ve anne babadan yavruya geçen kalıtım birimine gen denir."},{"t":"Sonucu söyle","a":"Gen","d":"Genler kalıtsal özelliklerin aktarılmasını sağlar."}],"ans":"Bu yapı birimine <b>gen</b> denir."},{"q":"Baskın gen ile çekinik gen arasındaki fark nedir?","steps":[{"t":"Baskın gen","a":"Görünür olan","d":"Baskın gen, yanında çekinik gen olsa bile özelliğini dışarıdan gösterir."},{"t":"Çekinik gen","a":"Gizlenen","d":"Çekinik gen ancak iki tane bir araya gelirse kendini gösterir; tek başına baskın tarafından örtülür."}],"ans":"Baskın gen tek başına bile özelliğini gösterir; çekinik gen ancak iki tane olunca görünür."},{"q":"Bezelyede mor çiçek (A) beyaza (a) baskındır. Aa genotipli bitkinin çiçek rengi ne olur?","steps":[{"t":"Genleri incele","a":"A baskın","d":"Aa bitkisinde bir baskın (A) bir çekinik (a) gen vardır."},{"t":"Görünüşü belirle","a":"Mor","d":"Baskın gen A bulunduğu için çiçek mor görünür; beyaz gen gizli kalır."}],"ans":"Aa genotipli bitkinin çiçeği <b>mor</b> olur."},{"q":"Bir canlının gözlemlediğimiz dış görünüşüne (örneğin mor çiçek) ne ad verilir?","steps":[{"t":"Dış görünüş nedir?","a":"Fenotip","d":"Canlının gözle görülen özelliklerine (renk, boy gibi) fenotip denir."},{"t":"Sonucu söyle","a":"Fenotip","d":"Mor çiçek, uzun boy gibi gözlemlenen özellikler fenotiptir."}],"ans":"Dış görünüşe <b>fenotip</b> denir."},{"q":"AA ve aa gibi gen yazılışlarına, yani bir canlının taşıdığı genlerin tamamına ne denir?","steps":[{"t":"Gen yapısı nedir?","a":"Genotip","d":"Bir canlının taşıdığı gen çiftine (AA, Aa, aa gibi) genotip denir."},{"t":"Sonucu söyle","a":"Genotip","d":"Genotip canlının gen yapısını, fenotip ise dış görünüşünü ifade eder."}],"ans":"Gen yapısına <b>genotip</b> denir."}],"zor":[{"q":"Mor çiçek (A) beyaza (a) baskındır. Saf mor (AA) bir bitki ile beyaz (aa) bitki çaprazlanırsa F1 dölünün genotip ve fenotipi ne olur?","steps":[{"t":"Gametleri yaz","a":"A ve a","d":"AA bitkisi yalnız A, aa bitkisi yalnız a gameti verir."},{"t":"Birleştir","a":"Aa","d":"A ile a birleşince tüm yavrular Aa genotipinde olur."},{"t":"Fenotipi belirle","a":"Hepsi mor","d":"Aa bitkilerinde baskın A bulunduğu için tüm F1 bireyleri mor çiçeklidir."}],"ans":"F1 dölünün hepsi <b>Aa</b> genotipinde ve <b>mor</b> çiçeklidir."},{"q":"Aa × Aa çaprazlamasında oluşabilecek dört yavrudan kaçı çekinik özelliği (aa) gösterir?","steps":[{"t":"Punnett karesi","a":"AA, Aa, Aa, aa","d":"Aa × Aa çaprazında dört yavru AA, Aa, Aa, aa olarak oluşur."},{"t":"Çekiniği say","a":"1 tanesi aa","d":"Dört yavrudan yalnız biri aa genotipindedir."},{"t":"Sonucu söyle","a":"1/4","d":"Yani yavruların dörtte biri çekinik özelliği gösterir."}],"ans":"Dört yavrudan <b>1 tanesi</b> (1/4) çekinik özellik gösterir."},{"q":"Aa × Aa çaprazlamasında fenotip oranı kaça kaçtır?","steps":[{"t":"Olası yavrular","a":"AA, Aa, Aa, aa","d":"Punnett karesinde dört yavru AA, Aa, Aa, aa olur."},{"t":"Görünüşleri grupla","a":"3 baskın, 1 çekinik","d":"AA, Aa, Aa baskın görünür (3), yalnız aa çekinik görünür (1)."},{"t":"Oranı yaz","a":"3:1","d":"Bu yüzden baskın fenotip ile çekinik fenotip oranı 3:1 olur."}],"ans":"Fenotip oranı <b>3:1</b> (3 baskın, 1 çekinik) olur."},{"q":"Çekinik özellik gösteren beyaz çiçekli (aa) bir bezelyenin genotipi neden kesin olarak bilinir?","steps":[{"t":"Çekinik kuralı","a":"İki çekinik gerekir","d":"Çekinik özellik ancak iki çekinik gen (aa) bir araya gelince görünür."},{"t":"Sonucu çıkar","a":"Genotip aa","d":"Beyaz görünen bitkide baskın gen olamaz, bu yüzden genotipi kesinlikle aa'dır."}],"ans":"Çekinik fenotip yalnız <b>aa</b> ile oluştuğu için genotipi kesin aa'dır."},{"q":"Bir bitkinin uzun (A) olduğu biliniyor ama AA mı Aa mı bilinmiyor. Bunu anlamak için hangi çaprazlama yapılır?","steps":[{"t":"Bilinmeyeni bul","a":"Çekinikle çapraz","d":"Bilinmeyen genotipi anlamak için onu çekinik (aa) bir bireyle çaprazlarız; buna kontrol (geri) çaprazlaması denir."},{"t":"Sonucu yorumla","a":"Kısa çıkarsa Aa","d":"Yavrularda kısa (aa) birey çıkarsa bitki Aa'dır; hepsi uzun çıkarsa AA'dır."}],"ans":"Çekinik (aa) birey ile <b>kontrol çaprazlaması</b> yapılır."}]},"lise":{"kolay":[{"q":"Monohibrit çaprazlama terimi neyi ifade eder?","steps":[{"t":"Tanımı incele","a":"Tek karakter","d":"Monohibrit çaprazlama, tek bir karakter (örneğin yalnız tohum rengi) bakımından farklı bireylerin çaprazlanmasıdır."},{"t":"Sonucu söyle","a":"Tek gen takibi","d":"Bu çaprazlamada tek bir gen çiftinin kalıtımı izlenir."}],"ans":"Monohibrit çaprazlama, <b>tek bir karakter</b> bakımından yapılan çaprazlamadır."},{"q":"Homozigot ve heterozigot birey ne demektir?","steps":[{"t":"Homozigot","a":"Aynı iki alel","d":"Bir gen için iki aleli aynı olan bireye homozigot (saf) denir: AA veya aa."},{"t":"Heterozigot","a":"Farklı iki alel","d":"Bir gen için alelleri farklı olan bireye heterozigot (melez) denir: Aa."}],"ans":"Homozigot alelleri aynıdır (AA, aa); heterozigot alelleri farklıdır (Aa)."},{"q":"Bezelyede sarı tohum (Y) yeşile (y) baskındır. YY bireyinin oluşturabileceği gamet çeşitleri nelerdir?","steps":[{"t":"Aleller ayrılır","a":"İki Y aleli","d":"Mayozda homolog kromozomlar ve aleller birbirinden ayrılır. YY bireyinde her iki alel de Y'dir."},{"t":"Gametleri yaz","a":"Yalnız Y","d":"Her gamet bir alel taşıdığı için YY bireyinin tüm gametleri Y'dir."}],"ans":"YY bireyi yalnızca <b>Y</b> taşıyan gamet oluşturur."},{"q":"Heterozigot (Aa) bir bireyin oluşturabileceği gamet çeşitleri ve oranları nedir?","steps":[{"t":"Aleller ayrılır","a":"A ve a","d":"Mayozda Aa bireyinin alelleri ayrılır; bir kısım gamet A, bir kısmı a taşır."},{"t":"Oranı belirle","a":"1/2 A, 1/2 a","d":"Gametlerin yarısı A, yarısı a olur (1:1 oranında)."}],"ans":"Aa bireyi <b>1/2 A</b> ve <b>1/2 a</b> olmak üzere iki çeşit gamet oluşturur."},{"q":"Mendel'in ayrılma (segregasyon) ilkesi neyi açıklar?","steps":[{"t":"İlkeyi tanı","a":"Aleller ayrılır","d":"Ayrılma ilkesine göre bir bireydeki alel çifti, gamet oluşumunda birbirinden ayrılır."},{"t":"Sonucu söyle","a":"Her gamete bir alel","d":"Böylece her gamet o gen için yalnızca bir alel taşır."}],"ans":"Ayrılma ilkesi, alel çiftinin gamet oluşumunda ayrılıp her gamete bir alel gittiğini açıklar."},{"q":"AA × aa çaprazlamasında F1 dölünün genotipi nedir?","steps":[{"t":"Gametleri belirle","a":"A ve a","d":"AA bireyi yalnız A, aa bireyi yalnız a gameti verir."},{"t":"Birleştir","a":"Aa","d":"A ile a birleşince tüm F1 bireyleri Aa olur."}],"ans":"F1 dölünün tamamı <b>Aa</b> genotipindedir."},{"q":"Saf döl (homozigot) ile melez döl (heterozigot) arasındaki temel fark nedir?","steps":[{"t":"Saf döl","a":"Aynı alel","d":"Saf döl aynı alelleri taşır (AA veya aa) ve kendi içinde çaprazlanınca hep aynı tip yavru verir."},{"t":"Melez döl","a":"Farklı alel","d":"Melez döl farklı alelleri taşır (Aa) ve kendi içinde çaprazlanınca farklı genotipte yavrular verir."}],"ans":"Saf döl aynı (AA/aa), melez döl farklı (Aa) alelleri taşır."},{"q":"Eşit baskınlık (kodominantlık) ile tam baskınlık arasındaki fark nedir?","steps":[{"t":"Tam baskınlık","a":"Biri örter","d":"Tam baskınlıkta heterozigotta baskın alelin özelliği görünür, çekinik tamamen örtülür (Aa = baskın fenotip)."},{"t":"Eşit baskınlık","a":"İkisi birlikte","d":"Eşit baskınlıkta heterozigotta her iki alelin özelliği de ayrı ayrı görülür (örneğin AB kan grubu)."}],"ans":"Tam baskınlıkta yalnız baskın görünür; eşit baskınlıkta her iki alel de birlikte görünür."},{"q":"Bir bireyin fenotipini hem genotip hem de çevre etkiler. Buna bir örnek veriniz.","steps":[{"t":"Çevre etkisi","a":"Beslenme/sıcaklık","d":"Aynı genotipe sahip bir bitki, az ışık veya kötü beslenme nedeniyle daha kısa kalabilir."},{"t":"Sonucu yorumla","a":"Fenotip değişir","d":"Genotip aynı kalsa da çevre koşulları fenotipi (boy gibi) değiştirebilir."}],"ans":"Aynı genotipli bitkinin beslenme veya ışık farkıyla farklı boyda görünmesi çevre etkisine örnektir."},{"q":"P, F1 ve F2 kuşakları sırasıyla neyi ifade eder?","steps":[{"t":"P ve F1","a":"Ata ve ilk döl","d":"P (parental) çaprazlanan ata bireyleri, F1 onların ilk yavru kuşağıdır."},{"t":"F2","a":"İkinci döl","d":"F2, F1 bireylerinin kendi aralarında çaprazlanmasıyla oluşan ikinci yavru kuşağıdır."}],"ans":"P ata kuşağı, F1 ilk yavru kuşağı, F2 ise F1'lerin çaprazından oluşan ikinci kuşaktır."},{"q":"Bezelyede uzunluk (T) kısalığa (t) baskındır. Tt × tt çaprazlamasında fenotip oranı ne olur?","steps":[{"t":"Gametleri yaz","a":"T,t ve t","d":"Tt bireyi T ve t, tt bireyi yalnız t gameti verir."},{"t":"Birleştir","a":"Tt ve tt","d":"Yavruların yarısı Tt (uzun), yarısı tt (kısa) olur."},{"t":"Oranı belirle","a":"1:1","d":"Böylece uzun ile kısa fenotip oranı 1:1 olur."}],"ans":"Tt × tt çaprazında fenotip oranı <b>1:1</b> (uzun:kısa) olur."},{"q":"Punnett karesi ne işe yarar?","steps":[{"t":"Amacı tanı","a":"Yavru tahmini","d":"Punnett karesi, ana bireylerin gametlerini satır ve sütuna yazıp olası yavru genotiplerini gösteren bir tablodur."},{"t":"Sonucu söyle","a":"Olasılık hesabı","d":"Bu tablo sayesinde yavruların genotip ve fenotip oranları kolayca hesaplanır."}],"ans":"Punnett karesi, olası yavru genotip ve fenotip oranlarını tahmin etmeye yarar."},{"q":"Test çaprazlaması (kontrol çaprazlaması) hangi amaçla yapılır?","steps":[{"t":"Amacı tanı","a":"Genotip bulma","d":"Baskın fenotipli bir bireyin AA mı Aa mı olduğunu anlamak için çekinik (aa) bireyle çaprazlanır."},{"t":"Sonucu yorumla","a":"Yavruya bak","d":"Çekinik yavru çıkarsa birey heterozigot (Aa), tüm yavrular baskın çıkarsa homozigottur (AA)."}],"ans":"Test çaprazlaması, baskın fenotipli bireyin bilinmeyen genotipini belirlemek için yapılır."},{"q":"aa × aa çaprazlamasında yavruların genotip ve fenotipi nasıl olur?","steps":[{"t":"Gametleri yaz","a":"İkisi de a","d":"Her iki birey de homozigot çekinik olduğu için yalnız a gameti verir."},{"t":"Birleştir","a":"Tümü aa","d":"a ile a birleşince tüm yavrular aa genotipinde ve çekinik fenotiplidir."}],"ans":"Tüm yavrular <b>aa</b> genotipinde ve çekinik fenotiplidir."},{"q":"AA × Aa çaprazlamasında çekinik fenotipli (aa) birey çıkar mı?","steps":[{"t":"Gametleri yaz","a":"A ve A,a","d":"AA bireyi yalnız A; Aa bireyi A ve a gameti verir."},{"t":"Birleştir","a":"AA ve Aa","d":"Olası yavrular AA ve Aa olur; her ikisinde de baskın A bulunur."},{"t":"Sonucu yorumla","a":"Çekinik çıkmaz","d":"En az bir A her zaman bulunduğu için aa genotipli birey oluşamaz."}],"ans":"Hayır, en az bir A her zaman bulunduğundan çekinik (aa) birey çıkmaz."}],"zor":[{"q":"Bezelyede sarı tohum (Y) yeşile (y) baskındır. Yy × Yy çaprazlamasında F2 dölünün genotip ve fenotip oranlarını bulunuz.","steps":[{"t":"Gametleri belirle","a":"Y ve y","d":"Her iki ebeveyn de Yy olduğundan 1/2 Y, 1/2 y gameti verir."},{"t":"Punnett karesi","a":"YY, Yy, Yy, yy","d":"Gametleri çaprazlayınca YY, Yy, Yy, yy yavruları oluşur."},{"t":"Oranları yaz","a":"1:2:1 ve 3:1","d":"Genotip oranı 1 YY : 2 Yy : 1 yy; sarı (YY+Yy) ile yeşil (yy) fenotip oranı 3:1'dir."}],"ans":"Genotip oranı <b>1:2:1</b>, fenotip oranı <b>3:1</b> (sarı:yeşil) olur."},{"q":"Yy × Yy çaprazlamasında sarı (baskın) görünen bir yavrunun heterozigot (Yy) olma olasılığı nedir?","steps":[{"t":"Genotipleri yaz","a":"1 YY:2 Yy:1 yy","d":"F2'de genotipler 1 YY, 2 Yy, 1 yy oranındadır."},{"t":"Sarı bireyleri seç","a":"YY ve Yy","d":"Sarı görünenler YY ve Yy bireyleridir; toplam 3 birimden (1 YY + 2 Yy) oluşur."},{"t":"Olasılığı hesapla","a":"2/3","d":"Sarı 3 birimin 2'si Yy olduğu için heterozigot olma olasılığı 2/3'tür."}],"ans":"Sarı bir yavrunun heterozigot olma olasılığı <b>2/3</b>'tür."},{"q":"Mor çiçekli (Aa) iki bitki çaprazlanıyor. Oluşan 480 yavrudan kaçının beyaz (aa) çiçekli olması beklenir?","steps":[{"t":"Çekinik oranı","a":"1/4","d":"Aa × Aa çaprazında çekinik (aa) fenotip oranı 1/4'tür."},{"t":"Sayıyla çarp","a":"480 × 1/4","d":"480 yavrunun 1/4'ü hesaplanır: 480 × 1/4 = 120."},{"t":"Sonucu yaz","a":"120 beyaz","d":"Beklenen beyaz çiçekli yavru sayısı 120'dir."}],"ans":"Yaklaşık <b>120</b> yavrunun beyaz çiçekli olması beklenir."},{"q":"Aa × Aa çaprazlamasından elde edilen 360 yavrudan kaç tanesinin baskın fenotipli olması beklenir?","steps":[{"t":"Baskın oranı","a":"3/4","d":"Aa × Aa çaprazında baskın fenotip oranı 3/4'tür (3 baskın : 1 çekinik)."},{"t":"Sayıyla çarp","a":"360 × 3/4","d":"360 yavrunun 3/4'ü: 360 × 3/4 = 270."},{"t":"Sonucu yaz","a":"270 baskın","d":"Beklenen baskın fenotipli yavru sayısı 270'tir."}],"ans":"Yaklaşık <b>270</b> yavrunun baskın fenotipli olması beklenir."},{"q":"Tt × Tt çaprazlamasında yavrularda hem homozigot baskın (TT) hem de homozigot çekinik (tt) çıkma olasılığı ayrı ayrı nedir?","steps":[{"t":"Genotipleri yaz","a":"1 TT:2 Tt:1 tt","d":"Tt × Tt çaprazında genotip oranı 1 TT : 2 Tt : 1 tt olur (toplam 4 birim)."},{"t":"Olasılıkları ayır","a":"TT=1/4, tt=1/4","d":"4 birimden 1'i TT, 1'i tt olduğu için her birinin olasılığı 1/4'tür."}],"ans":"TT olma olasılığı <b>1/4</b>, tt olma olasılığı da <b>1/4</b>'tür."},{"q":"Bir baskın fenotipli bitki, çekinik (aa) bir bitkiyle çaprazlanınca yavruların yarısı çekinik çıkıyor. Baskın bitkinin genotipi nedir?","steps":[{"t":"Çıkarımı yap","a":"Çekinik var","d":"Çaprazda çekinik (aa) yavru oluşması, baskın bitkinin bir çekinik (a) alel taşıdığını gösterir."},{"t":"Oranı yorumla","a":"1:1 oranı","d":"Yavruların yarısı baskın yarısı çekinik (1:1) çıkmasını ancak Aa × aa çaprazı verir."},{"t":"Sonucu yaz","a":"Aa","d":"Bu nedenle baskın bitkinin genotipi heterozigot (Aa) olmalıdır."}],"ans":"Baskın bitkinin genotipi <b>Aa</b> (heterozigot) olmalıdır."},{"q":"Yy × Yy çaprazlamasında bir yavrunun sarı tohumlu olma olasılığı ile aynı anda iki yavrunun da sarı olma olasılığı nedir?","steps":[{"t":"Tek yavru sarı","a":"3/4","d":"Aa türü çaprazda baskın (sarı) fenotip olasılığı 3/4'tür."},{"t":"İki yavru birden","a":"3/4 × 3/4","d":"Bağımsız olaylar olduğu için iki yavrunun da sarı olması: 3/4 × 3/4 = 9/16."},{"t":"Sonucu yaz","a":"9/16","d":"İki yavrunun da sarı olma olasılığı 9/16'dır."}],"ans":"Bir yavru için 3/4; iki yavrunun da sarı olması <b>9/16</b>'dır."},{"q":"Tam baskınlığın görülmediği aslanağzında kırmızı (RR) ile beyaz (BB) çiçek çaprazlanınca F1 pembe (RB) oluyor. RB × RB çaprazında F2 fenotip oranı ne olur?","steps":[{"t":"Eksik baskınlık","a":"Ara fenotip","d":"Burada heterozigot (RB) ara renk olan pembe görünür; bu eksik baskınlıktır."},{"t":"Punnett karesi","a":"RR, RB, RB, BB","d":"RB × RB çaprazında yavrular RR, RB, RB, BB oluşur."},{"t":"Fenotipleri grupla","a":"1:2:1","d":"Eksik baskınlıkta her genotip ayrı görünür: 1 kırmızı : 2 pembe : 1 beyaz."}],"ans":"Eksik baskınlık nedeniyle fenotip oranı <b>1:2:1</b> (kırmızı:pembe:beyaz) olur."},{"q":"Aa × Aa çaprazlamasından doğan 4 yavrunun da baskın fenotipli olma olasılığı nedir?","steps":[{"t":"Tek yavru baskın","a":"3/4","d":"Her bir yavru için baskın fenotip olasılığı 3/4'tür."},{"t":"Dört yavru çarp","a":"(3/4)⁴","d":"Olaylar bağımsız olduğundan dördünün de baskın olması (3/4)⁴ = 81/256'dır."},{"t":"Sonucu yaz","a":"81/256","d":"Dört yavrunun dördünün de baskın olma olasılığı 81/256 (≈ 0,32) olur."}],"ans":"Dört yavrunun da baskın olma olasılığı <b>81/256</b>'dır."},{"q":"Heterozigot uzun (Tt) bir bezelye kendi kendine tozlaşırsa, kısa (tt) yavru elde etme olasılığı ile uzun yavru olasılığını karşılaştırınız.","steps":[{"t":"Çaprazı kur","a":"Tt × Tt","d":"Kendine tozlaşma Tt × Tt çaprazına eşittir."},{"t":"Oranları bul","a":"3/4 uzun, 1/4 kısa","d":"Genotipler 1 TT : 2 Tt : 1 tt; uzun fenotip 3/4, kısa fenotip 1/4 olur."},{"t":"Karşılaştır","a":"Uzun 3 kat","d":"Uzun olma olasılığı (3/4), kısa olma olasılığının (1/4) 3 katıdır."}],"ans":"Uzun yavru olasılığı 3/4, kısa 1/4'tür; uzun olma olasılığı kısanın <b>3 katıdır</b>."},{"q":"Aa × aa çaprazlamasından 200 yavru doğuyor. Bunların kaçının çekinik (aa) fenotipli olması beklenir?","steps":[{"t":"Gametleri yaz","a":"A,a ve a","d":"Aa bireyi A ve a; aa bireyi yalnız a gameti verir."},{"t":"Oranı bul","a":"1/2 aa","d":"Yavrular 1/2 Aa, 1/2 aa olur; yani yarısı çekinik fenotiplidir."},{"t":"Sayıyla çarp","a":"200 × 1/2","d":"200 × 1/2 = 100; beklenen çekinik yavru sayısı 100'dür."}],"ans":"Yaklaşık <b>100</b> yavrunun çekinik fenotipli olması beklenir."},{"q":"Bir bezelye popülasyonunda Aa × Aa çaprazından oluşan yavrularda baskın fenotip ile çekinik fenotip sayıları 312 ve 104 ölçülmüştür. Bu sonuç hangi teorik orana uyar?","steps":[{"t":"Sayıları oranla","a":"312:104","d":"Gözlenen sayıların oranını sadeleştirelim: 312 ÷ 104 = 3, yani 312:104 = 3:1."},{"t":"Teoriyle karşılaştır","a":"3:1","d":"Bu oran, Aa × Aa monohibrit çaprazının beklenen 3:1 fenotip oranıyla uyumludur."}],"ans":"Sonuç, monohibrit çaprazın beklenen <b>3:1</b> fenotip oranına uyar."},{"q":"Yy × yy çaprazlamasından doğan iki yavrunun da yeşil (yy) olma olasılığı nedir?","steps":[{"t":"Tek yavru yeşil","a":"1/2","d":"Yy × yy çaprazında yavrular 1/2 Yy (sarı), 1/2 yy (yeşil) olur; yeşil olasılığı 1/2."},{"t":"İki yavru çarp","a":"1/2 × 1/2","d":"Bağımsız olduğu için iki yavrunun da yeşil olması: 1/2 × 1/2 = 1/4."},{"t":"Sonucu yaz","a":"1/4","d":"İki yavrunun da yeşil olma olasılığı 1/4'tür."}],"ans":"İki yavrunun da yeşil olma olasılığı <b>1/4</b>'tür."},{"q":"Aa × Aa çaprazlamasında ilk yavrunun baskın, ikinci yavrunun çekinik fenotipli olma olasılığı nedir?","steps":[{"t":"Tek tek olasılık","a":"3/4 ve 1/4","d":"Baskın fenotip olasılığı 3/4, çekinik fenotip olasılığı 1/4'tür."},{"t":"Sıralı çarpım","a":"3/4 × 1/4","d":"Belirli sıra istendiği için olasılıklar çarpılır: 3/4 × 1/4 = 3/16."},{"t":"Sonucu yaz","a":"3/16","d":"İlk baskın, ikinci çekinik olma olasılığı 3/16'dır."}],"ans":"İlk yavru baskın, ikinci çekinik olma olasılığı <b>3/16</b>'dır."},{"q":"Çekinik bir kalıtsal hastalık taşıyan iki sağlıklı (Aa) ebeveynin çocuğunun hasta (aa) olma olasılığı ve sağlıklı çocuğun taşıyıcı (Aa) olma olasılığı nedir?","steps":[{"t":"Çaprazı kur","a":"Aa × Aa","d":"İki taşıyıcı ebeveynin çaprazı Aa × Aa'dır; genotipler 1 AA : 2 Aa : 1 aa olur."},{"t":"Hasta olasılığı","a":"1/4","d":"Hastalık çekinik (aa) olduğundan çocuğun hasta olma olasılığı 1/4'tür."},{"t":"Taşıyıcı olasılığı","a":"2/3","d":"Sağlıklı çocuklar AA ve Aa'dır (3 birim); 2'si Aa olduğundan taşıyıcı olma olasılığı 2/3'tür."}],"ans":"Çocuğun hasta (aa) olma olasılığı <b>1/4</b>; sağlıklı bir çocuğun taşıyıcı olma olasılığı <b>2/3</b>'tür."}]}},"testCaprazlama":{"ilkokul":{"kolay":[{"q":"Bir bezelyenin çiçeği mor; içinde gizli beyaz özellik var mı, nasıl anlarız?","steps":[{"t":"Gizli özellik sorunu","a":"dıştan belli olmaz","d":"Mor çiçek dıştan aynı görünür ama içinde gizli beyaz özellik saklı olabilir."},{"t":"Çözüm yolu","a":"beyazla çaprazla","d":"Onu hep beyaz olan bir bitkiyle çaprazlayıp yavrularına bakarız."}],"ans":"Mor bitkiyi beyaz bir bitkiyle çaprazlar, yavruların rengine bakarak gizli özelliği anlarız."},{"q":"Saf beyaz çiçekli bitki neden gizli özellik bulmada yardımcı kullanılır?","steps":[{"t":"Beyazın özelliği","a":"gizlisi yok","d":"Beyaz çiçek baskın değildir; içinde saklı bir renk taşımaz, ne varsa odur."},{"t":"Yardımı","a":"gizliyi ortaya çıkarır","d":"Bu yüzden onunla çaprazlayınca diğer bitkinin gizli özelliği yavrularda görünür."}],"ans":"Beyaz çiçek hiç gizli özellik taşımadığı için karşısındaki bitkinin saklı özelliğini ortaya çıkarmaya yarar."},{"q":"Mor çiçekli bir bitkiyi beyazla çaprazladık, tüm yavrular mor oldu. Bu ne demek?","steps":[{"t":"Yavrulara bak","a":"hepsi mor","d":"Hiç beyaz yavru çıkmadı, yavruların tamamı mor renkte oldu."},{"t":"Anlamı","a":"gizli beyaz yok","d":"Bitkide saklı beyaz özellik yok demektir; o tam (saf) mordur."}],"ans":"Tüm yavrular mor çıktıysa o bitki saf mordur, içinde gizli beyaz özellik taşımaz."},{"q":"Mor çiçekli bir bitkiyi beyazla çaprazladık, yavruların yarısı beyaz çıktı. Bu ne demek?","steps":[{"t":"Yavrulara bak","a":"yarısı beyaz","d":"Yavruların bir kısmı mor, bir kısmı beyaz oldu."},{"t":"Anlamı","a":"gizli beyaz var","d":"Beyaz yavru çıktıysa o mor bitki içinde gizli beyaz özellik taşıyordu."}],"ans":"Beyaz yavrular çıktıysa o mor bitki içinde gizli beyaz özellik saklıyordu."},{"q":"İki mor bitki tıpatıp aynı görünüyor; içlerinde gizli özellik olup olmadığını nasıl ayırırız?","steps":[{"t":"Sorun","a":"dıştan aynı","d":"İkisi de mor olduğu için gözle bakarak farkı anlamak mümkün değildir."},{"t":"Çözüm","a":"beyazla dene","d":"Her ikisini de beyazla çaprazlar, yavrularına bakar ve gizliyi buluruz."}],"ans":"Her iki moru da beyazla çaprazlar, hangisinin yavrularında beyaz çıktığına bakarak gizli özelliği buluruz."}],"zor":[{"q":"Sarı tüylü bir kediyi hep beyaz olan kediyle çaprazladık; tüm yavrular sarı oldu. Sarı kedi hakkında ne söyleriz?","steps":[{"t":"Yavruları incele","a":"hepsi sarı","d":"Doğan yavruların tamamı sarı oldu, hiç beyaz çıkmadı."},{"t":"Gizli özellik var mı","a":"yok","d":"Beyaz çıkmadığına göre sarı kedide gizli beyaz özellik saklı değildir."},{"t":"Sonuç","a":"saf sarı","d":"Bu sarı kedi içinde gizli renk taşımayan saf (tam) sarıdır."}],"ans":"Tüm yavrular sarı çıktığı için sarı kedi gizli beyaz taşımayan saf sarıdır."},{"q":"Kara tüylü bir tavşanı hep gri olan tavşanla çaprazladık; yavruların yarısı gri çıktı. Kara tavşan hakkında ne söyleriz?","steps":[{"t":"Yavruları incele","a":"yarısı gri","d":"Yavruların bir bölümü kara, bir bölümü gri oldu."},{"t":"Gizli özellik var mı","a":"var","d":"Gri yavru çıktığına göre kara tavşan içinde gizli gri özellik taşıyordu."},{"t":"Sonuç","a":"gizli gri taşır","d":"Bu kara tavşan dıştan kara ama içinde saklı gri özellik barındırır."}],"ans":"Gri yavrular çıktığı için kara tavşan içinde gizli gri özellik saklayan bir tavşandır."},{"q":"Neden gizli özelliği bulmak için hep çekinik (beyaz gibi) olanla çaprazlarız, başka morla değil?","steps":[{"t":"Morla çaprazlarsak","a":"karışır","d":"İki mor çaprazlanınca gizli beyaz, baskın mor altında saklanıp görünmeyebilir."},{"t":"Beyazla çaprazlarsak","a":"net görünür","d":"Beyazın gizlisi olmadığı için karşıdaki gizli özellik yavrularda açıkça çıkar."},{"t":"Sonuç","a":"beyaz daha güvenli","d":"Bu yüzden gizli özelliği bulmak için saf beyaz olanı seçeriz."}],"ans":"Beyaz hiç gizli özellik taşımadığından karşıdaki gizli özelliği saklamadan ortaya çıkarır; bu yüzden test için beyazı seçeriz."},{"q":"Kahverengi gözlü bir kişiyi inceleyelim. Onu mavi gözlü (saf çekinik) biriyle düşünsek, çocuklarda mavi göz çıkması neyi gösterir?","steps":[{"t":"Mavi gözün durumu","a":"gizlisi yok","d":"Mavi göz çekiniktir; içinde saklı kahverengi taşımaz."},{"t":"Mavi çocuk çıkarsa","a":"gizli mavi var","d":"Çocukta mavi göz çıktıysa kahverengi gözlü kişide gizli mavi özellik vardı."},{"t":"Sonuç","a":"gizli özellik bulundu","d":"Böylece kahverengi kişinin içinde saklı mavi özellik taşıdığı anlaşılır."}],"ans":"Mavi gözlü çocuk çıkması, kahverengi gözlü kişinin içinde gizli mavi göz özelliği sakladığını gösterir."},{"q":"Bir bahçıvan uzun bir bitkinin saf mı yoksa gizli kısa özellik mi taşıdığını merak ediyor. Ne yapmalı ve neye bakmalı?","steps":[{"t":"Yapması gereken","a":"kısa ile çaprazla","d":"Uzun bitkiyi her zaman kısa olan (çekinik) bir bitkiyle çaprazlamalı."},{"t":"Tüm yavrular uzunsa","a":"saf uzun","d":"Eğer bütün yavrular uzun çıkarsa bitki gizli kısa taşımayan saf uzundur."},{"t":"Kısa yavru çıkarsa","a":"gizli kısa var","d":"Aralarda kısa yavru çıkarsa bitki içinde gizli kısa özellik saklıyordu."}],"ans":"Uzun bitkiyi kısa olanla çaprazlar; tüm yavrular uzunsa saf uzundur, kısa yavru çıkarsa içinde gizli kısa özellik taşır."}]},"ortaokul":{"kolay":[{"q":"Test (kontrol) çaprazlaması nedir, ne amaçla yapılır?","steps":[{"t":"Tanım","a":"çekinikle çaprazlama","d":"Baskın fenotipli bir bireyi saf çekinik (homozigot resesif) bireyle çaprazlamaktır."},{"t":"Amaç","a":"genotipi bulma","d":"Baskın görünen bireyin saf mı (AA) yoksa melez mi (Aa) olduğunu anlamak için yapılır."}],"ans":"Test çaprazlaması, baskın fenotipli bireyi saf çekinik bireyle çaprazlayarak genotipini belirlemektir."},{"q":"Test çaprazlamasında neden çekinik homozigot (aa) birey kullanılır?","steps":[{"t":"aa bireyin özelliği","a":"sadece a verir","d":"Çekinik homozigot birey yavrularına yalnızca çekinik (a) gen aktarır."},{"t":"Sonuç","a":"diğer eş netleşir","d":"Bu sayede yavrunun fenotipini, test edilen bireyin verdiği gen belirler."}],"ans":"aa birey yavruya yalnızca çekinik gen verdiğinden, yavrunun özelliği test edilen bireyin genotipini açığa çıkarır."},{"q":"Mor çiçekli (baskın) bir bezelye aa ile çaprazlandığında tüm yavrular mor çıkarsa genotip nedir?","steps":[{"t":"Yavruları yorumla","a":"hepsi baskın","d":"Tüm yavrular mor; hiç beyaz (çekinik) yavru görülmüyor."},{"t":"Genotipi belirle","a":"AA","d":"Çekinik yavru çıkmadığı için test edilen birey saf baskın AA'dır."}],"ans":"Tüm yavrular mor (baskın) çıktığı için test edilen bireyin genotipi AA'dır."},{"q":"Mor çiçekli (baskın) bir bezelye aa ile çaprazlandığında yavruların yarısı beyaz çıkarsa genotip nedir?","steps":[{"t":"Yavruları yorumla","a":"yarısı çekinik","d":"Yavruların yaklaşık yarısı mor, yarısı beyaz (çekinik) çıkıyor."},{"t":"Genotipi belirle","a":"Aa","d":"Çekinik yavru çıktığı için test edilen birey melez (heterozigot) Aa'dır."}],"ans":"Yavruların yaklaşık yarısı çekinik (beyaz) çıktığı için test edilen bireyin genotipi Aa'dır."},{"q":"Geri çaprazlama (back cross) ne demektir?","steps":[{"t":"Tanım","a":"ataya çaprazlama","d":"Bir bireyin, ana-babasından biriyle (veya aynı genotipli atayla) çaprazlanmasıdır."},{"t":"Test ile ilişkisi","a":"çekinik ataysa test olur","d":"Eğer geri çaprazlama çekinik ata ile yapılırsa bu aynı zamanda bir test çaprazlamasıdır."}],"ans":"Geri çaprazlama, bir bireyin atalarından biriyle çaprazlanmasıdır; çekinik atayla yapılırsa test çaprazlaması olur."}],"zor":[{"q":"Sarı tohumlu (baskın) bir bezelyeyi yeşil tohumlu (aa) ile çaprazladık ve 100 yavrudan yaklaşık 50'si yeşil çıktı. Genotip ve oranı yorumlayınız.","steps":[{"t":"Verilenleri yaz","a":"yarısı yeşil","d":"100 yavrunun yaklaşık 50'si yeşil (çekinik), 50'si sarıdır."},{"t":"Oranı yorumla","a":"1:1 oran","d":"Sarı:yeşil oranı 1:1 ise test edilen birey melezdir."},{"t":"Genotip","a":"Aa","d":"Aa × aa çaprazında yavruların yarısı çekinik çıkar; bu birey Aa'dır."}],"ans":"Yavruların yarısı yeşil (1:1 oran) çıktığından, test edilen sarı bezelyenin genotipi Aa (melez)dır."},{"q":"Kara tüylü (baskın) bir fareyi kahverengi (aa) ile çaprazladık; 12 yavrunun tümü kara çıktı. Genotip nedir ve neden?","steps":[{"t":"Verilenleri yaz","a":"hepsi kara","d":"12 yavrunun tamamı kara, hiç kahverengi (çekinik) çıkmadı."},{"t":"Yorumla","a":"çekinik gen yok","d":"Eğer fare Aa olsaydı kahverengi yavrular beklenirdi; hiç çıkmadı."},{"t":"Genotip","a":"AA","d":"Tüm yavruların baskın çıkması bireyin saf baskın AA olduğunu gösterir."}],"ans":"Tüm yavrular kara çıktığı için test edilen farenin genotipi AA (saf baskın)dır."},{"q":"Bir öğrenci 'baskın bireyi başka bir baskın bireyle çaprazlarsam genotipini bulurum' diyor. Bu yöntem neden test çaprazlamasına göre güvenilmez?","steps":[{"t":"Baskın × baskın","a":"çekinik saklanır","d":"İki baskın çaprazlanınca olası çekinik gen baskın altında gizlenebilir."},{"t":"Yorum güçlüğü","a":"oran belirsiz","d":"Çıkan yavru oranları genotipi tek başına net göstermez."},{"t":"Doğru yöntem","a":"aa kullan","d":"Çekinik homozigot (aa) kullanmak çekinik geni daima açığa çıkarır."}],"ans":"Baskın × baskın çaprazda çekinik gen gizlenip yavru oranları belirsiz kaldığından, genotip ancak çekinik (aa) ile yapılan test çaprazlamasında güvenle belirlenir."},{"q":"Test çaprazlamasında çekinik yavru oranının 1:1 olması neyi, hiç çekinik çıkmaması neyi gösterir?","steps":[{"t":"1:1 durumu","a":"melez ata","d":"Yavruların yarısı çekinikse test edilen birey Aa'dır (Aa × aa)."},{"t":"Hiç çekinik yok","a":"saf ata","d":"Hiç çekinik çıkmıyorsa birey AA'dır (AA × aa, tümü Aa)."},{"t":"Sonuç","a":"oran genotipi söyler","d":"Yavru oranı, baskın bireyin genotipini doğrudan açığa çıkarır."}],"ans":"Çekinik:baskın oranı 1:1 ise test edilen birey Aa, hiç çekinik çıkmıyorsa AA'dır."},{"q":"Düz tüylü (baskın) bir tavşanı kıvırcık (aa) ile çaprazladık; 8 yavrudan 4'ü kıvırcık çıktı. Yavruların genotiplerini de yazınız.","steps":[{"t":"Ata genotipi","a":"Aa × aa","d":"Yarısı kıvırcık (çekinik) çıktığı için düz tüylü ata Aa, diğer ata aa'dır."},{"t":"Çaprazı yap","a":"Aa, aa yavru","d":"Aa × aa çaprazında yavruların yarısı Aa (düz), yarısı aa (kıvırcık) olur."},{"t":"Sonuç","a":"4 Aa, 4 aa","d":"8 yavrunun 4'ü Aa (düz tüylü), 4'ü aa (kıvırcık) genotipindedir."}],"ans":"Düz tüylü ata Aa'dır; yavruların 4'ü Aa (düz tüylü), 4'ü aa (kıvırcık) genotipindedir."}]},"lise":{"kolay":[{"q":"Test (kontrol) çaprazlamasının amacı ve temel mantığı nedir?","steps":[{"t":"Amaç","a":"genotip belirleme","d":"Baskın fenotipli bir bireyin homozigot mu (AA) heterozigot mu (Aa) olduğunu saptamaktır."},{"t":"Mantık","a":"aa ile çaprazla","d":"Birey saf çekinik (aa) ile çaprazlanır; aa yalnızca a verdiğinden yavru fenotipini bilinmeyen alel belirler."}],"ans":"Test çaprazlaması, baskın fenotipli bireyi homozigot çekinik (aa) ile çaprazlayarak bilinmeyen genotipi (AA ya da Aa) belirleme yöntemidir."},{"q":"Test çaprazlamasında çaprazlama eşi olarak neden homozigot resesif (aa) birey seçilir?","steps":[{"t":"aa'nın gamet katkısı","a":"yalnız a","d":"Homozigot resesif birey tüm gametlerine yalnızca çekinik (a) aleli koyar."},{"t":"Sonuç","a":"diğer alel görünür","d":"Yavrunun fenotipi tamamen test edilen bireyin verdiği alele bağlı olur, böylece genotip açığa çıkar."}],"ans":"aa birey gametlerine yalnız çekinik alel verdiğinden, yavru fenotipi test edilen bireyin alellerini doğrudan yansıtır."},{"q":"AA × aa test çaprazlamasında yavru genotip ve fenotip dağılımı nasıldır?","steps":[{"t":"Gametler","a":"A ve a","d":"AA bireyi yalnız A, aa bireyi yalnız a gameti verir."},{"t":"Birleşme","a":"tümü Aa","d":"Tüm yavrular Aa genotipinde olur ve baskın fenotip gösterir."}],"ans":"AA × aa çaprazında yavruların tamamı Aa genotipinde ve baskın fenotiptedir; hiç çekinik birey görülmez."},{"q":"Aa × aa test çaprazlamasında yavru genotip ve fenotip oranı nedir?","steps":[{"t":"Gametler","a":"A,a ve a","d":"Aa bireyi A ve a; aa bireyi yalnız a gameti verir."},{"t":"Oran","a":"1 Aa : 1 aa","d":"Yavruların yarısı Aa (baskın), yarısı aa (çekinik) olur; fenotip oranı 1:1'dir."}],"ans":"Aa × aa çaprazında yavru genotipi 1 Aa : 1 aa, fenotip oranı 1 baskın : 1 çekinik (1:1)'dir."},{"q":"Test çaprazlaması sonucunda tüm yavruların baskın fenotipte olması neyi gösterir?","steps":[{"t":"Çekinik yokluğu","a":"a aleli açığa çıkmadı","d":"Hiç çekinik fenotipli yavru görülmemesi, test edilen bireyin çekinik alel taşımadığını düşündürür."},{"t":"Genotip","a":"AA","d":"Bu durumda test edilen birey büyük olasılıkla homozigot baskın (AA)'dır."}],"ans":"Tüm yavruların baskın çıkması, test edilen bireyin çekinik alel taşımadığını, yani genotipinin AA olduğunu gösterir."},{"q":"Test çaprazlaması sonucunda yavruların yaklaşık yarısının çekinik çıkması neyi gösterir?","steps":[{"t":"Çekinik birey varlığı","a":"a aleli taşınıyor","d":"Çekinik fenotipli yavru çıkması, test edilen bireyin bir çekinik (a) alel taşıdığını kanıtlar."},{"t":"Genotip","a":"Aa","d":"1:1 oranı, test edilen bireyin heterozigot (Aa) olduğunu gösterir."}],"ans":"Yavruların yaklaşık yarısının çekinik çıkması, test edilen bireyin bir çekinik alel taşıdığını ve genotipinin Aa olduğunu gösterir."},{"q":"Geri çaprazlama (back cross) nedir ve test çaprazlamasıyla ilişkisi nedir?","steps":[{"t":"Geri çaprazlama","a":"ata ile çaprazlama","d":"F₁ bireyinin ebeveynlerinden biriyle (ya da o genotiple) çaprazlanmasıdır."},{"t":"Test ile ilişki","a":"çekinik atayla=test","d":"Geri çaprazlama çekinik homozigot ata ile yapıldığında aynı zamanda bir test çaprazlamasıdır."}],"ans":"Geri çaprazlama bireyin ata genotipiyle çaprazlanmasıdır; çekinik homozigot ata ile yapıldığında bu çaprazlama aynı zamanda bir test çaprazlamasıdır."},{"q":"Test çaprazlamasında elde edilen 1:1 fenotip oranı hangi atayı işaret eder ve neden 3:1 görülmez?","steps":[{"t":"1:1 oranın kaynağı","a":"Aa × aa","d":"1:1 oranı, heterozigot bir bireyin çekinik homozigotla çaprazlanmasından doğar."},{"t":"3:1 neden çıkmaz","a":"aa A vermez","d":"3:1 oranı Aa × Aa'da görülür; testte eş aa olduğu için baskın alel katkısı tek taraflıdır."}],"ans":"Test çaprazlamasındaki 1:1 oranı Aa × aa atasını işaret eder; eş aa olduğundan iki baskın alelin birleşmesi olmaz, bu yüzden 3:1 oranı görülmez."},{"q":"Bir bitkinin fenotipi baskın olduğu halde genotipi neden doğrudan gözle belirlenemez, test çaprazlaması neyi çözer?","steps":[{"t":"Sorun","a":"AA ve Aa aynı görünür","d":"Baskın alel tek başına bile fenotipi belirlediğinden AA ve Aa bireyler dıştan ayırt edilemez."},{"t":"Test çözümü","a":"yavru oranı ayırır","d":"aa ile çaprazlamada AA tümü baskın, Aa ise 1:1 verir; oran iki genotipi ayırır."}],"ans":"AA ve Aa bireyler aynı baskın fenotipi gösterdiğinden gözle ayrılamaz; test çaprazlaması yavru fenotip oranıyla (tümü baskın ya da 1:1) bu iki genotipi ayırır."},{"q":"İki karakterli (dihibrit) bir bireyde test çaprazlaması nasıl yapılır ve neyi gösterir?","steps":[{"t":"Yöntem","a":"aabb ile çapraz","d":"Bilinmeyen AaBb gibi birey, çift çekinik homozigot (aabb) ile çaprazlanır."},{"t":"Yorum","a":"gamet oranı görünür","d":"Yavru fenotip oranları, test edilen bireyin oluşturduğu gamet tiplerini ve oranlarını doğrudan yansıtır."}],"ans":"Dihibrit test çaprazlamasında birey aabb ile çaprazlanır; yavru fenotip oranları bireyin gamet tiplerini ve oranlarını (bağımsız açılım gösterip göstermediğini) açığa çıkarır."},{"q":"AaBb bir birey aabb ile çaprazlandığında (bağımsız açılım) beklenen fenotip oranı nedir?","steps":[{"t":"Bireyin gametleri","a":"AB,Ab,aB,ab","d":"Bağımsız açılımla AaBb birey eşit oranda dört gamet tipi oluşturur."},{"t":"aabb katkısı","a":"yalnız ab","d":"aabb birey yalnız ab verdiğinden her gamet tipi farklı bir fenotip oluşturur."},{"t":"Oran","a":"1:1:1:1","d":"Sonuçta dört fenotip eşit oranda (1:1:1:1) görülür."}],"ans":"Bağımsız açılım gösteren AaBb × aabb çaprazında dört fenotip 1:1:1:1 oranında elde edilir."},{"q":"Test çaprazlaması sonuçlarının güvenilirliği neden yavru sayısına (örnek büyüklüğüne) bağlıdır?","steps":[{"t":"Az yavru riski","a":"şans sapması","d":"Çok az yavruda, Aa birey rastlantıyla hiç çekinik yavru vermeyip AA gibi görünebilir."},{"t":"Çok yavru","a":"oran gerçeğe yaklaşır","d":"Yavru sayısı arttıkça gözlenen oran beklenen 1:1 orana yaklaşır, hata azalır."}],"ans":"Az sayıda yavruda rastlantısal sapma Aa bireyi AA gibi gösterebileceğinden, sonucun güvenilirliği yavru sayısı arttıkça yükselir."},{"q":"Eş baskınlık (kodominantlık) gösteren bir karakterde test çaprazlaması neden ayrıca gerekmeyebilir?","steps":[{"t":"Eş baskınlık özelliği","a":"genotip=fenotip","d":"Eş baskınlıkta heterozigot birey her iki aleli de ayrı ayrı gösterir (örn. AB kan grubu)."},{"t":"Sonuç","a":"genotip görünür","d":"Fenotipe bakarak genotip doğrudan okunabildiği için test çaprazlamasına gerek kalmaz."}],"ans":"Eş baskınlıkta heterozigot her iki aleli de fenotipinde gösterdiğinden genotip doğrudan okunur; bu nedenle genotipi belirlemek için test çaprazlamasına çoğu kez gerek kalmaz."},{"q":"Test çaprazlaması ile melezleme (Aa × Aa) çaprazlaması arasındaki temel fark nedir?","steps":[{"t":"Test çaprazlaması","a":"aa ile","d":"Bilinmeyen baskın bireyi çekinik homozigot (aa) ile çaprazlar; amaç genotip belirlemektir."},{"t":"Melezleme","a":"iki heterozigot","d":"Aa × Aa çaprazında iki heterozigot çaprazlanır; amaç açılım oranlarını (3:1) görmektir."}],"ans":"Test çaprazlamasında bilinmeyen birey çekinik (aa) ile çaprazlanıp genotip belirlenir; melezlemede ise iki heterozigot (Aa × Aa) çaprazlanır ve 3:1 açılım gözlenir."},{"q":"Hayvan yetiştiriciliğinde test çaprazlaması neden önemli bir araçtır?","steps":[{"t":"Gizli alel sorunu","a":"taşıyıcılar","d":"Baskın görünen damızlık hayvan, istenmeyen çekinik bir aleli gizlice taşıyor olabilir."},{"t":"Testin yararı","a":"taşıyıcıyı ayıklar","d":"aa ile çaprazlama çekinik yavru verirse hayvan taşıyıcıdır ve damızlıktan ayıklanabilir."}],"ans":"Test çaprazlaması, baskın görünen damızlık hayvanların gizli çekinik alel taşıyıp taşımadığını ortaya çıkararak istenmeyen alellerin sürüden ayıklanmasını sağlar."}],"zor":[{"q":"Mor çiçekli bir bezelyenin (M_ baskın) genotipini belirlemek için yapılan test çaprazlamasında 64 yavrudan 30'u beyaz çıktı. Genotipi ve mantığı çözümleyiniz.","steps":[{"t":"Eş genotipi","a":"mm","d":"Test çaprazlamasında eş, homozigot çekinik beyaz (mm)'dir."},{"t":"Oranı incele","a":"≈1:1","d":"64 yavrunun 30'u beyaz, 34'ü mor; bu yaklaşık 1:1 orana karşılık gelir."},{"t":"Genotip","a":"Mm","d":"Çekinik yavru çıkması ve 1:1 oran, test edilen bireyin Mm (heterozigot) olduğunu gösterir."}],"ans":"Beyaz yavru çıkması ve oranın ≈1:1 olması, test edilen mor bezelyenin genotipinin Mm (heterozigot) olduğunu gösterir."},{"q":"Siyah tüylü (B baskın) bir fareyi kahverengi (bb) ile çaprazladık; 40 yavrunun tümü siyah çıktı. Bireyin Bb olma olasılığı neden tamamen dışlanamaz, ancak AA neden çok daha olasıdır?","steps":[{"t":"Gözlem","a":"hepsi siyah","d":"40 yavrunun tamamı siyah; hiç kahverengi (çekinik) görülmedi."},{"t":"BB yorumu","a":"en olası","d":"Bu sonuç en kolay BB × bb ile açıklanır; o zaman çekinik yavru zaten beklenmez."},{"t":"Bb olasılığı","a":"çok düşük","d":"Birey Bb olsaydı her yavruda kahverengi çıkmama olasılığı (1/2)⁴⁰ kadardır; bu yok denecek kadar küçüktür."}],"ans":"40 yavrunun tümü siyah çıktığından birey büyük olasılıkla BB'dir; Bb olsaydı hiç kahverengi yavru çıkmama olasılığı (1/2)⁴⁰ gibi yok denecek kadar küçük olurdu, ama teorik olarak sıfır olmadığı için kesinlik istatistikseldir."},{"q":"Bir test çaprazlamasında yavru oranının tam 1:1 yerine 55 baskın : 45 çekinik çıkması genotip yorumunu nasıl etkiler?","steps":[{"t":"Beklenen oran","a":"1:1 (Aa)","d":"Aa × aa çaprazında teorik beklenti yarı baskın yarı çekiniktir."},{"t":"Sapmanın nedeni","a":"rastlantı","d":"55:45 sapması küçük örnekte beklenen rastlantısal dalgalanmadır, oran hâlâ ≈1:1'dir."},{"t":"Sonuç","a":"yine Aa","d":"Çekinik bireylerin belirgin biçimde çıkması genotipin Aa olduğunu doğrular."}],"ans":"55:45 oranı, beklenen 1:1'den yalnızca rastlantısal olarak sapmıştır; çekinik bireylerin önemli oranda çıkması test edilen bireyin Aa olduğunu doğrular."},{"q":"AaBb genotipli bir bitki aabb ile test çaprazlandığında yavrularda 1:1:1:1 yerine yaklaşık 4:4:1:1 oran gözlenirse bu durum nasıl açıklanır?","steps":[{"t":"Beklenen oran","a":"1:1:1:1","d":"Genler bağımsız açılıyorsa dört fenotip eşit oranda beklenir."},{"t":"Gözlenen sapma","a":"ata tipleri fazla","d":"Ata tip kombinasyonlarının (4:4) fazla, yeni kombinasyonların (1:1) az olması bağımlılığı düşündürür."},{"t":"Yorum","a":"bağlı genler","d":"Genler aynı kromozomda bağlı (linked) olup az miktarda krossing-over ile rekombinant oluşmuştur."}],"ans":"Ata tiplerinin fazla, rekombinant tiplerin az çıkması, iki genin aynı kromozomda bağlı (linked) olduğunu ve sınırlı krossing-over ile az sayıda rekombinant oluştuğunu gösterir."},{"q":"Test çaprazlamasında bir dihibrit bireyin (AaBb) yavrularında yalnızca iki fenotip (AB ve ab) görülmesi neyi gösterir?","steps":[{"t":"Beklenen dört tip","a":"bağımsızsa 4","d":"Genler bağımsız olsaydı AB, Ab, aB, ab dört fenotip beklenirdi."},{"t":"Yalnız iki tip","a":"rekombinant yok","d":"Sadece ata tipleri (AB, ab) çıkıp Ab ve aB görülmemesi rekombinasyonun olmadığını gösterir."},{"t":"Yorum","a":"tam bağlı genler","d":"Genler aynı kromozomda tam bağlı (complete linkage) olup krossing-over gerçekleşmemiştir."}],"ans":"Yalnız ata tiplerinin (AB ve ab) görülmesi, iki genin aynı kromozomda tam bağlı olduğunu ve aralarında krossing-over gerçekleşmediğini gösterir."},{"q":"Test çaprazlamasında gözlenen rekombinant yavru yüzdesi iki gen arasındaki uzaklığı (harita birimi) belirlemekte nasıl kullanılır?","steps":[{"t":"Rekombinant oranı","a":"yeni kombinasyon %","d":"Test çaprazında ata tipi dışı (rekombinant) yavruların toplam yüzdesi hesaplanır."},{"t":"Harita birimi","a":"%1=1 cM","d":"Rekombinant yüzdesi doğrudan harita birimine (santimorgan) eşitlenir; %12 rekombinant ≈ 12 cM."},{"t":"Sonuç","a":"uzaklık","d":"Yüzde arttıkça genler arasındaki kromozom üzerindeki uzaklık da artar."}],"ans":"Test çaprazlamasındaki rekombinant yavru yüzdesi doğrudan harita birimine (santimorgan) çevrilir; örneğin %12 rekombinant, iki genin yaklaşık 12 cM uzaklıkta olduğunu gösterir."},{"q":"Bir öğrenci 'baskın bireyi kendisiyle özdeş baskın bireyle çaprazlarsam (AA gibi) genotipi bulabilirim' diyor. Bu yaklaşım test çaprazlamasına neden eşdeğer değildir?","steps":[{"t":"Baskın eşle çapraz","a":"çekinik gizlenir","d":"Eş baskın alel taşıdığından, test edilen bireydeki çekinik alel yavrularda fenotip olarak görünmeyebilir."},{"t":"Oran belirsizliği","a":"3:1 ya da tümü baskın","d":"Çıkan oranlar hem AA hem Aa için baskın fenotip ağırlıklı olur; ayrım net değildir."},{"t":"aa üstünlüğü","a":"çekiniği açar","d":"Yalnızca aa eşi her çekinik aleli fenotipe yansıtarak kesin ayrım sağlar."}],"ans":"Baskın bir eşle çaprazlamada çekinik alel fenotipte gizlenip oranlar belirsizleştiğinden genotip ayırt edilemez; yalnızca homozigot çekinik (aa) eş çekinik aleli açığa çıkararak kesin sonuç verir."},{"q":"İnsanda baskın bir kalıtsal özellik için neden klasik test çaprazlaması uygulanamaz ve genotip nasıl belirlenir?","steps":[{"t":"Uygulanamama nedeni","a":"planlı çaprazlama yok","d":"İnsanlarda eş seçilip kontrollü çaprazlama yapılamaz; etik ve pratik engeller vardır."},{"t":"Alternatif","a":"soy ağacı","d":"Bunun yerine soy ağacı (pedigri) analiziyle bireyin ve akrabalarının fenotipleri incelenir."},{"t":"Sonuç","a":"olasılıkla genotip","d":"Çekinik fenotipli çocuk ya da akraba varlığından bireyin heterozigot (taşıyıcı) olduğu çıkarılır."}],"ans":"İnsanlarda planlı çaprazlama yapılamadığından test çaprazlaması uygulanamaz; bunun yerine soy ağacı analiziyle, örneğin çekinik fenotipli çocuk varlığından bireyin heterozigot taşıyıcı olduğu belirlenir."},{"q":"Sarı (Y baskın) ve düz (R baskın) tohumlu bir bezelye aabb (yeşil, buruşuk) ile çaprazlandığında 160 yavruda 80 sarı-düz, 80 sarı-buruşuk çıktı. Test edilen bireyin genotipini belirleyiniz.","steps":[{"t":"Renk karakteri","a":"hepsi sarı","d":"Tüm yavrular sarı; hiç yeşil çıkmadığından renk geni homozigot baskın YY'dir."},{"t":"Şekil karakteri","a":"düz:buruşuk 1:1","d":"Düz ve buruşuk yaklaşık 1:1 oranda; bu, şekil geninin heterozigot Rr olduğunu gösterir."},{"t":"Genotip","a":"YYRr","d":"İki karakter birleştirilince test edilen bireyin genotipi YYRr'dir."}],"ans":"Tüm yavruların sarı (YY) ve düz:buruşuk oranının 1:1 (Rr) olması nedeniyle test edilen bezelyenin genotipi YYRr'dir."},{"q":"Test çaprazlamasında çekinik fenotipin eksik nüfuz (incomplete penetrance) göstermesi sonuçların yorumunu nasıl bozabilir?","steps":[{"t":"Eksik nüfuz","a":"genotip≠fenotip","d":"Eksik nüfuzda bir genotip her zaman beklenen fenotipi göstermez."},{"t":"Hatalı sayım","a":"baskın gibi görünür","d":"Bazı çekinik genotipli yavrular fenotipte baskın görünüp yanlış sınıflandırılabilir."},{"t":"Sonuç","a":"oran yanıltıcı","d":"Bu durumda gözlenen oran beklenenden saparak Aa bireyin AA gibi yorumlanmasına yol açabilir."}],"ans":"Eksik nüfuzda bazı çekinik genotipli yavrular beklenen fenotipi göstermeyip baskın gibi sayılabileceğinden, gözlenen oran saparak heterozigot bireyin yanlışlıkla homozigot baskın yorumlanmasına yol açabilir."},{"q":"Üç karakterli (trihibrit) AaBbCc bir bireyin test çaprazlamasında (aabbcc ile) bağımsız açılımda kaç farklı gamet tipi ve fenotip beklenir?","steps":[{"t":"Gamet tipi sayısı","a":"2³=8","d":"Heterozigot karakter sayısı n ise gamet tipi 2ⁿ'dir; üç karakter için 2³=8'dir."},{"t":"Eş katkısı","a":"yalnız abc","d":"aabbcc birey tek tip (abc) gamet verdiğinden her gamet tipi ayrı bir fenotip oluşturur."},{"t":"Fenotip oranı","a":"8 eşit tip","d":"Sonuçta 8 farklı fenotip 1:1:1:1:1:1:1:1 oranında beklenir."}],"ans":"AaBbCc × aabbcc test çaprazlamasında bağımsız açılımla 2³=8 farklı gamet tipi ve buna karşılık 8 farklı fenotip eşit (1:1:...:1) oranda beklenir."},{"q":"Test çaprazlamasında yavru sayısı çok az olduğunda 'AA' kararının neden istatistiksel olarak temkinli verilmesi gerektiğini olasılıkla açıklayınız.","steps":[{"t":"Az yavru durumu","a":"örnek küçük","d":"Örneğin yalnız 3 yavru varsa veri az olduğundan rastlantı etkisi büyüktür."},{"t":"Aa'nın gizlenmesi","a":"(1/2)ⁿ olasılık","d":"Birey Aa olsa bile n yavrunun hiçbirinin çekinik çıkmama olasılığı (1/2)ⁿ'dir; 3 yavruda bu 1/8'dir."},{"t":"Sonuç","a":"temkinli karar","d":"Bu olasılık küçük olmadığından az yavruyla 'kesin AA' demek yanıltıcı olabilir."}],"ans":"Az yavruda, Aa birey olsa bile hiçbir çekinik yavru çıkmama olasılığı (1/2)ⁿ kadar yüksektir (3 yavruda 1/8); bu nedenle az örnekle 'AA' kararı ancak temkinli ve olasılıksal verilmelidir."},{"q":"Bir bitkide A geni baskın olup aa genotipi öldürücü (letal) ise klasik test çaprazlaması neden uygulanamaz, alternatif ne olur?","steps":[{"t":"Sorun","a":"aa yaşamaz","d":"aa genotipi ölümcül olduğundan test eşi olacak canlı homozigot çekinik birey bulunamaz."},{"t":"Engel","a":"eş yok","d":"Çaprazlama eşi sağlanamadığı için klasik test çaprazlaması yapılamaz."},{"t":"Alternatif","a":"Aa × Aa açılım","d":"Bunun yerine heterozigotlar çaprazlanır; yavru açılım oranı (örn. 2:1 sapması) genotipi dolaylı belirler."}],"ans":"aa genotipi letal olduğundan canlı homozigot çekinik test eşi bulunamaz ve klasik test çaprazlaması yapılamaz; bunun yerine heterozigot bireyler çaprazlanıp letal genotip nedeniyle sapan açılım oranlarından genotip dolaylı olarak belirlenir."},{"q":"Test çaprazlaması ile bir bireyin gamet tiplerinin oranı arasında nasıl bir doğrudan ilişki vardır?","steps":[{"t":"Eşin tek gameti","a":"sadece çekinik","d":"Homozigot çekinik eş tek tip gamet verdiğinden yavru çeşitliliğini tamamen test edilen birey belirler."},{"t":"Yavru=gamet yansıması","a":"birebir","d":"Her yavru fenotipi, test edilen bireyin verdiği gametin doğrudan yansımasıdır."},{"t":"Oran ilişkisi","a":"yavru oranı=gamet oranı","d":"Bu nedenle yavru fenotip oranları, bireyin oluşturduğu gamet tiplerinin oranına birebir eşittir."}],"ans":"Homozigot çekinik eş tek tip gamet verdiğinden yavru fenotip oranları, test edilen bireyin oluşturduğu gamet tiplerinin oranını birebir yansıtır; bu yüzden test çaprazlaması bireyin gamet çeşitliliğini doğrudan okumayı sağlar."},{"q":"İki gen arasındaki test çaprazlamasında rekombinant oranının %50'ye ulaşması neyi gösterir?","steps":[{"t":"%50 rekombinant","a":"ata=rekombinant","d":"Rekombinant ve ata tiplerinin eşit (1:1:1:1) çıkması rekombinant oranının %50 olduğunu gösterir."},{"t":"Bağ durumu","a":"bağsız davranış","d":"Bu oran, genlerin sanki bağımsızmış gibi açıldığını gösterir."},{"t":"Yorum","a":"ayrı kromozom/çok uzak","d":"Genler ya ayrı kromozomlardadır ya da aynı kromozomda çok uzak olup bağları gizlenmiştir."}],"ans":"%50 rekombinant oranı, genlerin bağımsız açılım gösterdiğini; yani ya ayrı kromozomlarda bulunduğunu ya da aynı kromozomda bağ etkisi kaybolacak kadar uzak olduğunu gösterir."}]}},"xeBagliKalitim":{"ilkokul":{"kolay":[{"q":"İnsanlarda kız ve erkek olmayı belirleyen küçük yapılara ne ad verilir?","steps":[{"t":"Vücudumuzdaki şifre","a":"Kromozom","d":"Vücudumuzun içinde, bizi biz yapan bilgileri taşıyan küçük yapılara <b>kromozom</b> denir."},{"t":"Cinsiyeti belirleyen","a":"Cinsiyet kromozomu","d":"Kız mı erkek mi olacağımızı belirleyen özel kromozomlara <b>cinsiyet kromozomu</b> denir; bunlardan biri X kromozomudur."}],"ans":"Kız ve erkek olmayı belirleyen yapılara cinsiyet kromozomu denir."},{"q":"Bazı özellikler kızlarda ve erkeklerde aynı sıklıkta mı görülür?","steps":[{"t":"Her özellik aynı mı?","a":"Hayır","d":"Bazı özellikler kız ve erkeklerde <b>aynı sıklıkta</b> görülmeyebilir."},{"t":"Cinsiyete göre fark","a":"Farklı olabilir","d":"Renk körlüğü gibi bazı özellikler erkeklerde daha sık, kızlarda daha az görülebilir."}],"ans":"Bazı özellikler cinsiyete göre farklı sıklıkta görülebilir."},{"q":"Renk körlüğü olan bir kişi hangi konuda zorlanır?","steps":[{"t":"Renk körlüğü ne demek?","a":"Renkleri karıştırmak","d":"Renk körlüğü olan kişi bazı <b>renkleri</b> birbirinden zor ayırır."},{"t":"En çok hangi renkler?","a":"Kırmızı ve yeşil","d":"Genelde kırmızı ile yeşil renkleri karıştırırlar; bu yüzden bazı resimlerdeki sayıları göremezler."}],"ans":"Renk körlüğü olan kişi bazı renkleri, çoğunlukla kırmızı ile yeşili ayırmakta zorlanır."},{"q":"Renk körlüğü erkeklerde mi yoksa kızlarda mı daha sık görülür?","steps":[{"t":"Kimde daha çok?","a":"Erkeklerde","d":"Renk körlüğü <b>erkeklerde</b> kızlara göre daha sık görülen bir durumdur."},{"t":"Sonuç","a":"Erkekler daha çok","d":"Bu yüzden bir sınıfta renk körü olan kişi çoğunlukla bir erkek çocuk olur."}],"ans":"Renk körlüğü erkeklerde kızlardan daha sık görülür."},{"q":"Anne ve babanın özellikleri çocuğa nasıl geçer?","steps":[{"t":"Çocuk kimden alır?","a":"Anne ve babadan","d":"Çocuk, özelliklerini hem <b>annesinden</b> hem <b>babasından</b> alır."},{"t":"Nasıl geçer?","a":"Kromozomlarla","d":"Bu özellikler, anne ve babadan gelen kromozomlarla çocuğa geçer."}],"ans":"Anne ve babanın özellikleri kromozomlarla çocuğa geçer."}],"zor":[{"q":"Renk körü bir baba, kırmızı ve yeşili karıştırıyor. Bu özelliği nasıl edinmiş olabilir?","steps":[{"t":"Özellik nereden gelir?","a":"Ailesinden","d":"İnsanların özellikleri büyük ölçüde <b>ailelerinden</b> gelir."},{"t":"Kromozomla geçiş","a":"Doğuştan","d":"Renk körlüğü doğuştan gelen, kromozomlarla aktarılan bir özelliktir; sonradan oluşmaz."}],"ans":"Renk körlüğü doğuştan, ailesinden kromozomlarla geçtiği için edinilmiştir."},{"q":"Bir sınıfta renk körlüğü olan tek öğrenci bir erkek çocuktur. Bu beklenen bir durum mudur?","steps":[{"t":"Kimde daha sık?","a":"Erkekte","d":"Renk körlüğü <b>erkeklerde</b> kızlardan daha sık görülür."},{"t":"Beklenir mi?","a":"Evet","d":"Renk körü öğrencinin erkek olması beklenen bir durumdur, çünkü erkeklerde bu özellik daha çok ortaya çıkar."}],"ans":"Evet, renk körlüğü erkeklerde daha sık görüldüğü için beklenen bir durumdur."},{"q":"Bir doktor, kanı zor pıhtılaşan (kanaması güç duran) bir hastalığın çoğunlukla erkeklerde görüldüğünü söylüyor. Bu hastalık kalıtsal olabilir mi?","steps":[{"t":"Hastalık nereden?","a":"Doğuştan","d":"Kanın zor pıhtılaşması olan hemofili gibi durumlar genelde <b>doğuştan</b> gelir."},{"t":"Kalıtsal mı?","a":"Evet","d":"Aileden kromozomlarla geçtiği için kalıtsaldır ve erkeklerde daha sık görülür."}],"ans":"Evet, kanı zor pıhtılaşan bu hastalık kalıtsaldır ve erkeklerde daha sık görülür."},{"q":"Bir kız çocuğu hiçbir zorluk yaşamadan tüm renkleri ayırt edebiliyor. Bu durum şaşırtıcı mıdır?","steps":[{"t":"Kızlarda durum","a":"Daha az renk körü","d":"Renk körlüğü <b>kızlarda</b> erkeklere göre çok daha az görülür."},{"t":"Şaşırtıcı mı?","a":"Hayır","d":"Çoğu kız renkleri rahatça ayırt edebildiği için bu durum hiç şaşırtıcı değildir."}],"ans":"Hayır, kızlar genelde renkleri rahat ayırt ettiği için bu beklenen bir durumdur."},{"q":"Bir ailede dede ve torun erkek çocukta aynı renk körlüğü var, ama aradaki anne renkleri ayırt edebiliyor. Anne bu özelliği taşımış olabilir mi?","steps":[{"t":"Anne sağlıklı görünüyor","a":"Renkleri ayırıyor","d":"Anne renkleri ayırt edebildiği için kendisi renk körü <b>değildir</b>."},{"t":"Yine de aktarabilir mi?","a":"Evet","d":"Anne, özelliği kendisinde göstermeden saklayıp oğluna aktarmış olabilir; buna taşıyıcı denir."}],"ans":"Evet, anne renk körü olmasa da özelliği saklı taşıyıp oğluna aktarmış olabilir."}]},"ortaokul":{"kolay":[{"q":"İnsanda cinsiyeti belirleyen kromozomlar hangileridir?","steps":[{"t":"Cinsiyet kromozomları","a":"X ve Y","d":"İnsanda cinsiyeti belirleyen iki cinsiyet kromozomu vardır: <b>X</b> ve <b>Y</b>."},{"t":"Kız ve erkek","a":"XX ve XY","d":"Kızlarda iki X (XX), erkeklerde bir X ve bir Y (XY) bulunur."}],"ans":"Cinsiyeti X ve Y kromozomları belirler; kızlar XX, erkekler XY taşır."},{"q":"X'e bağlı kalıtım ne demektir?","steps":[{"t":"Gen nerede?","a":"X kromozomunda","d":"X'e bağlı kalıtımda, ilgili gen <b>X kromozomu</b> üzerinde taşınır."},{"t":"Sonuç","a":"X ile aktarılır","d":"Bu özellik kromozomlarla geçerken X kromozomu yoluyla bir sonraki nesle aktarılır."}],"ans":"X'e bağlı kalıtım, ilgili genin X kromozomu üzerinde taşınıp aktarıldığı kalıtım biçimidir."},{"q":"Renk körlüğü ve hemofili gibi hastalıklar erkeklerde neden daha sık görülür?","steps":[{"t":"Erkekte kaç X var?","a":"Tek X","d":"Erkeklerde yalnızca <b>tek bir X</b> kromozomu bulunur (XY)."},{"t":"Tek X'in etkisi","a":"Hemen ortaya çıkar","d":"Çekinik hastalık geni tek X'te varsa onu maskeleyecek ikinci bir X olmadığı için hastalık ortaya çıkar."}],"ans":"Erkeklerde tek X kromozomu olduğu için çekinik X'e bağlı hastalıklar daha sık görülür."},{"q":"Taşıyıcı anne ne demektir?","steps":[{"t":"İki X'i var","a":"XX","d":"Annede iki <b>X</b> kromozomu bulunur."},{"t":"Geni saklar","a":"Hasta değil ama taşır","d":"Bir X'inde hastalık geni, diğerinde sağlam gen varsa anne hasta olmaz ama geni saklayıp aktarabilir; buna taşıyıcı denir."}],"ans":"Taşıyıcı anne, hastalık genini bir X'inde taşıyan ama hasta olmayan annedir."},{"q":"Renk körü bir baba (X^aY), renk körlüğü genini kız çocuğuna mı yoksa erkek çocuğuna mı aktarır?","steps":[{"t":"Baba ne verir?","a":"Kıza X, oğla Y","d":"Baba kız çocuğuna <b>X</b> kromozomunu, erkek çocuğuna ise <b>Y</b> kromozomunu verir."},{"t":"Gen nerede?","a":"X'te","d":"Renk körlüğü geni X'te olduğu için baba bu geni yalnızca X verdiği kız çocuğuna aktarır."}],"ans":"Renk körü baba renk körlüğü genini X verdiği kız çocuğuna aktarır, oğluna Y verdiği için aktarmaz."}],"zor":[{"q":"Sağlıklı bir kadın (X^A X^a, taşıyıcı) ile sağlıklı bir erkek (X^A Y) evleniyor. Çocuklarda renk körlüğü kimde çıkabilir?","steps":[{"t":"Anneden gelen X","a":"X^A veya X^a","d":"Anne taşıyıcı olduğundan çocuğa ya sağlam (X^A) ya da hasta (<b>X^a</b>) X verir."},{"t":"Babadan gelen","a":"Kıza X^A, oğla Y","d":"Baba sağlıklıdır; kıza sağlam X^A, oğla ise Y verir."},{"t":"Kim hasta olur?","a":"Erkek çocuk","d":"Anneden X^a alan erkek çocuk X^a Y olur ve renk körü olur; kızlar baba X^A verdiği için en fazla taşıyıcı olur."}],"ans":"Renk körlüğü yalnızca anneden X^a alan erkek çocukta çıkabilir; kızlar hasta olmaz."},{"q":"Bir ailede baba renk körü, anne tamamen sağlam (X^A X^A). Kız çocukları renk körü olabilir mi?","steps":[{"t":"Babadan gelen","a":"X^a","d":"Renk körü baba kız çocuğuna renk körlüğü genli <b>X^a</b> verir."},{"t":"Anneden gelen","a":"X^A","d":"Anne tamamen sağlam olduğundan kıza sağlam X^A verir."},{"t":"Kızın durumu","a":"X^A X^a taşıyıcı","d":"Kız X^A X^a olur; sağlam gen hasta geni maskelediği için renk körü olmaz, sadece taşıyıcı olur."}],"ans":"Hayır, kızlar X^A X^a taşıyıcı olur ama renk körü olmaz."},{"q":"Hemofili neden çoğunlukla erkeklerde görülür? X kromozomu sayısıyla açıklayınız.","steps":[{"t":"Genin yeri","a":"X kromozomu","d":"Hemofili geni <b>X kromozomu</b> üzerinde taşınan çekinik bir gendir."},{"t":"Erkekte tek X","a":"Maskeleyen yok","d":"Erkekte tek X olduğu için hasta geni gizleyecek ikinci bir sağlam X bulunmaz."},{"t":"Kızda iki X","a":"Çoğu kez korunur","d":"Kızda iki X olduğundan bir X'teki sağlam gen hastalığı maskeleyebilir; bu yüzden kızlarda nadir görülür."}],"ans":"Erkekte tek X olduğu için çekinik hemofili geni maskelenemez ve hastalık çoğunlukla erkeklerde görülür."},{"q":"Y kromozomu üzerinde taşınan bir özellik, bir babadan hangi çocuklara geçer?","steps":[{"t":"Y'yi kim alır?","a":"Erkek çocuk","d":"Baba yalnızca erkek çocuğuna <b>Y</b> kromozomunu verir; kız çocuğuna X verir."},{"t":"Sonuç","a":"Babadan oğula","d":"Y'ye bağlı özellik bu yüzden babadan yalnızca oğullara, kuşaktan kuşağa erkek hattıyla geçer."}],"ans":"Y'ye bağlı bir özellik babadan yalnızca erkek çocuklara (babadan oğula) geçer."},{"q":"Bir soy ağacında renk körlüğü hep erkeklerde görülüyor ve hasta erkeklerin anneleri sağlıklı. Bu hangi kalıtım biçimine işaret eder?","steps":[{"t":"Kimde görülüyor?","a":"Erkeklerde","d":"Hastalığın çoğunlukla <b>erkeklerde</b> çıkması X'e bağlı çekinik kalıtımı düşündürür."},{"t":"Anneler nasıl?","a":"Sağlıklı taşıyıcı","d":"Hasta erkeklerin annelerinin sağlıklı olması, onların geni saklı taşıyan taşıyıcı olduğunu gösterir."}],"ans":"Bu durum, geni taşıyıcı annelerden erkeklere geçen X'e bağlı çekinik kalıtıma işaret eder."}]},"lise":{"kolay":[{"q":"X'e bağlı çekinik kalıtım nedir?","steps":[{"t":"Genin konumu","a":"X kromozomu","d":"İlgili çekinik gen, cinsiyet kromozomlarından <b>X</b> üzerinde taşınır ve homolog kısmı Y'de bulunmaz."},{"t":"Ortaya çıkış","a":"Erkekte tek, kızda çift gerek","d":"Erkekte tek X'te gen varsa fenotipe yansır; kızda fenotipe yansıması için iki X'te de çekinik genin (homozigot) bulunması gerekir."}],"ans":"X'e bağlı çekinik kalıtım, çekinik genin X kromozomunda taşındığı; erkekte tek dozda, kızda çift dozda ortaya çıkan kalıtım biçimidir."},{"q":"İnsanda eşey (cinsiyet) kromozomlarının dizilimi nasıldır ve cinsiyeti hangisi belirler?","steps":[{"t":"Dişi ve erkek","a":"XX ve XY","d":"Dişiler iki X (XX), erkekler bir X ve bir Y (XY) eşey kromozomu taşır."},{"t":"Belirleyici gamet","a":"Erkeğin gameti","d":"Dişi yalnızca X taşıyan yumurta verirken, erkek X ya da Y taşıyan sperm üretir; bu yüzden cinsiyeti babanın gameti belirler."}],"ans":"Dişi XX, erkek XY taşır; cinsiyeti X ya da Y taşıyan baba gameti belirler."},{"q":"X^a gösterimi neyi ifade eder?","steps":[{"t":"X neyi gösterir?","a":"X kromozomu","d":"<b>X</b> harfi, genin taşındığı X kromozomunu temsil eder."},{"t":"Üstteki küçük harf","a":"Çekinik alel","d":"Üstteki küçük 'a', X üzerindeki çekinik aleli (örneğin renk körlüğü alelini) belirtir; büyük X^A ise baskın sağlam aleldir."}],"ans":"X^a gösterimi, X kromozomu üzerinde çekinik bir alelin (örneğin renk körlüğü aleli) bulunduğunu ifade eder."},{"q":"Renk körlüğü hangi tür kalıtımla aktarılır?","steps":[{"t":"Genin yeri","a":"X kromozomu","d":"Renk körlüğü geni <b>X kromozomu</b> üzerinde bulunur, otozomal değildir."},{"t":"Aletin niteliği","a":"Çekinik","d":"Aleli çekinik olduğundan ve X'te taşındığından renk körlüğü X'e bağlı çekinik kalıtımla aktarılır."}],"ans":"Renk körlüğü, X kromozomundaki çekinik bir alelle, yani X'e bağlı çekinik kalıtımla aktarılır."},{"q":"Hemofili hastalığında vücutta temel olarak ne aksar?","steps":[{"t":"Aksayan süreç","a":"Pıhtılaşma","d":"Hemofilide kanın <b>pıhtılaşması</b> için gerekli pıhtılaşma faktörlerinden biri eksik ya da bozuktur."},{"t":"Sonuç","a":"Kanama güç durur","d":"Pıhtılaşma faktörü yetersiz olduğundan küçük yaralanmalarda bile kanama uzun sürer ve güç durur."}],"ans":"Hemofilide pıhtılaşma faktörü eksik olduğundan kanın pıhtılaşması aksar ve kanama güç durur."},{"q":"Bir erkeğin X'e bağlı çekinik bir özellik bakımından genotipi neden taşıyıcı olamaz?","steps":[{"t":"Erkekteki X sayısı","a":"Tek X","d":"Erkekte yalnızca <b>tek X</b> bulunduğu için X'e bağlı gen tek bir dozdadır (hemizigot)."},{"t":"Sonuç","a":"Ya hasta ya sağlam","d":"Tek X'teki alel ne ise fenotipe doğrudan yansır; geni gizleyecek ikinci bir X olmadığından erkek taşıyıcı olamaz, ya hasta (X^a Y) ya sağlamdır (X^A Y)."}],"ans":"Erkekte tek X bulunduğundan alel doğrudan fenotipe yansır; bu yüzden erkek X'e bağlı bir özellikte taşıyıcı olamaz."},{"q":"Taşıyıcı bir kadının (X^A X^a) genotipi neden hasta fenotip vermez?","steps":[{"t":"İki X'i var","a":"X^A ve X^a","d":"Kadında biri sağlam (<b>X^A</b>), biri çekinik (X^a) iki X kromozomu bulunur."},{"t":"Baskınlık ilişkisi","a":"X^A baskın","d":"Sağlam alel (X^A) baskın olduğu için çekinik aleli maskeler; bu yüzden kadın hasta olmaz, yalnızca taşıyıcıdır."}],"ans":"Sağlam baskın alel (X^A), çekinik aleli (X^a) maskelediği için taşıyıcı kadın hasta fenotip göstermez."},{"q":"Renk körü bir baba (X^a Y), genini hangi çocuklarına nasıl aktarır?","steps":[{"t":"Baba kıza ne verir?","a":"X^a","d":"Baba kız çocuğuna mutlaka <b>X^a</b> kromozomunu verir."},{"t":"Baba oğla ne verir?","a":"Y","d":"Baba erkek çocuğuna Y kromozomunu verdiğinden renk körlüğü genini oğullarına aktarmaz."}],"ans":"Renk körü baba genini tüm kız çocuklarına X^a ile aktarır (taşıyıcı olurlar), oğullarına Y verdiği için aktaramaz."},{"q":"X'e bağlı çekinik bir hastalık taşıyan bir kadının fenotipte hasta olabilmesi için hangi koşul gereklidir?","steps":[{"t":"Kadında gen sayısı","a":"İki X","d":"Kadında iki X bulunduğundan ilgili gen iki kopya halindedir."},{"t":"Gerekli koşul","a":"Her iki X'te çekinik alel","d":"Hasta olması için her iki X'te de çekinik alelin bulunması (homozigot çekinik, X^a X^a) gerekir."}],"ans":"Bir kadının hasta olabilmesi için her iki X kromozomunda da çekinik alelin bulunması (X^a X^a homozigot) gerekir."},{"q":"Y'ye bağlı (holandrik) kalıtım ne anlama gelir?","steps":[{"t":"Genin yeri","a":"Y kromozomu","d":"Y'ye bağlı kalıtımda gen, yalnızca <b>Y kromozomu</b> üzerinde, X'te karşılığı olmayan bölgede taşınır."},{"t":"Aktarım yolu","a":"Babadan oğula","d":"Y'yi yalnızca erkekler taşıdığı için özellik babadan tüm erkek çocuklara, kesintisiz erkek hattıyla geçer."}],"ans":"Y'ye bağlı (holandrik) kalıtım, geni yalnızca Y'de taşınan ve babadan oğula erkek hattıyla geçen kalıtımdır."},{"q":"Soy ağacında X'e bağlı çekinik kalıtımın tipik bir işareti nedir?","steps":[{"t":"Cinsiyet dağılımı","a":"Erkeklerde fazla","d":"X'e bağlı çekinik hastalık <b>erkeklerde</b> kadınlardan belirgin biçimde daha sık görülür."},{"t":"Atlama deseni","a":"Taşıyıcı anneler","d":"Hastalık çoğunlukla sağlıklı taşıyıcı annelerden erkek çocuklara geçtiği için kuşak atlayarak görünebilir."}],"ans":"X'e bağlı çekinik kalıtımın tipik işareti, hastalığın erkeklerde daha sık görülmesi ve taşıyıcı annelerle kuşak atlayarak ortaya çıkmasıdır."},{"q":"Renk körlüğü bir kadında ortaya çıkması için anne ve babanın genotipleri en az ne olmalıdır?","steps":[{"t":"Babadan gelmesi gereken","a":"X^a","d":"Kızın bir X^a'sı babadan gelmelidir; bu yüzden baba renk körü (<b>X^a Y</b>) olmalıdır."},{"t":"Anneden gelmesi gereken","a":"X^a","d":"Diğer X^a anneden gelmeli; anne ya taşıyıcı (X^A X^a) ya da renk körü (X^a X^a) olmalıdır."}],"ans":"Renk körü bir kız için baba mutlaka renk körü (X^a Y), anne ise en az taşıyıcı (X^A X^a) olmalıdır."},{"q":"Bir erkek hangi ebeveyninden X kromozomunu, hangisinden Y kromozomunu alır?","steps":[{"t":"X nereden gelir?","a":"Anneden","d":"Erkek çocuk tek X kromozomunu <b>annesinden</b> alır, çünkü anne yalnızca X taşıyan yumurta verir."},{"t":"Y nereden gelir?","a":"Babadan","d":"Y kromozomunu babasından alır; bu yüzden X'e bağlı özellikleri erkek çocuk her zaman annesinden edinir."}],"ans":"Erkek çocuk X kromozomunu annesinden, Y kromozomunu babasından alır."},{"q":"X'e bağlı çekinik hastalıklarda kadınlar çoğunlukla hangi rolü üstlenir?","steps":[{"t":"Genotip olasılığı","a":"X^A X^a","d":"Bir X'inde çekinik alel, diğerinde sağlam alel taşıyan kadın <b>X^A X^a</b> genotipindedir."},{"t":"Fenotipteki rol","a":"Taşıyıcı","d":"Bu kadın hasta olmadan geni taşır ve oğullarına aktarabildiği için sıklıkla taşıyıcı rolünü üstlenir."}],"ans":"X'e bağlı çekinik hastalıklarda kadınlar çoğunlukla hasta olmayan taşıyıcı (X^A X^a) rolünü üstlenir."},{"q":"Otozomal çekinik kalıtım ile X'e bağlı çekinik kalıtım arasındaki temel fark nedir?","steps":[{"t":"Genin konumu","a":"Otozom mu X mi","d":"Otozomal çekinikte gen vücut (otozom) kromozomunda, X'e bağlıda ise <b>X kromozomunda</b> taşınır."},{"t":"Cinsiyet dağılımı","a":"Eşit mi farklı mı","d":"Otozomalde hastalık erkek ve kadında benzer sıklıkta görülürken, X'e bağlı çekinikte erkeklerde belirgin biçimde daha sık görülür."}],"ans":"Temel fark genin konumudur: otozomalde gen otozomda olup cinsiyetler eşit etkilenir, X'e bağlıda gen X'tedir ve erkekler daha sık etkilenir."}],"zor":[{"q":"Taşıyıcı bir anne (X^A X^a) ile sağlıklı bir baba (X^A Y) evleniyor. Çocukların renk körlüğü ve taşıyıcılık olasılıklarını hesaplayınız.","steps":[{"t":"Çaprazlamayı kur","a":"X^A X^a × X^A Y","d":"Anne gametleri X^A ve X^a; baba gametleri X^A ve Y'dir. Dört birleşim eşit olasılıklıdır."},{"t":"Genotipleri yaz","a":"X^A X^A, X^A X^a, X^A Y, X^a Y","d":"Birleşimler: 1/4 X^A X^A (sağlam kız), 1/4 X^A X^a (<b>taşıyıcı</b> kız), 1/4 X^A Y (sağlam erkek), 1/4 X^a Y (renk körü erkek)."},{"t":"Olasılıkları yorumla","a":"Renk körü 1/4","d":"Tüm çocukların 1/4'ü renk körü (yalnızca erkekler); erkeklerin 1/2'si renk körü, kızların 1/2'si taşıyıcı, hiçbir kız hasta değildir."}],"ans":"Çocukların 1/4'ü renk körü erkek olur; kızların yarısı taşıyıcı, hiçbir kız hasta değildir, erkeklerin yarısı renk körüdür."},{"q":"Renk körü bir baba (X^a Y) ile taşıyıcı bir anne (X^A X^a) evleniyor. Kız ve erkek çocuklarda renk körlüğü olasılığını ayrı ayrı bulunuz.","steps":[{"t":"Çaprazlamayı kur","a":"X^A X^a × X^a Y","d":"Anne gametleri X^A ve X^a; baba gametleri X^a ve Y'dir."},{"t":"Kız çocuklar","a":"X^A X^a ve X^a X^a","d":"Kızlar babadan X^a alır; anneden X^A gelirse X^A X^a (taşıyıcı), X^a gelirse <b>X^a X^a</b> (renk körü) olur. Kızların 1/2'si renk körüdür."},{"t":"Erkek çocuklar","a":"X^A Y ve X^a Y","d":"Erkekler babadan Y alır; anneden X^A gelirse sağlam, X^a gelirse renk körü (X^a Y) olur. Erkeklerin 1/2'si renk körüdür."}],"ans":"Hem kız hem erkek çocukların yarısı (1/2) renk körü olur; bu çaprazlamada ilk kez kızlar da hasta olabilir."},{"q":"Renk körü bir baba (X^a Y) ile tamamen sağlıklı bir anne (X^A X^A) evleniyor. Çocukların durumunu açıklayınız.","steps":[{"t":"Çaprazlamayı kur","a":"X^A X^A × X^a Y","d":"Anne yalnızca X^A gameti, baba X^a ve Y gametleri verir."},{"t":"Kız çocuklar","a":"X^A X^a","d":"Tüm kızlar anneden X^A, babadan X^a alır; hepsi <b>X^A X^a taşıyıcı</b> olur, hiçbiri hasta değildir."},{"t":"Erkek çocuklar","a":"X^A Y","d":"Tüm erkekler anneden sağlam X^A, babadan Y alır; hepsi sağlıklıdır, çünkü babadan X^a alamazlar."}],"ans":"Tüm kızlar taşıyıcı (X^A X^a), tüm erkekler sağlıklı olur; bu nesilde hiçbir çocuk renk körü değildir."},{"q":"X'e bağlı çekinik bir hastalığın erkeklerde kadınlardan çok daha sık görülmesini, gen dozu ve maskelenme açısından detaylı açıklayınız.","steps":[{"t":"Erkekte gen dozu","a":"Tek (hemizigot)","d":"Erkekte tek X olduğundan X'e bağlı gen <b>tek dozdadır</b>; tek bir çekinik alel bile fenotipe doğrudan yansır."},{"t":"Kadında gen dozu","a":"Çift","d":"Kadında iki X olduğundan gen çift dozdadır; çekinik alel ancak her iki X'te de bulunursa (X^a X^a) hastalık çıkar."},{"t":"Olasılık karşılaştırması","a":"Tek alel ≫ iki alel","d":"Tek çekinik alele sahip olma olasılığı, iki çekinik aleli bir arada taşıma olasılığından çok daha yüksektir; bu yüzden erkekler çok daha sık etkilenir."}],"ans":"Erkekte tek X nedeniyle bir çekinik alel hastalık için yeterken, kadında iki çekinik alel gerektiğinden erkekler X'e bağlı çekinik hastalıklara çok daha sık yakalanır."},{"q":"Bir populasyonda renk körlüğü alelinin (X^a) sıklığı q = 0,08'dir. Erkeklerde ve kadınlarda renk körlüğü görülme oranlarını hesaplayıp karşılaştırınız.","steps":[{"t":"Erkeklerde oran","a":"q = 0,08","d":"Erkek tek X taşıdığından renk körü olma olasılığı doğrudan alel sıklığına eşittir: 0,08, yani <b>%8</b>."},{"t":"Kadınlarda oran","a":"q² = 0,08²","d":"Kadın hasta olması için iki X'te de X^a gerektiğinden olasılık q² = 0,08 × 0,08 = 0,0064, yani %0,64'tür."},{"t":"Karşılaştır","a":"0,08 / 0,0064 ≈ 12,5 kat","d":"Erkeklerdeki oran kadınlardakinin yaklaşık 12,5 katıdır; bu, erkeklerde neden çok daha sık görüldüğünü sayısal olarak gösterir."}],"ans":"Erkeklerde renk körlüğü oranı %8 (q), kadınlarda %0,64 (q²) olup erkeklerde yaklaşık 12,5 kat daha sıktır."},{"q":"Hemofili taşıyıcısı bir anne (X^H X^h) ile sağlıklı bir baba (X^H Y) evlenirse, doğacak bir erkek çocuğun hemofili olma olasılığı kaçtır?","steps":[{"t":"Erkek çocuğun X kaynağı","a":"Anneden","d":"Erkek çocuk X kromozomunu yalnızca <b>anneden</b> alır; babadan Y alır."},{"t":"Anne gametleri","a":"1/2 X^H, 1/2 X^h","d":"Taşıyıcı anne, oğluna 1/2 olasılıkla sağlam X^H, 1/2 olasılıkla hasta X^h verir."},{"t":"Olasılığı bul","a":"1/2 hasta","d":"Anneden X^h alan erkek X^h Y olup hemofilidir; bu yüzden bir erkek çocuğun hemofili olma olasılığı 1/2'dir."}],"ans":"Doğacak bir erkek çocuğun hemofili olma olasılığı 1/2'dir (%50)."},{"q":"Yukarıdaki taşıyıcı anne (X^H X^h) × sağlıklı baba (X^H Y) çaprazlamasında, doğacak herhangi bir çocuğun (cinsiyet bilinmeden) hemofili olma olasılığı kaçtır?","steps":[{"t":"Olası genotipler","a":"4 eşit grup","d":"Çocuklar 1/4 X^H X^H, 1/4 X^H X^h, 1/4 X^H Y, 1/4 X^h Y olarak dağılır."},{"t":"Hasta olanı seç","a":"Yalnızca X^h Y","d":"Bu genotiplerden yalnızca <b>X^h Y</b> hemofili hastasıdır; kızlar baba X^H verdiği için hasta olamaz."},{"t":"Olasılığı bul","a":"1/4","d":"Hasta birey dört eşit gruptan biri olduğundan, cinsiyet belirtilmeden bir çocuğun hemofili olma olasılığı 1/4'tür."}],"ans":"Cinsiyet bilinmeden bir çocuğun hemofili olma olasılığı 1/4'tür (%25)."},{"q":"Bir soy ağacında hemofilili bir erkeğin sağlıklı anne-babası var; ayrıca dayısı da hemofilidir. Anne ve anneanneanin genotipini açıklayınız.","steps":[{"t":"Hastanın X kaynağı","a":"Anneden","d":"Hemofilili erkek X^h'yi <b>anneden</b> almıştır; baba sağlıklı olduğundan ve oğluna Y verdiğinden baba kaynak olamaz."},{"t":"Annenin genotipi","a":"X^H X^h","d":"Anne sağlıklı ama oğlu hasta olduğundan zorunlu olarak taşıyıcıdır (X^H X^h)."},{"t":"Anneannenin durumu","a":"En az taşıyıcı","d":"Annenin kardeşi (dayı) da hemofili olduğundan X^h aleli bir kuşak önceden gelir; bu yüzden anneanne de en az taşıyıcı (X^H X^h) olmalıdır."}],"ans":"Anne zorunlu taşıyıcıdır (X^H X^h); dayının da hemofilili olması anneannenin en az taşıyıcı (X^H X^h) olduğunu gösterir."},{"q":"X'e bağlı çekinik ve X'e bağlı baskın kalıtımı, etkilenen cinsiyet dağılımı açısından karşılaştırınız.","steps":[{"t":"X'e bağlı çekinik","a":"Erkeklerde sık","d":"Çekinik tipte erkek tek X'te alel taşıdığında hastalanır; kadın iki X'te de taşımalıdır, bu yüzden <b>erkeklerde</b> daha sık görülür."},{"t":"X'e bağlı baskın","a":"Kadınlarda sık","d":"Baskın tipte tek bir baskın alel bile hastalık için yeter; kadın iki X taşıdığından alel bulundurma olasılığı yüksektir, bu yüzden kadınlarda görülme oranı erkeklere yakın veya daha fazladır."},{"t":"Baba aktarımı farkı","a":"Kıza geçer, oğula geçmez","d":"Her iki tipte de etkilenen baba aleli yalnızca kız çocuklarına aktarır; oğullarına X vermediğinden geçiremez."}],"ans":"X'e bağlı çekinik kalıtımda hastalık erkeklerde daha sık, X'e bağlı baskın kalıtımda ise kadınlarda en az erkekler kadar veya daha sık görülür; her iki tipte de etkilenen baba aleli yalnızca kızlarına aktarır."},{"q":"Renk körü olmayan ama taşıyıcı bir anne (X^A X^a) ile renk körü bir babanın (X^a Y) tüm olası çocuk genotip ve fenotiplerini Punnett karesiyle çıkarınız.","steps":[{"t":"Gametleri belirle","a":"Anne: X^A, X^a / Baba: X^a, Y","d":"Anne X^A ve X^a; baba X^a ve Y gametleri üretir, dört birleşim eşit olasılıklıdır."},{"t":"Genotipleri yaz","a":"X^A X^a, X^a X^a, X^A Y, X^a Y","d":"Birleşimler: X^A X^a (taşıyıcı kız), X^a X^a (renk körü kız), X^A Y (sağlam erkek), <b>X^a Y</b> (renk körü erkek)."},{"t":"Fenotip dağılımı","a":"Yarısı renk körü","d":"Kızların yarısı taşıyıcı yarısı renk körü; erkeklerin yarısı sağlam yarısı renk körü. Tüm çocukların 1/2'si renk körüdür."}],"ans":"Çocuklar 1/4 taşıyıcı kız, 1/4 renk körü kız, 1/4 sağlam erkek, 1/4 renk körü erkek olur; toplamda yarısı renk körüdür."},{"q":"İki X'e sahip bir kadında, X'e bağlı çekinik bir hastalığın taşıyıcı olduğu halde nadiren hafif belirti gösterebilmesini X kromozomu inaktivasyonu (Lyon hipotezi) ile açıklayınız.","steps":[{"t":"X inaktivasyonu","a":"Bir X susturulur","d":"Dişi hücrelerinde gen dozunu dengelemek için her hücrede iki X'ten biri rastgele <b>inaktive</b> edilir (Barr cismi)."},{"t":"Rastgele dağılım","a":"Hücreden hücreye değişir","d":"Bazı hücrelerde sağlam X^A, bazılarında çekinik X^a etkin kalır; bu mozaik bir doku oluşturur."},{"t":"Hafif belirti olasılığı","a":"X^a'lı hücre fazlaysa","d":"Çekinik aleli taşıyan X'in baskın biçimde etkin kaldığı hücreler çoğunluktaysa, taşıyıcı kadın hafif belirtiler gösterebilir."}],"ans":"X inaktivasyonu nedeniyle taşıyıcı kadının dokuları mozaiktir; çekinik aleli taşıyan X'in etkin kaldığı hücreler baskın gelirse taşıyıcı kadın hafif belirti gösterebilir."},{"q":"Bir araştırmacı, bir özelliğin babadan yalnızca tüm erkek çocuklara geçtiğini, hiçbir kız çocukta görülmediğini gözlemliyor. Bu özelliğin kalıtım biçimini gerekçeleriyle belirleyiniz.","steps":[{"t":"Aktarım yönü","a":"Baba → oğul","d":"Özellik yalnızca babadan erkek çocuklara geçiyorsa, ilgili gen babanın yalnızca oğullarına verdiği bir kromozomda olmalıdır."},{"t":"Hangi kromozom?","a":"Y kromozomu","d":"Baba oğullarına yalnızca <b>Y</b> kromozomunu verdiğinden ve kızlar hiç etkilenmediğinden gen Y üzerinde olmalıdır."},{"t":"Sonuç","a":"Y'ye bağlı","d":"Bu desen, genin Y'de taşındığı ve erkek hattıyla kesintisiz aktarıldığı Y'ye bağlı (holandrik) kalıtımdır."}],"ans":"Özellik babadan tüm oğullara geçip kızlarda hiç görülmediğinden bu, genin Y kromozomunda taşındığı Y'ye bağlı (holandrik) kalıtımdır."},{"q":"Taşıyıcı anne (X^A X^a) × renk körü baba (X^a Y) çiftinin doğacak kız çocuğunun renk körü OLMAMA olasılığını hesaplayınız.","steps":[{"t":"Kızın X kaynakları","a":"Anneden + babadan","d":"Kız bir X'i anneden (X^A veya X^a), diğerini babadan (her zaman X^a) alır."},{"t":"Kız genotipleri","a":"X^A X^a veya X^a X^a","d":"Anneden X^A gelirse X^A X^a (taşıyıcı, sağlam fenotip), X^a gelirse <b>X^a X^a</b> (renk körü) olur; iki durum eşit olasılıklıdır."},{"t":"Sağlam olasılığı","a":"1/2","d":"Kızın renk körü olmaması için anneden X^A alması gerekir; bu olasılık 1/2'dir."}],"ans":"Doğacak kız çocuğunun renk körü olmama olasılığı 1/2'dir (%50; taşıyıcı ama sağlam fenotip)."},{"q":"Bir ailede ilk erkek çocuk hemofili. İkinci çocuğun da hemofilili bir erkek olma olasılığını (taşıyıcı anne X^H X^h, sağlıklı baba X^H Y varsayarak) hesaplayınız.","steps":[{"t":"Erkek olma olasılığı","a":"1/2","d":"Her gebelikte çocuğun erkek olma olasılığı, babanın X ya da Y vermesine bağlı olarak <b>1/2</b>'dir."},{"t":"Erkekse hasta olma olasılığı","a":"1/2","d":"Erkek çocuk X'ini anneden alır; taşıyıcı anneden X^h alma olasılığı 1/2 olduğundan erkek çocuğun hasta olma olasılığı 1/2'dir."},{"t":"Birleşik olasılık","a":"1/2 × 1/2 = 1/4","d":"İki bağımsız koşulun birlikte gerçekleşme olasılığı çarpılır: 1/2 × 1/2 = 1/4. İlk çocuğun durumu ikinciyi etkilemez."}],"ans":"İkinci çocuğun hemofilili bir erkek olma olasılığı 1/4'tür (%25); ilk çocuğun hasta olması bu olasılığı değiştirmez."},{"q":"X'e bağlı çekinik bir hastalıkta, etkilenen bir erkeğin hastalığı torununa hangi yolla aktarabileceğini (kızı aracılığıyla) açıklayınız.","steps":[{"t":"Hasta erkek kıza ne verir?","a":"X^a","d":"Hasta erkek (X^a Y) kız çocuğuna mutlaka <b>X^a</b> aktarır; kız böylece taşıyıcı (X^A X^a) olur."},{"t":"Taşıyıcı kızın gametleri","a":"1/2 X^a","d":"Taşıyıcı kız ileride kendi çocuklarına 1/2 olasılıkla X^a verir."},{"t":"Toruna ulaşması","a":"Erkek torunda hasta","d":"Bu X^a'yı alan erkek torun (X^a Y) hastalanır; böylece hastalık dede → sağlıklı taşıyıcı kız → erkek torun yoluyla bir kuşak atlayarak aktarılır."}],"ans":"Hasta erkek X^a'yı kızına verir, kız taşıyıcı olur; bu X^a'yı alan erkek torun hastalanır, yani hastalık kızı aracılığıyla bir kuşak atlayarak torununa geçer."}]}}};
